/* fh-data.js — Food Handler practice (FDA Food Code 2022 basics). 5 topics, all 6 languages.
   window.FH = { cats:[{id,name,blurb}], q:[{cat,a,q,o,e}] }
   250 questions: hygiene(50), temp(52), crosscontam(51), illness(47), cleaning(50) */
window.FH = {"cats":[{"id":"hygiene","name":{"en":"Personal Hygiene & Health","es":"Higiene personal y salud","ru":"Личная гигиена и здоровье","tr":"Kişisel Hijyen ve Sağlık","hi":"व्यक्तिगत स्वच्छता और स्वास्थ्य","ar":"النظافة الشخصية والصحة"},"blurb":{"en":"Handwashing, gloves, no bare-hand contact, and when to stay home.","es":"Lavado de manos, guantes, sin contacto con las manos desnudas, y cuándo quedarse en casa.","ru":"Мытьё рук, перчатки, запрет голых рук и когда оставаться дома.","tr":"El yıkama, eldiven, çıplak elle temas yok ve ne zaman evde kalmalı.","hi":"हाथ धोना, दस्ताने, नंगे हाथ का संपर्क नहीं, और कब घर पर रहें।","ar":"غسل اليدين، والقفازات، وعدم الملامسة باليد العارية، ومتى تبقى في المنزل."}},{"id":"temp","name":{"en":"Time & Temperature","es":"Tiempo y temperatura","ru":"Время и температура","tr":"Zaman ve Sıcaklık","hi":"समय और तापमान","ar":"الوقت ودرجة الحرارة"},"blurb":{"en":"The danger zone, cooking, cooling, holding and thermometers.","es":"La zona de peligro, cocción, enfriamiento, conservación y termómetros.","ru":"Опасная зона, готовка, охлаждение, хранение и термометры.","tr":"Tehlikeli bölge, pişirme, soğutma, muhafaza ve termometreler.","hi":"खतरनाक क्षेत्र, पकाना, ठंडा करना, रखना और थर्मामीटर।","ar":"منطقة الخطر، والطهي، والتبريد، والحفظ، وموازين الحرارة."}},{"id":"crosscontam","name":{"en":"Cross-Contamination & Allergens","es":"Contaminación cruzada y alérgenos","ru":"Перекрёстное загрязнение и аллергены","tr":"Çapraz Bulaşma ve Alerjenler","hi":"क्रॉस-कॉन्टैमिनेशन और एलर्जेन","ar":"التلوث المتبادل ومسببات الحساسية"},"blurb":{"en":"Separation, storage order, and the major food allergens.","es":"Separación, orden de almacenamiento y los principales alérgenos.","ru":"Разделение, порядок хранения и основные пищевые аллергены.","tr":"Ayırma, depolama sırası ve başlıca gıda alerjenleri.","hi":"पृथक्करण, भंडारण क्रम, और प्रमुख खाद्य एलर्जेन।","ar":"الفصل، وترتيب التخزين، ومسببات الحساسية الغذائية الرئيسية."}},{"id":"illness","name":{"en":"Foodborne Illness","es":"Enfermedades transmitidas por alimentos","ru":"Пищевые заболевания","tr":"Gıda Kaynaklı Hastalıklar","hi":"खाद्यजनित बीमारी","ar":"الأمراض المنقولة بالغذاء"},"blurb":{"en":"The Big 6 pathogens, FAT TOM, symptoms and reporting.","es":"Los 6 grandes patógenos, FAT TOM, síntomas y notificación.","ru":"«Большая шестёрка» патогенов, FAT TOM, симптомы и отчётность.","tr":"Büyük 6 patojen, FAT TOM, belirtiler ve bildirim.","hi":"बिग 6 रोगाणु, FAT TOM, लक्षण और रिपोर्टिंग।","ar":"مسببات الأمراض الستة الكبرى، وFAT TOM، والأعراض والإبلاغ."}},{"id":"cleaning","name":{"en":"Cleaning, Receiving & Storage","es":"Limpieza, recepción y almacenamiento","ru":"Уборка, приёмка и хранение","tr":"Temizlik, Teslim Alma ve Depolama","hi":"सफाई, प्राप्ति और भंडारण","ar":"التنظيف والاستلام والتخزين"},"blurb":{"en":"Cleaning vs. sanitizing, the 3-sink method, receiving, FIFO and pests.","es":"Limpieza vs. desinfección, el método de 3 fregaderos, recepción, FIFO y plagas.","ru":"Уборка против дезинфекции, метод трёх моек, приёмка, FIFO и вредители.","tr":"Temizlik vs. sanitasyon, 3 evyeli yöntem, teslim alma, FIFO ve haşereler.","hi":"सफाई बनाम सैनिटाइज़िंग, 3-सिंक विधि, प्राप्ति, FIFO और कीट।","ar":"التنظيف مقابل التطهير، وطريقة الأحواض الثلاثة، والاستلام، وFIFO، والآفات."}}],"q":[{"cat":"hygiene","a":0,"q":{"en":"About how long should a food handler scrub their hands during proper handwashing?","es":"¿Aproximadamente cuánto tiempo debe restregarse las manos un manipulador de alimentos durante un lavado de manos adecuado?","ru":"Примерно сколько времени работник пищевого производства должен тереть руки при правильном мытье рук?","tr":"Bir gıda çalışanı doğru el yıkama sırasında ellerini yaklaşık ne kadar süre ovalamalıdır?","hi":"उचित हाथ धोने के दौरान एक फूड हैंडलर को लगभग कितनी देर तक अपने हाथ रगड़ने चाहिए?","ar":"ما المدة التقريبية التي ينبغي أن يفرك خلالها متداول الطعام يديه أثناء غسل اليدين بطريقة صحيحة؟"},"o":[{"en":"At least 20 seconds","es":"Al menos 20 segundos","ru":"Не менее 20 секунд","tr":"En az 20 saniye","hi":"कम से कम 20 सेकंड","ar":"20 ثانية على الأقل"},{"en":"About 5 seconds","es":"Aproximadamente 5 segundos","ru":"Около 5 секунд","tr":"Yaklaşık 5 saniye","hi":"लगभग 5 सेकंड","ar":"نحو 5 ثوانٍ"},{"en":"At least 2 minutes","es":"Al menos 2 minutos","ru":"Не менее 2 минут","tr":"En az 2 dakika","hi":"कम से कम 2 मिनट","ar":"دقيقتان على الأقل"},{"en":"Only until the soap is rinsed off","es":"Solo hasta que se enjuague el jabón","ru":"Только до тех пор, пока не смоется мыло","tr":"Yalnızca sabun durulanana kadar","hi":"केवल तब तक जब तक साबुन धुल न जाए","ar":"فقط حتى يُشطف الصابون"}],"e":{"en":"The whole handwashing process should take at least 20 seconds, with about 10 to 15 seconds of scrubbing with soap before rinsing and drying.","es":"Todo el proceso de lavado de manos debe durar al menos 20 segundos, con aproximadamente 10 a 15 segundos de restregado con jabón antes de enjuagar y secar.","ru":"Весь процесс мытья рук должен занимать не менее 20 секунд, при этом около 10–15 секунд нужно тереть руки с мылом перед ополаскиванием и высушиванием.","tr":"Tüm el yıkama süreci en az 20 saniye sürmeli; durulama ve kurulamadan önce yaklaşık 10 ila 15 saniye sabunla ovalama yapılmalıdır.","hi":"पूरी हाथ धोने की प्रक्रिया में कम से कम 20 सेकंड लगने चाहिए, जिसमें धोने और सुखाने से पहले लगभग 10 से 15 सेकंड साबुन के साथ रगड़ना शामिल है।","ar":"ينبغي أن تستغرق عملية غسل اليدين بأكملها 20 ثانية على الأقل، مع نحو 10 إلى 15 ثانية من الفرك بالصابون قبل الشطف والتجفيف."}},{"cat":"hygiene","a":2,"q":{"en":"Which of these should a food handler use to wash their hands?","es":"¿Cuál de estos debe usar un manipulador de alimentos para lavarse las manos?","ru":"Что из перечисленного работник пищевого производства должен использовать для мытья рук?","tr":"Bir gıda çalışanı ellerini yıkamak için bunlardan hangisini kullanmalıdır?","hi":"एक फूड हैंडलर को अपने हाथ धोने के लिए इनमें से किसका उपयोग करना चाहिए?","ar":"أيٌّ مما يلي ينبغي أن يستخدمه متداول الطعام لغسل يديه؟"},"o":[{"en":"Hand sanitizer alone","es":"Solo desinfectante de manos","ru":"Только дезинфицирующее средство для рук","tr":"Tek başına el dezenfektanı","hi":"केवल हैंड सैनिटाइज़र","ar":"معقم اليدين وحده"},{"en":"Cold water with no soap","es":"Agua fría sin jabón","ru":"Холодную воду без мыла","tr":"Sabunsuz soğuk su","hi":"बिना साबुन के ठंडा पानी","ar":"ماء بارد دون صابون"},{"en":"Soap and running warm water","es":"Jabón y agua corriente tibia","ru":"Мыло и проточную тёплую воду","tr":"Sabun ve akan ılık su","hi":"साबुन और बहता हुआ गुनगुना पानी","ar":"الصابون والماء الدافئ الجاري"},{"en":"A damp wiping cloth","es":"Un paño de limpieza húmedo","ru":"Влажную салфетку для протирания","tr":"Nemli bir silme bezi","hi":"एक नम पोंछने वाला कपड़ा","ar":"قطعة قماش مبللة للمسح"}],"e":{"en":"Proper handwashing requires soap and running warm water followed by drying; hand sanitizer is not a substitute for washing.","es":"El lavado de manos adecuado requiere jabón y agua corriente tibia, seguido del secado; el desinfectante de manos no sustituye el lavado.","ru":"Правильное мытьё рук требует мыла и проточной тёплой воды с последующим высушиванием; дезинфицирующее средство для рук не заменяет мытьё.","tr":"Doğru el yıkama, sabun ve akan ılık su ile yıkamayı ve ardından kurulamayı gerektirir; el dezenfektanı yıkamanın yerini tutmaz.","hi":"उचित हाथ धोने के लिए साबुन और बहते हुए गुनगुने पानी की आवश्यकता होती है, उसके बाद सुखाना; हैंड सैनिटाइज़र हाथ धोने का विकल्प नहीं है।","ar":"يتطلب غسل اليدين الصحيح الصابون والماء الدافئ الجاري يتبعه التجفيف؛ ومعقم اليدين ليس بديلاً عن الغسل."}},{"cat":"hygiene","a":1,"q":{"en":"A cook is about to prepare a salad that will be served without further cooking. What does the Food Code require?","es":"Un cocinero está a punto de preparar una ensalada que se servirá sin cocción posterior. ¿Qué exige el Código de Alimentos (Food Code)?","ru":"Повар собирается приготовить салат, который будет подан без дальнейшей тепловой обработки. Что требует Food Code (Пищевой кодекс)?","tr":"Bir aşçı, ek pişirme yapılmadan servis edilecek bir salata hazırlamak üzeredir. Gıda Kanunu (Food Code) ne gerektirir?","hi":"एक रसोइया एक ऐसा सलाद बनाने वाला है जिसे बिना और पकाए परोसा जाएगा। फूड कोड क्या आवश्यक मानता है?","ar":"يوشك طاهٍ على تحضير سلطة سيتم تقديمها دون طهي إضافي. ماذا يشترط قانون الغذاء (Food Code)؟"},"o":[{"en":"Bare hands are fine since the salad is fresh","es":"Las manos sin guantes están bien porque la ensalada es fresca","ru":"Голыми руками можно, ведь салат свежий","tr":"Salata taze olduğundan çıplak el kullanmak sorunsuzdur","hi":"चूंकि सलाद ताज़ा है, इसलिए नंगे हाथ ठीक हैं","ar":"لا بأس بملامسة اليدين العاريتين لأن السلطة طازجة"},{"en":"No bare-hand contact with the ready-to-eat food","es":"No tocar el alimento listo para comer con las manos descubiertas","ru":"Нельзя касаться готовых к употреблению продуктов голыми руками","tr":"Yemeye hazır gıdaya çıplak elle temas edilmemelidir","hi":"खाने के लिए तैयार भोजन के साथ नंगे हाथों का संपर्क नहीं","ar":"عدم ملامسة الطعام الجاهز للأكل باليدين العاريتين"},{"en":"Bare-hand contact is allowed if hands were just washed","es":"Se permite el contacto con las manos descubiertas si las manos se acaban de lavar","ru":"Касание голыми руками допустимо, если руки только что вымыли","tr":"Eller az önce yıkanmışsa çıplak elle temas edilebilir","hi":"अगर हाथ अभी-अभी धोए गए हों तो नंगे हाथों का संपर्क स्वीकार्य है","ar":"يُسمح بملامسة اليدين العاريتين إذا كانتا قد غُسلتا للتو"},{"en":"Only the person in charge may touch ready-to-eat food","es":"Solo la persona a cargo puede tocar el alimento listo para comer","ru":"Только ответственное лицо может касаться готовых к употреблению продуктов","tr":"Yemeye hazır gıdaya yalnızca sorumlu kişi dokunabilir","hi":"केवल प्रभारी व्यक्ति ही खाने के लिए तैयार भोजन को छू सकता है","ar":"يجوز للمسؤول وحده ملامسة الطعام الجاهز للأكل"}],"e":{"en":"Food handlers may not touch ready-to-eat food with bare hands; they must use gloves, tongs, deli paper, or other utensils.","es":"Los manipuladores de alimentos no pueden tocar los alimentos listos para comer con las manos descubiertas; deben usar guantes, pinzas, papel de charcutería u otros utensilios.","ru":"Работники пищевого производства не должны касаться готовых к употреблению продуктов голыми руками; они обязаны использовать перчатки, щипцы, специальную бумагу или другую утварь.","tr":"Gıda çalışanları yemeye hazır gıdaya çıplak elle dokunamaz; eldiven, maşa, deli kağıdı veya başka aletler kullanmalıdırlar.","hi":"फूड हैंडलर खाने के लिए तैयार भोजन को नंगे हाथों से नहीं छू सकते; उन्हें दस्ताने, चिमटे, डेली पेपर, या अन्य बर्तनों का उपयोग करना चाहिए।","ar":"لا يجوز لمتداولي الطعام ملامسة الطعام الجاهز للأكل باليدين العاريتين؛ بل يجب عليهم استخدام القفازات أو الملاقط أو ورق التغليف (deli paper) أو أدوات أخرى."}},{"cat":"hygiene","a":3,"q":{"en":"Which symptom requires a food handler to report to the person in charge AND typically stay home?","es":"¿Qué síntoma exige que un manipulador de alimentos lo reporte a la persona a cargo Y, por lo general, se quede en casa?","ru":"Какой симптом обязывает работника пищевого производства сообщить ответственному лицу И, как правило, остаться дома?","tr":"Hangi belirti, bir gıda çalışanının sorumlu kişiye bildirimde bulunmasını VE genellikle evde kalmasını gerektirir?","hi":"किस लक्षण के लिए एक फूड हैंडलर को प्रभारी व्यक्ति को रिपोर्ट करना AND आमतौर पर घर पर रहना आवश्यक है?","ar":"أيُّ عَرَض يُلزِم متداول الطعام بإبلاغ المسؤول، ويستوجب عادةً البقاء في المنزل؟"},"o":[{"en":"A mild headache","es":"Un dolor de cabeza leve","ru":"Лёгкая головная боль","tr":"Hafif bir baş ağrısı","hi":"हल्का सिरदर्द","ar":"صداع خفيف"},{"en":"A runny nose from allergies","es":"Goteo nasal por alergias","ru":"Насморк из-за аллергии","tr":"Alerjiye bağlı burun akıntısı","hi":"एलर्जी से बहती नाक","ar":"سيلان الأنف بسبب الحساسية"},{"en":"Feeling tired after a long shift","es":"Sentirse cansado después de un turno largo","ru":"Усталость после длинной смены","tr":"Uzun bir vardiyadan sonra yorgun hissetmek","hi":"लंबी शिफ्ट के बाद थकान महसूस करना","ar":"الشعور بالتعب بعد مناوبة طويلة"},{"en":"Vomiting or diarrhea","es":"Vómito o diarrea","ru":"Рвота или диарея","tr":"Kusma veya ishal","hi":"उल्टी या दस्त","ar":"التقيؤ أو الإسهال"}],"e":{"en":"Vomiting and diarrhea are reportable symptoms that require excluding the employee from the establishment until they are symptom-free as required.","es":"El vómito y la diarrea son síntomas que deben reportarse y que exigen excluir al empleado del establecimiento hasta que esté libre de síntomas según lo requerido.","ru":"Рвота и диарея — это симптомы, подлежащие обязательному уведомлению, которые требуют отстранения работника от заведения до тех пор, пока он не будет свободен от симптомов, как предписано.","tr":"Kusma ve ishal, bildirimi zorunlu belirtilerdir ve çalışanın gerekli süre boyunca belirtileri geçene kadar işletmeden uzaklaştırılmasını (hariç tutulmasını) gerektirir.","hi":"उल्टी और दस्त रिपोर्ट करने योग्य लक्षण हैं जिनके लिए कर्मचारी को आवश्यकतानुसार लक्षण-मुक्त होने तक प्रतिष्ठान से बाहर रखना आवश्यक है।","ar":"يُعدّ التقيؤ والإسهال من الأعراض الواجب الإبلاغ عنها، وهي تستوجب استبعاد الموظف من المنشأة إلى أن يتعافى من الأعراض وفق ما هو مطلوب."}},{"cat":"hygiene","a":1,"q":{"en":"How should a food handler wearing single-use gloves handle a small cut on a finger?","es":"¿Cómo debe manejar un manipulador de alimentos que usa guantes desechables un pequeño corte en un dedo?","ru":"Как работник пищевого производства, носящий одноразовые перчатки, должен поступить с небольшим порезом на пальце?","tr":"Tek kullanımlık eldiven giyen bir gıda çalışanı, parmağındaki küçük bir kesiği nasıl ele almalıdır?","hi":"एकल-उपयोग दस्ताने पहने हुए एक फूड हैंडलर को अपनी उंगली पर एक छोटे से कट को कैसे संभालना चाहिए?","ar":"كيف ينبغي لمتداول طعام يرتدي قفازات أحادية الاستخدام أن يتعامل مع جرح صغير في إصبعه؟"},"o":[{"en":"Just wash the cut and keep working bare-handed","es":"Solo lavar el corte y seguir trabajando con las manos descubiertas","ru":"Просто промыть порез и продолжать работать голыми руками","tr":"Sadece kesiği yıkayıp çıplak elle çalışmaya devam etmeli","hi":"बस कट को धोएं और नंगे हाथों से काम करते रहें","ar":"مجرد غسل الجرح والاستمرار في العمل باليدين العاريتين"},{"en":"Cover it with a bandage and a finger cot, then put a glove over it","es":"Cubrirlo con una venda y un dedil, y luego ponerse un guante encima","ru":"Закрыть его пластырем и напальчником, а затем надеть сверху перчатку","tr":"Yara bandı ve parmak kılıfı (finger cot) ile kapatıp üzerine eldiven giymeli","hi":"इसे एक पट्टी और एक फिंगर कॉट से ढकें, फिर उसके ऊपर एक दस्ताना पहनें","ar":"تغطيته بلاصق طبي وكُمّ إصبعي (finger cot)، ثم وضع قفاز فوقه"},{"en":"Cover it with a cloth napkin tucked into the glove","es":"Cubrirlo con una servilleta de tela metida dentro del guante","ru":"Закрыть его тканевой салфеткой, заправленной в перчатку","tr":"Eldivenin içine sıkıştırılmış bir kumaş peçeteyle kapatmalı","hi":"इसे दस्ताने में दबाए गए कपड़े के नैपकिन से ढकें","ar":"تغطيته بمنديل قماشي مثبَّت داخل القفاز"},{"en":"Leave it uncovered since the glove is enough","es":"Dejarlo descubierto porque el guante es suficiente","ru":"Оставить его открытым, ведь перчатки достаточно","tr":"Eldiven yeterli olduğundan açık bırakmalı","hi":"इसे खुला छोड़ दें क्योंकि दस्ताना ही काफी है","ar":"تركه مكشوفاً لأن القفاز كافٍ"}],"e":{"en":"Cuts or wounds on the hand must be covered with a waterproof bandage plus a finger cot and/or single-use glove to prevent contamination.","es":"Los cortes o heridas en la mano deben cubrirse con una venda impermeable más un dedil o un guante desechable para evitar la contaminación.","ru":"Порезы или раны на руке должны быть закрыты водонепроницаемым пластырем плюс напальчником и/или одноразовой перчаткой, чтобы предотвратить загрязнение.","tr":"El üzerindeki kesikler veya yaralar, kontaminasyonu önlemek için su geçirmez bir yara bandının yanı sıra bir parmak kılıfı ve/veya tek kullanımlık eldivenle kapatılmalıdır.","hi":"हाथ पर कट या घावों को संदूषण रोकने के लिए एक जलरोधक पट्टी के साथ एक फिंगर कॉट और/या एकल-उपयोग दस्ताने से ढका जाना चाहिए।","ar":"يجب تغطية الجروح أو الإصابات في اليد بلاصق طبي مقاوم للماء مع كُمّ إصبعي (finger cot) و/أو قفاز أحادي الاستخدام لمنع التلوث."}},{"cat":"hygiene","a":3,"q":{"en":"Why must food handlers wear an effective hair restraint while working with food?","es":"¿Por qué deben usar los manipuladores de alimentos una sujeción eficaz para el cabello mientras trabajan con alimentos?","ru":"Почему работники пищевого производства должны носить эффективное средство для фиксации волос во время работы с продуктами?","tr":"Gıda çalışanları neden gıdayla çalışırken etkili bir saç koruyucu (bone vb.) takmalıdır?","hi":"भोजन के साथ काम करते समय फूड हैंडलर को प्रभावी बाल अवरोधक क्यों पहनना चाहिए?","ar":"لماذا يجب على متداولي الطعام ارتداء غطاء فعّال للشعر أثناء العمل مع الطعام؟"},"o":[{"en":"Because hair restraints keep the kitchen cooler","es":"Porque las sujeciones para el cabello mantienen la cocina más fresca","ru":"Потому что средства для фиксации волос сохраняют прохладу на кухне","tr":"Saç koruyucular mutfağı serin tuttuğu için","hi":"क्योंकि बाल अवरोधक रसोई को ठंडा रखते हैं","ar":"لأن أغطية الشعر تُبقي المطبخ أكثر برودة"},{"en":"To replace the need for handwashing","es":"Para reemplazar la necesidad de lavarse las manos","ru":"Чтобы заменить необходимость мытья рук","tr":"El yıkama ihtiyacının yerini almak için","hi":"हाथ धोने की आवश्यकता को बदलने के लिए","ar":"لتحل محل الحاجة إلى غسل اليدين"},{"en":"Only to look professional for customers","es":"Solo para verse profesionales ante los clientes","ru":"Только чтобы выглядеть профессионально для клиентов","tr":"Sadece müşterilere karşı profesyonel görünmek için","hi":"केवल ग्राहकों के लिए पेशेवर दिखने के लिए","ar":"فقط ليبدو مظهرهم احترافياً أمام الزبائن"},{"en":"To keep hair from falling into food and to reduce touching the hair","es":"Para evitar que el cabello caiga en los alimentos y para reducir el contacto con el cabello","ru":"Чтобы волосы не попадали в продукты и чтобы реже трогать волосы","tr":"Saçın gıdaya düşmesini önlemek ve saça dokunmayı azaltmak için","hi":"बालों को भोजन में गिरने से रोकने और बालों को छूने को कम करने के लिए","ar":"لمنع تساقط الشعر في الطعام ولتقليل ملامسة الشعر"}],"e":{"en":"Hair restraints such as hats or nets keep hair out of food and discourage workers from touching their hair, which can contaminate hands.","es":"Las sujeciones para el cabello, como gorros o redecillas, mantienen el cabello fuera de los alimentos y desalientan a los trabajadores de tocarse el cabello, lo que puede contaminar las manos.","ru":"Средства для фиксации волос, такие как головные уборы или сетки, не позволяют волосам попадать в продукты и отбивают у работников желание трогать волосы, что может загрязнить руки.","tr":"Şapka veya file gibi saç koruyucular, saçı gıdadan uzak tutar ve çalışanların elleri kirletebilecek şekilde saçlarına dokunmalarını engeller.","hi":"टोपी या जाल जैसे बाल अवरोधक बालों को भोजन से बाहर रखते हैं और कर्मचारियों को अपने बालों को छूने से हतोत्साहित करते हैं, जो हाथों को दूषित कर सकता है।","ar":"تُبقي أغطية الشعر مثل القبعات أو الشبكات الشعرَ بعيداً عن الطعام وتثني العاملين عن ملامسة شعرهم، الأمر الذي قد يلوّث اليدين."}},{"cat":"hygiene","a":0,"q":{"en":"Which jewelry is generally permitted on the hands while preparing food?","es":"¿Qué joyería se permite generalmente en las manos al preparar alimentos?","ru":"Какие украшения обычно разрешено носить на руках при приготовлении пищи?","tr":"Gıda hazırlarken ellerde genellikle hangi takıya izin verilir?","hi":"भोजन तैयार करते समय हाथों पर आम तौर पर कौन से आभूषण की अनुमति है?","ar":"أيُّ نوع من المجوهرات يُسمح به عموماً على اليدين أثناء تحضير الطعام؟"},"o":[{"en":"A plain ring such as a wedding band","es":"Un anillo liso como una alianza de boda","ru":"Простое кольцо, например обручальное","tr":"Alyans gibi düz (taşsız) bir yüzük","hi":"एक सादी अंगूठी जैसे शादी का छल्ला","ar":"خاتم بسيط مثل خاتم الزواج"},{"en":"A ring with a raised stone setting","es":"Un anillo con una piedra en engaste elevado","ru":"Кольцо с выступающей вставкой-камнем","tr":"Kabartmalı taş yuvası olan bir yüzük","hi":"उभरे हुए पत्थर की सेटिंग वाली एक अंगूठी","ar":"خاتم بفص بارز مرصّع"},{"en":"A bracelet and a wristwatch","es":"Una pulsera y un reloj de muñeca","ru":"Браслет и наручные часы","tr":"Bir bilezik ve bir kol saati","hi":"एक कंगन और एक कलाई घड़ी","ar":"سوار وساعة معصم"},{"en":"No restrictions apply to hand jewelry","es":"No se aplican restricciones a la joyería de las manos","ru":"Никаких ограничений на украшения для рук нет","tr":"El takıları için herhangi bir kısıtlama yoktur","hi":"हाथ के आभूषणों पर कोई प्रतिबंध लागू नहीं होता","ar":"لا توجد قيود على مجوهرات اليد"}],"e":{"en":"A plain band may be worn, but other hand and arm jewelry like stoned rings, bracelets, and watches must be removed because they can harbor pathogens and fall into food.","es":"Se puede usar una alianza lisa, pero otra joyería de manos y brazos, como anillos con piedras, pulseras y relojes, debe quitarse porque puede albergar patógenos y caer en los alimentos.","ru":"Простое кольцо носить можно, но другие украшения для рук и запястий, такие как кольца с камнями, браслеты и часы, должны быть сняты, поскольку они могут служить рассадником патогенов и попадать в продукты.","tr":"Düz bir alyans takılabilir, ancak taşlı yüzükler, bilezikler ve saatler gibi diğer el ve kol takıları, patojen barındırabileceği ve gıdaya düşebileceği için çıkarılmalıdır.","hi":"एक सादा छल्ला पहना जा सकता है, लेकिन पत्थर जड़ी अंगूठियां, कंगन और घड़ियों जैसे अन्य हाथ और बांह के आभूषणों को हटाया जाना चाहिए क्योंकि वे रोगजनकों को आश्रय दे सकते हैं और भोजन में गिर सकते हैं।","ar":"يُسمح بارتداء خاتم بسيط، لكن يجب نزع مجوهرات اليد والذراع الأخرى كالخواتم المرصّعة والأساور والساعات لأنها قد تؤوي مسببات الأمراض وتسقط في الطعام."}},{"cat":"hygiene","a":2,"q":{"en":"Which activity is NOT allowed in food preparation areas?","es":"¿Qué actividad NO está permitida en las áreas de preparación de alimentos?","ru":"Какое действие НЕ разрешено в зонах приготовления пищи?","tr":"Gıda hazırlama alanlarında hangi etkinliğe izin verilmez?","hi":"भोजन तैयारी क्षेत्रों में कौन सी गतिविधि की अनुमति नहीं है?","ar":"أيُّ نشاط غير مسموح به في مناطق تحضير الطعام؟"},"o":[{"en":"Washing hands at the handwashing sink","es":"Lavarse las manos en el lavabo para lavado de manos","ru":"Мытьё рук в раковине для мытья рук","tr":"El yıkama lavabosunda el yıkamak","hi":"हाथ धोने के सिंक पर हाथ धोना","ar":"غسل اليدين في حوض غسل اليدين"},{"en":"Wearing a clean apron","es":"Usar un delantal limpio","ru":"Ношение чистого фартука","tr":"Temiz bir önlük giymek","hi":"एक साफ एप्रन पहनना","ar":"ارتداء مريلة نظيفة"},{"en":"Eating, smoking, or chewing gum","es":"Comer, fumar o masticar chicle","ru":"Приём пищи, курение или жевание жвачки","tr":"Yemek yemek, sigara içmek veya sakız çiğnemek","hi":"खाना, धूम्रपान, या च्युइंग गम चबाना","ar":"الأكل أو التدخين أو مضغ العلكة"},{"en":"Putting on single-use gloves","es":"Ponerse guantes desechables","ru":"Надевание одноразовых перчаток","tr":"Tek kullanımlık eldiven giymek","hi":"एकल-उपयोग दस्ताने पहनना","ar":"ارتداء قفازات أحادية الاستخدام"}],"e":{"en":"Eating, drinking from open containers, smoking, and chewing gum are prohibited in prep areas because they can transfer saliva and contaminants to food.","es":"Comer, beber de recipientes abiertos, fumar y masticar chicle están prohibidos en las áreas de preparación porque pueden transferir saliva y contaminantes a los alimentos.","ru":"Приём пищи, питьё из открытых ёмкостей, курение и жевание жвачки запрещены в зонах приготовления, поскольку они могут перенести слюну и загрязняющие вещества на продукты.","tr":"Yemek yemek, açık kaplardan içmek, sigara içmek ve sakız çiğnemek; tükürük ve kirleticileri gıdaya bulaştırabileceği için hazırlık alanlarında yasaktır.","hi":"भोजन तैयारी क्षेत्रों में खाना, खुले कंटेनरों से पीना, धूम्रपान और च्युइंग गम चबाना निषिद्ध है क्योंकि वे लार और संदूषकों को भोजन में स्थानांतरित कर सकते हैं।","ar":"يُحظر الأكل والشرب من حاويات مفتوحة والتدخين ومضغ العلكة في مناطق التحضير لأنها قد تنقل اللعاب والملوثات إلى الطعام."}},{"cat":"hygiene","a":3,"q":{"en":"What is the rule for a food handler's fingernails?","es":"¿Cuál es la regla para las uñas de un manipulador de alimentos?","ru":"Каково правило относительно ногтей работника пищевого производства?","tr":"Bir gıda çalışanının tırnaklarıyla ilgili kural nedir?","hi":"एक फूड हैंडलर के नाखूनों के लिए नियम क्या है?","ar":"ما القاعدة المتعلقة بأظافر متداول الطعام؟"},"o":[{"en":"Long nails are fine if gloves are never worn","es":"Las uñas largas están bien si nunca se usan guantes","ru":"Длинные ногти допустимы, если перчатки никогда не надеваются","tr":"Hiç eldiven giyilmiyorsa uzun tırnaklar sorunsuzdur","hi":"यदि दस्ताने कभी नहीं पहने जाते तो लंबे नाखून ठीक हैं","ar":"لا بأس بالأظافر الطويلة إذا لم تُرتدَ القفازات أبداً"},{"en":"Artificial nails are allowed at all food stations","es":"Las uñas artificiales se permiten en todas las estaciones de alimentos","ru":"Искусственные ногти разрешены на всех пищевых станциях","tr":"Tüm gıda istasyonlarında takma tırnaklara izin verilir","hi":"सभी भोजन स्टेशनों पर कृत्रिम नाखूनों की अनुमति है","ar":"يُسمح بالأظافر الاصطناعية في جميع محطات الطعام"},{"en":"Dark nail polish is preferred so chips are visible","es":"Se prefiere el esmalte de uñas oscuro para que las desconchaduras se vean","ru":"Тёмный лак предпочтительнее, чтобы сколы были заметны","tr":"Çatlaklar görünür olsun diye koyu renk oje tercih edilir","hi":"गहरी नेल पॉलिश को प्राथमिकता दी जाती है ताकि छीलन दिखाई दे","ar":"يُفضَّل طلاء الأظافر الداكن لكي تظهر القشور"},{"en":"Keep them clean, trimmed, and filed so edges are smooth","es":"Mantenerlas limpias, recortadas y limadas para que los bordes queden lisos","ru":"Держите их чистыми, подстриженными и подпиленными, чтобы края были гладкими","tr":"Kenarları pürüzsüz olacak şekilde temiz, kısa ve düzgün kesilmiş tutulmalı","hi":"उन्हें साफ, छंटे हुए, और घिसे हुए रखें ताकि किनारे चिकने हों","ar":"إبقاؤها نظيفة ومقصوصة ومبرَّدة بحيث تكون حوافها ملساء"}],"e":{"en":"Nails must be kept short, clean, and filed smooth; nail polish and artificial nails are not allowed when working with exposed food unless intact gloves are worn.","es":"Las uñas deben mantenerse cortas, limpias y limadas; no se permite el esmalte de uñas ni las uñas artificiales al trabajar con alimentos expuestos, a menos que se usen guantes intactos.","ru":"Ногти должны быть короткими, чистыми и подпиленными до гладкости; лак для ногтей и искусственные ногти не допускаются при работе с открытыми продуктами, если только не надеты целые перчатки.","tr":"Tırnaklar kısa, temiz ve pürüzsüz şekilde törpülenmiş tutulmalıdır; sağlam eldiven giyilmediği sürece açık gıdayla çalışırken oje ve takma tırnaklara izin verilmez.","hi":"नाखूनों को छोटा, साफ, और चिकना घिसा हुआ रखा जाना चाहिए; उजागर भोजन के साथ काम करते समय नेल पॉलिश और कृत्रिम नाखूनों की अनुमति नहीं है, जब तक कि सही-सलामत दस्ताने न पहने जाएं।","ar":"يجب إبقاء الأظافر قصيرة ونظيفة ومبرَّدة بحيث تكون ملساء؛ ولا يُسمح بطلاء الأظافر ولا بالأظافر الاصطناعية عند العمل مع الطعام المكشوف ما لم تُرتدَ قفازات سليمة."}},{"cat":"hygiene","a":1,"q":{"en":"A food handler finishes cutting raw chicken and now needs to prepare a fresh garnish. What should they do with their gloves?","es":"Un manipulador de alimentos termina de cortar pollo crudo y ahora necesita preparar una guarnición fresca. ¿Qué debe hacer con sus guantes?","ru":"Работник пищевого производства закончил резать сырую курицу и теперь должен приготовить свежий гарнир. Что он должен сделать со своими перчатками?","tr":"Bir gıda çalışanı çiğ tavuk doğramayı bitirir ve şimdi taze bir garnitür hazırlaması gerekir. Eldivenleriyle ne yapmalıdır?","hi":"एक फूड हैंडलर कच्चा चिकन काटना समाप्त करता है और अब उसे एक ताज़ा गार्निश तैयार करने की आवश्यकता है। उसे अपने दस्ताने के साथ क्या करना चाहिए?","ar":"ينتهي متداول طعام من تقطيع دجاج نيء وعليه الآن تحضير زينة طازجة. ماذا ينبغي أن يفعل بقفازاته؟"},"o":[{"en":"Keep the same gloves to save time","es":"Conservar los mismos guantes para ahorrar tiempo","ru":"Оставить те же перчатки, чтобы сэкономить время","tr":"Zaman kazanmak için aynı eldivenleri kullanmaya devam etmeli","hi":"समय बचाने के लिए वही दस्ताने रखें","ar":"إبقاء القفازات نفسها لتوفير الوقت"},{"en":"Remove the gloves, wash hands, and put on a new pair","es":"Quitarse los guantes, lavarse las manos y ponerse un par nuevo","ru":"Снять перчатки, вымыть руки и надеть новую пару","tr":"Eldivenleri çıkarmalı, ellerini yıkamalı ve yeni bir çift giymeli","hi":"दस्ताने हटाएं, हाथ धोएं, और एक नई जोड़ी पहनें","ar":"نزع القفازات وغسل اليدين وارتداء زوج جديد"},{"en":"Rinse the gloves under water and continue","es":"Enjuagar los guantes bajo el agua y continuar","ru":"Ополоснуть перчатки под водой и продолжить","tr":"Eldivenleri suyun altında durulayıp devam etmeli","hi":"दस्ताने को पानी के नीचे धोएं और जारी रखें","ar":"شطف القفازات تحت الماء والمتابعة"},{"en":"Wipe the gloves on a clean towel and continue","es":"Limpiar los guantes con una toalla limpia y continuar","ru":"Вытереть перчатки чистым полотенцем и продолжить","tr":"Eldivenleri temiz bir havluya silip devam etmeli","hi":"दस्ताने को एक साफ तौलिये पर पोंछें और जारी रखें","ar":"مسح القفازات بمنشفة نظيفة والمتابعة"}],"e":{"en":"Gloves are single-use; after handling raw poultry the worker must discard the gloves, wash hands, and don a new pair to avoid cross-contamination.","es":"Los guantes son desechables; después de manipular aves crudas, el trabajador debe desechar los guantes, lavarse las manos y ponerse un par nuevo para evitar la contaminación cruzada.","ru":"Перчатки одноразовые; после работы с сырой птицей работник должен выбросить перчатки, вымыть руки и надеть новую пару, чтобы избежать перекрёстного загрязнения.","tr":"Eldivenler tek kullanımlıktır; çalışan, çiğ kümes hayvanı işledikten sonra çapraz bulaşmayı önlemek için eldivenleri atmalı, ellerini yıkamalı ve yeni bir çift giymelidir.","hi":"दस्ताने एकल-उपयोग वाले होते हैं; कच्चे पोल्ट्री को संभालने के बाद कर्मचारी को क्रॉस-कॉन्टैमिनेशन से बचने के लिए दस्ताने को फेंक देना चाहिए, हाथ धोने चाहिए, और एक नई जोड़ी पहननी चाहिए।","ar":"القفازات أحادية الاستخدام؛ فبعد التعامل مع الدواجن النيئة يجب على العامل التخلص من القفازات وغسل اليدين وارتداء زوج جديد لتجنب التلوث المتبادل."}},{"cat":"hygiene","a":2,"q":{"en":"Before putting on a fresh pair of single-use gloves, a food handler should first do what?","es":"Antes de ponerse un par nuevo de guantes desechables, ¿qué debe hacer primero un manipulador de alimentos?","ru":"Прежде чем надеть свежую пару одноразовых перчаток, работник пищевого производства должен сначала сделать что?","tr":"Temiz bir çift tek kullanımlık eldiven giymeden önce, bir gıda çalışanı ilk olarak ne yapmalıdır?","hi":"एकल-उपयोग दस्ताने की एक नई जोड़ी पहनने से पहले, एक फूड हैंडलर को सबसे पहले क्या करना चाहिए?","ar":"قبل ارتداء زوج جديد من القفازات أحادية الاستخدام، ماذا ينبغي لمتداول الطعام أن يفعل أولاً؟"},"o":[{"en":"Apply hand lotion to the gloves","es":"Aplicar loción para manos a los guantes","ru":"Нанести лосьон для рук на перчатки","tr":"Eldivenlere el losyonu sürmeli","hi":"दस्ताने पर हैंड लोशन लगाएं","ar":"وضع مرطّب اليدين على القفازات"},{"en":"Rinse the gloves in sanitizer","es":"Enjuagar los guantes en desinfectante","ru":"Ополоснуть перчатки в дезинфицирующем средстве","tr":"Eldivenleri dezenfektanda durulamalı","hi":"दस्ताने को सैनिटाइज़र में धोएं","ar":"شطف القفازات في المطهّر"},{"en":"Wash and dry their hands","es":"Lavarse y secarse las manos","ru":"Вымыть и высушить руки","tr":"Ellerini yıkayıp kurulamalı","hi":"अपने हाथ धोएं और सुखाएं","ar":"غسل يديه وتجفيفهما"},{"en":"Blow into the gloves to open them","es":"Soplar dentro de los guantes para abrirlos","ru":"Подуть в перчатки, чтобы раскрыть их","tr":"Açmak için eldivenlerin içine üflemeli","hi":"दस्ताने खोलने के लिए उनमें फूंक मारें","ar":"النفخ في القفازات لفتحها"}],"e":{"en":"Hands must be washed and dried before gloving; gloves do not replace handwashing and can spread pathogens if put on over dirty hands.","es":"Las manos deben lavarse y secarse antes de ponerse los guantes; los guantes no reemplazan el lavado de manos y pueden propagar patógenos si se ponen sobre manos sucias.","ru":"Руки должны быть вымыты и высушены перед надеванием перчаток; перчатки не заменяют мытьё рук и могут распространять патогены, если их надеть на грязные руки.","tr":"Eldiven giymeden önce eller yıkanıp kurulanmalıdır; eldivenler el yıkamanın yerini tutmaz ve kirli ellerin üzerine giyilirse patojen yayabilir.","hi":"दस्ताने पहनने से पहले हाथों को धोया और सुखाया जाना चाहिए; दस्ताने हाथ धोने की जगह नहीं लेते और अगर गंदे हाथों पर पहने जाएं तो रोगजनकों को फैला सकते हैं।","ar":"يجب غسل اليدين وتجفيفهما قبل ارتداء القفازات؛ فالقفازات لا تحل محل غسل اليدين، وقد تنشر مسببات الأمراض إذا ارتُديت فوق يدين متسختين."}},{"cat":"hygiene","a":0,"q":{"en":"Which is one of the times a food handler is required to wash their hands?","es":"¿Cuál es uno de los momentos en que un manipulador de alimentos debe lavarse las manos?","ru":"Что является одним из случаев, когда работник пищевого производства обязан вымыть руки?","tr":"Bir gıda çalışanının ellerini yıkamasının gerektiği durumlardan biri hangisidir?","hi":"उन समयों में से एक कौन सा है जब एक फूड हैंडलर को अपने हाथ धोने की आवश्यकता होती है?","ar":"ما إحدى الحالات التي يُلزَم فيها متداول الطعام بغسل يديه؟"},"o":[{"en":"After using the restroom","es":"Después de usar el baño","ru":"После посещения туалета","tr":"Tuvaleti kullandıktan sonra","hi":"शौचालय का उपयोग करने के बाद","ar":"بعد استخدام دورة المياه"},{"en":"Once at the start of each shift only","es":"Solo una vez al inicio de cada turno","ru":"Только один раз в начале каждой смены","tr":"Yalnızca her vardiyanın başında bir kez","hi":"केवल हर शिफ्ट की शुरुआत में एक बार","ar":"مرة واحدة فقط في بداية كل مناوبة"},{"en":"Only after touching ready-to-eat food","es":"Solo después de tocar alimentos listos para comer","ru":"Только после касания готовых к употреблению продуктов","tr":"Yalnızca yemeye hazır gıdaya dokunduktan sonra","hi":"केवल खाने के लिए तैयार भोजन को छूने के बाद","ar":"فقط بعد ملامسة الطعام الجاهز للأكل"},{"en":"Only when hands look visibly dirty","es":"Solo cuando las manos se ven visiblemente sucias","ru":"Только когда руки выглядят явно грязными","tr":"Yalnızca eller gözle görülür şekilde kirli göründüğünde","hi":"केवल जब हाथ दिखाई देने वाले गंदे हों","ar":"فقط عندما تبدو اليدان متسختين بوضوح"}],"e":{"en":"Hands must be washed after using the restroom, and also after handling raw food, touching the face or body, taking out trash, and other contaminating activities.","es":"Las manos deben lavarse después de usar el baño, y también después de manipular alimentos crudos, tocarse la cara o el cuerpo, sacar la basura y otras actividades contaminantes.","ru":"Руки нужно мыть после посещения туалета, а также после работы с сырыми продуктами, касания лица или тела, выноса мусора и других загрязняющих действий.","tr":"Eller tuvaleti kullandıktan sonra; ayrıca çiğ gıda işledikten, yüze veya vücuda dokunduktan, çöp attıktan ve diğer kirletici faaliyetlerden sonra yıkanmalıdır.","hi":"शौचालय का उपयोग करने के बाद हाथ धोने चाहिए, और कच्चे भोजन को संभालने, चेहरे या शरीर को छूने, कचरा बाहर निकालने, और अन्य संदूषण करने वाली गतिविधियों के बाद भी।","ar":"يجب غسل اليدين بعد استخدام دورة المياه، وكذلك بعد التعامل مع الطعام النيء، وملامسة الوجه أو الجسم، وإخراج القمامة، وغير ذلك من الأنشطة الملوِّثة."}},{"cat":"hygiene","a":2,"q":{"en":"A food handler's doctor diagnoses them with hepatitis A. What must the establishment do?","es":"El médico de un manipulador de alimentos le diagnostica hepatitis A. ¿Qué debe hacer el establecimiento?","ru":"Врач работника пищевого производства диагностирует у него гепатит А. Что должно сделать заведение?","tr":"Bir gıda çalışanının doktoru, ona hepatit A teşhisi koyar. İşletme ne yapmalıdır?","hi":"एक फूड हैंडलर के डॉक्टर ने उन्हें हेपेटाइटिस A का निदान किया। प्रतिष्ठान को क्या करना चाहिए?","ar":"يُشخِّص طبيبٌ متداولَ طعام بالإصابة بالتهاب الكبد الوبائي A. ماذا يجب على المنشأة أن تفعل؟"},"o":[{"en":"Restrict them to washing dishes only","es":"Restringirlo a lavar platos únicamente","ru":"Ограничить его обязанности только мытьём посуды","tr":"Onu yalnızca bulaşık yıkamayla sınırlandırmalı","hi":"उन्हें केवल बर्तन धोने तक सीमित करें","ar":"قصر عمله على غسل الأطباق فقط"},{"en":"Allow them to work if they wear gloves","es":"Permitirle trabajar si usa guantes","ru":"Разрешить ему работать, если он носит перчатки","tr":"Eldiven giyerse çalışmasına izin vermeli","hi":"अगर वे दस्ताने पहनें तो उन्हें काम करने दें","ar":"السماح له بالعمل إذا ارتدى قفازات"},{"en":"Exclude the employee and notify the regulatory authority","es":"Excluir al empleado y notificar a la autoridad reguladora","ru":"Отстранить работника и уведомить регулирующий орган","tr":"Çalışanı işletmeden hariç tutmalı (uzaklaştırmalı) ve düzenleyici otoriteyi bilgilendirmeli","hi":"कर्मचारी को बाहर रखें और नियामक प्राधिकरण को सूचित करें","ar":"استبعاد الموظف وإخطار الجهة التنظيمية"},{"en":"Let them keep working until symptoms appear","es":"Dejarlo seguir trabajando hasta que aparezcan los síntomas","ru":"Позволить ему продолжать работать до появления симптомов","tr":"Belirtiler ortaya çıkana kadar çalışmaya devam etmesine izin vermeli","hi":"लक्षण प्रकट होने तक उन्हें काम करते रहने दें","ar":"تركه يواصل العمل إلى أن تظهر الأعراض"}],"e":{"en":"Hepatitis A is one of the Big 6; a diagnosed employee must be excluded from the establishment and the regulatory authority must be notified.","es":"La hepatitis A es una de los 6 grandes (Big 6); un empleado diagnosticado debe ser excluido del establecimiento y se debe notificar a la autoridad reguladora.","ru":"Гепатит А — один из «Большой шестёрки» (Big 6); работник с подтверждённым диагнозом должен быть отстранён от заведения, а регулирующий орган должен быть уведомлён.","tr":"Hepatit A, Büyük 6'dan (Big 6) biridir; teşhis konulan bir çalışan işletmeden hariç tutulmalı ve düzenleyici otorite bilgilendirilmelidir.","hi":"हेपेटाइटिस A Big 6 में से एक है; निदान किए गए कर्मचारी को प्रतिष्ठान से बाहर रखा जाना चाहिए और नियामक प्राधिकरण को सूचित किया जाना चाहिए।","ar":"التهاب الكبد الوبائي A هو أحد الستة الكبار (Big 6)؛ ويجب استبعاد الموظف المُشخَّص من المنشأة وإخطار الجهة التنظيمية."}},{"cat":"hygiene","a":0,"q":{"en":"Which set lists pathogens from the \"Big 6\" that food handlers must report to their manager?","es":"¿Qué conjunto enumera patógenos de los \"6 grandes\" (Big 6) que los manipuladores de alimentos deben reportar a su gerente?","ru":"В каком наборе перечислены патогены из «Большой шестёрки» (Big 6), о которых работники пищевого производства должны сообщать своему руководителю?","tr":"Hangi grup, gıda çalışanlarının yöneticilerine bildirmesi gereken \"Büyük 6\" (Big 6) patojenlerini listeler?","hi":"कौन सा समूह \"Big 6\" के उन रोगजनकों को सूचीबद्ध करता है जिन्हें फूड हैंडलर को अपने प्रबंधक को रिपोर्ट करना चाहिए?","ar":"أيُّ مجموعة تُدرِج مسببات أمراض من \"الستة الكبار\" (Big 6) التي يجب على متداولي الطعام الإبلاغ عنها لمديرهم؟"},"o":[{"en":"Norovirus, Hepatitis A, and Shigella","es":"Norovirus, Hepatitis A y Shigella","ru":"Норовирус, гепатит А и шигелла (Shigella)","tr":"Norovirüs, Hepatit A ve Shigella","hi":"नोरोवायरस, हेपेटाइटिस A, और शिगेला","ar":"نوروفيروس، والتهاب الكبد الوبائي A، والشيغيلا"},{"en":"Norovirus, Listeria, and botulism","es":"Norovirus, Listeria y botulismo","ru":"Норовирус, листерия (Listeria) и ботулизм","tr":"Norovirüs, Listeria ve botulizm","hi":"नोरोवायरस, लिस्टेरिया, और बोटुलिज़्म","ar":"نوروفيروس، والليستيريا، والتسمم الوشيقي (botulism)"},{"en":"Hepatitis A, Staphylococcus, and Listeria","es":"Hepatitis A, Staphylococcus y Listeria","ru":"Гепатит А, стафилококк (Staphylococcus) и листерия (Listeria)","tr":"Hepatit A, Stafilokok ve Listeria","hi":"हेपेटाइटिस A, स्टैफिलोकोकस, और लिस्टेरिया","ar":"التهاب الكبد الوبائي A، والمكورات العنقودية، والليستيريا"},{"en":"Salmonella, Listeria, and Clostridium perfringens","es":"Salmonella, Listeria y Clostridium perfringens","ru":"Сальмонелла (Salmonella), листерия (Listeria) и клостридия (Clostridium perfringens)","tr":"Salmonella, Listeria ve Clostridium perfringens","hi":"साल्मोनेला, लिस्टेरिया, और क्लोस्ट्रिडियम परफ्रिंजेंस","ar":"السالمونيلا، والليستيريا، والمطثية الحاطمة (Clostridium perfringens)"}],"e":{"en":"The Big 6 are Norovirus, Hepatitis A, Shigella spp., Shiga toxin-producing E. coli, nontyphoidal Salmonella, and Salmonella Typhi; Listeria and Staphylococcus are not on that reportable list.","es":"Los 6 grandes (Big 6) son Norovirus, Hepatitis A, Shigella spp., E. coli productora de toxina Shiga, Salmonella no tifoidea y Salmonella Typhi; Listeria y Staphylococcus no están en esa lista de reporte.","ru":"«Большая шестёрка» (Big 6) — это норовирус, гепатит А, Shigella spp., шига-токсин-продуцирующая E. coli, нетифоидная Salmonella и Salmonella Typhi; листерия и стафилококк не входят в этот список, подлежащий уведомлению.","tr":"Büyük 6; Norovirüs, Hepatit A, Shigella spp., Shiga toksini üreten E. coli, tifo dışı (nontyphoidal) Salmonella ve Salmonella Typhi'dir; Listeria ve Stafilokok bu bildirim listesinde yer almaz.","hi":"Big 6 हैं नोरोवायरस, हेपेटाइटिस A, शिगेला spp., शिगा टॉक्सिन उत्पन्न करने वाला E. coli, नॉनटाइफॉइडल साल्मोनेला, और साल्मोनेला टाइफी; लिस्टेरिया और स्टैफिलोकोकस उस रिपोर्ट करने योग्य सूची में नहीं हैं।","ar":"الستة الكبار هم: نوروفيروس، والتهاب الكبد الوبائي A، وأنواع الشيغيلا (Shigella spp.)، والإشريكية القولونية المنتجة لذيفان شيغا (Shiga toxin-producing E. coli)، والسالمونيلا غير التيفية (nontyphoidal Salmonella)، وسالمونيلا التيفية (Salmonella Typhi)؛ والليستيريا والمكورات العنقودية ليستا على تلك القائمة الواجب الإبلاغ عنها."}},{"cat":"hygiene","a":3,"q":{"en":"An employee reports a sore throat with a fever. If the operation serves a population that is NOT highly susceptible, what is the appropriate action?","es":"Un empleado reporta dolor de garganta con fiebre. Si la operación atiende a una población que NO es altamente susceptible, ¿cuál es la acción apropiada?","ru":"Работник сообщает о боли в горле с повышенной температурой. Если заведение обслуживает население, которое НЕ является высоковосприимчивым, каково правильное действие?","tr":"Bir çalışan ateşle birlikte boğaz ağrısı bildirir. İşletme, hassasiyeti yüksek OLMAYAN bir nüfusa hizmet veriyorsa, uygun eylem nedir?","hi":"एक कर्मचारी बुखार के साथ गले में खराश की रिपोर्ट करता है। यदि ऑपरेशन ऐसी आबादी को सेवा देता है जो अत्यधिक संवेदनशील नहीं है, तो उचित कार्रवाई क्या है?","ar":"يُبلِغ موظف عن التهاب في الحلق مصحوب بالحُمّى. إذا كانت المنشأة تخدم فئة من السكان غير شديدة التأثر، فما الإجراء المناسب؟"},"o":[{"en":"Exclude them from the establishment entirely","es":"Excluirlo del establecimiento por completo","ru":"Полностью отстранить его от заведения","tr":"Onu tamamen işletmeden hariç tutmak (uzaklaştırmak)","hi":"उन्हें पूरी तरह से प्रतिष्ठान से बाहर रखें","ar":"استبعاده من المنشأة تماماً"},{"en":"Take no action since a sore throat is minor","es":"No tomar ninguna acción porque un dolor de garganta es menor","ru":"Не предпринимать действий, поскольку боль в горле — это пустяк","tr":"Boğaz ağrısı önemsiz olduğundan hiçbir işlem yapmamak","hi":"कोई कार्रवाई न करें क्योंकि गले में खराश मामूली है","ar":"عدم اتخاذ أي إجراء لأن التهاب الحلق أمر بسيط"},{"en":"Send them to handle ready-to-eat food only","es":"Enviarlo a manipular únicamente alimentos listos para comer","ru":"Направить его работать только с готовыми к употреблению продуктами","tr":"Onu yalnızca yemeye hazır gıdayla ilgilenmesi için göndermek","hi":"उन्हें केवल खाने के लिए तैयार भोजन संभालने के लिए भेजें","ar":"إرساله للتعامل مع الطعام الجاهز للأكل فقط"},{"en":"Restrict them from working with exposed food and clean equipment","es":"Restringirlo de trabajar con alimentos expuestos y equipo limpio","ru":"Ограничить его от работы с открытыми продуктами и чистым оборудованием","tr":"Açık gıda ve temiz ekipmanla çalışmasını kısıtlamak","hi":"उन्हें उजागर भोजन और साफ उपकरणों के साथ काम करने से प्रतिबंधित करें","ar":"تقييد عمله بحيث لا يتعامل مع الطعام المكشوف والمعدات النظيفة"}],"e":{"en":"Sore throat with fever is a reportable symptom; in a non high-risk operation the employee is restricted from food and food-contact surfaces, while exclusion applies if serving a highly susceptible population.","es":"El dolor de garganta con fiebre es un síntoma que debe reportarse; en una operación de bajo riesgo el empleado queda restringido de los alimentos y las superficies de contacto con alimentos, mientras que la exclusión aplica si se atiende a una población altamente susceptible.","ru":"Боль в горле с температурой — это симптом, подлежащий уведомлению; в заведении с невысоким риском работника ограничивают от продуктов и поверхностей, контактирующих с пищей, тогда как отстранение применяется при обслуживании высоковосприимчивого населения.","tr":"Ateşle birlikte boğaz ağrısı bildirimi zorunlu bir belirtidir; yüksek riskli olmayan bir işletmede çalışan gıdadan ve gıdayla temas eden yüzeylerden kısıtlanır, hassasiyeti yüksek bir nüfusa hizmet veriliyorsa hariç tutma (uzaklaştırma) uygulanır.","hi":"बुखार के साथ गले में खराश एक रिपोर्ट करने योग्य लक्षण है; एक गैर-उच्च-जोखिम वाले ऑपरेशन में कर्मचारी को भोजन और भोजन-संपर्क सतहों से प्रतिबंधित किया जाता है, जबकि अत्यधिक संवेदनशील आबादी की सेवा करने पर बहिष्कार लागू होता है।","ar":"التهاب الحلق المصحوب بالحُمّى عَرَض واجب الإبلاغ عنه؛ ففي المنشأة غير عالية الخطورة يُقيَّد الموظف عن الطعام وأسطح ملامسة الطعام، بينما يُطبَّق الاستبعاد إذا كانت تخدم فئة شديدة التأثر."}},{"cat":"hygiene","a":1,"q":{"en":"Which condition requires EXCLUDING a food employee from the establishment rather than only restricting them?","es":"¿Qué condición exige EXCLUIR a un empleado de alimentos del establecimiento en lugar de solo restringirlo?","ru":"Какое состояние требует ОТСТРАНЕНИЯ работника пищевого производства от заведения, а не только его ограничения?","tr":"Hangi durum, bir gıda çalışanının yalnızca kısıtlanması yerine işletmeden HARİÇ TUTULMASINI (uzaklaştırılmasını) gerektirir?","hi":"किस स्थिति में एक फूड कर्मचारी को केवल प्रतिबंधित करने के बजाय प्रतिष्ठान से बाहर रखना (EXCLUDE) आवश्यक है?","ar":"أيُّ حالة تستوجب استبعاد موظف الطعام من المنشأة بدلاً من مجرد تقييده؟"},"o":[{"en":"A small covered cut on the arm","es":"Un pequeño corte cubierto en el brazo","ru":"Небольшой закрытый порез на руке","tr":"Kolda kapatılmış küçük bir kesik","hi":"बांह पर एक छोटा ढका हुआ कट","ar":"جرح صغير مغطى على الذراع"},{"en":"Jaundice with a recent onset","es":"Ictericia de aparición reciente","ru":"Желтуха недавнего возникновения","tr":"Yeni başlamış sarılık (jaundice)","hi":"हाल ही में शुरू हुआ पीलिया","ar":"اليرقان (الصُّفار) حديث الظهور"},{"en":"A clean bandage on a finger under a glove","es":"Una venda limpia en un dedo bajo un guante","ru":"Чистый пластырь на пальце под перчаткой","tr":"Eldiven altında bir parmaktaki temiz yara bandı","hi":"दस्ताने के नीचे उंगली पर एक साफ पट्टी","ar":"لاصق طبي نظيف على إصبع تحت قفاز"},{"en":"Wearing nail polish under intact gloves","es":"Usar esmalte de uñas bajo guantes intactos","ru":"Ношение лака для ногтей под целыми перчатками","tr":"Sağlam eldiven altında oje takmak","hi":"सही-सलामत दस्ताने के नीचे नेल पॉलिश पहनना","ar":"ارتداء طلاء أظافر تحت قفازات سليمة"}],"e":{"en":"Jaundice (yellowing of skin or eyes) of recent onset requires exclusion and reporting to the regulatory authority, as it may signal hepatitis A.","es":"La ictericia (coloración amarilla de la piel o los ojos) de aparición reciente exige la exclusión y el reporte a la autoridad reguladora, ya que puede indicar hepatitis A.","ru":"Желтуха (пожелтение кожи или глаз) недавнего возникновения требует отстранения и уведомления регулирующего органа, поскольку она может указывать на гепатит А.","tr":"Yeni başlayan sarılık (cilt veya gözlerin sararması), hepatit A'nın işareti olabileceğinden hariç tutma (uzaklaştırma) ve düzenleyici otoriteye bildirim gerektirir.","hi":"हाल ही में शुरू हुए पीलिया (त्वचा या आंखों का पीला पड़ना) के लिए बहिष्कार और नियामक प्राधिकरण को रिपोर्ट करना आवश्यक है, क्योंकि यह हेपेटाइटिस A का संकेत हो सकता है।","ar":"يستوجب اليرقان (اصفرار الجلد أو العينين) حديث الظهور الاستبعادَ والإبلاغ للجهة التنظيمية، إذ قد يشير إلى التهاب الكبد الوبائي A."}},{"cat":"hygiene","a":0,"q":{"en":"A food handler with an infected, pus-filled wound on the hand that cannot be properly covered should be:","es":"Un manipulador de alimentos con una herida infectada y llena de pus en la mano que no puede cubrirse adecuadamente debe ser:","ru":"Работник пищевого производства с инфицированной, наполненной гноем раной на руке, которую нельзя должным образом закрыть, должен быть:","tr":"Elinde, düzgünce kapatılamayan iltihaplı, irin dolu bir yarası olan bir gıda çalışanı:","hi":"हाथ पर एक संक्रमित, मवाद से भरे घाव वाले फूड हैंडलर को जिसे ठीक से ढका नहीं जा सकता, उसके साथ क्या किया जाना चाहिए:","ar":"متداول الطعام المصاب بجرح ملتهب مملوء بالقيح في اليد لا يمكن تغطيته بشكل سليم ينبغي أن:"},"o":[{"en":"Restricted or excluded from handling food until it is resolved or properly covered","es":"Restringido o excluido de manipular alimentos hasta que se resuelva o se cubra adecuadamente","ru":"Ограничен или отстранён от работы с продуктами до её заживления или надлежащего закрытия","tr":"Yara iyileşene veya düzgünce kapatılana kadar gıdayla ilgilenmesi kısıtlanmalı veya hariç tutulmalı (uzaklaştırılmalı)","hi":"इसके ठीक होने या ठीक से ढके जाने तक भोजन संभालने से प्रतिबंधित या बाहर रखा जाए","ar":"يُقيَّد أو يُستبعَد عن التعامل مع الطعام حتى يُشفى أو يُغطّى بشكل سليم"},{"en":"Allowed to continue if they wash hands more often","es":"Permitido continuar si se lava las manos con más frecuencia","ru":"Допущен к продолжению работы, если он чаще моет руки","tr":"Ellerini daha sık yıkarsa devam etmesine izin verilmeli","hi":"अगर वे अधिक बार हाथ धोएं तो जारी रखने की अनुमति दी जाए","ar":"يُسمح له بالاستمرار إذا غسل يديه أكثر تكراراً"},{"en":"Permitted to work as long as they wear two gloves","es":"Permitido trabajar siempre que use dos guantes","ru":"Допущен к работе при условии ношения двух перчаток","tr":"İki eldiven giydiği sürece çalışmasına izin verilmeli","hi":"जब तक वे दो दस्ताने पहनें तब तक काम करने की अनुमति दी जाए","ar":"يُسمح له بالعمل ما دام يرتدي قفازين"},{"en":"Moved to plating ready-to-eat desserts","es":"Trasladado a emplatar postres listos para comer","ru":"Переведён на сервировку готовых к употреблению десертов","tr":"Yemeye hazır tatlıları tabaklamaya kaydırılmalı","hi":"खाने के लिए तैयार मिठाइयां प्लेटिंग करने के लिए स्थानांतरित किया जाए","ar":"يُنقَل إلى تنسيق الحلويات الجاهزة للأكل"}],"e":{"en":"An infected wound on the hand or wrist that cannot be effectively covered is a reportable condition that requires restricting or excluding the employee from food handling.","es":"Una herida infectada en la mano o la muñeca que no puede cubrirse eficazmente es una condición que debe reportarse y que exige restringir o excluir al empleado de la manipulación de alimentos.","ru":"Инфицированная рана на руке или запястье, которую нельзя эффективно закрыть, — это состояние, подлежащее уведомлению, которое требует ограничения или отстранения работника от работы с продуктами.","tr":"El veya bilekte etkili bir şekilde kapatılamayan iltihaplı bir yara, çalışanın gıda işlemekten kısıtlanmasını veya hariç tutulmasını gerektiren, bildirimi zorunlu bir durumdur.","hi":"हाथ या कलाई पर एक संक्रमित घाव जिसे प्रभावी ढंग से ढका नहीं जा सकता, एक रिपोर्ट करने योग्य स्थिति है जिसके लिए कर्मचारी को भोजन संभालने से प्रतिबंधित या बाहर रखना आवश्यक है।","ar":"الجرح الملتهب في اليد أو المعصم الذي لا يمكن تغطيته بفعالية هو حالة واجبة الإبلاغ عنها تستوجب تقييد الموظف أو استبعاده عن تداول الطعام."}},{"cat":"hygiene","a":3,"q":{"en":"An employee is medically cleared to return after a Salmonella Typhi (typhoid fever) diagnosis. Why is this pathogen treated so strictly?","es":"Un empleado recibe el alta médica para regresar después de un diagnóstico de Salmonella Typhi (fiebre tifoidea). ¿Por qué se trata este patógeno con tanta rigurosidad?","ru":"Работник получил медицинское разрешение вернуться после диагноза Salmonella Typhi (брюшной тиф). Почему этот патоген рассматривается так строго?","tr":"Bir çalışan, Salmonella Typhi (tifo) teşhisinden sonra işe dönmek için tıbbi olarak onaylanır. Bu patojen neden bu kadar katı şekilde ele alınır?","hi":"एक कर्मचारी को साल्मोनेला टाइफी (टाइफॉइड बुखार) निदान के बाद वापस लौटने के लिए चिकित्सकीय रूप से मंजूरी दी जाती है। इस रोगजनक के साथ इतनी सख्ती से व्यवहार क्यों किया जाता है?","ar":"تتم الموافقة الطبية على عودة موظف بعد تشخيصه بسالمونيلا التيفية (Salmonella Typhi) (حمى التيفوئيد). لماذا يُعامَل هذا الممرض بهذه الصرامة؟"},"o":[{"en":"It is harmless once symptoms stop the same day","es":"Es inofensivo una vez que los síntomas cesan el mismo día","ru":"Он безвреден, как только симптомы прекращаются в тот же день","tr":"Belirtiler aynı gün durduğunda zararsızdır","hi":"लक्षण उसी दिन रुकने के बाद यह हानिरहित है","ar":"إنه غير ضار بمجرد توقف الأعراض في اليوم نفسه"},{"en":"It only affects raw meat, not the food handler","es":"Solo afecta la carne cruda, no al manipulador de alimentos","ru":"Он поражает только сырое мясо, а не работника","tr":"Yalnızca çiğ eti etkiler, gıda çalışanını değil","hi":"यह केवल कच्चे मांस को प्रभावित करता है, फूड हैंडलर को नहीं","ar":"إنه يؤثر فقط على اللحم النيء، لا على متداول الطعام"},{"en":"It cannot be transmitted by food handlers at all","es":"No puede ser transmitido por los manipuladores de alimentos en absoluto","ru":"Он вообще не может передаваться работниками пищевого производства","tr":"Gıda çalışanları tarafından kesinlikle bulaştırılamaz","hi":"इसे फूड हैंडलर द्वारा बिल्कुल भी प्रसारित नहीं किया जा सकता","ar":"لا يمكن أن ينتقل عن طريق متداولي الطعام على الإطلاق"},{"en":"It can be shed and spread to food for an extended period, so reinstatement needs medical documentation","es":"Puede excretarse y propagarse a los alimentos durante un período prolongado, por lo que la reincorporación requiere documentación médica","ru":"Он может выделяться и распространяться на продукты в течение длительного периода, поэтому для восстановления требуется медицинская документация","tr":"Uzun bir süre boyunca saçılıp gıdaya yayılabilir, bu yüzden işe iade tıbbi belgelendirme gerektirir","hi":"इसे एक लंबी अवधि तक बहाया और भोजन में फैलाया जा सकता है, इसलिए पुनर्बहाली के लिए चिकित्सा दस्तावेज़ की आवश्यकता होती है","ar":"يمكن أن يُطرَح وينتقل إلى الطعام لفترة ممتدة، لذا تتطلب إعادته توثيقاً طبياً"}],"e":{"en":"Salmonella Typhi is a Big 6 pathogen that can be shed for a long time; an excluded employee may only be reinstated with regulatory approval and medical documentation.","es":"Salmonella Typhi es un patógeno de los 6 grandes (Big 6) que puede excretarse durante mucho tiempo; un empleado excluido solo puede reincorporarse con la aprobación de la autoridad reguladora y documentación médica.","ru":"Salmonella Typhi — патоген из «Большой шестёрки» (Big 6), который может выделяться в течение длительного времени; отстранённый работник может быть восстановлен только с одобрения регулирующего органа и при наличии медицинской документации.","tr":"Salmonella Typhi, uzun süre saçılabilen bir Büyük 6 (Big 6) patojenidir; hariç tutulan bir çalışan yalnızca düzenleyici onay ve tıbbi belgelendirmeyle işe iade edilebilir.","hi":"साल्मोनेला टाइफी एक Big 6 रोगजनक है जिसे लंबे समय तक बहाया जा सकता है; एक बाहर रखे गए कर्मचारी को केवल नियामक अनुमोदन और चिकित्सा दस्तावेज़ के साथ पुनर्बहाल किया जा सकता है।","ar":"سالمونيلا التيفية (Salmonella Typhi) هي أحد مسببات الستة الكبار (Big 6) التي يمكن أن تُطرَح لفترة طويلة؛ ولا يجوز إعادة الموظف المُستبعَد إلا بموافقة الجهة التنظيمية وتوثيق طبي."}},{"cat":"temp","a":1,"q":{"en":"What is the temperature range commonly called the \"danger zone,\" where bacteria in food grow most rapidly?","es":"¿Cuál es el rango de temperatura comúnmente llamado \"zona de peligro\", donde las bacterias en los alimentos crecen más rápidamente?","ru":"Каков температурный диапазон, обычно называемый «опасной температурной зоной», в котором бактерии в продуктах размножаются наиболее быстро?","tr":"Gıdadaki bakterilerin en hızlı çoğaldığı, yaygın olarak \"tehlikeli sıcaklık bölgesi\" (danger zone) olarak adlandırılan sıcaklık aralığı nedir?","hi":"वह तापमान सीमा क्या है जिसे आमतौर पर \"खतरनाक तापमान क्षेत्र\" कहा जाता है, जहां भोजन में बैक्टीरिया सबसे तेज़ी से बढ़ते हैं?","ar":"ما نطاق درجات الحرارة الذي يُسمى عادةً \"منطقة الخطر الحرارية\"، حيث تنمو البكتيريا في الطعام بأسرع وتيرة؟"},"o":[{"en":"32°F to 100°F","es":"32°F a 100°F","ru":"32°F to 100°F","tr":"32°F ile 100°F arası","hi":"32°F से 100°F","ar":"32°F to 100°F"},{"en":"41°F to 135°F","es":"41°F a 135°F","ru":"41°F to 135°F","tr":"41°F ile 135°F arası","hi":"41°F से 135°F","ar":"41°F to 135°F"},{"en":"45°F to 140°F","es":"45°F a 140°F","ru":"45°F to 140°F","tr":"45°F ile 140°F arası","hi":"45°F से 140°F","ar":"45°F to 140°F"},{"en":"50°F to 120°F","es":"50°F a 120°F","ru":"50°F to 120°F","tr":"50°F ile 120°F arası","hi":"50°F से 120°F","ar":"50°F to 120°F"}],"e":{"en":"The FDA Food Code defines the temperature danger zone as 41°F to 135°F (5°C to 57°C), the range in which TCS foods support the fastest bacterial growth.","es":"El Código de Alimentos de la FDA define la zona de temperatura de peligro como 41°F a 135°F (5°C a 57°C), el rango en el que los alimentos TCS favorecen el crecimiento bacteriano más rápido.","ru":"FDA Food Code (Пищевой кодекс) определяет опасную температурную зону как диапазон от 41°F до 135°F (5°C–57°C) — диапазон, в котором TCS-продукты поддерживают самый быстрый рост бактерий.","tr":"FDA Gıda Kanunu (Food Code), tehlikeli sıcaklık bölgesini 41°F ile 135°F (5°C ile 57°C) olarak tanımlar; bu aralık, TCS gıdalarının en hızlı bakteriyel üremeyi desteklediği aralıktır.","hi":"FDA फूड कोड खतरनाक तापमान क्षेत्र को 41°F से 135°F (5°C से 57°C) के रूप में परिभाषित करता है, वह सीमा जिसमें TCS भोजन सबसे तेज़ बैक्टीरिया वृद्धि का समर्थन करते हैं।","ar":"يُعرّف قانون الغذاء الصادر عن FDA منطقة الخطر الحرارية بأنها 41°F to 135°F (5°C to 57°C)، وهي النطاق الذي تدعم فيه الأطعمة TCS أسرع نمو بكتيري."}},{"cat":"temp","a":1,"q":{"en":"Why do food handlers keep TCS foods out of the danger zone?","es":"¿Por qué los manipuladores de alimentos mantienen los alimentos TCS fuera de la zona de peligro?","ru":"Почему работники пищевого производства держат TCS-продукты вне опасной температурной зоны?","tr":"Gıda çalışanları neden TCS gıdaları tehlikeli sıcaklık bölgesinden uzak tutar?","hi":"फूड हैंडलर TCS भोजन को खतरनाक तापमान क्षेत्र से बाहर क्यों रखते हैं?","ar":"لماذا يُبقي متداولو الطعام أطعمة TCS خارج منطقة الخطر الحرارية؟"},"o":[{"en":"Cold temperatures destroy all bacteria instantly","es":"Las temperaturas frías destruyen todas las bacterias al instante","ru":"Холодные температуры мгновенно уничтожают все бактерии","tr":"Soğuk sıcaklıklar tüm bakterileri anında yok eder","hi":"ठंडा तापमान सभी बैक्टीरिया को तुरंत नष्ट कर देता है","ar":"تقضي درجات الحرارة المنخفضة على كل البكتيريا فوراً"},{"en":"Bacteria multiply fastest within that temperature range","es":"Las bacterias se multiplican más rápido dentro de ese rango de temperatura","ru":"Бактерии размножаются быстрее всего в этом температурном диапазоне","tr":"Bakteriler bu sıcaklık aralığında en hızlı çoğalır","hi":"उस तापमान सीमा के भीतर बैक्टीरिया सबसे तेज़ी से बढ़ते हैं","ar":"تتكاثر البكتيريا بأسرع وتيرة ضمن ذلك النطاق الحراري"},{"en":"Food loses flavor between 41°F and 135°F","es":"El alimento pierde sabor entre 41°F y 135°F","ru":"Продукты теряют вкус при температуре от 41°F до 135°F","tr":"Gıda, 41°F ile 135°F arasında lezzetini kaybeder","hi":"41°F और 135°F के बीच भोजन का स्वाद खो जाता है","ar":"يفقد الطعام نكهته بين 41°F و135°F"},{"en":"It is the range where freezing damages food cells","es":"Es el rango en el que la congelación daña las células del alimento","ru":"Это диапазон, в котором замораживание повреждает клетки продуктов","tr":"Donmanın gıda hücrelerine zarar verdiği aralıktır","hi":"यह वह सीमा है जहां जमने से भोजन कोशिकाएं क्षतिग्रस्त होती हैं","ar":"إنه النطاق الذي يُتلف فيه التجميد خلايا الطعام"}],"e":{"en":"Bacteria grow fastest between 41°F and 135°F, so limiting time in this range slows growth to safe levels rather than killing the bacteria outright.","es":"Las bacterias crecen más rápido entre 41°F y 135°F, por lo que limitar el tiempo en este rango ralentiza el crecimiento a niveles seguros en lugar de eliminar las bacterias por completo.","ru":"Бактерии растут быстрее всего при температуре от 41°F до 135°F, поэтому ограничение времени пребывания в этом диапазоне замедляет рост до безопасного уровня, а не убивает бактерии напрямую.","tr":"Bakteriler 41°F ile 135°F arasında en hızlı ürer, bu yüzden bu aralıkta geçirilen süreyi sınırlamak, bakterileri tamamen öldürmek yerine üremeyi güvenli seviyelere yavaşlatır.","hi":"बैक्टीरिया 41°F और 135°F के बीच सबसे तेज़ी से बढ़ते हैं, इसलिए इस सीमा में समय सीमित करने से बैक्टीरिया को सीधे मारने के बजाय वृद्धि को सुरक्षित स्तर तक धीमा कर दिया जाता है।","ar":"تنمو البكتيريا بأسرع وتيرة بين 41°F و135°F، لذا فإن الحد من الوقت في هذا النطاق يبطئ النمو إلى مستويات آمنة بدلاً من قتل البكتيريا تماماً."}},{"cat":"temp","a":2,"q":{"en":"What is the minimum internal cooking temperature for poultry, such as chicken or turkey?","es":"¿Cuál es la temperatura interna mínima de cocción para las aves, como el pollo o el pavo?","ru":"Какова минимальная внутренняя температура приготовления для птицы, такой как курица или индейка?","tr":"Tavuk veya hindi gibi kümes hayvanları için minimum iç pişirme sıcaklığı nedir?","hi":"पोल्ट्री, जैसे चिकन या टर्की, के लिए न्यूनतम आंतरिक खाना पकाने का तापमान क्या है?","ar":"ما الحد الأدنى لدرجة حرارة الطهي الداخلية للدواجن، مثل الدجاج أو الديك الرومي؟"},"o":[{"en":"155°F","es":"155°F","ru":"155°F","tr":"155°F","hi":"155°F","ar":"155°F"},{"en":"160°F","es":"160°F","ru":"160°F","tr":"160°F","hi":"160°F","ar":"160°F"},{"en":"165°F","es":"165°F","ru":"165°F","tr":"165°F","hi":"165°F","ar":"165°F"},{"en":"170°F","es":"170°F","ru":"170°F","tr":"170°F","hi":"170°F","ar":"170°F"}],"e":{"en":"Poultry must reach a minimum internal temperature of 165°F for less than 1 second under the FDA Food Code.","es":"Las aves deben alcanzar una temperatura interna mínima de 165°F durante menos de 1 segundo según el Código de Alimentos de la FDA.","ru":"Птица должна достичь минимальной внутренней температуры 165°F в течение менее 1 секунды согласно FDA Food Code (Пищевому кодексу).","tr":"FDA Gıda Kanunu (Food Code) uyarınca kümes hayvanları, 1 saniyeden kısa süreyle minimum 165°F iç sıcaklığa ulaşmalıdır.","hi":"FDA फूड कोड के तहत पोल्ट्री को 1 सेकंड से कम के लिए न्यूनतम आंतरिक तापमान 165°F तक पहुंचना चाहिए।","ar":"يجب أن تصل الدواجن إلى حد أدنى من درجة الحرارة الداخلية قدره 165°F لأقل من ثانية واحدة بموجب قانون الغذاء الصادر عن FDA."}},{"cat":"temp","a":3,"q":{"en":"Stuffed pasta, stuffed poultry, and other stuffed foods must be cooked to a minimum internal temperature of:","es":"La pasta rellena, las aves rellenas y otros alimentos rellenos deben cocinarse a una temperatura interna mínima de:","ru":"Фаршированная паста, фаршированная птица и другие фаршированные блюда должны быть приготовлены до минимальной внутренней температуры:","tr":"İçi doldurulmuş makarna, içi doldurulmuş kümes hayvanları ve diğer içi doldurulmuş gıdalar, minimum hangi iç sıcaklığa kadar pişirilmelidir?","hi":"भरवां पास्ता, भरवां पोल्ट्री, और अन्य भरवां भोजन को न्यूनतम आंतरिक तापमान तक पकाया जाना चाहिए:","ar":"يجب طهي المعكرونة المحشوة والدواجن المحشوة وغيرها من الأطعمة المحشوة إلى حد أدنى من درجة الحرارة الداخلية قدره:"},"o":[{"en":"145°F","es":"145°F","ru":"145°F","tr":"145°F","hi":"145°F","ar":"145°F"},{"en":"155°F","es":"155°F","ru":"155°F","tr":"155°F","hi":"155°F","ar":"155°F"},{"en":"160°F","es":"160°F","ru":"160°F","tr":"160°F","hi":"160°F","ar":"160°F"},{"en":"165°F","es":"165°F","ru":"165°F","tr":"165°F","hi":"165°F","ar":"165°F"}],"e":{"en":"Stuffed foods and stuffing containing TCS ingredients must reach 165°F for less than 1 second because the stuffing can shield bacteria from heat.","es":"Los alimentos rellenos y el relleno que contiene ingredientes TCS deben alcanzar 165°F durante menos de 1 segundo porque el relleno puede proteger a las bacterias del calor.","ru":"Фаршированные блюда и начинка, содержащая TCS-ингредиенты, должны достичь 165°F в течение менее 1 секунды, поскольку начинка может защищать бактерии от тепла.","tr":"İç dolgu, bakterileri ısıdan koruyabileceğinden, TCS içerikli içi doldurulmuş gıdalar ve dolgular 1 saniyeden kısa süreyle 165°F'ye ulaşmalıdır.","hi":"भरवां भोजन और TCS सामग्री वाली भराई को 1 सेकंड से कम के लिए 165°F तक पहुंचना चाहिए क्योंकि भराई बैक्टीरिया को गर्मी से बचा सकती है।","ar":"يجب أن تصل الأطعمة المحشوة والحشوات التي تحتوي على مكونات TCS إلى 165°F لأقل من ثانية واحدة لأن الحشوة قد تحمي البكتيريا من الحرارة."}},{"cat":"temp","a":2,"q":{"en":"What is the minimum internal cooking temperature for ground beef, such as hamburger patties?","es":"¿Cuál es la temperatura interna mínima de cocción para la carne molida de res, como las hamburguesas?","ru":"Какова минимальная внутренняя температура приготовления для говяжьего фарша, например для котлет для гамбургеров?","tr":"Hamburger köftesi gibi kıyma sığır eti için minimum iç pişirme sıcaklığı nedir?","hi":"कीमा बीफ, जैसे हैमबर्गर पैटीज़, के लिए न्यूनतम आंतरिक खाना पकाने का तापमान क्या है?","ar":"ما الحد الأدنى لدرجة حرارة الطهي الداخلية للحم البقري المفروم، مثل أقراص الهامبرغر؟"},"o":[{"en":"145°F","es":"145°F","ru":"145°F","tr":"145°F","hi":"145°F","ar":"145°F"},{"en":"150°F","es":"150°F","ru":"150°F","tr":"150°F","hi":"150°F","ar":"150°F"},{"en":"155°F","es":"155°F","ru":"155°F","tr":"155°F","hi":"155°F","ar":"155°F"},{"en":"165°F","es":"165°F","ru":"165°F","tr":"165°F","hi":"165°F","ar":"165°F"}],"e":{"en":"Ground (comminuted) meat must reach 155°F for 17 seconds, because grinding spreads surface bacteria throughout the meat.","es":"La carne molida (triturada) debe alcanzar 155°F durante 17 segundos, porque la molienda distribuye las bacterias de la superficie por toda la carne.","ru":"Измельчённое (фаршированное) мясо должно достичь 155°F в течение 17 секунд, поскольку измельчение распространяет поверхностные бактерии по всему мясу.","tr":"Kıyma yapma işlemi yüzeydeki bakterileri etin her yerine yaydığından, kıyılmış (parçalanmış) et 17 saniye boyunca 155°F'ye ulaşmalıdır.","hi":"कीमा (बारीक किया हुआ) मांस को 17 सेकंड के लिए 155°F तक पहुंचना चाहिए, क्योंकि कीमा बनाने से सतह के बैक्टीरिया पूरे मांस में फैल जाते हैं।","ar":"يجب أن يصل اللحم المفروم (المُجزَّأ) إلى 155°F لمدة 17 ثانية، لأن الفرم ينشر بكتيريا السطح في جميع أنحاء اللحم."}},{"cat":"temp","a":2,"q":{"en":"Fish (seafood), pork chops, and eggs cooked for immediate service must reach a minimum internal temperature of:","es":"El pescado (mariscos), las chuletas de cerdo y los huevos cocinados para servicio inmediato deben alcanzar una temperatura interna mínima de:","ru":"Рыба (морепродукты), свиные отбивные и яйца, приготовленные для немедленной подачи, должны достичь минимальной внутренней температуры:","tr":"Anında servis için pişirilen balık (deniz ürünleri), domuz pirzolası ve yumurtalar, minimum hangi iç sıcaklığa ulaşmalıdır?","hi":"तत्काल सेवा के लिए पकाई गई मछली (सीफूड), पोर्क चॉप्स, और अंडे न्यूनतम आंतरिक तापमान तक पहुंचने चाहिए:","ar":"يجب أن تصل الأسماك (المأكولات البحرية) وشرائح لحم الخنزير والبيض المطهوة للتقديم الفوري إلى حد أدنى من درجة الحرارة الداخلية قدره:"},"o":[{"en":"135°F","es":"135°F","ru":"135°F","tr":"135°F","hi":"135°F","ar":"135°F"},{"en":"140°F","es":"140°F","ru":"140°F","tr":"140°F","hi":"140°F","ar":"140°F"},{"en":"145°F","es":"145°F","ru":"145°F","tr":"145°F","hi":"145°F","ar":"145°F"},{"en":"155°F","es":"155°F","ru":"155°F","tr":"155°F","hi":"155°F","ar":"155°F"}],"e":{"en":"Seafood, intact pork, and eggs cooked to order for immediate service must reach 145°F for 15 seconds under the FDA Food Code.","es":"Los mariscos, el cerdo intacto y los huevos cocinados al momento para servicio inmediato deben alcanzar 145°F durante 15 segundos según el Código de Alimentos de la FDA.","ru":"Морепродукты, цельная свинина и яйца, приготовленные на заказ для немедленной подачи, должны достичь 145°F в течение 15 секунд согласно FDA Food Code (Пищевому кодексу).","tr":"FDA Gıda Kanunu (Food Code) uyarınca, anında servis için sipariş üzerine pişirilen deniz ürünleri, bütün (sağlam) domuz eti ve yumurtalar 15 saniye boyunca 145°F'ye ulaşmalıdır.","hi":"FDA फूड कोड के तहत तत्काल सेवा के लिए ऑर्डर पर पकाए गए सीफूड, सही-सलामत पोर्क, और अंडे 15 सेकंड के लिए 145°F तक पहुंचने चाहिए।","ar":"يجب أن تصل المأكولات البحرية ولحم الخنزير غير المفروم والبيض المطهو حسب الطلب للتقديم الفوري إلى 145°F لمدة 15 ثانية بموجب قانون الغذاء الصادر عن FDA."}},{"cat":"temp","a":0,"q":{"en":"A whole cut of beef roast is cooked to 145°F. What additional step does the FDA Food Code require?","es":"Un corte entero de carne de res asada se cocina a 145°F. ¿Qué paso adicional exige el Código de Alimentos de la FDA?","ru":"Цельный кусок говяжьей вырезки приготовлен до 145°F. Какой дополнительный шаг требует FDA Food Code (Пищевой кодекс)?","tr":"Bütün bir parça sığır rosto 145°F'ye kadar pişirilir. FDA Gıda Kanunu (Food Code) ek olarak hangi adımı gerektirir?","hi":"बीफ रोस्ट का एक पूरा टुकड़ा 145°F तक पकाया जाता है। FDA फूड कोड किस अतिरिक्त कदम की आवश्यकता मानता है?","ar":"تُطهى قطعة كاملة من شواء اللحم البقري إلى 145°F. ما الخطوة الإضافية التي يشترطها قانون الغذاء الصادر عن FDA؟"},"o":[{"en":"A 3-minute rest at or above that temperature","es":"Un reposo de 3 minutos a esa temperatura o por encima de ella","ru":"3-минутную выдержку при этой температуре или выше","tr":"Bu sıcaklıkta veya üzerinde 3 dakikalık bekleme (dinlendirme)","hi":"उस तापमान पर या उससे ऊपर 3 मिनट का विश्राम","ar":"إراحة لمدة 3 دقائق عند تلك الدرجة أو أعلى منها"},{"en":"An immediate ice-water bath","es":"Un baño de agua helada inmediato","ru":"Немедленную ванну с ледяной водой","tr":"Anında buzlu su banyosu","hi":"एक तत्काल बर्फ-पानी का स्नान","ar":"حمام بماء مثلج فوري"},{"en":"Reheating to 165°F","es":"Recalentar a 165°F","ru":"Повторный нагрев до 165°F","tr":"165°F'ye yeniden ısıtma","hi":"165°F तक पुनः गर्म करना","ar":"إعادة التسخين إلى 165°F"},{"en":"A 30-second rest before slicing","es":"Un reposo de 30 segundos antes de rebanar","ru":"30-секундную выдержку перед нарезкой","tr":"Dilimlemeden önce 30 saniyelik bekleme","hi":"काटने से पहले 30 सेकंड का विश्राम","ar":"إراحة لمدة 30 ثانية قبل التقطيع"}],"e":{"en":"Whole cuts of beef and pork cooked to 145°F require a 3-minute rest time, during which the temperature is maintained to ensure pathogen reduction.","es":"Los cortes enteros de res y cerdo cocinados a 145°F requieren un tiempo de reposo de 3 minutos, durante el cual se mantiene la temperatura para asegurar la reducción de patógenos.","ru":"Цельные куски говядины и свинины, приготовленные до 145°F, требуют 3-минутной выдержки, в течение которой температура поддерживается для обеспечения снижения количества патогенов.","tr":"145°F'ye pişirilen bütün parça sığır ve domuz eti, patojen azaltmayı sağlamak için sıcaklığın korunduğu 3 dakikalık bir dinlendirme süresi gerektirir.","hi":"145°F तक पकाए गए बीफ और पोर्क के पूरे टुकड़ों के लिए 3 मिनट के विश्राम समय की आवश्यकता होती है, जिसके दौरान रोगजनक कमी सुनिश्चित करने के लिए तापमान बनाए रखा जाता है।","ar":"تتطلب القطع الكاملة من اللحم البقري ولحم الخنزير المطهوة إلى 145°F وقت إراحة قدره 3 دقائق، يتم خلالها الحفاظ على درجة الحرارة لضمان تقليل مسببات الأمراض."}},{"cat":"temp","a":3,"q":{"en":"Previously cooked food that is being reheated for hot holding must reach what minimum internal temperature?","es":"Los alimentos previamente cocinados que se recalientan para mantenimiento en caliente deben alcanzar ¿qué temperatura interna mínima?","ru":"Ранее приготовленная пища, которую повторно разогревают для горячего хранения, должна достичь какой минимальной внутренней температуры?","tr":"Sıcak muhafaza için yeniden ısıtılan, daha önce pişirilmiş gıda hangi minimum iç sıcaklığa ulaşmalıdır?","hi":"पहले से पका हुआ भोजन जिसे हॉट होल्डिंग के लिए पुनः गर्म किया जा रहा है, उसे किस न्यूनतम आंतरिक तापमान तक पहुंचना चाहिए?","ar":"يجب أن يصل الطعام المطهو مسبقاً والذي يُعاد تسخينه للحفظ الساخن إلى أيِّ حد أدنى من درجة الحرارة الداخلية؟"},"o":[{"en":"135°F","es":"135°F","ru":"135°F","tr":"135°F","hi":"135°F","ar":"135°F"},{"en":"145°F","es":"145°F","ru":"145°F","tr":"145°F","hi":"145°F","ar":"145°F"},{"en":"155°F","es":"155°F","ru":"155°F","tr":"155°F","hi":"155°F","ar":"155°F"},{"en":"165°F","es":"165°F","ru":"165°F","tr":"165°F","hi":"165°F","ar":"165°F"}],"e":{"en":"Food reheated for hot holding must reach 165°F for 15 seconds to be safe.","es":"Los alimentos recalentados para mantenimiento en caliente deben alcanzar 165°F durante 15 segundos para ser seguros.","ru":"Пища, разогреваемая для горячего хранения, должна достичь 165°F в течение 15 секунд, чтобы быть безопасной.","tr":"Sıcak muhafaza için yeniden ısıtılan gıda, güvenli olması için 15 saniye boyunca 165°F'ye ulaşmalıdır.","hi":"हॉट होल्डिंग के लिए पुनः गर्म किए गए भोजन को सुरक्षित होने के लिए 15 सेकंड के लिए 165°F तक पहुंचना चाहिए।","ar":"يجب أن يصل الطعام المُعاد تسخينه للحفظ الساخن إلى 165°F لمدة 15 ثانية ليكون آمناً."}},{"cat":"temp","a":1,"q":{"en":"When reheating food for hot holding, the food must reach the required temperature within how many hours?","es":"Al recalentar alimentos para mantenimiento en caliente, el alimento debe alcanzar la temperatura requerida dentro de ¿cuántas horas?","ru":"При повторном разогреве пищи для горячего хранения пища должна достичь требуемой температуры в течение скольких часов?","tr":"Gıdayı sıcak muhafaza için yeniden ısıtırken, gıda gerekli sıcaklığa kaç saat içinde ulaşmalıdır?","hi":"हॉट होल्डिंग के लिए भोजन को पुनः गर्म करते समय, भोजन को कितने घंटों के भीतर आवश्यक तापमान तक पहुंचना चाहिए?","ar":"عند إعادة تسخين الطعام للحفظ الساخن، يجب أن يصل الطعام إلى درجة الحرارة المطلوبة في غضون كم ساعة؟"},"o":[{"en":"1 hour","es":"1 hora","ru":"1 hour","tr":"1 saat","hi":"1 घंटा","ar":"1 hour"},{"en":"2 hours","es":"2 horas","ru":"2 hours","tr":"2 saat","hi":"2 घंटे","ar":"2 hours"},{"en":"4 hours","es":"4 horas","ru":"4 hours","tr":"4 saat","hi":"4 घंटे","ar":"4 hours"},{"en":"6 hours","es":"6 horas","ru":"6 hours","tr":"6 saat","hi":"6 घंटे","ar":"6 hours"}],"e":{"en":"Reheating for hot holding must bring food to 165°F within 2 hours to minimize the time spent in the danger zone.","es":"El recalentamiento para mantenimiento en caliente debe llevar el alimento a 165°F dentro de 2 horas para minimizar el tiempo en la zona de peligro.","ru":"Повторный разогрев для горячего хранения должен довести пищу до 165°F в течение 2 часов, чтобы минимизировать время, проведённое в опасной температурной зоне.","tr":"Sıcak muhafaza için yeniden ısıtma, tehlikeli sıcaklık bölgesinde geçirilen süreyi en aza indirmek için gıdayı 2 saat içinde 165°F'ye getirmelidir.","hi":"हॉट होल्डिंग के लिए पुनः गर्म करने से खतरनाक तापमान क्षेत्र में बिताए गए समय को कम करने के लिए भोजन को 2 घंटे के भीतर 165°F तक लाना चाहिए।","ar":"يجب أن تُوصِل إعادة التسخين للحفظ الساخن الطعامَ إلى 165°F في غضون 2 hours لتقليل الوقت المُمضى في منطقة الخطر الحرارية."}},{"cat":"temp","a":2,"q":{"en":"What is the minimum temperature at which hot TCS foods must be held on a steam table or buffet line?","es":"¿Cuál es la temperatura mínima a la que deben mantenerse los alimentos TCS calientes en una mesa de vapor o línea de bufé?","ru":"Какова минимальная температура, при которой горячие TCS-продукты должны храниться на паровом столе или линии буфета?","tr":"Sıcak TCS gıdaların bir buharlı tezgahta veya açık büfe hattında tutulması gereken minimum sıcaklık nedir?","hi":"स्टीम टेबल या बुफे लाइन पर गर्म TCS भोजन को किस न्यूनतम तापमान पर रखा जाना चाहिए?","ar":"ما الحد الأدنى لدرجة الحرارة التي يجب عندها حفظ أطعمة TCS الساخنة على طاولة بخارية أو خط بوفيه؟"},"o":[{"en":"125°F","es":"125°F","ru":"125°F","tr":"125°F","hi":"125°F","ar":"125°F"},{"en":"130°F","es":"130°F","ru":"130°F","tr":"130°F","hi":"130°F","ar":"130°F"},{"en":"135°F","es":"135°F","ru":"135°F","tr":"135°F","hi":"135°F","ar":"135°F"},{"en":"145°F","es":"145°F","ru":"145°F","tr":"145°F","hi":"145°F","ar":"145°F"}],"e":{"en":"Hot TCS foods must be held at 135°F or above to stay out of the danger zone.","es":"Los alimentos TCS calientes deben mantenerse a 135°F o más para permanecer fuera de la zona de peligro.","ru":"Горячие TCS-продукты должны храниться при температуре 135°F или выше, чтобы оставаться вне опасной температурной зоны.","tr":"Sıcak TCS gıdalar, tehlikeli sıcaklık bölgesinin dışında kalmak için 135°F veya üzerinde tutulmalıdır.","hi":"गर्म TCS भोजन को खतरनाक तापमान क्षेत्र से बाहर रहने के लिए 135°F या उससे ऊपर रखा जाना चाहिए।","ar":"يجب حفظ أطعمة TCS الساخنة عند 135°F أو أعلى للبقاء خارج منطقة الخطر الحرارية."}},{"cat":"temp","a":1,"q":{"en":"What is the maximum temperature at which cold TCS foods may be held?","es":"¿Cuál es la temperatura máxima a la que pueden mantenerse los alimentos TCS fríos?","ru":"Какова максимальная температура, при которой могут храниться холодные TCS-продукты?","tr":"Soğuk TCS gıdaların tutulabileceği maksimum sıcaklık nedir?","hi":"ठंडे TCS भोजन को किस अधिकतम तापमान पर रखा जा सकता है?","ar":"ما الحد الأقصى لدرجة الحرارة التي يجوز عندها حفظ أطعمة TCS الباردة؟"},"o":[{"en":"38°F","es":"38°F","ru":"38°F","tr":"38°F","hi":"38°F","ar":"38°F"},{"en":"41°F","es":"41°F","ru":"41°F","tr":"41°F","hi":"41°F","ar":"41°F"},{"en":"45°F","es":"45°F","ru":"45°F","tr":"45°F","hi":"45°F","ar":"45°F"},{"en":"50°F","es":"50°F","ru":"50°F","tr":"50°F","hi":"50°F","ar":"50°F"}],"e":{"en":"Cold TCS foods must be held at 41°F or below to limit bacterial growth.","es":"Los alimentos TCS fríos deben mantenerse a 41°F o menos para limitar el crecimiento bacteriano.","ru":"Холодные TCS-продукты должны храниться при температуре 41°F или ниже, чтобы ограничить рост бактерий.","tr":"Soğuk TCS gıdalar, bakteriyel üremeyi sınırlamak için 41°F veya altında tutulmalıdır.","hi":"ठंडे TCS भोजन को बैक्टीरिया वृद्धि सीमित करने के लिए 41°F या उससे नीचे रखा जाना चाहिए।","ar":"يجب حفظ أطعمة TCS الباردة عند 41°F أو أقل للحد من النمو البكتيري."}},{"cat":"temp","a":1,"q":{"en":"During the first stage of cooling, hot food must be cooled from 135°F down to 70°F within how long?","es":"Durante la primera etapa de enfriamiento, el alimento caliente debe enfriarse de 135°F a 70°F en ¿cuánto tiempo?","ru":"На первом этапе охлаждения горячая пища должна быть охлаждена со 135°F до 70°F в течение какого времени?","tr":"Soğutmanın ilk aşamasında, sıcak gıda 135°F'den 70°F'ye ne kadar süre içinde soğutulmalıdır?","hi":"ठंडा करने के पहले चरण के दौरान, गर्म भोजन को 135°F से 70°F तक कितनी देर के भीतर ठंडा किया जाना चाहिए?","ar":"خلال المرحلة الأولى من التبريد، يجب تبريد الطعام الساخن من 135°F نزولاً إلى 70°F في غضون كم من الوقت؟"},"o":[{"en":"1 hour","es":"1 hora","ru":"1 hour","tr":"1 saat","hi":"1 घंटा","ar":"1 hour"},{"en":"2 hours","es":"2 horas","ru":"2 hours","tr":"2 saat","hi":"2 घंटे","ar":"2 hours"},{"en":"4 hours","es":"4 horas","ru":"4 hours","tr":"4 saat","hi":"4 घंटे","ar":"4 hours"},{"en":"6 hours","es":"6 horas","ru":"6 hours","tr":"6 saat","hi":"6 घंटे","ar":"6 hours"}],"e":{"en":"The FDA Food Code requires cooling from 135°F to 70°F within 2 hours during the first stage of the cooling process.","es":"El Código de Alimentos de la FDA exige enfriar de 135°F a 70°F dentro de 2 horas durante la primera etapa del proceso de enfriamiento.","ru":"FDA Food Code (Пищевой кодекс) требует охлаждения со 135°F до 70°F в течение 2 часов на первом этапе процесса охлаждения.","tr":"FDA Gıda Kanunu (Food Code), soğutma sürecinin ilk aşamasında 135°F'den 70°F'ye soğutmanın 2 saat içinde yapılmasını gerektirir.","hi":"FDA फूड कोड के अनुसार ठंडा करने की प्रक्रिया के पहले चरण के दौरान 135°F से 70°F तक 2 घंटे के भीतर ठंडा करना आवश्यक है।","ar":"يشترط قانون الغذاء الصادر عن FDA التبريد من 135°F إلى 70°F في غضون 2 hours خلال المرحلة الأولى من عملية التبريد."}},{"cat":"temp","a":2,"q":{"en":"After food reaches 70°F, it must be cooled from 70°F to 41°F within how many additional hours?","es":"Después de que el alimento alcanza 70°F, debe enfriarse de 70°F a 41°F dentro de ¿cuántas horas adicionales?","ru":"После того как пища достигает 70°F, она должна быть охлаждена с 70°F до 41°F в течение скольких дополнительных часов?","tr":"Gıda 70°F'ye ulaştıktan sonra, 70°F'den 41°F'ye kaç saat içinde daha soğutulmalıdır?","hi":"भोजन के 70°F तक पहुंचने के बाद, इसे 70°F से 41°F तक कितने अतिरिक्त घंटों के भीतर ठंडा किया जाना चाहिए?","ar":"بعد أن يصل الطعام إلى 70°F، يجب تبريده من 70°F إلى 41°F في غضون كم ساعة إضافية؟"},"o":[{"en":"2 hours","es":"2 horas","ru":"2 hours","tr":"2 saat","hi":"2 घंटे","ar":"2 hours"},{"en":"3 hours","es":"3 horas","ru":"3 hours","tr":"3 saat","hi":"3 घंटे","ar":"3 hours"},{"en":"4 hours","es":"4 horas","ru":"4 hours","tr":"4 saat","hi":"4 घंटे","ar":"4 hours"},{"en":"5 hours","es":"5 horas","ru":"5 hours","tr":"5 saat","hi":"5 घंटे","ar":"5 hours"}],"e":{"en":"The second cooling stage allows 4 additional hours to go from 70°F to 41°F, for a total of 6 hours of cooling time.","es":"La segunda etapa de enfriamiento permite 4 horas adicionales para pasar de 70°F a 41°F, para un total de 6 horas de tiempo de enfriamiento.","ru":"Второй этап охлаждения отводит 4 дополнительных часа на переход с 70°F до 41°F, что в сумме даёт 6 часов времени охлаждения.","tr":"İkinci soğutma aşaması, 70°F'den 41°F'ye geçmek için 4 saat daha süre tanır; bu da toplam 6 saatlik soğutma süresi demektir.","hi":"दूसरा ठंडा करने का चरण 70°F से 41°F तक जाने के लिए 4 अतिरिक्त घंटे की अनुमति देता है, कुल 6 घंटे के ठंडा करने के समय के लिए।","ar":"تتيح مرحلة التبريد الثانية 4 hours إضافية للانتقال من 70°F إلى 41°F، بإجمالي 6 hours من وقت التبريد."}},{"cat":"temp","a":2,"q":{"en":"Under the two-stage cooling rule, what is the maximum total time allowed to cool food from 135°F to 41°F?","es":"Según la regla de enfriamiento en dos etapas, ¿cuál es el tiempo total máximo permitido para enfriar el alimento de 135°F a 41°F?","ru":"Согласно двухэтапному правилу охлаждения, каково максимальное общее время, отведённое на охлаждение пищи со 135°F до 41°F?","tr":"İki aşamalı soğutma kuralı uyarınca, gıdayı 135°F'den 41°F'ye soğutmak için izin verilen maksimum toplam süre nedir?","hi":"दो-चरण ठंडा करने के नियम के तहत, भोजन को 135°F से 41°F तक ठंडा करने के लिए अनुमत अधिकतम कुल समय क्या है?","ar":"بموجب قاعدة التبريد ذات المرحلتين، ما الحد الأقصى لإجمالي الوقت المسموح به لتبريد الطعام من 135°F إلى 41°F؟"},"o":[{"en":"4 hours","es":"4 horas","ru":"4 hours","tr":"4 saat","hi":"4 घंटे","ar":"4 hours"},{"en":"5 hours","es":"5 horas","ru":"5 hours","tr":"5 saat","hi":"5 घंटे","ar":"5 hours"},{"en":"6 hours","es":"6 horas","ru":"6 hours","tr":"6 saat","hi":"6 घंटे","ar":"6 hours"},{"en":"8 hours","es":"8 horas","ru":"8 hours","tr":"8 saat","hi":"8 घंटे","ar":"8 hours"}],"e":{"en":"The total cooling time may not exceed 6 hours: 2 hours from 135°F to 70°F plus 4 hours from 70°F to 41°F.","es":"El tiempo total de enfriamiento no puede exceder las 6 horas: 2 horas de 135°F a 70°F más 4 horas de 70°F a 41°F.","ru":"Общее время охлаждения не может превышать 6 часов: 2 часа со 135°F до 70°F плюс 4 часа с 70°F до 41°F.","tr":"Toplam soğutma süresi 6 saati aşamaz: 135°F'den 70°F'ye 2 saat artı 70°F'den 41°F'ye 4 saat.","hi":"कुल ठंडा करने का समय 6 घंटे से अधिक नहीं हो सकता: 135°F से 70°F तक 2 घंटे और 70°F से 41°F तक 4 घंटे।","ar":"يجب ألا يتجاوز إجمالي وقت التبريد 6 hours: 2 hours من 135°F إلى 70°F زائد 4 hours من 70°F إلى 41°F."}},{"cat":"temp","a":2,"q":{"en":"Which of the following is NOT an approved method for thawing frozen TCS food?","es":"¿Cuál de los siguientes NO es un método aprobado para descongelar alimentos TCS congelados?","ru":"Какой из перечисленных методов НЕ является одобренным методом размораживания замороженных TCS-продуктов?","tr":"Aşağıdakilerden hangisi donmuş TCS gıdayı çözmek için onaylanmış bir yöntem DEĞİLDİR?","hi":"जमे हुए TCS भोजन को पिघलाने के लिए इनमें से कौन सी एक अनुमोदित विधि नहीं है?","ar":"أيٌّ مما يلي ليس طريقة معتمدة لإذابة الطعام المجمَّد من نوع TCS؟"},"o":[{"en":"In a refrigerator at 41°F or below","es":"En un refrigerador a 41°F o menos","ru":"В холодильнике при температуре 41°F или ниже","tr":"41°F veya altındaki bir buzdolabında","hi":"41°F या उससे नीचे रेफ्रिजरेटर में","ar":"في ثلاجة عند 41°F أو أقل"},{"en":"Under running water at 70°F or below","es":"Bajo agua corriente a 70°F o menos","ru":"Под проточной водой при температуре 70°F или ниже","tr":"70°F veya altındaki akan su altında","hi":"70°F या उससे नीचे बहते पानी के नीचे","ar":"تحت ماء جارٍ عند 70°F أو أقل"},{"en":"On a countertop at room temperature","es":"En una encimera a temperatura ambiente","ru":"На столешнице при комнатной температуре","tr":"Oda sıcaklığında bir tezgah üzerinde","hi":"कमरे के तापमान पर काउंटरटॉप पर","ar":"على سطح المنضدة في درجة حرارة الغرفة"},{"en":"In a microwave, then cooked immediately","es":"En un microondas, y luego cocinado de inmediato","ru":"В микроволновой печи с последующим немедленным приготовлением","tr":"Mikrodalgada, ardından hemen pişirilerek","hi":"माइक्रोवेव में, फिर तुरंत पकाया गया","ar":"في الميكروويف، ثم طهيه فوراً"}],"e":{"en":"Thawing at room temperature is never permitted because it lets the surface of the food sit in the danger zone; running water must be 70°F or below.","es":"Descongelar a temperatura ambiente nunca está permitido porque deja la superficie del alimento en la zona de peligro; el agua corriente debe estar a 70°F o menos.","ru":"Размораживание при комнатной температуре никогда не допускается, поскольку оно позволяет поверхности продукта находиться в опасной температурной зоне; проточная вода должна быть 70°F или ниже.","tr":"Oda sıcaklığında çözme asla izin verilmez çünkü gıdanın yüzeyinin tehlikeli sıcaklık bölgesinde kalmasına neden olur; akan su 70°F veya altında olmalıdır.","hi":"कमरे के तापमान पर पिघलाना कभी भी अनुमत नहीं है क्योंकि यह भोजन की सतह को खतरनाक तापमान क्षेत्र में बैठने देता है; बहता पानी 70°F या उससे नीचे होना चाहिए।","ar":"لا يُسمح بالإذابة في درجة حرارة الغرفة أبداً لأنها تترك سطح الطعام في منطقة الخطر الحرارية؛ ويجب أن يكون الماء الجاري عند 70°F أو أقل."}},{"cat":"temp","a":2,"q":{"en":"If thawing food under running water, the water temperature must be at or below:","es":"Si se descongela el alimento bajo agua corriente, la temperatura del agua debe ser igual o inferior a:","ru":"При размораживании продукта под проточной водой температура воды должна быть на уровне или ниже:","tr":"Gıda akan su altında çözülüyorsa, su sıcaklığı en fazla şu olmalıdır:","hi":"बहते पानी के नीचे भोजन पिघलाते समय, पानी का तापमान इस पर या उससे नीचे होना चाहिए:","ar":"إذا تم إذابة الطعام تحت ماء جارٍ، فيجب أن تكون درجة حرارة الماء عند أو دون:"},"o":[{"en":"41°F","es":"41°F","ru":"41°F","tr":"41°F","hi":"41°F","ar":"41°F"},{"en":"60°F","es":"60°F","ru":"60°F","tr":"60°F","hi":"60°F","ar":"60°F"},{"en":"70°F","es":"70°F","ru":"70°F","tr":"70°F","hi":"70°F","ar":"70°F"},{"en":"75°F","es":"75°F","ru":"75°F","tr":"75°F","hi":"75°F","ar":"75°F"}],"e":{"en":"Running-water thawing requires potable water at 70°F or below, flowing fast enough to wash food particles into the drain overflow.","es":"La descongelación con agua corriente requiere agua potable a 70°F o menos, fluyendo con la rapidez suficiente para arrastrar las partículas de alimento hacia el desagüe.","ru":"Размораживание проточной водой требует питьевой воды при температуре 70°F или ниже, текущей достаточно быстро, чтобы смывать частицы продукта в перелив сливного отверстия.","tr":"Akan suyla çözme, gıda parçacıklarını giderin taşma kanalına yıkayacak kadar hızlı akan, 70°F veya altında içme suyu gerektirir.","hi":"बहते-पानी से पिघलाने के लिए 70°F या उससे नीचे पीने योग्य पानी की आवश्यकता होती है, जो इतनी तेज़ी से बहता हो कि भोजन के कण नाली के अतिप्रवाह में बह जाएं।","ar":"تتطلب الإذابة بالماء الجاري ماءً صالحاً للشرب عند 70°F أو أقل، يتدفق بسرعة كافية لجرف جزيئات الطعام إلى فائض التصريف."}},{"cat":"temp","a":1,"q":{"en":"When calibrating a thermometer using the ice-point method, the thermometer should read:","es":"Al calibrar un termómetro usando el método de punto de hielo, el termómetro debe marcar:","ru":"При калибровке термометра методом точки таяния льда термометр должен показывать:","tr":"Buz noktası (ice-point) yöntemiyle bir termometre kalibre edilirken, termometre şunu göstermelidir:","hi":"आइस-पॉइंट विधि का उपयोग करके थर्मामीटर को कैलिब्रेट करते समय, थर्मामीटर को यह दिखाना चाहिए:","ar":"عند معايرة ميزان الحرارة باستخدام طريقة نقطة الثلج، ينبغي أن يقرأ الميزان:"},"o":[{"en":"28°F","es":"28°F","ru":"28°F","tr":"28°F","hi":"28°F","ar":"28°F"},{"en":"32°F","es":"32°F","ru":"32°F","tr":"32°F","hi":"32°F","ar":"32°F"},{"en":"34°F","es":"34°F","ru":"34°F","tr":"34°F","hi":"34°F","ar":"34°F"},{"en":"40°F","es":"40°F","ru":"40°F","tr":"40°F","hi":"40°F","ar":"40°F"}],"e":{"en":"In the ice-point (ice-water) method, a correctly calibrated thermometer reads 32°F, the freezing point of water.","es":"En el método de punto de hielo (agua con hielo), un termómetro correctamente calibrado marca 32°F, el punto de congelación del agua.","ru":"При методе точки таяния льда (ледяной воды) правильно откалиброванный термометр показывает 32°F — точку замерзания воды.","tr":"Buz noktası (buzlu su) yönteminde, doğru şekilde kalibre edilmiş bir termometre, suyun donma noktası olan 32°F'yi gösterir.","hi":"आइस-पॉइंट (आइस-वॉटर) विधि में, एक सही ढंग से कैलिब्रेट किया गया थर्मामीटर 32°F दिखाता है, जो पानी का जमने का बिंदु है।","ar":"في طريقة نقطة الثلج (الماء المثلج)، يقرأ ميزان الحرارة المُعايَر بشكل صحيح 32°F، وهي نقطة تجمد الماء."}},{"cat":"temp","a":1,"q":{"en":"Where should a food thermometer be inserted to take an accurate reading of a food's internal temperature?","es":"¿Dónde debe insertarse un termómetro de alimentos para obtener una lectura precisa de la temperatura interna de un alimento?","ru":"Куда следует вставлять пищевой термометр для точного измерения внутренней температуры продукта?","tr":"Bir gıdanın iç sıcaklığını doğru ölçmek için gıda termometresi nereye batırılmalıdır?","hi":"भोजन के आंतरिक तापमान की सटीक रीडिंग लेने के लिए एक फूड थर्मामीटर को कहां डाला जाना चाहिए?","ar":"أين ينبغي إدخال ميزان حرارة الطعام للحصول على قراءة دقيقة لدرجة الحرارة الداخلية للطعام؟"},"o":[{"en":"Near the surface of the food","es":"Cerca de la superficie del alimento","ru":"Рядом с поверхностью продукта","tr":"Gıdanın yüzeyine yakın bir yere","hi":"भोजन की सतह के पास","ar":"قرب سطح الطعام"},{"en":"In the thickest part of the food","es":"En la parte más gruesa del alimento","ru":"В самую толстую часть продукта","tr":"Gıdanın en kalın kısmına","hi":"भोजन के सबसे मोटे हिस्से में","ar":"في أكثف جزء من الطعام"},{"en":"Touching the bottom of the pan","es":"Tocando el fondo de la sartén","ru":"Касаясь дна кастрюли","tr":"Tencerenin dibine değecek şekilde","hi":"पैन के तल को छूते हुए","ar":"ملامساً لقاع الإناء"},{"en":"Just under the food's outer crust","es":"Justo debajo de la corteza exterior del alimento","ru":"Прямо под наружной корочкой продукта","tr":"Gıdanın dış kabuğunun hemen altına","hi":"भोजन की बाहरी परत के ठीक नीचे","ar":"تحت القشرة الخارجية للطعام مباشرة"}],"e":{"en":"The thermometer stem should be placed in the thickest part of the food, away from bone, fat, or the container, to read the true internal temperature.","es":"El vástago del termómetro debe colocarse en la parte más gruesa del alimento, lejos del hueso, la grasa o el recipiente, para leer la verdadera temperatura interna.","ru":"Стержень термометра следует помещать в самую толстую часть продукта, вдали от кости, жира или стенок ёмкости, чтобы измерить истинную внутреннюю температуру.","tr":"Termometre çubuğu, gerçek iç sıcaklığı okumak için kemikten, yağdan veya kaptan uzakta, gıdanın en kalın kısmına yerleştirilmelidir.","hi":"थर्मामीटर का तना भोजन के सबसे मोटे हिस्से में, हड्डी, वसा, या कंटेनर से दूर रखा जाना चाहिए, ताकि सही आंतरिक तापमान पढ़ा जा सके।","ar":"ينبغي وضع ساق ميزان الحرارة في أكثف جزء من الطعام، بعيداً عن العظم أو الدهن أو الحاوية، لقراءة درجة الحرارة الداخلية الحقيقية."}},{"cat":"temp","a":1,"q":{"en":"Which of the following is a TCS (potentially hazardous) food that requires time and temperature control for safety?","es":"¿Cuál de los siguientes es un alimento TCS (potencialmente peligroso) que requiere control de tiempo y temperatura para su seguridad?","ru":"Что из перечисленного является TCS-продуктом (потенциально опасным продуктом), требующим контроля времени и температуры для безопасности?","tr":"Aşağıdakilerden hangisi, güvenlik için zaman ve sıcaklık kontrolü gerektiren bir TCS (potansiyel olarak tehlikeli) gıdadır?","hi":"इनमें से कौन सा एक TCS (संभावित रूप से खतरनाक) भोजन है जिसे सुरक्षा के लिए समय और तापमान नियंत्रण की आवश्यकता होती है?","ar":"أيٌّ مما يلي يُعدّ طعاماً من نوع TCS (يُحتمل أن يكون خطراً) يتطلب التحكم في الوقت ودرجة الحرارة للسلامة؟"},"o":[{"en":"Dry white rice","es":"Arroz blanco seco","ru":"Сухой белый рис","tr":"Kuru beyaz pirinç","hi":"सूखा सफेद चावल","ar":"الأرز الأبيض الجاف"},{"en":"Cut cantaloupe","es":"Melón cantalupo cortado","ru":"Нарезанная дыня канталупа","tr":"Kesilmiş kavun (cantaloupe)","hi":"कटा हुआ खरबूजा (कैंटालूप)","ar":"شمام مقطَّع"},{"en":"Whole raw onions","es":"Cebollas crudas enteras","ru":"Цельный сырой лук","tr":"Bütün çiğ soğan","hi":"साबुत कच्चे प्याज","ar":"بصل نيء كامل"},{"en":"Plain saltine crackers","es":"Galletas saladas tipo saltine simples","ru":"Простые крекеры (солёное печенье)","tr":"Sade tuzlu kraker","hi":"सादे साल्टीन क्रैकर्स","ar":"مقرمشات سالتين عادية"}],"e":{"en":"Cut melons such as cantaloupe are TCS foods because their moisture and neutral pH support rapid bacterial growth once cut.","es":"Los melones cortados, como el cantalupo, son alimentos TCS porque su humedad y su pH neutro favorecen el crecimiento bacteriano rápido una vez cortados.","ru":"Нарезанные дыни, такие как канталупа, являются TCS-продуктами, поскольку их влажность и нейтральный pH поддерживают быстрый рост бактерий после нарезки.","tr":"Kavun gibi kesilmiş kavunlar, kesildikten sonra nem ve nötr pH değerleri hızlı bakteriyel üremeyi desteklediğinden TCS gıdalardır.","hi":"कैंटालूप जैसे कटे हुए खरबूजे TCS भोजन हैं क्योंकि उनकी नमी और तटस्थ pH कटने के बाद तेज़ी से बैक्टीरिया वृद्धि का समर्थन करते हैं।","ar":"يُعدّ الشمام المقطَّع كالكنتالوب طعاماً من نوع TCS لأن رطوبته ودرجة حموضته المتعادلة (pH) تدعمان النمو البكتيري السريع بمجرد تقطيعه."}},{"cat":"temp","a":2,"q":{"en":"If TCS food is held using time alone as a control (no temperature control) starting at 41°F or below, it must be served or discarded within:","es":"Si un alimento TCS se mantiene usando solo el tiempo como control (sin control de temperatura) comenzando a 41°F o menos, debe servirse o desecharse dentro de:","ru":"Если TCS-продукт хранится с использованием только времени в качестве контроля (без контроля температуры) начиная с 41°F или ниже, он должен быть подан или выброшен в течение:","tr":"TCS gıda, 41°F veya altında başlayarak yalnızca zaman kontrol olarak kullanılarak (sıcaklık kontrolü olmadan) tutuluyorsa, ne kadar süre içinde servis edilmeli veya atılmalıdır?","hi":"यदि TCS भोजन को केवल समय को नियंत्रण के रूप में उपयोग करते हुए (कोई तापमान नियंत्रण नहीं) 41°F या उससे नीचे शुरू करते हुए रखा जाता है, तो इसे इसके भीतर परोसा या फेंका जाना चाहिए:","ar":"إذا حُفظ طعام TCS باستخدام الوقت وحده كوسيلة تحكم (دون التحكم في درجة الحرارة) بدءاً من 41°F أو أقل، فيجب تقديمه أو التخلص منه في غضون:"},"o":[{"en":"2 hours","es":"2 horas","ru":"2 hours","tr":"2 saat","hi":"2 घंटे","ar":"2 hours"},{"en":"4 hours","es":"4 horas","ru":"4 hours","tr":"4 saat","hi":"4 घंटे","ar":"4 hours"},{"en":"6 hours","es":"6 horas","ru":"6 hours","tr":"6 saat","hi":"6 घंटे","ar":"6 hours"},{"en":"8 hours","es":"8 horas","ru":"8 hours","tr":"8 saat","hi":"8 घंटे","ar":"8 hours"}],"e":{"en":"Cold TCS food held under the time-as-a-public-health-control method may be kept up to 6 hours if it starts at 41°F or below and does not exceed 70°F, after which it must be discarded.","es":"El alimento TCS frío mantenido bajo el método del tiempo como control de salud pública puede conservarse hasta 6 horas si comienza a 41°F o menos y no excede los 70°F, tras lo cual debe desecharse.","ru":"Холодный TCS-продукт, хранимый по методу «время как мера общественного здоровья», может храниться до 6 часов, если он начинается с 41°F или ниже и не превышает 70°F, после чего он должен быть выброшен.","tr":"Zaman-halk sağlığı kontrolü yöntemiyle tutulan soğuk TCS gıda, 41°F veya altında başlıyor ve 70°F'yi aşmıyorsa 6 saate kadar tutulabilir; bu süreden sonra atılmalıdır.","hi":"समय-को-जन-स्वास्थ्य-नियंत्रण-के-रूप-में विधि के तहत रखे गए ठंडे TCS भोजन को 6 घंटे तक रखा जा सकता है यदि यह 41°F या उससे नीचे शुरू होता है और 70°F से अधिक नहीं होता है, उसके बाद इसे फेंक देना चाहिए।","ar":"يمكن الاحتفاظ بطعام TCS البارد المحفوظ بطريقة الوقت كوسيلة تحكم في الصحة العامة حتى 6 hours إذا بدأ عند 41°F أو أقل ولم يتجاوز 70°F، وبعدها يجب التخلص منه."}},{"cat":"crosscontam","a":1,"q":{"en":"What does cross-contamination mean in a food service operation?","es":"¿Qué significa la contaminación cruzada en una operación de servicio de alimentos?","ru":"Что означает перекрёстное загрязнение в работе предприятия общественного питания?","tr":"Bir gıda servisi işletmesinde çapraz bulaşma ne anlama gelir?","hi":"फूड सर्विस ऑपरेशन में क्रॉस-कॉन्टैमिनेशन का क्या अर्थ है?","ar":"ماذا يعني التلوث المتبادل في عملية خدمة الطعام؟"},"o":[{"en":"Cooking a food to the wrong internal temperature","es":"Cocinar un alimento a la temperatura interna incorrecta","ru":"Приготовление продукта до неправильной внутренней температуры","tr":"Bir gıdayı yanlış iç sıcaklığa pişirmek","hi":"भोजन को गलत आंतरिक तापमान तक पकाना","ar":"طهي طعام إلى درجة حرارة داخلية خاطئة"},{"en":"The transfer of harmful microorganisms or substances from one surface or food to another","es":"La transferencia de microorganismos o sustancias dañinas de una superficie o alimento a otro","ru":"Перенос вредных микроорганизмов или веществ с одной поверхности или продукта на другой","tr":"Zararlı mikroorganizmaların veya maddelerin bir yüzeyden ya da gıdadan diğerine geçmesi","hi":"हानिकारक सूक्ष्मजीवों या पदार्थों का एक सतह या भोजन से दूसरे में स्थानांतरण","ar":"انتقال الكائنات الدقيقة الضارة أو المواد الضارة من سطح أو طعام إلى آخر"},{"en":"Storing food past its expiration date","es":"Almacenar alimentos pasada su fecha de vencimiento","ru":"Хранение продукта по истечении срока годности","tr":"Gıdayı son kullanma tarihinden sonra saklamak","hi":"भोजन को उसकी समाप्ति तिथि के बाद संग्रहीत करना","ar":"تخزين الطعام بعد تاريخ انتهاء صلاحيته"},{"en":"Leaving food in the temperature danger zone too long","es":"Dejar el alimento demasiado tiempo en la zona de temperatura de peligro","ru":"Слишком долгое нахождение продукта в опасной температурной зоне","tr":"Gıdayı tehlikeli sıcaklık bölgesinde çok uzun süre bırakmak","hi":"भोजन को खतरनाक तापमान क्षेत्र में बहुत देर तक छोड़ना","ar":"ترك الطعام في منطقة الخطر الحرارية لمدة طويلة جداً"}],"e":{"en":"Cross-contamination is the transfer of pathogens, allergens, or other harmful substances from one food, surface, or person to another.","es":"La contaminación cruzada es la transferencia de patógenos, alérgenos u otras sustancias dañinas de un alimento, superficie o persona a otro.","ru":"Перекрёстное загрязнение — это перенос патогенов, аллергенов или других вредных веществ с одного продукта, поверхности или человека на другой.","tr":"Çapraz bulaşma, patojenlerin, alerjenlerin veya diğer zararlı maddelerin bir gıdadan, yüzeyden ya da kişiden diğerine geçmesidir.","hi":"क्रॉस-कॉन्टैमिनेशन रोगजनकों, एलर्जन, या अन्य हानिकारक पदार्थों का एक भोजन, सतह, या व्यक्ति से दूसरे में स्थानांतरण है।","ar":"التلوث المتبادل هو انتقال مسببات الأمراض أو مسببات الحساسية أو غيرها من المواد الضارة من طعام أو سطح أو شخص إلى آخر."}},{"cat":"crosscontam","a":2,"q":{"en":"When storing raw chicken and a tray of fresh salad greens in the same refrigerator, where should each be placed?","es":"Al almacenar pollo crudo y una bandeja de hojas frescas para ensalada en el mismo refrigerador, ¿dónde debe colocarse cada uno?","ru":"При хранении сырой курицы и подноса со свежей зеленью для салата в одном холодильнике где следует размещать каждый продукт?","tr":"Çiğ tavuk ile bir tepsi taze salata yeşilliğini aynı buzdolabında saklarken, her biri nereye yerleştirilmelidir?","hi":"कच्चे चिकन और ताज़ी सलाद पत्तियों की एक ट्रे को एक ही रेफ्रिजरेटर में संग्रहीत करते समय, प्रत्येक को कहां रखा जाना चाहिए?","ar":"عند تخزين دجاج نيء وصينية من أوراق سلطة طازجة في الثلاجة نفسها، أين ينبغي وضع كلٍّ منهما؟"},"o":[{"en":"Salad greens on a lower shelf and raw chicken on a higher shelf","es":"Las hojas para ensalada en un estante más bajo y el pollo crudo en un estante más alto","ru":"Зелень для салата на нижней полке, а сырую курицу на верхней","tr":"Salata yeşillikleri alt rafa, çiğ tavuk üst rafa","hi":"सलाद पत्तियां निचली शेल्फ पर और कच्चा चिकन ऊंची शेल्फ पर","ar":"أوراق السلطة على رف أسفل والدجاج النيء على رف أعلى"},{"en":"Both items on the same shelf as long as they are wrapped","es":"Ambos artículos en el mismo estante siempre que estén envueltos","ru":"Оба продукта на одной полке, если они упакованы","tr":"Sarılı oldukları sürece her ikisi de aynı rafa","hi":"दोनों वस्तुएं एक ही शेल्फ पर जब तक वे लपेटी हुई हों","ar":"كلا الصنفين على الرف نفسه ما داما مغلَّفين"},{"en":"Raw chicken on a lower shelf and salad greens on a higher shelf","es":"El pollo crudo en un estante más bajo y las hojas para ensalada en un estante más alto","ru":"Сырую курицу на нижней полке, а зелень для салата на верхней","tr":"Çiğ tavuk alt rafa, salata yeşillikleri üst rafa","hi":"कच्चा चिकन निचली शेल्फ पर और सलाद पत्तियां ऊंची शेल्फ पर","ar":"الدجاج النيء على رف أسفل وأوراق السلطة على رف أعلى"},{"en":"Raw chicken in the door and salad greens in the back","es":"El pollo crudo en la puerta y las hojas para ensalada al fondo","ru":"Сырую курицу в дверце, а зелень для салата в глубине","tr":"Çiğ tavuk kapağa, salata yeşillikleri arkaya","hi":"कच्चा चिकन दरवाज़े में और सलाद पत्तियां पीछे","ar":"الدجاج النيء في الباب وأوراق السلطة في الخلف"}],"e":{"en":"Ready-to-eat foods like salad greens are stored above raw meats so that juices from the raw chicken cannot drip onto and contaminate them.","es":"Los alimentos listos para comer, como las hojas para ensalada, se almacenan por encima de las carnes crudas para que los jugos del pollo crudo no puedan gotear sobre ellos y contaminarlos.","ru":"Готовые к употреблению продукты, такие как зелень для салата, хранятся выше сырого мяса, чтобы соки от сырой курицы не могли капать на них и загрязнять их.","tr":"Salata yeşillikleri gibi yemeye hazır gıdalar, çiğ tavuğun sularının üzerlerine damlayıp onları kirletememesi için çiğ etlerin üzerinde saklanır.","hi":"सलाद पत्तियों जैसे खाने के लिए तैयार भोजन को कच्चे मांस के ऊपर संग्रहीत किया जाता है ताकि कच्चे चिकन का रस उन पर टपक कर उन्हें दूषित न कर सके।","ar":"تُخزَّن الأطعمة الجاهزة للأكل كأوراق السلطة فوق اللحوم النيئة بحيث لا يمكن لعصارة الدجاج النيء أن تقطر عليها وتلوثها."}},{"cat":"crosscontam","a":1,"q":{"en":"In a cooler holding several raw products, which item should be stored on the BOTTOM shelf?","es":"En una cámara de refrigeración que contiene varios productos crudos, ¿qué artículo debe almacenarse en el estante INFERIOR?","ru":"В холодильной камере, где хранятся несколько сырых продуктов, какой продукт следует хранить на НИЖНЕЙ полке?","tr":"Birkaç çiğ ürün bulunan bir soğutucuda, hangi ürün EN ALT rafta saklanmalıdır?","hi":"कई कच्चे उत्पादों को रखने वाले एक कूलर में, किस वस्तु को सबसे निचली (BOTTOM) शेल्फ पर संग्रहीत किया जाना चाहिए?","ar":"في مبرّد يحفظ عدة منتجات نيئة، أيُّ صنف ينبغي تخزينه على الرف السفلي؟"},"o":[{"en":"Raw whole-muscle beef steaks","es":"Filetes de res de músculo entero crudos","ru":"Сырые цельномышечные говяжьи стейки","tr":"Bütün kas dokulu çiğ sığır bifteği","hi":"कच्चे साबुत-मांसपेशी बीफ स्टेक","ar":"شرائح لحم بقري كاملة العضل"},{"en":"Raw poultry","es":"Aves crudas","ru":"Сырую птицу","tr":"Çiğ kümes hayvanı (tavuk vb.)","hi":"कच्ची पोल्ट्री","ar":"دواجن نيئة"},{"en":"Raw fish","es":"Pescado crudo","ru":"Сырую рыбу","tr":"Çiğ balık","hi":"कच्ची मछली","ar":"سمك نيء"},{"en":"Raw ground beef","es":"Carne molida de res cruda","ru":"Сырой говяжий фарш","tr":"Çiğ kıyma sığır eti","hi":"कच्चा कीमा बीफ","ar":"لحم بقري مفروم نيء"}],"e":{"en":"Raw poultry has the highest minimum internal cooking temperature (165°F), so it is stored on the bottom to prevent its juices from dripping onto foods cooked to lower temperatures.","es":"Las aves crudas tienen la temperatura interna mínima de cocción más alta (165°F), por lo que se almacenan en la parte inferior para evitar que sus jugos goteen sobre alimentos que se cocinan a temperaturas más bajas.","ru":"Сырая птица имеет самую высокую минимальную внутреннюю температуру приготовления (165°F), поэтому она хранится внизу, чтобы её соки не капали на продукты, готовящиеся при более низких температурах.","tr":"Çiğ kümes hayvanları en yüksek minimum iç pişirme sıcaklığına (165°F) sahiptir, bu yüzden sularının daha düşük sıcaklıklarda pişirilen gıdaların üzerine damlamasını önlemek için en alta yerleştirilir.","hi":"कच्ची पोल्ट्री का सबसे ऊंचा न्यूनतम आंतरिक खाना पकाने का तापमान (165°F) होता है, इसलिए इसे सबसे नीचे संग्रहीत किया जाता है ताकि इसका रस कम तापमान पर पकाए जाने वाले भोजन पर न टपके।","ar":"للدواجن النيئة أعلى حد أدنى من درجة حرارة الطهي الداخلية (165°F)، لذا تُخزَّن في الأسفل لمنع عصارتها من القطر على الأطعمة التي تُطهى عند درجات حرارة أقل."}},{"cat":"crosscontam","a":1,"q":{"en":"Listing from the TOP shelf down, what is the correct top-to-bottom storage order based on minimum cooking temperature?","es":"Enumerando desde el estante SUPERIOR hacia abajo, ¿cuál es el orden de almacenamiento correcto de arriba hacia abajo según la temperatura mínima de cocción?","ru":"Перечисляя от ВЕРХНЕЙ полки вниз, каков правильный порядок хранения сверху вниз на основе минимальной температуры приготовления?","tr":"En ÜST raftan aşağıya doğru sıralandığında, minimum pişirme sıcaklığına göre doğru üstten alta saklama sırası nedir?","hi":"सबसे ऊपरी (TOP) शेल्फ से नीचे की ओर सूचीबद्ध करते हुए, न्यूनतम खाना पकाने के तापमान के आधार पर ऊपर-से-नीचे संग्रहण का सही क्रम क्या है?","ar":"بدءاً من الرف العلوي نزولاً، ما الترتيب الصحيح للتخزين من الأعلى إلى الأسفل بناءً على الحد الأدنى لدرجة حرارة الطهي؟"},"o":[{"en":"Poultry; ground meat; whole beef and pork; seafood; ready-to-eat food","es":"Aves; carne molida; res y cerdo enteros; mariscos; alimentos listos para comer","ru":"Птица; фарш; цельная говядина и свинина; морепродукты; готовые к употреблению продукты","tr":"Kümes hayvanı; kıyma et; bütün sığır ve domuz; deniz ürünleri; yemeye hazır gıda","hi":"पोल्ट्री; कीमा मांस; साबुत बीफ और पोर्क; सीफूड; खाने के लिए तैयार भोजन","ar":"الدواجن؛ اللحم المفروم؛ اللحم البقري ولحم الخنزير الكاملان؛ المأكولات البحرية؛ الطعام الجاهز للأكل"},{"en":"Ready-to-eat food; seafood; whole beef and pork; ground meat; poultry","es":"Alimentos listos para comer; mariscos; res y cerdo enteros; carne molida; aves","ru":"Готовые к употреблению продукты; морепродукты; цельная говядина и свинина; фарш; птица","tr":"Yemeye hazır gıda; deniz ürünleri; bütün sığır ve domuz; kıyma et; kümes hayvanı","hi":"खाने के लिए तैयार भोजन; सीफूड; साबुत बीफ और पोर्क; कीमा मांस; पोल्ट्री","ar":"الطعام الجاهز للأكل؛ المأكولات البحرية؛ اللحم البقري ولحم الخنزير الكاملان؛ اللحم المفروم؛ الدواجن"},{"en":"Ready-to-eat food; poultry; ground meat; whole beef and pork; seafood","es":"Alimentos listos para comer; aves; carne molida; res y cerdo enteros; mariscos","ru":"Готовые к употреблению продукты; птица; фарш; цельная говядина и свинина; морепродукты","tr":"Yemeye hazır gıda; kümes hayvanı; kıyma et; bütün sığır ve domuz; deniz ürünleri","hi":"खाने के लिए तैयार भोजन; पोल्ट्री; कीमा मांस; साबुत बीफ और पोर्क; सीफूड","ar":"الطعام الجاهز للأكل؛ الدواجن؛ اللحم المفروم؛ اللحم البقري ولحم الخنزير الكاملان؛ المأكولات البحرية"},{"en":"Seafood; ready-to-eat food; whole beef and pork; ground meat; poultry","es":"Mariscos; alimentos listos para comer; res y cerdo enteros; carne molida; aves","ru":"Морепродукты; готовые к употреблению продукты; цельная говядина и свинина; фарш; птица","tr":"Deniz ürünleri; yemeye hazır gıda; bütün sığır ve domuz; kıyma et; kümes hayvanı","hi":"सीफूड; खाने के लिए तैयार भोजन; साबुत बीफ और पोर्क; कीमा मांस; पोल्ट्री","ar":"المأكولات البحرية؛ الطعام الجاهز للأكل؛ اللحم البقري ولحم الخنزير الكاملان؛ اللحم المفروم؛ الدواجن"}],"e":{"en":"Foods are stacked by minimum cooking temperature: ready-to-eat on top, then seafood (145°F), whole cuts of beef/pork (145°F), ground meat (155°F), and poultry (165°F) on the bottom.","es":"Los alimentos se apilan según la temperatura mínima de cocción: los listos para comer arriba, luego los mariscos (145°F), los cortes enteros de res/cerdo (145°F), la carne molida (155°F) y las aves (165°F) en la parte inferior.","ru":"Продукты складываются по минимальной температуре приготовления: готовые к употреблению наверху, затем морепродукты (145°F), цельные куски говядины/свинины (145°F), фарш (155°F) и птица (165°F) внизу.","tr":"Gıdalar minimum pişirme sıcaklığına göre istiflenir: en üstte yemeye hazır gıda, ardından deniz ürünleri (145°F), bütün parça sığır/domuz (145°F), kıyma et (155°F) ve en altta kümes hayvanı (165°F).","hi":"भोजन को न्यूनतम खाना पकाने के तापमान के अनुसार रखा जाता है: खाने के लिए तैयार सबसे ऊपर, फिर सीफूड (145°F), बीफ/पोर्क के साबुत टुकड़े (145°F), कीमा मांस (155°F), और पोल्ट्री (165°F) सबसे नीचे।","ar":"تُرتَّب الأطعمة حسب الحد الأدنى لدرجة حرارة الطهي: الطعام الجاهز للأكل في الأعلى، ثم المأكولات البحرية (145°F)، فالقطع الكاملة من اللحم البقري/الخنزير (145°F)، فاللحم المفروم (155°F)، والدواجن (165°F) في الأسفل."}},{"cat":"crosscontam","a":0,"q":{"en":"A cook uses the same cutting board for raw chicken and then for slicing fresh tomatoes without any steps in between. What did the cook fail to do?","es":"Un cocinero usa la misma tabla de cortar para pollo crudo y luego para rebanar tomates frescos sin ningún paso intermedio. ¿Qué dejó de hacer el cocinero?","ru":"Повар использует одну и ту же разделочную доску для сырой курицы, а затем для нарезки свежих помидоров без каких-либо действий между этими операциями. Что повар не сделал?","tr":"Bir aşçı, aynı kesme tahtasını önce çiğ tavuk için kullanır ve ardından arada hiçbir adım atmadan taze domates dilimlemek için kullanır. Aşçı neyi yapmayı ihmal etmiştir?","hi":"एक रसोइया कच्चे चिकन के लिए और फिर बीच में कोई कदम उठाए बिना ताज़े टमाटर काटने के लिए एक ही कटिंग बोर्ड का उपयोग करता है। रसोइया क्या करने में विफल रहा?","ar":"يستخدم طاهٍ لوح التقطيع نفسه للدجاج النيء ثم لتقطيع طماطم طازجة دون أي خطوات بينهما. ماذا أغفل الطاهي فعله؟"},"o":[{"en":"Wash, rinse, and sanitize the cutting board between tasks","es":"Lavar, enjuagar y desinfectar la tabla de cortar entre tareas","ru":"Не вымыл, не ополоснул и не продезинфицировал разделочную доску между операциями","tr":"Görevler arasında kesme tahtasını yıkamayı, durulamayı ve sanitize etmeyi","hi":"कार्यों के बीच कटिंग बोर्ड को धोना, खंगालना, और सैनिटाइज़ करना","ar":"غسل لوح التقطيع وشطفه وتطهيره بين المهمتين"},{"en":"Wear gloves while cutting the tomatoes","es":"Usar guantes mientras cortaba los tomates","ru":"Не надел перчатки во время нарезки помидоров","tr":"Domatesleri keserken eldiven giymeyi","hi":"टमाटर काटते समय दस्ताने पहनना","ar":"ارتداء قفازات أثناء تقطيع الطماطم"},{"en":"Chill the tomatoes before cutting them","es":"Enfriar los tomates antes de cortarlos","ru":"Не охладил помидоры перед нарезкой","tr":"Domatesleri kesmeden önce soğutmayı","hi":"टमाटर काटने से पहले उन्हें ठंडा करना","ar":"تبريد الطماطم قبل تقطيعها"},{"en":"Use a sharper knife for the tomatoes","es":"Usar un cuchillo más afilado para los tomates","ru":"Не использовал более острый нож для помидоров","tr":"Domatesler için daha keskin bir bıçak kullanmayı","hi":"टमाटर के लिए एक तेज़ चाकू का उपयोग करना","ar":"استخدام سكين أحدّ للطماطم"}],"e":{"en":"Equipment and surfaces must be cleaned and sanitized between handling raw animal foods and ready-to-eat foods to prevent cross-contamination.","es":"El equipo y las superficies deben limpiarse y desinfectarse entre la manipulación de alimentos de origen animal crudos y los alimentos listos para comer para evitar la contaminación cruzada.","ru":"Оборудование и поверхности должны быть очищены и продезинфицированы между работой с сырыми продуктами животного происхождения и готовыми к употреблению продуктами, чтобы предотвратить перекрёстное загрязнение.","tr":"Çapraz bulaşmayı önlemek için ekipman ve yüzeyler, çiğ hayvansal gıdaları ve yemeye hazır gıdaları işleme arasında temizlenip sanitize edilmelidir.","hi":"क्रॉस-कॉन्टैमिनेशन रोकने के लिए कच्चे पशु भोजन और खाने के लिए तैयार भोजन को संभालने के बीच उपकरणों और सतहों को साफ और सैनिटाइज़ किया जाना चाहिए।","ar":"يجب تنظيف المعدات والأسطح وتطهيرها بين التعامل مع الأطعمة الحيوانية النيئة والأطعمة الجاهزة للأكل لمنع التلوث المتبادل."}},{"cat":"crosscontam","a":3,"q":{"en":"Why do many kitchens use color-coded cutting boards (for example, red, green, and yellow)?","es":"¿Por qué muchas cocinas usan tablas de cortar codificadas por colores (por ejemplo, roja, verde y amarilla)?","ru":"Почему многие кухни используют разделочные доски с цветовой маркировкой (например, красные, зелёные и жёлтые)?","tr":"Birçok mutfak neden renk kodlu kesme tahtaları (örneğin kırmızı, yeşil ve sarı) kullanır?","hi":"कई रसोई रंग-कोडित कटिंग बोर्ड (उदाहरण के लिए, लाल, हरा, और पीला) का उपयोग क्यों करती हैं?","ar":"لماذا تستخدم العديد من المطابخ ألواح تقطيع مرمَّزة بالألوان (مثل الأحمر والأخضر والأصفر)؟"},"o":[{"en":"To make the kitchen look more organized for inspectors","es":"Para que la cocina se vea más organizada ante los inspectores","ru":"Чтобы кухня выглядела более организованной для инспекторов","tr":"Mutfağı denetçilere daha düzenli göstermek için","hi":"रसोई को निरीक्षकों के लिए अधिक व्यवस्थित दिखाने के लिए","ar":"لجعل المطبخ يبدو أكثر تنظيماً أمام المفتشين"},{"en":"To match boards to specific chefs on the line","es":"Para asignar las tablas a chefs específicos en la línea","ru":"Чтобы закрепить доски за конкретными поварами на линии","tr":"Tahtaları hattaki belirli aşçılarla eşleştirmek için","hi":"लाइन पर विशिष्ट शेफ से बोर्ड का मिलान करने के लिए","ar":"لمطابقة الألواح مع طهاة محددين على خط العمل"},{"en":"To indicate which boards have been sanitized most recently","es":"Para indicar qué tablas se han desinfectado más recientemente","ru":"Чтобы указать, какие доски были продезинфицированы последними","tr":"Hangi tahtaların en son sanitize edildiğini göstermek için","hi":"यह इंगित करने के लिए कि किन बोर्डों को सबसे हाल ही में सैनिटाइज़ किया गया है","ar":"للإشارة إلى الألواح التي تم تطهيرها مؤخراً"},{"en":"To dedicate specific boards to specific food types and reduce cross-contamination","es":"Para dedicar tablas específicas a tipos de alimentos específicos y reducir la contaminación cruzada","ru":"Чтобы выделить определённые доски для определённых видов продуктов и снизить перекрёстное загрязнение","tr":"Belirli tahtaları belirli gıda türlerine ayırmak ve çapraz bulaşmayı azaltmak için","hi":"विशिष्ट बोर्डों को विशिष्ट भोजन प्रकारों के लिए समर्पित करने और क्रॉस-कॉन्टैमिनेशन कम करने के लिए","ar":"لتخصيص ألواح محددة لأنواع طعام محددة وتقليل التلوث المتبادل"}],"e":{"en":"Color-coding assigns boards to particular food categories (such as raw poultry or produce) so the same surface is not used across food types that could cross-contaminate.","es":"La codificación por colores asigna las tablas a categorías de alimentos específicas (como aves crudas o productos agrícolas) para que la misma superficie no se use entre tipos de alimentos que podrían contaminarse de forma cruzada.","ru":"Цветовая маркировка закрепляет доски за конкретными категориями продуктов (такими как сырая птица или овощи), чтобы одна и та же поверхность не использовалась для разных видов продуктов, которые могли бы вызвать перекрёстное загрязнение.","tr":"Renk kodlaması, tahtaları belirli gıda kategorilerine (çiğ kümes hayvanı veya sebze gibi) atar, böylece aynı yüzey çapraz bulaşmaya yol açabilecek gıda türleri arasında kullanılmaz.","hi":"रंग-कोडिंग बोर्डों को विशेष भोजन श्रेणियों (जैसे कच्ची पोल्ट्री या उपज) को सौंपती है ताकि एक ही सतह का उपयोग उन भोजन प्रकारों में न किया जाए जो क्रॉस-कॉन्टैमिनेट कर सकते हैं।","ar":"يخصص الترميز اللوني الألواحَ لفئات طعام معينة (كالدواجن النيئة أو المنتجات الطازجة) بحيث لا يُستخدم السطح نفسه عبر أنواع طعام قد تتسبب في التلوث المتبادل."}},{"cat":"crosscontam","a":0,"q":{"en":"Which list correctly names all nine major food allergens (the \"Big 9\") recognized in the United States?","es":"¿Qué lista nombra correctamente los nueve principales alérgenos alimentarios (los \"9 grandes\" / Big 9) reconocidos en los Estados Unidos?","ru":"В каком списке правильно названы все девять основных пищевых аллергенов («Большая девятка», Big 9), признанных в Соединённых Штатах?","tr":"Hangi liste, Amerika Birleşik Devletleri'nde tanınan dokuz büyük gıda alerjeninin (\"Büyük 9\") tamamını doğru şekilde adlandırır?","hi":"कौन सी सूची संयुक्त राज्य अमेरिका में मान्यता प्राप्त सभी नौ प्रमुख खाद्य एलर्जन (\"Big 9\") को सही ढंग से नाम देती है?","ar":"أيُّ قائمة تُسمّي بشكل صحيح جميع مسببات الحساسية الغذائية الرئيسية التسعة (\"التسعة الكبار\" Big 9) المُعتَرَف بها في الولايات المتحدة؟"},"o":[{"en":"Milk, eggs, fish, crustacean shellfish, tree nuts, peanuts, wheat, soybeans, sesame","es":"Leche, huevos, pescado, mariscos crustáceos, frutos secos de árbol, maní (cacahuates), trigo, soya, sésamo (ajonjolí)","ru":"Молоко, яйца, рыба, ракообразные, древесные орехи, арахис, пшеница, соя, кунжут","tr":"Süt, yumurta, balık, kabuklu deniz hayvanları (crustacean), ağaç kuruyemişleri, yer fıstığı, buğday, soya fasulyesi, susam","hi":"दूध, अंडे, मछली, क्रस्टेशियन शेलफिश, ट्री नट्स, मूंगफली, गेहूं, सोयाबीन, तिल","ar":"الحليب، البيض، السمك، القشريات، المكسرات الشجرية، الفول السوداني، القمح، فول الصويا، السمسم"},{"en":"Milk, eggs, fish, crustacean shellfish, tree nuts, peanuts, wheat, soybeans, corn","es":"Leche, huevos, pescado, mariscos crustáceos, frutos secos de árbol, maní (cacahuates), trigo, soya, maíz","ru":"Молоко, яйца, рыба, ракообразные, древесные орехи, арахис, пшеница, соя, кукуруза","tr":"Süt, yumurta, balık, kabuklu deniz hayvanları (crustacean), ağaç kuruyemişleri, yer fıstığı, buğday, soya fasulyesi, mısır","hi":"दूध, अंडे, मछली, क्रस्टेशियन शेलफिश, ट्री नट्स, मूंगफली, गेहूं, सोयाबीन, मक्का","ar":"الحليب، البيض، السمك، القشريات، المكسرات الشجرية، الفول السوداني، القمح، فول الصويا، الذرة"},{"en":"Milk, eggs, fish, mollusk shellfish, tree nuts, peanuts, wheat, soybeans, sesame","es":"Leche, huevos, pescado, mariscos moluscos, frutos secos de árbol, maní (cacahuates), trigo, soya, sésamo (ajonjolí)","ru":"Молоко, яйца, рыба, моллюски, древесные орехи, арахис, пшеница, соя, кунжут","tr":"Süt, yumurta, balık, yumuşakça deniz hayvanları (mollusk), ağaç kuruyemişleri, yer fıstığı, buğday, soya fasulyesi, susam","hi":"दूध, अंडे, मछली, मोलस्क शेलफिश, ट्री नट्स, मूंगफली, गेहूं, सोयाबीन, तिल","ar":"الحليب، البيض، السمك، الرخويات، المكسرات الشجرية، الفول السوداني، القمح، فول الصويا، السمسم"},{"en":"Milk, eggs, fish, crustacean shellfish, tree nuts, peanuts, gluten, soybeans, sesame","es":"Leche, huevos, pescado, mariscos crustáceos, frutos secos de árbol, maní (cacahuates), gluten, soya, sésamo (ajonjolí)","ru":"Молоко, яйца, рыба, ракообразные, древесные орехи, арахис, глютен, соя, кунжут","tr":"Süt, yumurta, balık, kabuklu deniz hayvanları (crustacean), ağaç kuruyemişleri, yer fıstığı, glüten, soya fasulyesi, susam","hi":"दूध, अंडे, मछली, क्रस्टेशियन शेलफिश, ट्री नट्स, मूंगफली, ग्लूटेन, सोयाबीन, तिल","ar":"الحليب، البيض، السمك، القشريات، المكسرات الشجرية، الفول السوداني، الغلوتين، فول الصويا، السمسم"}],"e":{"en":"The Big 9 are milk, eggs, fish, crustacean shellfish, tree nuts, peanuts, wheat, soybeans, and sesame; sesame became the ninth major allergen effective January 1, 2023.","es":"Los 9 grandes (Big 9) son leche, huevos, pescado, mariscos crustáceos, frutos secos de árbol, maní (cacahuates), trigo, soya y sésamo (ajonjolí); el sésamo se convirtió en el noveno alérgeno principal a partir del 1 de enero de 2023.","ru":"«Большая девятка» (Big 9) — это молоко, яйца, рыба, ракообразные, древесные орехи, арахис, пшеница, соя и кунжут; кунжут стал девятым основным аллергеном с 1 января 2023 года.","tr":"Büyük 9; süt, yumurta, balık, kabuklu deniz hayvanları (crustacean), ağaç kuruyemişleri, yer fıstığı, buğday, soya fasulyesi ve susamdır; susam, 1 Ocak 2023 itibarıyla dokuzuncu büyük alerjen olmuştur.","hi":"Big 9 हैं दूध, अंडे, मछली, क्रस्टेशियन शेलफिश, ट्री नट्स, मूंगफली, गेहूं, सोयाबीन, और तिल; तिल 1 जनवरी 2023 से प्रभावी नौवां प्रमुख एलर्जन बन गया।","ar":"التسعة الكبار (Big 9) هي: الحليب، والبيض، والسمك، والقشريات، والمكسرات الشجرية، والفول السوداني، والقمح، وفول الصويا، والسمسم؛ وقد أصبح السمسم مسبب الحساسية الرئيسي التاسع اعتباراً من January 1, 2023."}},{"cat":"crosscontam","a":2,"q":{"en":"Which food was added as the ninth major food allergen in the United States, effective January 1, 2023?","es":"¿Qué alimento se agregó como el noveno alérgeno alimentario principal en los Estados Unidos, a partir del 1 de enero de 2023?","ru":"Какой продукт был добавлен как девятый основной пищевой аллерген в Соединённых Штатах, вступивший в силу с 1 января 2023 года?","tr":"Amerika Birleşik Devletleri'nde 1 Ocak 2023 itibarıyla dokuzuncu büyük gıda alerjeni olarak eklenen gıda hangisidir?","hi":"1 जनवरी 2023 से प्रभावी, संयुक्त राज्य अमेरिका में नौवें प्रमुख खाद्य एलर्जन के रूप में कौन सा भोजन जोड़ा गया?","ar":"أيُّ طعام أُضيف بوصفه مسبب الحساسية الغذائية الرئيسي التاسع في الولايات المتحدة، اعتباراً من January 1, 2023؟"},"o":[{"en":"Corn","es":"Maíz","ru":"Кукуруза","tr":"Mısır","hi":"मक्का","ar":"الذرة"},{"en":"Mustard","es":"Mostaza","ru":"Горчица","tr":"Hardal","hi":"सरसों","ar":"الخردل"},{"en":"Sesame","es":"Sésamo (ajonjolí)","ru":"Кунжут","tr":"Susam","hi":"तिल","ar":"السمسم"},{"en":"Celery","es":"Apio","ru":"Сельдерей","tr":"Kereviz","hi":"अजवाइन (सेलरी)","ar":"الكرفس"}],"e":{"en":"Under the FASTER Act, sesame became the ninth major food allergen requiring declaration, effective January 1, 2023.","es":"Bajo la Ley FASTER (FASTER Act), el sésamo (ajonjolí) se convirtió en el noveno alérgeno alimentario principal que requiere declaración, a partir del 1 de enero de 2023.","ru":"Согласно Закону FASTER Act, кунжут стал девятым основным пищевым аллергеном, требующим декларирования, вступившим в силу с 1 января 2023 года.","tr":"FASTER Yasası uyarınca susam, 1 Ocak 2023 itibarıyla beyan edilmesi gereken dokuzuncu büyük gıda alerjeni olmuştur.","hi":"FASTER अधिनियम के तहत, तिल 1 जनवरी 2023 से प्रभावी, घोषणा की आवश्यकता वाला नौवां प्रमुख खाद्य एलर्जन बन गया।","ar":"بموجب قانون FASTER، أصبح السمسم مسبب الحساسية الغذائية الرئيسي التاسع الواجب الإعلان عنه، اعتباراً من January 1, 2023."}},{"cat":"crosscontam","a":1,"q":{"en":"What is allergen cross-contact?","es":"¿Qué es el contacto cruzado con alérgenos?","ru":"Что такое перекрёстный контакт с аллергеном?","tr":"Alerjen çapraz teması nedir?","hi":"एलर्जेन क्रॉस-कॉन्टैक्ट क्या है?","ar":"ما هو التلامس المتبادل لمسببات الحساسية؟"},"o":[{"en":"When an allergen is intentionally added to a recipe as an ingredient","es":"Cuando un alérgeno se agrega intencionalmente a una receta como ingrediente","ru":"Когда аллерген намеренно добавляется в рецепт в качестве ингредиента","tr":"Bir alerjenin tarife bilerek bir malzeme olarak eklenmesi","hi":"जब किसी एलर्जेन को जानबूझकर एक सामग्री के रूप में रेसिपी में मिलाया जाता है","ar":"عندما يُضاف أحد مسببات الحساسية عمداً إلى وصفة كأحد المكونات"},{"en":"When an allergen unintentionally transfers from a food containing it to a food that does not","es":"Cuando un alérgeno se transfiere de forma no intencional de un alimento que lo contiene a un alimento que no lo contiene","ru":"Когда аллерген непреднамеренно переносится из продукта, содержащего его, в продукт, который его не содержит","tr":"Bir alerjenin, onu içeren bir gıdadan içermeyen bir gıdaya istemeden geçmesi","hi":"जब कोई एलर्जेन अनजाने में उसे रखने वाले भोजन से ऐसे भोजन में स्थानांतरित हो जाता है जिसमें वह नहीं होता","ar":"عندما ينتقل أحد مسببات الحساسية بشكل غير مقصود من طعام يحتوي عليه إلى طعام لا يحتوي عليه"},{"en":"When a guest is allergic to more than one food at the same time","es":"Cuando un comensal es alérgico a más de un alimento al mismo tiempo","ru":"Когда у гостя одновременно аллергия более чем на один продукт","tr":"Bir misafirin aynı anda birden fazla gıdaya alerjisinin olması","hi":"जब किसी मेहमान को एक ही समय में एक से अधिक भोजन से एलर्जी होती है","ar":"عندما يكون لدى الضيف حساسية تجاه أكثر من طعام واحد في الوقت نفسه"},{"en":"When two allergens chemically react inside a cooked dish","es":"Cuando dos alérgenos reaccionan químicamente dentro de un platillo cocinado","ru":"Когда два аллергена химически реагируют внутри приготовленного блюда","tr":"İki alerjenin pişmiş bir yemeğin içinde kimyasal olarak tepkimeye girmesi","hi":"जब पके हुए व्यंजन के अंदर दो एलर्जेन रासायनिक रूप से प्रतिक्रिया करते हैं","ar":"عندما يتفاعل مسبّبان للحساسية كيميائياً داخل طبق مطبوخ"}],"e":{"en":"Allergen cross-contact occurs when an allergen is unintentionally transferred to a food that is supposed to be free of that allergen, which can trigger a serious reaction.","es":"El contacto cruzado con alérgenos ocurre cuando un alérgeno se transfiere de forma no intencional a un alimento que se supone debe estar libre de ese alérgeno, lo que puede desencadenar una reacción grave.","ru":"Перекрёстный контакт с аллергеном происходит, когда аллерген непреднамеренно переносится в продукт, который должен быть свободен от этого аллергена, что может вызвать серьёзную реакцию.","tr":"Alerjen çapraz teması, bir alerjenin o alerjeni içermemesi gereken bir gıdaya istemeden geçmesiyle oluşur ve bu durum ciddi bir reaksiyonu tetikleyebilir.","hi":"एलर्जेन क्रॉस-कॉन्टैक्ट तब होता है जब कोई एलर्जेन अनजाने में ऐसे भोजन में स्थानांतरित हो जाता है जिसमें वह एलर्जेन नहीं होना चाहिए, जो एक गंभीर प्रतिक्रिया को ट्रिगर कर सकता है।","ar":"يحدث التلامس المتبادل لمسببات الحساسية عندما ينتقل أحد مسببات الحساسية بشكل غير مقصود إلى طعام يُفترض أن يكون خالياً من ذلك المسبّب، وهو ما قد يُحدث رد فعل تحسسياً خطيراً."}},{"cat":"crosscontam","a":2,"q":{"en":"A guest with a shrimp allergy is served a salad, then notices it contains shrimp. What is the correct response?","es":"A un comensal con alergia al camarón se le sirve una ensalada y luego nota que contiene camarón. ¿Cuál es la respuesta correcta?","ru":"Гостю с аллергией на креветки подали салат, после чего он замечает, что в нём есть креветки. Каким должен быть правильный ответ?","tr":"Karides alerjisi olan bir misafire salata servis ediliyor, ardından misafir salatada karides olduğunu fark ediyor. Doğru tepki nedir?","hi":"झींगा (shrimp) से एलर्जी वाले एक मेहमान को सलाद परोसा जाता है, फिर वह देखता है कि उसमें झींगा है। सही प्रतिक्रिया क्या है?","ar":"يُقدَّم سلطة لضيف لديه حساسية من الجمبري، ثم يلاحظ أنها تحتوي على جمبري. ما هو الإجراء الصحيح؟"},"o":[{"en":"Pick the shrimp off the salad and return the same plate to the guest","es":"Quitar el camarón de la ensalada y devolver el mismo plato al comensal","ru":"Снять креветки с салата и вернуть гостю ту же тарелку","tr":"Karidesleri salatadan ayıklayıp aynı tabağı misafire geri vermek","hi":"सलाद से झींगा निकाल दें और वही प्लेट मेहमान को वापस कर दें","ar":"انتزاع الجمبري من السلطة وإعادة الطبق نفسه إلى الضيف"},{"en":"Add extra dressing to mask any remaining shrimp residue","es":"Agregar más aderezo para enmascarar cualquier residuo de camarón que quede","ru":"Добавить дополнительную заправку, чтобы скрыть оставшиеся следы креветок","tr":"Kalan karides kalıntısını gizlemek için fazladan sos eklemek","hi":"बचे हुए झींगा के अवशेष को छिपाने के लिए अतिरिक्त ड्रेसिंग मिला दें","ar":"إضافة مزيد من الصلصة لإخفاء أي بقايا جمبري متبقية"},{"en":"Prepare a completely new salad with clean utensils and a clean surface","es":"Preparar una ensalada completamente nueva con utensilios limpios y una superficie limpia","ru":"Приготовить совершенно новый салат, используя чистую посуду и чистую поверхность","tr":"Temiz mutfak aletleri ve temiz bir yüzeyle tamamen yeni bir salata hazırlamak","hi":"साफ बर्तनों और साफ सतह के साथ पूरी तरह से एक नया सलाद तैयार करें","ar":"تحضير سلطة جديدة تماماً باستخدام أدوات نظيفة وسطح نظيف"},{"en":"Rinse the shrimp off and re-plate the salad","es":"Enjuagar el camarón y volver a emplatar la ensalada","ru":"Смыть креветки и заново выложить салат на тарелку","tr":"Karidesleri durulayıp salatayı yeniden tabağa koymak","hi":"झींगा को धोकर निकाल दें और सलाद को फिर से प्लेट करें","ar":"شطف الجمبري من السلطة وإعادة تقديمها في الطبق"}],"e":{"en":"Simply removing an allergen from a finished dish does not make it safe, because allergen residue remains; a fresh dish must be made with clean equipment.","es":"Simplemente retirar un alérgeno de un platillo terminado no lo hace seguro, porque queda residuo del alérgeno; se debe preparar un platillo nuevo con equipo limpio.","ru":"Простое удаление аллергена из готового блюда не делает его безопасным, поскольку остаются следы аллергена; необходимо приготовить свежее блюдо с использованием чистого оборудования.","tr":"Bir alerjeni bitmiş bir yemekten sadece çıkarmak onu güvenli hale getirmez, çünkü alerjen kalıntısı kalır; temiz ekipmanla yeni bir yemek yapılmalıdır.","hi":"किसी तैयार व्यंजन से एलर्जेन को केवल हटा देने से वह सुरक्षित नहीं हो जाता, क्योंकि एलर्जेन का अवशेष बना रहता है; साफ उपकरण के साथ एक ताज़ा व्यंजन बनाना चाहिए।","ar":"مجرد إزالة مسبب الحساسية من طبق جاهز لا يجعله آمناً، لأن بقايا المسبب تظل موجودة؛ يجب تحضير طبق جديد باستخدام معدات نظيفة."}},{"cat":"crosscontam","a":0,"q":{"en":"Which practice best helps prevent allergen cross-contact when preparing a meal for a guest with a food allergy?","es":"¿Cuál práctica ayuda mejor a prevenir el contacto cruzado con alérgenos al preparar una comida para un comensal con alergia alimentaria?","ru":"Какая практика лучше всего помогает предотвратить перекрёстный контакт с аллергеном при приготовлении блюда для гостя с пищевой аллергией?","tr":"Gıda alerjisi olan bir misafire yemek hazırlarken alerjen çapraz temasını önlemeye en çok hangi uygulama yardımcı olur?","hi":"किसी खाद्य एलर्जी वाले मेहमान के लिए भोजन तैयार करते समय एलर्जेन क्रॉस-कॉन्टैक्ट को रोकने में कौन सी प्रथा सबसे अधिक मदद करती है?","ar":"أي ممارسة تساعد بشكل أفضل على منع التلامس المتبادل لمسببات الحساسية عند تحضير وجبة لضيف لديه حساسية غذائية؟"},"o":[{"en":"Use freshly cleaned and sanitized equipment and separate, dedicated utensils","es":"Usar equipo recién limpiado y desinfectado, y utensilios separados y exclusivos","ru":"Использовать свежевымытое и продезинфицированное оборудование и отдельную, выделенную посуду","tr":"Yeni temizlenmiş ve dezenfekte edilmiş ekipman ile ayrı, özel mutfak aletleri kullanmak","hi":"ताज़ा साफ किए और सैनिटाइज़ किए गए उपकरण तथा अलग, समर्पित बर्तनों का उपयोग करें","ar":"استخدام معدات نظيفة ومطهَّرة حديثاً وأدوات منفصلة ومخصّصة"},{"en":"Cook the allergen-free meal at a slightly higher temperature","es":"Cocinar la comida libre de alérgenos a una temperatura ligeramente más alta","ru":"Готовить блюдо без аллергена при немного более высокой температуре","tr":"Alerjensiz yemeği biraz daha yüksek sıcaklıkta pişirmek","hi":"एलर्जेन-मुक्त भोजन को थोड़े अधिक तापमान पर पकाएं","ar":"طهي الوجبة الخالية من مسبب الحساسية عند درجة حرارة أعلى قليلاً"},{"en":"Prepare the meal last, after all other orders, on the same surfaces","es":"Preparar la comida al final, después de todos los demás pedidos, en las mismas superficies","ru":"Готовить блюдо последним, после всех остальных заказов, на тех же поверхностях","tr":"Yemeği diğer tüm siparişlerden sonra, en son, aynı yüzeylerde hazırlamak","hi":"भोजन को सबसे आखिर में, सभी अन्य ऑर्डर के बाद, उन्हीं सतहों पर तैयार करें","ar":"تحضير الوجبة في النهاية، بعد جميع الطلبات الأخرى، على الأسطح نفسها"},{"en":"Use the same fryer oil but a new basket","es":"Usar el mismo aceite de la freidora pero una canasta nueva","ru":"Использовать то же масло для фритюра, но новую корзину","tr":"Aynı kızartma yağını ama yeni bir sepet kullanmak","hi":"उसी फ्रायर के तेल का उपयोग करें लेकिन एक नई टोकरी का","ar":"استخدام زيت القلي نفسه لكن مع سلة جديدة"}],"e":{"en":"Cleaning and sanitizing equipment and using separate utensils prevents allergen residue from transferring; shared fryer oil and shared surfaces can still carry allergens.","es":"Limpiar y desinfectar el equipo y usar utensilios separados evita que el residuo del alérgeno se transfiera; el aceite de freidora compartido y las superficies compartidas todavía pueden contener alérgenos.","ru":"Очистка и дезинфекция оборудования, а также использование отдельной посуды предотвращают перенос следов аллергена; общее масло для фритюра и общие поверхности всё равно могут содержать аллергены.","tr":"Ekipmanı temizleyip dezenfekte etmek ve ayrı mutfak aletleri kullanmak alerjen kalıntısının geçmesini önler; ortak kızartma yağı ve ortak yüzeyler hâlâ alerjen taşıyabilir.","hi":"उपकरण को साफ और सैनिटाइज़ करना तथा अलग बर्तनों का उपयोग करना एलर्जेन अवशेष को स्थानांतरित होने से रोकता है; साझा फ्रायर तेल और साझा सतहें फिर भी एलर्जेन ले जा सकती हैं।","ar":"يمنع تنظيف المعدات وتطهيرها واستخدام أدوات منفصلة انتقال بقايا مسبب الحساسية؛ أما زيت القلي المشترك والأسطح المشتركة فقد تظل تحمل مسببات الحساسية."}},{"cat":"crosscontam","a":2,"q":{"en":"Why is clear communication with the guest and kitchen important when handling a food allergy order?","es":"¿Por qué es importante la comunicación clara con el comensal y la cocina al manejar un pedido con alergia alimentaria?","ru":"Почему чёткое общение с гостем и кухней важно при обработке заказа с учётом пищевой аллергии?","tr":"Bir gıda alerjisi siparişini ele alırken misafir ve mutfakla net iletişim neden önemlidir?","hi":"खाद्य एलर्जी वाले ऑर्डर को संभालते समय मेहमान और रसोई के साथ स्पष्ट संवाद क्यों महत्वपूर्ण है?","ar":"لماذا يُعد التواصل الواضح مع الضيف والمطبخ أمراً مهماً عند التعامل مع طلب يتعلق بحساسية غذائية؟"},"o":[{"en":"It allows the kitchen to charge extra for the special order","es":"Permite que la cocina cobre extra por el pedido especial","ru":"Это позволяет кухне взимать дополнительную плату за специальный заказ","tr":"Mutfağın özel sipariş için ekstra ücret almasını sağlar","hi":"यह रसोई को विशेष ऑर्डर के लिए अतिरिक्त शुल्क लेने की अनुमति देता है","ar":"لأنه يتيح للمطبخ فرض رسوم إضافية على الطلب الخاص"},{"en":"It speeds up ticket times during a rush","es":"Acelera los tiempos de los pedidos durante una hora pico","ru":"Это ускоряет время обработки заказов в час пик","tr":"Yoğunluk sırasında sipariş sürelerini hızlandırır","hi":"यह व्यस्त समय के दौरान टिकट का समय तेज़ कर देता है","ar":"لأنه يسرّع أوقات الطلبات أثناء الازدحام"},{"en":"It ensures the allergen is correctly identified and avoided throughout preparation and service","es":"Garantiza que el alérgeno se identifique correctamente y se evite durante toda la preparación y el servicio","ru":"Это гарантирует, что аллерген будет правильно определён и исключён на всех этапах приготовления и подачи","tr":"Alerjenin doğru şekilde tespit edilip hazırlık ve servis boyunca önlenmesini sağlar","hi":"यह सुनिश्चित करता है कि एलर्जेन की सही पहचान हो और तैयारी तथा सर्विस के दौरान उससे बचा जाए","ar":"لأنه يضمن تحديد مسبب الحساسية بشكل صحيح وتجنّبه طوال التحضير والتقديم"},{"en":"It is only necessary when the restaurant serves alcohol","es":"Solo es necesaria cuando el restaurante sirve alcohol","ru":"Это необходимо только тогда, когда в ресторане подают алкоголь","tr":"Yalnızca restoran alkol servis ettiğinde gereklidir","hi":"यह केवल तभी आवश्यक है जब रेस्तरां शराब परोसता है","ar":"لأنه ضروري فقط عندما يقدّم المطعم الكحول"}],"e":{"en":"Accurate communication between the guest, server, and kitchen ensures everyone knows the allergen so it is identified and kept out of the meal at every step.","es":"La comunicación precisa entre el comensal, el mesero y la cocina garantiza que todos conozcan el alérgeno para que se identifique y se mantenga fuera de la comida en cada paso.","ru":"Точное общение между гостем, официантом и кухней гарантирует, что все знают об аллергене, поэтому он определяется и не попадает в блюдо на каждом этапе.","tr":"Misafir, garson ve mutfak arasındaki doğru iletişim, herkesin alerjeni bilmesini, böylece her aşamada tespit edilip yemeğin dışında tutulmasını sağlar.","hi":"मेहमान, सर्वर और रसोई के बीच सटीक संवाद यह सुनिश्चित करता है कि सभी को एलर्जेन के बारे में पता हो ताकि हर चरण पर इसकी पहचान की जाए और इसे भोजन से बाहर रखा जाए।","ar":"يضمن التواصل الدقيق بين الضيف والنادل والمطبخ معرفة الجميع بمسبب الحساسية بحيث يتم تحديده وإبقاؤه خارج الوجبة في كل خطوة."}},{"cat":"crosscontam","a":1,"q":{"en":"Which of the following is an example of PHYSICAL contamination?","es":"¿Cuál de los siguientes es un ejemplo de contaminación FÍSICA?","ru":"Что из перечисленного является примером ФИЗИЧЕСКОГО загрязнения?","tr":"Aşağıdakilerden hangisi FİZİKSEL bulaşmaya bir örnektir?","hi":"निम्नलिखित में से कौन सा भौतिक (PHYSICAL) संदूषण का उदाहरण है?","ar":"أي مما يلي يُعد مثالاً على التلوث الفيزيائي؟"},"o":[{"en":"Salmonella bacteria on raw chicken","es":"Bacterias de Salmonella en pollo crudo","ru":"Бактерии сальмонеллы на сырой курице","tr":"Çiğ tavuktaki Salmonella bakterisi","hi":"कच्चे चिकन पर साल्मोनेला (Salmonella) बैक्टीरिया","ar":"بكتيريا السالمونيلا على الدجاج النيء"},{"en":"A piece of broken glass or metal shaving in a dish","es":"Un trozo de vidrio roto o una viruta de metal en un platillo","ru":"Кусок битого стекла или металлической стружки в блюде","tr":"Bir yemekteki kırık cam parçası veya metal talaşı","hi":"किसी व्यंजन में टूटे हुए कांच का टुकड़ा या धातु की छीलन","ar":"قطعة زجاج مكسور أو رقاقة معدنية في طبق"},{"en":"Cleaning sanitizer sprayed onto food","es":"Desinfectante de limpieza rociado sobre la comida","ru":"Чистящее дезинфицирующее средство, распылённое на еду","tr":"Gıdaya püskürtülen temizlik dezenfektanı","hi":"भोजन पर छिड़का गया सफाई का सैनिटाइज़र","ar":"رشّ مطهِّر التنظيف على الطعام"},{"en":"A norovirus transferred by an ill employee","es":"Un norovirus transferido por un empleado enfermo","ru":"Норовирус, переданный больным сотрудником","tr":"Hasta bir çalışan tarafından geçirilen norovirüs","hi":"किसी बीमार कर्मचारी द्वारा स्थानांतरित नोरोवायरस (norovirus)","ar":"فيروس نوروفيروس ينتقل عن طريق موظف مريض"}],"e":{"en":"Physical contamination involves foreign objects such as glass, metal, bone fragments, or hair getting into food.","es":"La contaminación física implica objetos extraños como vidrio, metal, fragmentos de hueso o cabello que llegan a la comida.","ru":"Физическое загрязнение связано с попаданием в пищу посторонних предметов, таких как стекло, металл, осколки костей или волосы.","tr":"Fiziksel bulaşma, cam, metal, kemik parçaları veya saç gibi yabancı cisimlerin gıdaya karışmasını içerir.","hi":"भौतिक संदूषण में कांच, धातु, हड्डी के टुकड़े या बाल जैसी बाहरी वस्तुओं का भोजन में चले जाना शामिल है।","ar":"يتضمن التلوث الفيزيائي وجود أجسام غريبة مثل الزجاج أو المعدن أو شظايا العظم أو الشعر في الطعام."}},{"cat":"crosscontam","a":2,"q":{"en":"A bottle of degreaser is stored on a shelf directly above a pan of prepared coleslaw, and some drips into the food. This is an example of which type of contamination?","es":"Una botella de desengrasante se almacena en un estante directamente arriba de una bandeja de ensalada de col preparada, y algo gotea dentro de la comida. ¿Esto es un ejemplo de qué tipo de contaminación?","ru":"Бутылка обезжиривателя хранится на полке прямо над лотком с готовым салатом из капусты, и часть средства капает в еду. Это пример какого типа загрязнения?","tr":"Bir şişe yağ çözücü, hazırlanmış lahana salatası tavasının tam üstündeki rafa konuluyor ve bir miktarı gıdaya damlıyor. Bu hangi tür bulaşmaya örnektir?","hi":"डीग्रीज़र की एक बोतल तैयार कोलस्लॉ के पैन के ठीक ऊपर एक शेल्फ पर रखी है, और कुछ भोजन में टपक जाता है। यह किस प्रकार के संदूषण का उदाहरण है?","ar":"تُخزَّن زجاجة مزيل شحوم على رفّ مباشرة فوق صينية سلطة كرنب مُحضَّرة، وتتسرّب بعض منها إلى الطعام. هذا مثال على أي نوع من التلوث؟"},"o":[{"en":"Biological","es":"Biológica","ru":"Биологического","tr":"Biyolojik","hi":"जैविक","ar":"بيولوجي"},{"en":"Physical","es":"Física","ru":"Физического","tr":"Fiziksel","hi":"भौतिक","ar":"فيزيائي"},{"en":"Chemical","es":"Química","ru":"Химического","tr":"Kimyasal","hi":"रासायनिक","ar":"كيميائي"},{"en":"Allergenic","es":"Alérgena","ru":"Аллергенного","tr":"Alerjenik","hi":"एलर्जेनिक","ar":"تحسسي"}],"e":{"en":"Chemical contamination occurs when substances like cleaners, sanitizers, or pesticides get into food; chemicals must be stored below and away from food.","es":"La contaminación química ocurre cuando sustancias como limpiadores, desinfectantes o pesticidas llegan a la comida; los químicos deben almacenarse por debajo y lejos de los alimentos.","ru":"Химическое загрязнение происходит, когда в пищу попадают такие вещества, как чистящие средства, дезинфектанты или пестициды; химикаты следует хранить ниже еды и отдельно от неё.","tr":"Kimyasal bulaşma, temizleyiciler, dezenfektanlar veya böcek ilaçları gibi maddelerin gıdaya karışmasıyla oluşur; kimyasallar gıdanın altında ve uzağında saklanmalıdır.","hi":"रासायनिक संदूषण तब होता है जब क्लीनर, सैनिटाइज़र या कीटनाशक जैसे पदार्थ भोजन में चले जाते हैं; रसायनों को भोजन के नीचे और उससे दूर रखा जाना चाहिए।","ar":"يحدث التلوث الكيميائي عندما تدخل مواد مثل المنظفات أو المطهِّرات أو المبيدات إلى الطعام؛ يجب تخزين المواد الكيميائية أسفل الطعام وبعيداً عنه."}},{"cat":"crosscontam","a":2,"q":{"en":"Bacteria, viruses, parasites, and fungi that contaminate food are categorized as which type of hazard?","es":"Las bacterias, los virus, los parásitos y los hongos que contaminan los alimentos se clasifican como qué tipo de peligro?","ru":"Бактерии, вирусы, паразиты и грибки, загрязняющие пищу, относятся к какому типу опасности?","tr":"Gıdayı kirleten bakteriler, virüsler, parazitler ve mantarlar hangi tehlike türü olarak sınıflandırılır?","hi":"बैक्टीरिया, वायरस, परजीवी और कवक जो भोजन को संदूषित करते हैं, उन्हें किस प्रकार के खतरे के रूप में वर्गीकृत किया जाता है?","ar":"تُصنَّف البكتيريا والفيروسات والطفيليات والفطريات التي تلوّث الطعام ضمن أي نوع من المخاطر؟"},"o":[{"en":"Chemical","es":"Químico","ru":"Химической","tr":"Kimyasal","hi":"रासायनिक","ar":"كيميائي"},{"en":"Physical","es":"Físico","ru":"Физической","tr":"Fiziksel","hi":"भौतिक","ar":"فيزيائي"},{"en":"Biological","es":"Biológico","ru":"Биологической","tr":"Biyolojik","hi":"जैविक","ar":"بيولوجي"},{"en":"Environmental","es":"Ambiental","ru":"Экологической","tr":"Çevresel","hi":"पर्यावरणीय","ar":"بيئي"}],"e":{"en":"Biological hazards are living or organic contaminants such as bacteria, viruses, parasites, and fungi, and they are the most common cause of foodborne illness.","es":"Los peligros biológicos son contaminantes vivos u orgánicos como bacterias, virus, parásitos y hongos, y son la causa más común de enfermedades transmitidas por los alimentos.","ru":"Биологические опасности — это живые или органические загрязнители, такие как бактерии, вирусы, паразиты и грибки, и они являются наиболее частой причиной пищевых заболеваний.","tr":"Biyolojik tehlikeler bakteri, virüs, parazit ve mantar gibi canlı veya organik kirleticilerdir ve gıda kaynaklı hastalıkların en yaygın nedenidir.","hi":"जैविक खतरे जीवित या जैविक संदूषक होते हैं जैसे बैक्टीरिया, वायरस, परजीवी और कवक, और ये खाद्यजनित बीमारी का सबसे आम कारण हैं।","ar":"المخاطر البيولوجية هي ملوثات حية أو عضوية مثل البكتيريا والفيروسات والطفيليات والفطريات، وهي السبب الأكثر شيوعاً للأمراض المنقولة بالغذاء."}},{"cat":"crosscontam","a":1,"q":{"en":"An operation must store raw fish, raw ground pork, and a pan of cooked rice in one cooler with three shelves. Which arrangement is correct from top to bottom?","es":"Una operación debe almacenar pescado crudo, carne molida de cerdo cruda y una bandeja de arroz cocido en un refrigerador con tres estantes. ¿Cuál disposición es correcta de arriba hacia abajo?","ru":"Предприятие должно хранить сырую рыбу, сырой свиной фарш и лоток с варёным рисом в одном холодильнике с тремя полками. Какое расположение правильное сверху вниз?","tr":"Bir işletme, çiğ balığı, çiğ kıyma domuz etini ve bir tava pişmiş pirinci üç raflı bir soğutucuda saklamak zorundadır. Yukarıdan aşağıya doğru hangi düzen doğrudur?","hi":"एक प्रतिष्ठान को कच्ची मछली, कच्चे पिसे हुए सूअर का मांस (pork) और पके हुए चावल का एक पैन तीन शेल्फ वाले एक कूलर में रखना है। ऊपर से नीचे तक कौन सी व्यवस्था सही है?","ar":"على منشأة تخزين سمك نيء ولحم خنزير مفروم نيء وصينية أرز مطبوخ في ثلاجة واحدة بثلاثة أرفف. أي ترتيب صحيح من الأعلى إلى الأسفل؟"},"o":[{"en":"Raw ground pork on top, raw fish in the middle, cooked rice on the bottom","es":"Carne molida de cerdo cruda arriba, pescado crudo en el medio, arroz cocido abajo","ru":"Сырой свиной фарш сверху, сырая рыба посередине, варёный рис снизу","tr":"En üstte çiğ kıyma domuz eti, ortada çiğ balık, en altta pişmiş pirinç","hi":"सबसे ऊपर कच्चा पिसा हुआ सूअर का मांस, बीच में कच्ची मछली, सबसे नीचे पके हुए चावल","ar":"لحم الخنزير المفروم النيء في الأعلى، والسمك النيء في الوسط، والأرز المطبوخ في الأسفل"},{"en":"Cooked rice on top, raw fish in the middle, raw ground pork on the bottom","es":"Arroz cocido arriba, pescado crudo en el medio, carne molida de cerdo cruda abajo","ru":"Варёный рис сверху, сырая рыба посередине, сырой свиной фарш снизу","tr":"En üstte pişmiş pirinç, ortada çiğ balık, en altta çiğ kıyma domuz eti","hi":"सबसे ऊपर पके हुए चावल, बीच में कच्ची मछली, सबसे नीचे कच्चा पिसा हुआ सूअर का मांस","ar":"الأرز المطبوخ في الأعلى، والسمك النيء في الوسط، ولحم الخنزير المفروم النيء في الأسفل"},{"en":"Raw fish on top, cooked rice in the middle, raw ground pork on the bottom","es":"Pescado crudo arriba, arroz cocido en el medio, carne molida de cerdo cruda abajo","ru":"Сырая рыба сверху, варёный рис посередине, сырой свиной фарш снизу","tr":"En üstte çiğ balık, ortada pişmiş pirinç, en altta çiğ kıyma domuz eti","hi":"सबसे ऊपर कच्ची मछली, बीच में पके हुए चावल, सबसे नीचे कच्चा पिसा हुआ सूअर का मांस","ar":"السمك النيء في الأعلى، والأرز المطبوخ في الوسط، ولحم الخنزير المفروم النيء في الأسفل"},{"en":"Cooked rice on top, raw ground pork in the middle, raw fish on the bottom","es":"Arroz cocido arriba, carne molida de cerdo cruda en el medio, pescado crudo abajo","ru":"Варёный рис сверху, сырой свиной фарш посередине, сырая рыба снизу","tr":"En üstte pişmiş pirinç, ortada çiğ kıyma domuz eti, en altta çiğ balık","hi":"सबसे ऊपर पके हुए चावल, बीच में कच्चा पिसा हुआ सूअर का मांस, सबसे नीचे कच्ची मछली","ar":"الأرز المطبوخ في الأعلى، ولحم الخنزير المفروم النيء في الوسط، والسمك النيء في الأسفل"}],"e":{"en":"Ready-to-eat cooked rice goes on top, then raw fish (145°F), and raw ground pork (155°F) on the bottom because it has the higher minimum cooking temperature.","es":"El arroz cocido listo para comer va arriba, luego el pescado crudo (145°F), y la carne molida de cerdo cruda (155°F) abajo porque tiene la temperatura mínima de cocción más alta.","ru":"Готовый к употреблению варёный рис размещается сверху, затем сырая рыба (145°F), а сырой свиной фарш (155°F) снизу, поскольку у него более высокая минимальная температура приготовления.","tr":"Yemeye hazır pişmiş pirinç en üste, ardından çiğ balık (145°F) gelir ve çiğ kıyma domuz eti (155°F) daha yüksek asgari pişirme sıcaklığına sahip olduğu için en alta konur.","hi":"खाने के लिए तैयार पके हुए चावल सबसे ऊपर जाते हैं, फिर कच्ची मछली (145°F), और कच्चा पिसा हुआ सूअर का मांस (155°F) सबसे नीचे क्योंकि इसका न्यूनतम पकाने का तापमान अधिक होता है।","ar":"يوضع الأرز المطبوخ الجاهز للأكل في الأعلى، ثم السمك النيء (145°F)، ولحم الخنزير المفروم النيء (155°F) في الأسفل لأنه يتطلب درجة حرارة طهي دنيا أعلى."}},{"cat":"illness","a":2,"q":{"en":"What does the acronym FAT TOM stand for in food safety?","es":"¿Qué significa el acrónimo FAT TOM en la seguridad alimentaria?","ru":"Что означает акроним FAT TOM в области пищевой безопасности?","tr":"Gıda güvenliğinde FAT TOM kısaltması neyi ifade eder?","hi":"खाद्य सुरक्षा में FAT TOM संक्षिप्त नाम किसका प्रतिनिधित्व करता है?","ar":"ماذا يرمز اختصار FAT TOM في سلامة الغذاء؟"},"o":[{"en":"Freshness, Air, Temperature, Toxins, Oxygen, Metals","es":"Frescura, Aire, Temperatura, Toxinas, Oxígeno, Metales","ru":"Свежесть, Воздух, Температура, Токсины, Кислород, Металлы","tr":"Tazelik, Hava, Sıcaklık, Toksinler, Oksijen, Metaller","hi":"Freshness, Air, Temperature, Toxins, Oxygen, Metals","ar":"Freshness، Air، Temperature، Toxins، Oxygen، Metals"},{"en":"Fat, Allergens, Texture, Taste, Odor, Microbes","es":"Grasa, Alérgenos, Textura, Sabor, Olor, Microbios","ru":"Жир, Аллергены, Текстура, Вкус, Запах, Микробы","tr":"Yağ, Alerjenler, Doku, Tat, Koku, Mikroplar","hi":"Fat, Allergens, Texture, Taste, Odor, Microbes","ar":"Fat، Allergens، Texture، Taste، Odor، Microbes"},{"en":"Food, Acidity, Temperature, Time, Oxygen, Moisture","es":"Alimento (Food), Acidez, Temperatura (Temperature), Tiempo (Time), Oxígeno, Humedad (Moisture)","ru":"Пища, Кислотность, Температура, Время, Кислород, Влажность","tr":"Gıda, Asitlik, Sıcaklık, Zaman, Oksijen, Nem","hi":"Food, Acidity, Temperature, Time, Oxygen, Moisture","ar":"Food، Acidity، Temperature، Time، Oxygen، Moisture"},{"en":"Food, Allergens, Time, Toxins, Oxygen, Moisture","es":"Alimento, Alérgenos, Tiempo, Toxinas, Oxígeno, Humedad","ru":"Пища, Аллергены, Время, Токсины, Кислород, Влажность","tr":"Gıda, Alerjenler, Zaman, Toksinler, Oksijen, Nem","hi":"Food, Allergens, Time, Toxins, Oxygen, Moisture","ar":"Food، Allergens، Time، Toxins، Oxygen، Moisture"}],"e":{"en":"FAT TOM names the six conditions bacteria need to grow: Food, Acidity, Temperature, Time, Oxygen, and Moisture.","es":"FAT TOM nombra las seis condiciones que las bacterias necesitan para crecer: Alimento (Food), Acidez, Temperatura (Temperature), Tiempo (Time), Oxígeno y Humedad (Moisture).","ru":"FAT TOM называет шесть условий, необходимых бактериям для роста: Пища (Food), Кислотность (Acidity), Температура (Temperature), Время (Time), Кислород (Oxygen) и Влажность (Moisture).","tr":"FAT TOM, bakterilerin büyümesi için ihtiyaç duyduğu altı koşulu adlandırır: Gıda (Food), Asitlik (Acidity), Sıcaklık (Temperature), Zaman (Time), Oksijen (Oxygen) ve Nem (Moisture).","hi":"FAT TOM उन छह स्थितियों के नाम बताता है जिनकी बैक्टीरिया को बढ़ने के लिए आवश्यकता होती है: Food, Acidity, Temperature, Time, Oxygen, और Moisture।","ar":"يُسمّي FAT TOM الظروف الستة التي تحتاجها البكتيريا للنمو: الغذاء (Food)، والحموضة (Acidity)، ودرجة الحرارة (Temperature)، والوقت (Time)، والأكسجين (Oxygen)، والرطوبة (Moisture)."}},{"cat":"illness","a":2,"q":{"en":"A food employee tells the person-in-charge they are vomiting at home. According to the FDA Food Code, what is the correct action?","es":"Un empleado de alimentos le dice a la persona a cargo que está vomitando en casa. Según el Código de Alimentos de la FDA, ¿cuál es la acción correcta?","ru":"Сотрудник, работающий с пищей, сообщает ответственному лицу, что у него рвота дома. Согласно Пищевому кодексу FDA, каким должно быть правильное действие?","tr":"Bir gıda çalışanı, sorumlu kişiye evde kustuğunu söylüyor. FDA Gıda Yönetmeliği'ne göre doğru eylem nedir?","hi":"एक खाद्य कर्मचारी प्रभारी व्यक्ति (person-in-charge) को बताता है कि वह घर पर उल्टी कर रहा है। FDA Food Code के अनुसार, सही कार्रवाई क्या है?","ar":"يُخبر موظف غذاء المسؤول المباشر بأنه يتقيأ في المنزل. وفقاً لمدوّنة الغذاء الصادرة عن FDA، ما هو الإجراء الصحيح؟"},"o":[{"en":"Allow them to work as long as they wear gloves","es":"Permitirle trabajar siempre que use guantes","ru":"Разрешить ему работать, если он надевает перчатки","tr":"Eldiven taktığı sürece çalışmasına izin vermek","hi":"जब तक वह दस्ताने पहनता है तब तक उसे काम करने दें","ar":"السماح له بالعمل ما دام يرتدي قفازات"},{"en":"Send them to prep raw meat only, away from ready-to-eat food","es":"Enviarlo a preparar solo carne cruda, lejos de los alimentos listos para comer","ru":"Отправить его готовить только сырое мясо, вдали от готовых к употреблению продуктов","tr":"Onu yemeye hazır gıdadan uzakta yalnızca çiğ et hazırlamaya yönlendirmek","hi":"उसे केवल कच्चा मांस तैयार करने भेजें, खाने के लिए तैयार भोजन से दूर","ar":"إرساله لتحضير اللحوم النيئة فقط، بعيداً عن الطعام الجاهز للأكل"},{"en":"Exclude or restrict them from handling food until cleared","es":"Excluirlo o restringirlo de manipular alimentos hasta que sea autorizado","ru":"Отстранить или ограничить его от работы с пищей до получения разрешения","tr":"İyileştiği onaylanana kadar gıdayla teması engellemek veya kısıtlamak","hi":"उसे तब तक भोजन संभालने से बाहर रखें या प्रतिबंधित करें जब तक उसे मंज़ूरी न मिल जाए","ar":"استبعاده أو تقييده من التعامل مع الطعام حتى يُسمح له بالعودة"},{"en":"Let them work but assign them to dishwashing","es":"Dejarlo trabajar pero asignarlo a lavar platos","ru":"Разрешить ему работать, но поручить мытьё посуды","tr":"Çalışmasına izin verip ona bulaşık yıkamayı görevlendirmek","hi":"उसे काम करने दें लेकिन बर्तन धोने का काम सौंपें","ar":"السماح له بالعمل مع تكليفه بغسل الأطباق"}],"e":{"en":"Vomiting is a reportable symptom; the person-in-charge must exclude or restrict the employee to prevent spreading foodborne illness.","es":"El vómito es un síntoma que debe reportarse; la persona a cargo debe excluir o restringir al empleado para evitar la propagación de enfermedades transmitidas por los alimentos.","ru":"Рвота — это симптом, подлежащий обязательному сообщению; ответственное лицо должно отстранить или ограничить сотрудника, чтобы предотвратить распространение пищевого заболевания.","tr":"Kusma bildirilmesi gereken bir belirtidir; sorumlu kişi, gıda kaynaklı hastalığın yayılmasını önlemek için çalışanın teması engellemeli veya kısıtlamalıdır.","hi":"उल्टी एक रिपोर्ट करने योग्य लक्षण है; प्रभारी व्यक्ति को खाद्यजनित बीमारी फैलने से रोकने के लिए कर्मचारी को बाहर रखना या प्रतिबंधित करना चाहिए।","ar":"التقيؤ عَرَض يجب الإبلاغ عنه؛ على المسؤول المباشر استبعاد الموظف أو تقييده لمنع انتشار المرض المنقول بالغذاء."}},{"cat":"illness","a":1,"q":{"en":"Which group is NOT considered a highly susceptible population for foodborne illness?","es":"¿Cuál grupo NO se considera una población altamente susceptible a las enfermedades transmitidas por los alimentos?","ru":"Какая группа НЕ считается группой повышенного риска по пищевым заболеваниям?","tr":"Hangi grup gıda kaynaklı hastalık için yüksek riskli bir nüfus olarak KABUL EDİLMEZ?","hi":"कौन सा समूह खाद्यजनित बीमारी के लिए अत्यधिक संवेदनशील आबादी नहीं माना जाता है?","ar":"أي فئة لا تُعتبر من السكان شديدي القابلية للإصابة بالأمراض المنقولة بالغذاء؟"},"o":[{"en":"Young children","es":"Niños pequeños","ru":"Маленькие дети","tr":"Küçük çocuklar","hi":"छोटे बच्चे","ar":"الأطفال الصغار"},{"en":"Healthy adults in their 20s","es":"Adultos sanos de veintitantos años","ru":"Здоровые взрослые в возрасте около 20 лет","tr":"20'li yaşlarındaki sağlıklı yetişkinler","hi":"अपने 20 के दशक में स्वस्थ वयस्क","ar":"البالغون الأصحّاء في العشرينيات من العمر"},{"en":"Pregnant women","es":"Mujeres embarazadas","ru":"Беременные женщины","tr":"Hamile kadınlar","hi":"गर्भवती महिलाएं","ar":"النساء الحوامل"},{"en":"People with weakened immune systems","es":"Personas con sistemas inmunitarios debilitados","ru":"Люди с ослабленным иммунитетом","tr":"Bağışıklık sistemi zayıflamış kişiler","hi":"कमज़ोर प्रतिरक्षा प्रणाली वाले लोग","ar":"الأشخاص ذوو المناعة الضعيفة"}],"e":{"en":"Highly susceptible populations are the young, old, pregnant, and immunocompromised (YOPI); healthy young adults are not included.","es":"Las poblaciones altamente susceptibles son los jóvenes, los adultos mayores, las embarazadas y las personas inmunocomprometidas (YOPI); los adultos jóvenes y sanos no están incluidos.","ru":"Группы повышенного риска — это дети, пожилые люди, беременные и люди с ослабленным иммунитетом (YOPI); здоровые молодые взрослые в них не входят.","tr":"Yüksek riskli nüfuslar küçükler, yaşlılar, hamileler ve bağışıklığı baskılanmış kişilerdir (YOPI); sağlıklı genç yetişkinler buna dahil değildir.","hi":"अत्यधिक संवेदनशील आबादी में छोटे, बुज़ुर्ग, गर्भवती और प्रतिरक्षा-समझौता वाले लोग (YOPI) शामिल हैं; स्वस्थ युवा वयस्क इसमें शामिल नहीं हैं।","ar":"السكان شديدو القابلية للإصابة هم الصغار وكبار السن والحوامل وضعاف المناعة (YOPI)؛ ولا يشمل ذلك البالغين الأصحّاء صغار السن."}},{"cat":"illness","a":0,"q":{"en":"Which of the following is an example of a physical hazard in food?","es":"¿Cuál de los siguientes es un ejemplo de un peligro físico en los alimentos?","ru":"Что из перечисленного является примером физической опасности в пище?","tr":"Aşağıdakilerden hangisi gıdada fiziksel bir tehlikeye örnektir?","hi":"निम्नलिखित में से कौन सा भोजन में भौतिक खतरे का उदाहरण है?","ar":"أي مما يلي يُعد مثالاً على خطر فيزيائي في الطعام؟"},"o":[{"en":"A piece of broken glass","es":"Un trozo de vidrio roto","ru":"Кусок битого стекла","tr":"Bir kırık cam parçası","hi":"टूटे हुए कांच का एक टुकड़ा","ar":"قطعة زجاج مكسور"},{"en":"Salmonella bacteria","es":"Bacterias de Salmonella","ru":"Бактерии сальмонеллы","tr":"Salmonella bakterisi","hi":"साल्मोनेला (Salmonella) बैक्टीरिया","ar":"بكتيريا السالمونيلا"},{"en":"A cleaning sanitizer residue","es":"Un residuo de desinfectante de limpieza","ru":"Остатки чистящего дезинфицирующего средства","tr":"Bir temizlik dezenfektanı kalıntısı","hi":"एक सफाई सैनिटाइज़र अवशेष","ar":"بقايا مطهِّر تنظيف"},{"en":"Norovirus particles","es":"Partículas de norovirus","ru":"Частицы норовируса","tr":"Norovirüs partikülleri","hi":"नोरोवायरस (norovirus) के कण","ar":"جزيئات فيروس نوروفيروس"}],"e":{"en":"Physical hazards are foreign objects such as glass, metal, or bone; bacteria and viruses are biological and sanitizer is chemical.","es":"Los peligros físicos son objetos extraños como vidrio, metal o hueso; las bacterias y los virus son biológicos y el desinfectante es químico.","ru":"Физические опасности — это посторонние предметы, такие как стекло, металл или кость; бактерии и вирусы являются биологическими, а дезинфицирующее средство — химическим.","tr":"Fiziksel tehlikeler cam, metal veya kemik gibi yabancı cisimlerdir; bakteri ve virüsler biyolojik, dezenfektan ise kimyasaldır.","hi":"भौतिक खतरे बाहरी वस्तुएं होती हैं जैसे कांच, धातु या हड्डी; बैक्टीरिया और वायरस जैविक होते हैं और सैनिटाइज़र रासायनिक होता है।","ar":"المخاطر الفيزيائية هي أجسام غريبة مثل الزجاج أو المعدن أو العظم؛ أما البكتيريا والفيروسات فبيولوجية والمطهِّر كيميائي."}},{"cat":"illness","a":3,"q":{"en":"Which symptom is most commonly associated with Hepatitis A infection and must be reported to the person-in-charge?","es":"¿Qué síntoma se asocia más comúnmente con la infección por Hepatitis A y debe reportarse a la persona a cargo?","ru":"Какой симптом наиболее часто связан с инфекцией гепатита А и должен быть сообщён ответственному лицу?","tr":"Hepatit A enfeksiyonuyla en yaygın olarak ilişkilendirilen ve sorumlu kişiye bildirilmesi gereken belirti hangisidir?","hi":"कौन सा लक्षण हेपेटाइटिस A (Hepatitis A) संक्रमण से सबसे आम तौर पर जुड़ा है और जिसे प्रभारी व्यक्ति को रिपोर्ट किया जाना चाहिए?","ar":"أي عَرَض يرتبط بشكل أكثر شيوعاً بعدوى التهاب الكبد A (Hepatitis A) ويجب الإبلاغ عنه للمسؤول المباشر؟"},"o":[{"en":"Itchy skin rash","es":"Erupción cutánea con picazón","ru":"Зудящая кожная сыпь","tr":"Kaşıntılı cilt döküntüsü","hi":"खुजली वाला त्वचा पर चकत्ता","ar":"طفح جلدي مثير للحكة"},{"en":"A runny nose","es":"Secreción nasal","ru":"Насморк","tr":"Burun akıntısı","hi":"बहती नाक","ar":"سيلان الأنف"},{"en":"Muscle cramps in the legs","es":"Calambres musculares en las piernas","ru":"Мышечные судороги в ногах","tr":"Bacaklarda kas krampları","hi":"पैरों में मांसपेशियों की ऐंठन","ar":"تشنجات عضلية في الساقين"},{"en":"Jaundice (yellowing of the skin or eyes)","es":"Ictericia (coloración amarillenta de la piel o los ojos)","ru":"Желтуха (пожелтение кожи или глаз)","tr":"Sarılık (cildin veya gözlerin sararması)","hi":"पीलिया (त्वचा या आंखों का पीला होना)","ar":"اليرقان (اصفرار الجلد أو العينين)"}],"e":{"en":"Hepatitis A commonly causes jaundice, and any food employee who is jaundiced must be reported and excluded under the Food Code.","es":"La Hepatitis A comúnmente causa ictericia, y cualquier empleado de alimentos que tenga ictericia debe ser reportado y excluido según el Código de Alimentos.","ru":"Гепатит А часто вызывает желтуху, и о любом сотруднике с желтухой необходимо сообщить и отстранить его согласно Пищевому кодексу.","tr":"Hepatit A yaygın olarak sarılığa neden olur ve sarılığı olan herhangi bir gıda çalışanı Gıda Yönetmeliği uyarınca bildirilmeli ve gıdayla teması engellenmelidir.","hi":"हेपेटाइटिस A आमतौर पर पीलिया का कारण बनता है, और किसी भी खाद्य कर्मचारी को जिसे पीलिया हो, उसे Food Code के तहत रिपोर्ट किया जाना चाहिए और बाहर रखा जाना चाहिए।","ar":"يسبب التهاب الكبد A عادةً اليرقان، وأي موظف غذاء مصاب باليرقان يجب الإبلاغ عنه واستبعاده بموجب مدوّنة الغذاء."}},{"cat":"illness","a":2,"q":{"en":"Which of these pathogens is one of the 'Big 6' highly contagious reportable pathogens?","es":"¿Cuál de estos patógenos es uno de los patógenos altamente contagiosos y de declaración obligatoria de los 'Seis Grandes' (Big 6)?","ru":"Какой из этих патогенов входит в «Большую шестёрку» (Big 6) высокозаразных патогенов, подлежащих обязательному сообщению?","tr":"Bu patojenlerden hangisi 'Büyük 6' yüksek bulaşıcı, bildirilmesi gereken patojenlerden biridir?","hi":"इनमें से कौन सा रोगजनक 'Big 6' अत्यधिक संक्रामक रिपोर्ट करने योग्य रोगजनकों में से एक है?","ar":"أي من مسببات الأمراض التالية يُعد من 'الستة الكبار' (Big 6) شديدي العدوى الواجب الإبلاغ عنهم؟"},"o":[{"en":"Staphylococcus aureus","es":"Staphylococcus aureus","ru":"Золотистый стафилококк (Staphylococcus aureus)","tr":"Staphylococcus aureus","hi":"स्टैफिलोकोकस ऑरियस (Staphylococcus aureus)","ar":"المكورات العنقودية الذهبية (Staphylococcus aureus)"},{"en":"Clostridium botulinum","es":"Clostridium botulinum","ru":"Клостридия ботулизма (Clostridium botulinum)","tr":"Clostridium botulinum","hi":"क्लोस्ट्रिडियम बोटुलिनम (Clostridium botulinum)","ar":"المطثية الوشيقية (Clostridium botulinum)"},{"en":"Norovirus","es":"Norovirus","ru":"Норовирус","tr":"Norovirüs","hi":"नोरोवायरस (Norovirus)","ar":"فيروس نوروفيروس (Norovirus)"},{"en":"Bacillus cereus","es":"Bacillus cereus","ru":"Бацилла цереус (Bacillus cereus)","tr":"Bacillus cereus","hi":"बैसिलस सीरियस (Bacillus cereus)","ar":"العصوية الشمعية (Bacillus cereus)"}],"e":{"en":"The Big 6 are Norovirus, Hepatitis A, Shigella, STEC, Salmonella Typhi, and nontyphoidal Salmonella.","es":"Los Seis Grandes (Big 6) son Norovirus, Hepatitis A, Shigella, STEC, Salmonella Typhi y Salmonella no tifoidea.","ru":"В «Большую шестёрку» (Big 6) входят норовирус, гепатит А, шигелла, STEC, Salmonella Typhi и нетифоидная сальмонелла.","tr":"Büyük 6; Norovirüs, Hepatit A, Shigella, STEC, Salmonella Typhi ve tifo dışı Salmonella'dır.","hi":"Big 6 हैं Norovirus, Hepatitis A, Shigella, STEC, Salmonella Typhi, और नॉनटाइफॉइडल Salmonella।","ar":"الستة الكبار هم نوروفيروس (Norovirus)، والتهاب الكبد A (Hepatitis A)، والشيغيلا (Shigella)، وE. coli المنتجة لسم شيغا (STEC)، والسالمونيلا التيفية (Salmonella Typhi)، والسالمونيلا غير التيفية."}},{"cat":"illness","a":3,"q":{"en":"Within FAT TOM, what is the Temperature Danger Zone in which bacteria grow most rapidly?","es":"Dentro de FAT TOM, ¿cuál es la Zona de Peligro de Temperatura en la que las bacterias crecen más rápidamente?","ru":"В рамках FAT TOM, что такое опасная температурная зона, в которой бактерии растут наиболее быстро?","tr":"FAT TOM içinde, bakterilerin en hızlı büyüdüğü Tehlikeli Sıcaklık Bölgesi nedir?","hi":"FAT TOM के भीतर, खतरनाक तापमान क्षेत्र (Temperature Danger Zone) क्या है जिसमें बैक्टीरिया सबसे तेज़ी से बढ़ते हैं?","ar":"ضمن FAT TOM، ما هي منطقة الخطر الحرارية التي تنمو فيها البكتيريا بأسرع ما يمكن؟"},"o":[{"en":"32°F to 41°F (0°C to 5°C)","es":"32°F a 41°F (0°C a 5°C)","ru":"От 32°F до 41°F (от 0°C до 5°C)","tr":"32°F ile 41°F arası (0°C ile 5°C)","hi":"32°F से 41°F (0°C से 5°C)","ar":"32°F to 41°F (0°C to 5°C)"},{"en":"0°F to 32°F (-18°C to 0°C)","es":"0°F a 32°F (-18°C a 0°C)","ru":"От 0°F до 32°F (от -18°C до 0°C)","tr":"0°F ile 32°F arası (-18°C ile 0°C)","hi":"0°F से 32°F (-18°C से 0°C)","ar":"0°F to 32°F (-18°C to 0°C)"},{"en":"135°F to 212°F (57°C to 100°C)","es":"135°F a 212°F (57°C a 100°C)","ru":"От 135°F до 212°F (от 57°C до 100°C)","tr":"135°F ile 212°F arası (57°C ile 100°C)","hi":"135°F से 212°F (57°C से 100°C)","ar":"135°F to 212°F (57°C to 100°C)"},{"en":"41°F to 135°F (5°C to 57°C)","es":"41°F a 135°F (5°C a 57°C)","ru":"От 41°F до 135°F (от 5°C до 57°C)","tr":"41°F ile 135°F arası (5°C ile 57°C)","hi":"41°F से 135°F (5°C से 57°C)","ar":"41°F to 135°F (5°C to 57°C)"}],"e":{"en":"The temperature danger zone is 41°F to 135°F, where foodborne pathogens multiply most quickly.","es":"La zona de peligro de temperatura es de 41°F a 135°F, donde los patógenos transmitidos por los alimentos se multiplican más rápidamente.","ru":"Опасная температурная зона — это от 41°F до 135°F, где пищевые патогены размножаются быстрее всего.","tr":"Tehlikeli sıcaklık bölgesi 41°F ile 135°F arasıdır ve gıda kaynaklı patojenlerin en hızlı çoğaldığı aralıktır.","hi":"खतरनाक तापमान क्षेत्र 41°F से 135°F है, जहां खाद्यजनित रोगजनक सबसे तेज़ी से गुणा करते हैं।","ar":"منطقة الخطر الحرارية هي 41°F to 135°F، حيث تتكاثر مسببات الأمراض المنقولة بالغذاء بأسرع ما يمكن."}},{"cat":"illness","a":3,"q":{"en":"Which foodborne pathogen is most strongly linked to undercooked ground beef and can cause bloody diarrhea?","es":"¿Cuál patógeno transmitido por los alimentos está más fuertemente vinculado a la carne molida de res poco cocida y puede causar diarrea con sangre?","ru":"Какой пищевой патоген наиболее тесно связан с недостаточно прожаренным говяжьим фаршем и может вызывать кровавую диарею?","tr":"Hangi gıda kaynaklı patojen, az pişmiş kıyma dana eti ile en güçlü şekilde bağlantılıdır ve kanlı ishale neden olabilir?","hi":"कौन सा खाद्यजनित रोगजनक अधपके पिसे हुए गोमांस (ground beef) से सबसे मज़बूती से जुड़ा है और खूनी दस्त का कारण बन सकता है?","ar":"أي من مسببات الأمراض المنقولة بالغذاء يرتبط بأقوى صورة باللحم البقري المفروم غير المطهو جيداً ويمكن أن يسبب إسهالاً دموياً؟"},"o":[{"en":"Salmonella Typhi","es":"Salmonella Typhi","ru":"Salmonella Typhi","tr":"Salmonella Typhi","hi":"साल्मोनेला टाइफी (Salmonella Typhi)","ar":"السالمونيلا التيفية (Salmonella Typhi)"},{"en":"Norovirus","es":"Norovirus","ru":"Норовирус","tr":"Norovirüs","hi":"नोरोवायरस (Norovirus)","ar":"فيروس نوروفيروس (Norovirus)"},{"en":"Hepatitis A","es":"Hepatitis A","ru":"Гепатит А","tr":"Hepatit A","hi":"हेपेटाइटिस A (Hepatitis A)","ar":"التهاب الكبد A (Hepatitis A)"},{"en":"Shiga toxin-producing E. coli (STEC)","es":"E. coli productora de toxina Shiga (STEC)","ru":"Шига-токсин-продуцирующая кишечная палочка (STEC)","tr":"Shiga toksini üreten E. coli (STEC)","hi":"शिगा टॉक्सिन-उत्पादक E. coli (STEC)","ar":"E. coli المنتجة لسم شيغا (STEC)"}],"e":{"en":"STEC is classically associated with undercooked ground beef and can cause severe, often bloody, diarrhea.","es":"La STEC se asocia clásicamente con la carne molida de res poco cocida y puede causar diarrea grave, a menudo con sangre.","ru":"STEC классически ассоциируется с недостаточно прожаренным говяжьим фаршем и может вызывать тяжёлую, часто кровавую диарею.","tr":"STEC klasik olarak az pişmiş kıyma dana eti ile ilişkilendirilir ve şiddetli, çoğu zaman kanlı ishale neden olabilir.","hi":"STEC पारंपरिक रूप से अधपके पिसे हुए गोमांस से जुड़ा है और गंभीर, अक्सर खूनी, दस्त का कारण बन सकता है।","ar":"ترتبط STEC تقليدياً باللحم البقري المفروم غير المطهو جيداً ويمكن أن تسبب إسهالاً شديداً، غالباً ما يكون دموياً."}},{"cat":"illness","a":1,"q":{"en":"Which of the following is one of the five main risk factors for foodborne illness identified by the CDC and FDA?","es":"¿Cuál de los siguientes es uno de los cinco factores de riesgo principales de enfermedades transmitidas por los alimentos identificados por los CDC y la FDA?","ru":"Что из перечисленного является одним из пяти основных факторов риска пищевых заболеваний, определённых CDC и FDA?","tr":"Aşağıdakilerden hangisi CDC ve FDA tarafından belirlenen gıda kaynaklı hastalığın beş ana risk faktöründen biridir?","hi":"निम्नलिखित में से कौन सा CDC और FDA द्वारा पहचाने गए खाद्यजनित बीमारी के पांच मुख्य जोखिम कारकों में से एक है?","ar":"أي مما يلي يُعد أحد عوامل الخطر الرئيسية الخمسة للأمراض المنقولة بالغذاء التي حدّدتها CDC وFDA؟"},"o":[{"en":"Serving food on white plates","es":"Servir la comida en platos blancos","ru":"Подача еды на белых тарелках","tr":"Yemeği beyaz tabaklarda servis etmek","hi":"सफेद प्लेटों में भोजन परोसना","ar":"تقديم الطعام في أطباق بيضاء"},{"en":"Poor personal hygiene","es":"Higiene personal deficiente","ru":"Плохая личная гигиена","tr":"Kötü kişisel hijyen","hi":"खराब व्यक्तिगत स्वच्छता","ar":"النظافة الشخصية السيئة"},{"en":"Using stainless steel work tables","es":"Usar mesas de trabajo de acero inoxidable","ru":"Использование рабочих столов из нержавеющей стали","tr":"Paslanmaz çelik çalışma tezgâhları kullanmak","hi":"स्टेनलेस स्टील के वर्क टेबल का उपयोग करना","ar":"استخدام طاولات عمل من الفولاذ المقاوم للصدأ"},{"en":"Storing dry goods on shelves","es":"Almacenar productos secos en estantes","ru":"Хранение сухих продуктов на полках","tr":"Kuru gıdaları raflarda saklamak","hi":"सूखे सामान को शेल्फ पर रखना","ar":"تخزين السلع الجافة على الأرفف"}],"e":{"en":"The CDC/FDA name poor personal hygiene, time-temperature abuse, cross-contamination, contaminated equipment, and unsafe sources as the top risk factors.","es":"Los CDC/FDA nombran la higiene personal deficiente, el abuso de tiempo y temperatura, la contaminación cruzada, el equipo contaminado y las fuentes no seguras como los principales factores de riesgo.","ru":"CDC/FDA называют плохую личную гигиену, нарушение режима времени и температуры, перекрёстное загрязнение, загрязнённое оборудование и небезопасные источники главными факторами риска.","tr":"CDC/FDA, en önemli risk faktörleri olarak kötü kişisel hijyen, zaman-sıcaklık ihlali, çapraz bulaşma, kirli ekipman ve güvenli olmayan kaynakları belirtir.","hi":"CDC/FDA खराब व्यक्तिगत स्वच्छता, समय-तापमान दुरुपयोग, क्रॉस-कॉन्टैमिनेशन, संदूषित उपकरण, और असुरक्षित स्रोतों को शीर्ष जोखिम कारकों के रूप में नाम देते हैं।","ar":"تحدّد CDC/FDA النظافة الشخصية السيئة، وإساءة استخدام الوقت ودرجة الحرارة، والتلوث المتبادل، والمعدات الملوثة، والمصادر غير الآمنة بوصفها أبرز عوامل الخطر."}},{"cat":"illness","a":1,"q":{"en":"Norovirus and Hepatitis A are most often spread to food through which route?","es":"El Norovirus y la Hepatitis A se propagan más a menudo a los alimentos a través de qué vía?","ru":"Норовирус и гепатит А чаще всего попадают в пищу каким путём?","tr":"Norovirüs ve Hepatit A en sık hangi yolla gıdaya yayılır?","hi":"नोरोवायरस और हेपेटाइटिस A सबसे अधिक बार किस मार्ग से भोजन में फैलते हैं?","ar":"ينتقل فيروس نوروفيروس والتهاب الكبد A إلى الطعام في الغالب عبر أي مسار؟"},"o":[{"en":"Cooking food at too high a temperature","es":"Cocinar los alimentos a una temperatura demasiado alta","ru":"При приготовлении пищи при слишком высокой температуре","tr":"Gıdayı çok yüksek sıcaklıkta pişirerek","hi":"भोजन को बहुत अधिक तापमान पर पकाना","ar":"طهي الطعام عند درجة حرارة مرتفعة جداً"},{"en":"The fecal-oral route from an infected food handler's unwashed hands","es":"La vía fecal-oral desde las manos sin lavar de un manipulador de alimentos infectado","ru":"Фекально-оральным путём с немытых рук инфицированного работника пищевой сферы","tr":"Enfekte bir gıda çalışanının yıkanmamış ellerinden fekal-oral yolla","hi":"संक्रमित खाद्य संचालक के बिना धोए हाथों से मल-मौखिक (fecal-oral) मार्ग","ar":"المسار البرازي الفموي من يدي متداول طعام مصاب غير مغسولتين"},{"en":"Storing food in metal containers","es":"Almacenar los alimentos en recipientes metálicos","ru":"При хранении пищи в металлических контейнерах","tr":"Gıdayı metal kaplarda saklayarak","hi":"भोजन को धातु के कंटेनरों में रखना","ar":"تخزين الطعام في حاويات معدنية"},{"en":"Leaving food uncovered overnight in a freezer","es":"Dejar los alimentos destapados toda la noche en un congelador","ru":"При оставлении пищи открытой на ночь в морозильной камере","tr":"Gıdayı bir gecede dondurucuda üstü açık bırakarak","hi":"भोजन को फ्रीज़र में रात भर खुला छोड़ना","ar":"ترك الطعام مكشوفاً طوال الليل في المجمّد"}],"e":{"en":"Both viruses spread via the fecal-oral route, often when an infected handler with poor hand hygiene touches ready-to-eat food.","es":"Ambos virus se propagan por la vía fecal-oral, a menudo cuando un manipulador infectado con higiene de manos deficiente toca alimentos listos para comer.","ru":"Оба вируса распространяются фекально-оральным путём, часто когда инфицированный работник с плохой гигиеной рук прикасается к готовым к употреблению продуктам.","tr":"Her iki virüs de fekal-oral yolla, çoğunlukla kötü el hijyeni olan enfekte bir çalışan yemeye hazır gıdaya dokunduğunda yayılır.","hi":"दोनों वायरस मल-मौखिक मार्ग से फैलते हैं, अक्सर तब जब खराब हाथ स्वच्छता वाला कोई संक्रमित संचालक खाने के लिए तैयार भोजन को छूता है।","ar":"ينتشر كلا الفيروسين عبر المسار البرازي الفموي، غالباً عندما يلمس متداول مصاب ذو نظافة يدين سيئة طعاماً جاهزاً للأكل."}},{"cat":"illness","a":3,"q":{"en":"In FAT TOM, bacteria grow best in foods with which acidity (pH) range?","es":"En FAT TOM, las bacterias crecen mejor en alimentos con qué rango de acidez (pH)?","ru":"В FAT TOM бактерии лучше всего растут в продуктах с каким диапазоном кислотности (pH)?","tr":"FAT TOM içinde, bakteriler hangi asitlik (pH) aralığındaki gıdalarda en iyi büyür?","hi":"FAT TOM में, बैक्टीरिया किस अम्लता (pH) सीमा वाले भोजन में सबसे अच्छी तरह बढ़ते हैं?","ar":"في FAT TOM، تنمو البكتيريا على أفضل نحو في الأطعمة ذات أي نطاق حموضة (pH)؟"},"o":[{"en":"Only at exactly pH 7.0","es":"Solo exactamente a pH 7.0","ru":"Только точно при pH 7,0","tr":"Yalnızca tam olarak pH 7.0'da","hi":"केवल बिल्कुल pH 7.0 पर","ar":"فقط عند pH 7.0 بالضبط"},{"en":"Very acidic, below pH 2.0","es":"Muy ácido, por debajo de pH 2.0","ru":"Очень кислой, ниже pH 2,0","tr":"Çok asidik, pH 2.0'ın altında","hi":"बहुत अम्लीय, pH 2.0 से नीचे","ar":"حمضية جداً، أقل من pH 2.0"},{"en":"Strongly alkaline, above pH 11.0","es":"Fuertemente alcalino, por encima de pH 11.0","ru":"Сильно щелочной, выше pH 11,0","tr":"Güçlü alkali, pH 11.0'ın üzerinde","hi":"मज़बूत क्षारीय, pH 11.0 से ऊपर","ar":"قلوية بقوة، أعلى من pH 11.0"},{"en":"Slightly acidic to neutral, about pH 4.6 to 7.5","es":"De ligeramente ácido a neutro, aproximadamente pH 4.6 a 7.5","ru":"Слабокислой до нейтральной, около pH от 4,6 до 7,5","tr":"Hafif asidikten nötre, yaklaşık pH 4.6 ile 7.5 arası","hi":"थोड़ा अम्लीय से उदासीन, लगभग pH 4.6 से 7.5","ar":"حمضية قليلاً إلى متعادلة، نحو pH 4.6 to 7.5"}],"e":{"en":"Most foodborne bacteria thrive in the slightly acidic to neutral range (about pH 4.6–7.5); highly acidic foods inhibit growth.","es":"La mayoría de las bacterias transmitidas por los alimentos prosperan en el rango de ligeramente ácido a neutro (aproximadamente pH 4.6–7.5); los alimentos muy ácidos inhiben el crecimiento.","ru":"Большинство пищевых бактерий процветают в слабокислом и нейтральном диапазоне (около pH 4,6–7,5); сильнокислые продукты подавляют рост.","tr":"Çoğu gıda kaynaklı bakteri hafif asidikten nötre kadar olan aralıkta (yaklaşık pH 4.6–7.5) gelişir; yüksek asitli gıdalar büyümeyi engeller.","hi":"अधिकांश खाद्यजनित बैक्टीरिया थोड़े अम्लीय से उदासीन सीमा (लगभग pH 4.6–7.5) में पनपते हैं; अत्यधिक अम्लीय भोजन वृद्धि को रोकते हैं।","ar":"تزدهر معظم البكتيريا المنقولة بالغذاء في النطاق الحمضي قليلاً إلى المتعادل (نحو pH 4.6–7.5)؛ أما الأطعمة شديدة الحموضة فتثبّط النمو."}},{"cat":"illness","a":0,"q":{"en":"Salmonella Typhi, one of the Big 6, is the cause of which disease?","es":"Salmonella Typhi, uno de los Seis Grandes (Big 6), es la causa de qué enfermedad?","ru":"Salmonella Typhi, одна из «Большой шестёрки» (Big 6), является причиной какого заболевания?","tr":"Büyük 6'dan biri olan Salmonella Typhi, hangi hastalığın nedenidir?","hi":"साल्मोनेला टाइफी (Salmonella Typhi), Big 6 में से एक, किस बीमारी का कारण है?","ar":"السالمونيلا التيفية (Salmonella Typhi)، أحد الستة الكبار، هي سبب أي مرض؟"},"o":[{"en":"Typhoid fever","es":"Fiebre tifoidea","ru":"Брюшного тифа","tr":"Tifo (tifoid ateşi)","hi":"टाइफाइड बुखार","ar":"حمى التيفوئيد"},{"en":"Botulism","es":"Botulismo","ru":"Ботулизма","tr":"Botulizm","hi":"बोटुलिज़्म (Botulism)","ar":"التسمم الوشيقي (البوتوليزم)"},{"en":"Listeriosis","es":"Listeriosis","ru":"Листериоза","tr":"Listeriyoz","hi":"लिस्टेरियोसिस (Listeriosis)","ar":"داء الليستيريات"},{"en":"Tetanus","es":"Tétanos","ru":"Столбняка","tr":"Tetanoz","hi":"टिटनेस (Tetanus)","ar":"الكزاز (التيتانوس)"}],"e":{"en":"Salmonella Typhi causes typhoid fever and is specifically listed among the Big 6 reportable pathogens.","es":"Salmonella Typhi causa la fiebre tifoidea y está específicamente incluida entre los patógenos de declaración obligatoria de los Seis Grandes (Big 6).","ru":"Salmonella Typhi вызывает брюшной тиф и конкретно указана среди патогенов «Большой шестёрки» (Big 6), подлежащих обязательному сообщению.","tr":"Salmonella Typhi tifo ateşine neden olur ve Büyük 6 bildirilmesi gereken patojenler arasında özellikle yer alır.","hi":"साल्मोनेला टाइफी टाइफाइड बुखार का कारण बनता है और इसे विशेष रूप से Big 6 रिपोर्ट करने योग्य रोगजनकों में सूचीबद्ध किया गया है।","ar":"تسبب السالمونيلا التيفية حمى التيفوئيد وهي مُدرجة تحديداً ضمن مسببات الأمراض الستة الكبار الواجب الإبلاغ عنها."}},{"cat":"illness","a":1,"q":{"en":"Which scenario is the clearest example of cross-contamination?","es":"¿Cuál escenario es el ejemplo más claro de contaminación cruzada?","ru":"Какой сценарий является наиболее наглядным примером перекрёстного загрязнения?","tr":"Hangi senaryo çapraz bulaşmanın en açık örneğidir?","hi":"कौन सा परिदृश्य क्रॉस-कॉन्टैमिनेशन का सबसे स्पष्ट उदाहरण है?","ar":"أي سيناريو هو المثال الأوضح على التلوث المتبادل؟"},"o":[{"en":"Cooking chicken to 165°F before serving","es":"Cocinar el pollo a 165°F antes de servirlo","ru":"Приготовление курицы до 165°F перед подачей","tr":"Tavuğu servis etmeden önce 165°F'ye pişirmek","hi":"परोसने से पहले चिकन को 165°F तक पकाना","ar":"طهي الدجاج إلى 165°F قبل التقديم"},{"en":"Using the same cutting board for raw chicken and then fresh salad without cleaning","es":"Usar la misma tabla de cortar para pollo crudo y luego para ensalada fresca sin limpiarla","ru":"Использование одной разделочной доски для сырой курицы, а затем для свежего салата без очистки","tr":"Aynı kesme tahtasını çiğ tavuk için kullanıp ardından temizlemeden taze salata için kullanmak","hi":"कच्चे चिकन के लिए उसी कटिंग बोर्ड का उपयोग करना और फिर बिना साफ किए ताज़ा सलाद के लिए","ar":"استخدام لوح التقطيع نفسه للدجاج النيء ثم للسلطة الطازجة دون تنظيف"},{"en":"Storing milk at 38°F in the cooler","es":"Almacenar la leche a 38°F en el refrigerador","ru":"Хранение молока при 38°F в холодильнике","tr":"Sütü soğutucuda 38°F'de saklamak","hi":"कूलर में दूध को 38°F पर रखना","ar":"تخزين الحليب عند 38°F في الثلاجة"},{"en":"Labeling and dating leftovers before refrigerating","es":"Etiquetar y fechar las sobras antes de refrigerarlas","ru":"Маркировка и датирование остатков перед охлаждением","tr":"Artıkları buzdolabına koymadan önce etiketleyip tarih atmak","hi":"रेफ्रिजरेट करने से पहले बचे हुए भोजन को लेबल और तारीख डालना","ar":"وضع ملصقات وتواريخ على بقايا الطعام قبل تبريدها"}],"e":{"en":"Cross-contamination occurs when pathogens transfer from one food or surface to another, such as raw chicken juices to ready-to-eat salad.","es":"La contaminación cruzada ocurre cuando los patógenos se transfieren de un alimento o superficie a otro, como los jugos del pollo crudo a una ensalada lista para comer.","ru":"Перекрёстное загрязнение происходит, когда патогены переносятся с одного продукта или поверхности на другой, например соки сырой курицы на готовый к употреблению салат.","tr":"Çapraz bulaşma, patojenler bir gıdadan veya yüzeyden bir diğerine geçtiğinde oluşur, örneğin çiğ tavuk sularının yemeye hazır salataya bulaşması gibi.","hi":"क्रॉस-कॉन्टैमिनेशन तब होता है जब रोगजनक एक भोजन या सतह से दूसरे में स्थानांतरित होते हैं, जैसे कच्चे चिकन का रस खाने के लिए तैयार सलाद में।","ar":"يحدث التلوث المتبادل عندما تنتقل مسببات الأمراض من طعام أو سطح إلى آخر، مثل انتقال عصارة الدجاج النيء إلى سلطة جاهزة للأكل."}},{"cat":"illness","a":0,"q":{"en":"Most foodborne bacteria need available water to grow. They generally require a water activity (aw) above which value?","es":"La mayoría de las bacterias transmitidas por los alimentos necesitan agua disponible para crecer. Generalmente requieren una actividad de agua (aw) por encima de qué valor?","ru":"Большинству пищевых бактерий для роста требуется доступная вода. Обычно им необходима активность воды (aw) выше какого значения?","tr":"Çoğu gıda kaynaklı bakteri büyümek için mevcut suya ihtiyaç duyar. Genellikle hangi değerin üzerinde bir su aktivitesine (aw) ihtiyaç duyarlar?","hi":"अधिकांश खाद्यजनित बैक्टीरिया को बढ़ने के लिए उपलब्ध पानी की आवश्यकता होती है। उन्हें आम तौर पर किस मान से ऊपर जल सक्रियता (water activity, aw) की आवश्यकता होती है?","ar":"تحتاج معظم البكتيريا المنقولة بالغذاء إلى ماء متاح لتنمو. وهي تتطلب عموماً نشاطاً مائياً (aw) أعلى من أي قيمة؟"},"o":[{"en":"About 0.85","es":"Aproximadamente 0.85","ru":"Около 0,85","tr":"Yaklaşık 0.85","hi":"लगभग 0.85","ar":"نحو 0.85"},{"en":"Exactly 0.10","es":"Exactamente 0.10","ru":"Ровно 0,10","tr":"Tam olarak 0.10","hi":"बिल्कुल 0.10","ar":"0.10 بالضبط"},{"en":"About 0.30","es":"Aproximadamente 0.30","ru":"Около 0,30","tr":"Yaklaşık 0.30","hi":"लगभग 0.30","ar":"نحو 0.30"},{"en":"Exactly 0.00","es":"Exactamente 0.00","ru":"Ровно 0,00","tr":"Tam olarak 0.00","hi":"बिल्कुल 0.00","ar":"0.00 بالضبط"}],"e":{"en":"Pathogenic bacteria generally require a water activity above roughly 0.85, which is why dried and low-moisture foods resist growth.","es":"Las bacterias patógenas generalmente requieren una actividad de agua por encima de aproximadamente 0.85, por lo que los alimentos secos y de baja humedad resisten el crecimiento.","ru":"Патогенным бактериям обычно требуется активность воды выше примерно 0,85, поэтому сушёные продукты и продукты с низкой влажностью устойчивы к росту.","tr":"Patojenik bakteriler genellikle yaklaşık 0.85'in üzerinde bir su aktivitesine ihtiyaç duyar; bu nedenle kurutulmuş ve düşük nemli gıdalar büyümeye karşı dirençlidir.","hi":"रोगजनक बैक्टीरिया को आम तौर पर लगभग 0.85 से ऊपर जल सक्रियता की आवश्यकता होती है, यही कारण है कि सूखे और कम नमी वाले भोजन वृद्धि का प्रतिरोध करते हैं।","ar":"تتطلب البكتيريا المُمرِضة عموماً نشاطاً مائياً أعلى من نحو 0.85، وهذا هو سبب مقاومة الأطعمة المجففة وقليلة الرطوبة للنمو."}},{"cat":"illness","a":1,"q":{"en":"Which pair correctly matches a hazard type with an example?","es":"¿Cuál par relaciona correctamente un tipo de peligro con un ejemplo?","ru":"Какая пара правильно сопоставляет тип опасности с примером?","tr":"Hangi çift bir tehlike türünü bir örnekle doğru şekilde eşleştirir?","hi":"कौन सी जोड़ी खतरे के प्रकार को एक उदाहरण के साथ सही ढंग से मिलाती है?","ar":"أي زوج يطابق بشكل صحيح نوع الخطر مع مثاله؟"},"o":[{"en":"Biological hazard - a metal shaving from a worn can opener","es":"Peligro biológico - una viruta de metal de un abrelatas desgastado","ru":"Биологическая опасность — металлическая стружка от изношенного консервного ножа","tr":"Biyolojik tehlike - aşınmış bir konserve açacağından gelen metal talaşı","hi":"जैविक खतरा - घिसे हुए कैन ओपनर से धातु की छीलन","ar":"خطر بيولوجي - رقاقة معدنية من فتّاحة علب مهترئة"},{"en":"Chemical hazard - a sanitizer accidentally sprayed into food","es":"Peligro químico - un desinfectante rociado accidentalmente en la comida","ru":"Химическая опасность — дезинфицирующее средство, случайно распылённое в пищу","tr":"Kimyasal tehlike - gıdaya yanlışlıkla püskürtülen bir dezenfektan","hi":"रासायनिक खतरा - गलती से भोजन में छिड़का गया सैनिटाइज़र","ar":"خطر كيميائي - مطهِّر رُشّ في الطعام عن طريق الخطأ"},{"en":"Physical hazard - Shigella bacteria from unwashed hands","es":"Peligro físico - bacterias de Shigella de manos sin lavar","ru":"Физическая опасность — бактерии шигеллы с немытых рук","tr":"Fiziksel tehlike - yıkanmamış ellerden gelen Shigella bakterisi","hi":"भौतिक खतरा - बिना धोए हाथों से शिगेला (Shigella) बैक्टीरिया","ar":"خطر فيزيائي - بكتيريا الشيغيلا من أيدٍ غير مغسولة"},{"en":"Chemical hazard - Hepatitis A virus on produce","es":"Peligro químico - virus de la Hepatitis A en productos agrícolas","ru":"Химическая опасность — вирус гепатита А на продуктах","tr":"Kimyasal tehlike - sebzelerdeki Hepatit A virüsü","hi":"रासायनिक खतरा - उपज पर हेपेटाइटिस A (Hepatitis A) वायरस","ar":"خطر كيميائي - فيروس التهاب الكبد A على المنتجات الطازجة"}],"e":{"en":"Chemicals like sanitizers and cleaners are chemical hazards; metal is physical, and Shigella and Hepatitis A are biological.","es":"Los químicos como los desinfectantes y los limpiadores son peligros químicos; el metal es físico, y Shigella y la Hepatitis A son biológicos.","ru":"Химикаты, такие как дезинфектанты и чистящие средства, являются химическими опасностями; металл — физической, а шигелла и гепатит А — биологическими.","tr":"Dezenfektanlar ve temizleyiciler gibi kimyasallar kimyasal tehlikedir; metal fizikseldir ve Shigella ile Hepatit A biyolojiktir.","hi":"सैनिटाइज़र और क्लीनर जैसे रसायन रासायनिक खतरे हैं; धातु भौतिक है, और शिगेला तथा हेपेटाइटिस A जैविक हैं।","ar":"المواد الكيميائية مثل المطهِّرات والمنظفات هي مخاطر كيميائية؛ أما المعدن ففيزيائي، والشيغيلا والتهاب الكبد A بيولوجيان."}},{"cat":"illness","a":0,"q":{"en":"A handler has been diagnosed with nontyphoidal Salmonella. Why does the Food Code require reporting and exclusion?","es":"A un manipulador se le ha diagnosticado Salmonella no tifoidea. ¿Por qué el Código de Alimentos exige reportarlo y excluirlo?","ru":"У работника диагностирована нетифоидная сальмонелла. Почему Пищевой кодекс требует сообщения и отстранения?","tr":"Bir çalışana tifo dışı Salmonella teşhisi konmuştur. Gıda Yönetmeliği neden bildirim ve teması engellemeyi gerektirir?","hi":"एक संचालक को नॉनटाइफॉइडल साल्मोनेला (nontyphoidal Salmonella) का निदान हुआ है। Food Code रिपोर्टिंग और बहिष्करण की आवश्यकता क्यों रखता है?","ar":"شُخِّص متداول طعام بالسالمونيلا غير التيفية. لماذا تتطلب مدوّنة الغذاء الإبلاغ والاستبعاد؟"},"o":[{"en":"It is highly transmissible through food and is one of the Big 6 reportable pathogens","es":"Es altamente transmisible a través de los alimentos y es uno de los patógenos de declaración obligatoria de los Seis Grandes (Big 6)","ru":"Она легко передаётся через пищу и является одним из патогенов «Большой шестёрки» (Big 6), подлежащих обязательному сообщению","tr":"Gıda yoluyla yüksek bulaşıcılığa sahiptir ve Büyük 6 bildirilmesi gereken patojenlerden biridir","hi":"यह भोजन के माध्यम से अत्यधिक संक्रामक है और Big 6 रिपोर्ट करने योग्य रोगजनकों में से एक है","ar":"لأنها شديدة الانتقال عبر الطعام وهي أحد مسببات الأمراض الستة الكبار الواجب الإبلاغ عنهم"},{"en":"It is only dangerous if the food is frozen","es":"Solo es peligrosa si el alimento está congelado","ru":"Она опасна только если пища заморожена","tr":"Yalnızca gıda donmuşsa tehlikelidir","hi":"यह केवल तभी खतरनाक है जब भोजन फ्रोज़न हो","ar":"لأنها خطيرة فقط إذا كان الطعام مجمّداً"},{"en":"It cannot be spread by people, only by packaging","es":"No puede ser propagada por personas, solo por el empaque","ru":"Она не может передаваться людьми, только упаковкой","tr":"İnsanlar tarafından değil, yalnızca ambalaj yoluyla yayılabilir","hi":"इसे लोगों द्वारा नहीं फैलाया जा सकता, केवल पैकेजिंग द्वारा","ar":"لأنها لا تنتقل عن طريق الأشخاص، بل عن طريق التغليف فقط"},{"en":"It is not actually a foodborne pathogen","es":"No es realmente un patógeno transmitido por los alimentos","ru":"Она на самом деле не является пищевым патогеном","tr":"Aslında gıda kaynaklı bir patojen değildir","hi":"यह वास्तव में एक खाद्यजनित रोगजनक नहीं है","ar":"لأنها ليست في الواقع من مسببات الأمراض المنقولة بالغذاء"}],"e":{"en":"Nontyphoidal Salmonella is one of the Big 6; an infected handler can readily transmit it through food, so reporting and exclusion are required.","es":"La Salmonella no tifoidea es uno de los Seis Grandes (Big 6); un manipulador infectado puede transmitirla fácilmente a través de los alimentos, por lo que se requiere reportarlo y excluirlo.","ru":"Нетифоидная сальмонелла — один из патогенов «Большой шестёрки» (Big 6); инфицированный работник может легко передать её через пищу, поэтому сообщение и отстранение обязательны.","tr":"Tifo dışı Salmonella Büyük 6'dan biridir; enfekte bir çalışan onu gıda yoluyla kolayca bulaştırabilir, bu nedenle bildirim ve teması engelleme gereklidir.","hi":"नॉनटाइफॉइडल साल्मोनेला Big 6 में से एक है; एक संक्रमित संचालक इसे आसानी से भोजन के माध्यम से फैला सकता है, इसलिए रिपोर्टिंग और बहिष्करण आवश्यक है।","ar":"السالمونيلا غير التيفية هي أحد الستة الكبار؛ ويمكن لمتداول مصاب أن ينقلها بسهولة عبر الطعام، لذا يُشترط الإبلاغ والاستبعاد."}},{"cat":"illness","a":0,"q":{"en":"Refrigerating a potentially hazardous food at 39°F primarily controls bacterial growth by limiting which two FAT TOM factors?","es":"Refrigerar un alimento potencialmente peligroso a 39°F controla principalmente el crecimiento bacteriano al limitar cuáles dos factores de FAT TOM?","ru":"Охлаждение потенциально опасной пищи при 39°F в основном контролирует рост бактерий, ограничивая какие два фактора FAT TOM?","tr":"Potansiyel olarak tehlikeli bir gıdayı 39°F'de soğutmak, bakteri büyümesini esas olarak FAT TOM faktörlerinden hangi ikisini sınırlayarak kontrol eder?","hi":"किसी संभावित रूप से खतरनाक भोजन को 39°F पर रेफ्रिजरेट करना मुख्य रूप से किन दो FAT TOM कारकों को सीमित करके बैक्टीरिया की वृद्धि को नियंत्रित करता है?","ar":"تبريد طعام يحتمل أن يكون خطراً عند 39°F يتحكم في نمو البكتيريا أساساً عن طريق الحد من أيٍّ من عاملي FAT TOM؟"},"o":[{"en":"Temperature and Time","es":"Temperatura y Tiempo","ru":"Температуру и Время","tr":"Sıcaklık ve Zaman","hi":"Temperature और Time","ar":"درجة الحرارة والوقت"},{"en":"Acidity and Oxygen","es":"Acidez y Oxígeno","ru":"Кислотность и Кислород","tr":"Asitlik ve Oksijen","hi":"Acidity और Oxygen","ar":"الحموضة والأكسجين"},{"en":"Food and Moisture","es":"Alimento y Humedad","ru":"Пищу и Влажность","tr":"Gıda ve Nem","hi":"Food और Moisture","ar":"الغذاء والرطوبة"},{"en":"Oxygen and Acidity","es":"Oxígeno y Acidez","ru":"Кислород и Кислотность","tr":"Oksijen ve Asitlik","hi":"Oxygen और Acidity","ar":"الأكسجين والحموضة"}],"e":{"en":"Keeping food at 39°F holds it below the danger zone (Temperature) and slows multiplication, extending the safe holding window (Time).","es":"Mantener el alimento a 39°F lo conserva por debajo de la zona de peligro (Temperatura) y ralentiza la multiplicación, extendiendo el período seguro de conservación (Tiempo).","ru":"Хранение пищи при 39°F удерживает её ниже опасной зоны (Температура) и замедляет размножение, продлевая безопасный срок хранения (Время).","tr":"Gıdayı 39°F'de tutmak onu tehlikeli bölgenin altında tutar (Sıcaklık) ve çoğalmayı yavaşlatarak güvenli saklama süresini uzatır (Zaman).","hi":"भोजन को 39°F पर रखना इसे खतरनाक क्षेत्र (Temperature) से नीचे रखता है और गुणन को धीमा करता है, जिससे सुरक्षित होल्डिंग अवधि (Time) बढ़ती है।","ar":"يُبقي حفظ الطعام عند 39°F الطعام دون منطقة الخطر (درجة الحرارة) ويبطئ التكاثر، مما يطيل نافذة الحفظ الآمن (الوقت)."}},{"cat":"illness","a":2,"q":{"en":"Clostridium botulinum can grow in sealed canned and vacuum-packed foods because it is an anaerobe. Which FAT TOM factor does this exception specifically illustrate?","es":"Clostridium botulinum puede crecer en alimentos enlatados y empacados al vacío sellados porque es anaerobio. ¿Cuál factor de FAT TOM ilustra específicamente esta excepción?","ru":"Clostridium botulinum может расти в герметичных консервированных и вакуумно-упакованных продуктах, поскольку является анаэробом. Какой фактор FAT TOM конкретно иллюстрирует это исключение?","tr":"Clostridium botulinum anaerob olduğu için kapalı konserve ve vakumlu paketlenmiş gıdalarda büyüyebilir. Bu istisna özellikle hangi FAT TOM faktörünü gösterir?","hi":"क्लोस्ट्रिडियम बोटुलिनम (Clostridium botulinum) सीलबंद डिब्बाबंद और वैक्यूम-पैक्ड भोजन में बढ़ सकता है क्योंकि यह एक अवायवीय (anaerobe) है। यह अपवाद विशेष रूप से किस FAT TOM कारक को दर्शाता है?","ar":"يمكن للمطثية الوشيقية (Clostridium botulinum) أن تنمو في الأطعمة المعلّبة والمغلّفة بتفريغ الهواء لأنها لا هوائية. أي عامل من FAT TOM يوضّحه هذا الاستثناء تحديداً؟"},"o":[{"en":"Moisture","es":"Humedad","ru":"Влажность","tr":"Nem","hi":"Moisture","ar":"الرطوبة"},{"en":"Acidity","es":"Acidez","ru":"Кислотность","tr":"Asitlik","hi":"Acidity","ar":"الحموضة"},{"en":"Oxygen","es":"Oxígeno","ru":"Кислород","tr":"Oksijen","hi":"Oxygen","ar":"الأكسجين"},{"en":"Food","es":"Alimento","ru":"Пища","tr":"Gıda","hi":"Food","ar":"الغذاء"}],"e":{"en":"Most pathogens need oxygen, but anaerobes like C. botulinum grow without it, which is why oxygen-free packaging does not guarantee safety.","es":"La mayoría de los patógenos necesitan oxígeno, pero los anaerobios como C. botulinum crecen sin él, por lo que el empaque libre de oxígeno no garantiza la seguridad.","ru":"Большинству патогенов нужен кислород, но анаэробы, такие как C. botulinum, растут без него, поэтому бескислородная упаковка не гарантирует безопасность.","tr":"Çoğu patojen oksijene ihtiyaç duyar, ancak C. botulinum gibi anaeroblar oksijensiz büyür, bu nedenle oksijensiz ambalaj güvenliği garanti etmez.","hi":"अधिकांश रोगजनकों को ऑक्सीजन की आवश्यकता होती है, लेकिन C. botulinum जैसे अवायवीय इसके बिना बढ़ते हैं, यही कारण है कि ऑक्सीजन-मुक्त पैकेजिंग सुरक्षा की गारंटी नहीं देती।","ar":"تحتاج معظم مسببات الأمراض إلى الأكسجين، لكن اللاهوائيات مثل C. botulinum تنمو بدونه، ولهذا فإن التغليف الخالي من الأكسجين لا يضمن السلامة."}},{"cat":"cleaning","a":0,"q":{"en":"What is the main difference between cleaning and sanitizing a surface?","es":"¿Cuál es la diferencia principal entre limpiar y desinfectar una superficie?","ru":"В чём основное различие между очисткой и дезинфекцией поверхности?","tr":"Bir yüzeyi temizlemek ile dezenfekte etmek arasındaki temel fark nedir?","hi":"किसी सतह को साफ करने (cleaning) और सैनिटाइज़ करने (sanitizing) के बीच मुख्य अंतर क्या है?","ar":"ما الفرق الرئيسي بين تنظيف السطح وتطهيره؟"},"o":[{"en":"Cleaning removes food residue and dirt, while sanitizing reduces pathogens to safe levels","es":"Limpiar elimina los residuos de comida y la suciedad, mientras que desinfectar reduce los patógenos a niveles seguros","ru":"Очистка удаляет остатки пищи и грязь, а дезинфекция снижает количество патогенов до безопасного уровня","tr":"Temizlik gıda kalıntısını ve kiri giderir, dezenfekte etmek ise patojenleri güvenli seviyelere düşürür","hi":"सफाई भोजन के अवशेष और गंदगी को हटाती है, जबकि सैनिटाइज़ करना रोगजनकों को सुरक्षित स्तर तक कम करता है","ar":"التنظيف يزيل بقايا الطعام والأوساخ، بينما التطهير يقلّل مسببات الأمراض إلى مستويات آمنة"},{"en":"Cleaning kills germs, while sanitizing only removes visible dirt","es":"Limpiar mata los gérmenes, mientras que desinfectar solo elimina la suciedad visible","ru":"Очистка убивает микробы, а дезинфекция только удаляет видимую грязь","tr":"Temizlik mikropları öldürür, dezenfekte etmek ise yalnızca görünür kiri giderir","hi":"सफाई कीटाणुओं को मारती है, जबकि सैनिटाइज़ करना केवल दिखाई देने वाली गंदगी को हटाता है","ar":"التنظيف يقتل الجراثيم، بينما التطهير يزيل الأوساخ المرئية فقط"},{"en":"Cleaning and sanitizing are two words for the same single step","es":"Limpiar y desinfectar son dos palabras para el mismo paso único","ru":"Очистка и дезинфекция — это два слова для одного и того же единственного этапа","tr":"Temizlik ve dezenfekte tek bir adımın iki farklı adıdır","hi":"सफाई और सैनिटाइज़ करना एक ही एकल चरण के लिए दो शब्द हैं","ar":"التنظيف والتطهير كلمتان لنفس الخطوة الواحدة"},{"en":"Cleaning is done with hot water only, while sanitizing requires no chemicals","es":"Limpiar se hace solo con agua caliente, mientras que desinfectar no requiere químicos","ru":"Очистка выполняется только горячей водой, а дезинфекция не требует химикатов","tr":"Temizlik yalnızca sıcak suyla yapılır, dezenfekte ise kimyasal gerektirmez","hi":"सफाई केवल गर्म पानी से की जाती है, जबकि सैनिटाइज़ करने के लिए किसी रसायन की आवश्यकता नहीं होती","ar":"التنظيف يُجرى بالماء الساخن فقط، بينما التطهير لا يتطلب أي مواد كيميائية"}],"e":{"en":"Cleaning physically removes food, soil, and grease, while sanitizing reduces the number of pathogens on a clean surface to safe levels; a surface must be cleaned before it can be sanitized.","es":"Limpiar elimina físicamente la comida, la mugre y la grasa, mientras que desinfectar reduce el número de patógenos en una superficie limpia a niveles seguros; una superficie debe limpiarse antes de poder desinfectarse.","ru":"Очистка физически удаляет пищу, грязь и жир, а дезинфекция снижает количество патогенов на чистой поверхности до безопасного уровня; поверхность должна быть очищена, прежде чем её можно будет продезинфицировать.","tr":"Temizlik gıdayı, kiri ve yağı fiziksel olarak giderir, dezenfekte etmek ise temiz bir yüzeydeki patojen sayısını güvenli seviyelere düşürür; bir yüzey dezenfekte edilmeden önce temizlenmelidir.","hi":"सफाई भौतिक रूप से भोजन, मिट्टी और चिकनाई को हटाती है, जबकि सैनिटाइज़ करना एक साफ सतह पर रोगजनकों की संख्या को सुरक्षित स्तर तक कम करता है; किसी सतह को सैनिटाइज़ करने से पहले उसे साफ करना चाहिए।","ar":"يزيل التنظيف الطعام والأوساخ والشحوم فيزيائياً، بينما يقلّل التطهير عدد مسببات الأمراض على سطح نظيف إلى مستويات آمنة؛ ويجب تنظيف السطح قبل أن يمكن تطهيره."}},{"cat":"cleaning","a":2,"q":{"en":"Why must a surface be cleaned before it is sanitized?","es":"¿Por qué debe limpiarse una superficie antes de desinfectarla?","ru":"Почему поверхность необходимо очистить перед дезинфекцией?","tr":"Bir yüzey dezenfekte edilmeden önce neden temizlenmelidir?","hi":"किसी सतह को सैनिटाइज़ करने से पहले उसे साफ क्यों किया जाना चाहिए?","ar":"لماذا يجب تنظيف السطح قبل تطهيره؟"},"o":[{"en":"Sanitizer is too expensive to use on a dirty surface","es":"El desinfectante es demasiado caro para usarlo en una superficie sucia","ru":"Дезинфицирующее средство слишком дорого, чтобы использовать его на грязной поверхности","tr":"Dezenfektan kirli bir yüzeyde kullanılamayacak kadar pahalıdır","hi":"गंदी सतह पर उपयोग करने के लिए सैनिटाइज़र बहुत महंगा है","ar":"لأن المطهِّر باهظ الثمن لاستخدامه على سطح متسخ"},{"en":"Cleaning makes the surface too wet for sanitizer to stick","es":"Limpiar deja la superficie demasiado mojada para que el desinfectante se adhiera","ru":"Очистка делает поверхность слишком влажной для прилипания дезинфицирующего средства","tr":"Temizlik yüzeyi dezenfektanın tutunamayacağı kadar ıslak yapar","hi":"सफाई सतह को सैनिटाइज़र के चिपकने के लिए बहुत गीला बना देती है","ar":"لأن التنظيف يجعل السطح رطباً جداً بحيث لا يلتصق به المطهِّر"},{"en":"Leftover food and soil shield pathogens and stop the sanitizer from working","es":"Los restos de comida y la mugre protegen a los patógenos e impiden que el desinfectante funcione","ru":"Остатки пищи и грязь защищают патогены и мешают действию дезинфицирующего средства","tr":"Kalan gıda ve kir patojenleri korur ve dezenfektanın çalışmasını engeller","hi":"बचा हुआ भोजन और मिट्टी रोगजनकों को ढक लेते हैं और सैनिटाइज़र को काम करने से रोकते हैं","ar":"لأن بقايا الطعام والأوساخ تحمي مسببات الأمراض وتمنع المطهِّر من العمل"},{"en":"Sanitizing first makes the food debris harder to scrub off","es":"Desinfectar primero hace que los restos de comida sean más difíciles de tallar","ru":"Дезинфекция в первую очередь усложняет отскабливание пищевых остатков","tr":"Önce dezenfekte etmek gıda kalıntısını ovmayı zorlaştırır","hi":"पहले सैनिटाइज़ करने से भोजन के अवशेष को रगड़कर निकालना कठिन हो जाता है","ar":"لأن التطهير أولاً يجعل بقايا الطعام أصعب في الفرك لإزالتها"}],"e":{"en":"Food particles, grease, and soap residue physically block the sanitizer from contacting and killing pathogens, so surfaces must be cleaned and rinsed first.","es":"Las partículas de comida, la grasa y el residuo de jabón bloquean físicamente que el desinfectante entre en contacto con los patógenos y los mate, por lo que las superficies deben limpiarse y enjuagarse primero.","ru":"Частицы пищи, жир и остатки мыла физически препятствуют контакту дезинфицирующего средства с патогенами и их уничтожению, поэтому поверхности необходимо сначала очистить и промыть.","tr":"Gıda partikülleri, yağ ve sabun kalıntısı dezenfektanın patojenlere temas etmesini ve onları öldürmesini fiziksel olarak engeller, bu nedenle yüzeyler önce temizlenmeli ve durulanmalıdır.","hi":"भोजन के कण, चिकनाई और साबुन का अवशेष भौतिक रूप से सैनिटाइज़र को रोगजनकों से संपर्क करने और उन्हें मारने से रोकते हैं, इसलिए सतहों को पहले साफ और रिंस किया जाना चाहिए।","ar":"تمنع جزيئات الطعام والشحوم وبقايا الصابون المطهِّر فيزيائياً من ملامسة مسببات الأمراض وقتلها، لذا يجب تنظيف الأسطح وشطفها أولاً."}},{"cat":"cleaning","a":1,"q":{"en":"In a three-compartment sink, what is the correct order of steps?","es":"En un fregadero de tres compartimentos, ¿cuál es el orden correcto de los pasos?","ru":"В трёхсекционной мойке какой правильный порядок действий?","tr":"Üç bölmeli bir evyede adımların doğru sırası nedir?","hi":"तीन-कम्पार्टमेंट वाले सिंक में, चरणों का सही क्रम क्या है?","ar":"في حوض ذي ثلاثة أقسام، ما هو الترتيب الصحيح للخطوات؟"},"o":[{"en":"Wash, scrape, sanitize, rinse, towel dry","es":"Lavar, raspar, desinfectar, enjuagar, secar con toalla","ru":"Мыть, соскребать, дезинфицировать, промывать, вытирать полотенцем","tr":"Yıka, kazı, dezenfekte et, durula, havluyla kurula","hi":"धोना, खुरचना, सैनिटाइज़ करना, रिंस करना, तौलिए से सुखाना","ar":"الغسل، الكشط، التطهير، الشطف، التجفيف بالمنشفة"},{"en":"Scrape, wash, rinse, sanitize, air dry","es":"Raspar, lavar, enjuagar, desinfectar, secar al aire","ru":"Соскребать, мыть, промывать, дезинфицировать, сушить на воздухе","tr":"Kazı, yıka, durula, dezenfekte et, havada kurut","hi":"खुरचना, धोना, रिंस करना, सैनिटाइज़ करना, हवा में सुखाना","ar":"الكشط، الغسل، الشطف، التطهير، التجفيف بالهواء"},{"en":"Rinse, wash, scrape, air dry, sanitize","es":"Enjuagar, lavar, raspar, secar al aire, desinfectar","ru":"Промывать, мыть, соскребать, сушить на воздухе, дезинфицировать","tr":"Durula, yıka, kazı, havada kurut, dezenfekte et","hi":"रिंस करना, धोना, खुरचना, हवा में सुखाना, सैनिटाइज़ करना","ar":"الشطف، الغسل، الكشط، التجفيف بالهواء، التطهير"},{"en":"Scrape, sanitize, wash, rinse, towel dry","es":"Raspar, desinfectar, lavar, enjuagar, secar con toalla","ru":"Соскребать, дезинфицировать, мыть, промывать, вытирать полотенцем","tr":"Kazı, dezenfekte et, yıka, durula, havluyla kurula","hi":"खुरचना, सैनिटाइज़ करना, धोना, रिंस करना, तौलिए से सुखाना","ar":"الكشط، التطهير، الغسل، الشطف، التجفيف بالمنشفة"}],"e":{"en":"The correct sequence is scrape off debris, wash in detergent, rinse in clean water, sanitize, then air dry; the order ensures food and soap do not interfere with the sanitizer.","es":"La secuencia correcta es raspar los restos, lavar con detergente, enjuagar en agua limpia, desinfectar y luego secar al aire; el orden garantiza que la comida y el jabón no interfieran con el desinfectante.","ru":"Правильная последовательность: соскрести остатки, вымыть с моющим средством, промыть в чистой воде, продезинфицировать, затем высушить на воздухе; такой порядок гарантирует, что пища и мыло не помешают действию дезинфицирующего средства.","tr":"Doğru sıra; kalıntıları kazımak, deterjanla yıkamak, temiz suda durulamak, dezenfekte etmek ve ardından havada kurutmaktır; bu sıra gıda ve sabunun dezenfektana müdahale etmemesini sağlar.","hi":"सही क्रम है मलबे को खुरचना, डिटर्जेंट में धोना, साफ पानी में रिंस करना, सैनिटाइज़ करना, फिर हवा में सुखाना; यह क्रम सुनिश्चित करता है कि भोजन और साबुन सैनिटाइज़र में हस्तक्षेप न करें।","ar":"التسلسل الصحيح هو كشط البقايا، ثم الغسل بالمنظف، ثم الشطف بماء نظيف، ثم التطهير، ثم التجفيف بالهواء؛ ويضمن هذا الترتيب ألا يتداخل الطعام والصابون مع المطهِّر."}},{"cat":"cleaning","a":3,"q":{"en":"After sanitizing dishes in a three-compartment sink, how should they be dried?","es":"Después de desinfectar los platos en un fregadero de tres compartimentos, ¿cómo deben secarse?","ru":"После дезинфекции посуды в трёхсекционной мойке, как её следует сушить?","tr":"Üç bölmeli bir evyede bulaşıkları dezenfekte ettikten sonra nasıl kurutulmalıdır?","hi":"तीन-कम्पार्टमेंट वाले सिंक में बर्तनों को सैनिटाइज़ करने के बाद, उन्हें कैसे सुखाया जाना चाहिए?","ar":"بعد تطهير الأطباق في حوض ذي ثلاثة أقسام، كيف ينبغي تجفيفها؟"},"o":[{"en":"Wipe dry with a clean cloth towel","es":"Secarlos con una toalla de tela limpia","ru":"Вытереть насухо чистым тканевым полотенцем","tr":"Temiz bir bez havluyla silerek kurutmak","hi":"एक साफ कपड़े के तौलिए से पोंछकर सुखाएं","ar":"مسحها حتى تجف بمنشفة قماشية نظيفة"},{"en":"Stack them while still wet to save counter space","es":"Apilarlos mientras todavía están mojados para ahorrar espacio en el mostrador","ru":"Сложить её ещё влажной, чтобы сэкономить место на столе","tr":"Tezgâh alanından tasarruf etmek için hâlâ ıslakken üst üste istiflemek","hi":"काउंटर की जगह बचाने के लिए उन्हें गीला रहते हुए ही ढेर कर दें","ar":"تكديسها وهي لا تزال مبللة لتوفير مساحة الطاولة"},{"en":"Dry them with a paper towel and a final wipe of sanitizer","es":"Secarlos con una toalla de papel y un repaso final de desinfectante","ru":"Высушить бумажным полотенцем и в завершение протереть дезинфицирующим средством","tr":"Bir kâğıt havlu ve son bir dezenfektan silmesiyle kurutmak","hi":"उन्हें एक पेपर टॉवल और सैनिटाइज़र के एक अंतिम पोंछे से सुखाएं","ar":"تجفيفها بمنشفة ورقية ومسحة أخيرة من المطهِّر"},{"en":"Air dry completely before stacking or storing","es":"Secar al aire completamente antes de apilarlos o guardarlos","ru":"Полностью высушить на воздухе перед складыванием или хранением","tr":"İstiflemeden veya saklamadan önce tamamen havada kurutmak","hi":"ढेर करने या रखने से पहले उन्हें पूरी तरह से हवा में सुखाएं","ar":"تركها تجف بالهواء تماماً قبل التكديس أو التخزين"}],"e":{"en":"Items must be allowed to air dry; towel drying can recontaminate the just-sanitized surface.","es":"Los artículos deben dejarse secar al aire; secarlos con toalla puede recontaminar la superficie recién desinfectada.","ru":"Предметы должны высыхать на воздухе; вытирание полотенцем может повторно загрязнить только что продезинфицированную поверхность.","tr":"Eşyaların havada kurumasına izin verilmelidir; havluyla kurutmak yeni dezenfekte edilmiş yüzeyi yeniden kirletebilir.","hi":"वस्तुओं को हवा में सूखने दिया जाना चाहिए; तौलिए से सुखाने से अभी-अभी सैनिटाइज़ की गई सतह फिर से संदूषित हो सकती है।","ar":"يجب ترك الأدوات تجف بالهواء؛ فالتجفيف بالمنشفة قد يعيد تلويث السطح الذي تم تطهيره للتو."}},{"cat":"cleaning","a":2,"q":{"en":"What is the minimum recommended water temperature for the wash (detergent) compartment of a three-compartment sink?","es":"¿Cuál es la temperatura mínima recomendada del agua para el compartimento de lavado (detergente) de un fregadero de tres compartimentos?","ru":"Какова минимальная рекомендуемая температура воды для моечной секции (с моющим средством) трёхсекционной мойки?","tr":"Üç bölmeli bir evyenin yıkama (deterjan) bölmesi için önerilen asgari su sıcaklığı nedir?","hi":"तीन-कम्पार्टमेंट वाले सिंक के धोने (डिटर्जेंट) वाले कम्पार्टमेंट के लिए न्यूनतम अनुशंसित पानी का तापमान क्या है?","ar":"ما هي الحد الأدنى الموصى به لدرجة حرارة الماء في قسم الغسل (المنظف) من حوض ذي ثلاثة أقسام؟"},"o":[{"en":"75°F (24°C)","es":"75°F (24°C)","ru":"75°F (24°C)","tr":"75°F (24°C)","hi":"75°F (24°C)","ar":"75°F (24°C)"},{"en":"95°F (35°C)","es":"95°F (35°C)","ru":"95°F (35°C)","tr":"95°F (35°C)","hi":"95°F (35°C)","ar":"95°F (35°C)"},{"en":"110°F (43°C)","es":"110°F (43°C)","ru":"110°F (43°C)","tr":"110°F (43°C)","hi":"110°F (43°C)","ar":"110°F (43°C)"},{"en":"171°F (77°C)","es":"171°F (77°C)","ru":"171°F (77°C)","tr":"171°F (77°C)","hi":"171°F (77°C)","ar":"171°F (77°C)"}],"e":{"en":"The wash water should be at least 110°F (43°C) so the detergent can effectively cut grease and loosen food soil.","es":"El agua de lavado debe estar a por lo menos 110°F (43°C) para que el detergente pueda cortar eficazmente la grasa y aflojar la mugre de la comida.","ru":"Вода для мытья должна быть не менее 110°F (43°C), чтобы моющее средство могло эффективно растворять жир и отделять пищевую грязь.","tr":"Yıkama suyu en az 110°F (43°C) olmalıdır ki deterjan yağı etkili şekilde kesebilsin ve gıda kirini çözebilsin.","hi":"धोने का पानी कम से कम 110°F (43°C) होना चाहिए ताकि डिटर्जेंट प्रभावी ढंग से चिकनाई काट सके और भोजन की मिट्टी को ढीला कर सके।","ar":"يجب أن تكون درجة حرارة ماء الغسل 110°F (43°C) على الأقل حتى يتمكن المنظف من تفتيت الشحوم وتفكيك بقايا الطعام بفعالية."}},{"cat":"cleaning","a":0,"q":{"en":"For chlorine (bleach) sanitizer, which concentration is a commonly accepted range for sanitizing food-contact surfaces?","es":"Para el desinfectante de cloro (lejía), ¿cuál concentración es un rango comúnmente aceptado para desinfectar las superficies en contacto con los alimentos?","ru":"Для хлорного (отбеливающего) дезинфицирующего средства какая концентрация является общепринятым диапазоном для дезинфекции поверхностей, контактирующих с пищей?","tr":"Klor (çamaşır suyu) dezenfektanı için, gıdayla temas eden yüzeyleri dezenfekte etmede yaygın olarak kabul edilen konsantrasyon aralığı hangisidir?","hi":"क्लोरीन (ब्लीच) सैनिटाइज़र के लिए, खाद्य-संपर्क सतहों को सैनिटाइज़ करने के लिए कौन सी सांद्रता आमतौर पर स्वीकृत सीमा है?","ar":"بالنسبة لمطهِّر الكلور (المبيّض)، أي تركيز يُعد نطاقاً مقبولاً عموماً لتطهير الأسطح الملامسة للطعام؟"},"o":[{"en":"50–100 ppm","es":"50–100 ppm","ru":"50–100 ppm","tr":"50–100 ppm","hi":"50–100 ppm","ar":"50–100 ppm"},{"en":"5–10 ppm","es":"5–10 ppm","ru":"5–10 ppm","tr":"5–10 ppm","hi":"5–10 ppm","ar":"5–10 ppm"},{"en":"200–400 ppm","es":"200–400 ppm","ru":"200–400 ppm","tr":"200–400 ppm","hi":"200–400 ppm","ar":"200–400 ppm"},{"en":"500–1000 ppm","es":"500–1000 ppm","ru":"500–1000 ppm","tr":"500–1000 ppm","hi":"500–1000 ppm","ar":"500–1000 ppm"}],"e":{"en":"Chlorine sanitizer is typically used at about 50–100 ppm for food-contact surfaces; too little is ineffective and too much can be unsafe.","es":"El desinfectante de cloro se usa típicamente a aproximadamente 50–100 ppm para las superficies en contacto con los alimentos; muy poco es ineficaz y demasiado puede ser peligroso.","ru":"Хлорное дезинфицирующее средство обычно используется в концентрации около 50–100 ppm для поверхностей, контактирующих с пищей; слишком малое количество неэффективно, а слишком большое может быть небезопасным.","tr":"Klor dezenfektanı gıdayla temas eden yüzeyler için tipik olarak yaklaşık 50–100 ppm'de kullanılır; çok az etkisizdir, çok fazlası ise güvenli olmayabilir.","hi":"क्लोरीन सैनिटाइज़र आमतौर पर खाद्य-संपर्क सतहों के लिए लगभग 50–100 ppm पर उपयोग किया जाता है; बहुत कम अप्रभावी है और बहुत अधिक असुरक्षित हो सकता है।","ar":"يُستخدم مطهِّر الكلور عادةً بتركيز نحو 50–100 ppm للأسطح الملامسة للطعام؛ فالقليل جداً غير فعّال والكثير جداً قد يكون غير آمن."}},{"cat":"cleaning","a":3,"q":{"en":"When sanitizing by hot-water immersion (no chemicals), the water must be held at a minimum of which temperature?","es":"Al desinfectar por inmersión en agua caliente (sin químicos), el agua debe mantenerse a un mínimo de qué temperatura?","ru":"При дезинфекции погружением в горячую воду (без химикатов) вода должна поддерживаться при минимальной температуре в какое значение?","tr":"Sıcak suya daldırarak (kimyasal kullanmadan) dezenfekte ederken, su asgari hangi sıcaklıkta tutulmalıdır?","hi":"गर्म-पानी में डुबोकर (बिना रसायन के) सैनिटाइज़ करते समय, पानी को न्यूनतम किस तापमान पर रखा जाना चाहिए?","ar":"عند التطهير بالغمر في الماء الساخن (بدون مواد كيميائية)، يجب الحفاظ على الماء عند حد أدنى لأي درجة حرارة؟"},"o":[{"en":"120°F (49°C)","es":"120°F (49°C)","ru":"120°F (49°C)","tr":"120°F (49°C)","hi":"120°F (49°C)","ar":"120°F (49°C)"},{"en":"150°F (66°C)","es":"150°F (66°C)","ru":"150°F (66°C)","tr":"150°F (66°C)","hi":"150°F (66°C)","ar":"150°F (66°C)"},{"en":"194°F (90°C)","es":"194°F (90°C)","ru":"194°F (90°C)","tr":"194°F (90°C)","hi":"194°F (90°C)","ar":"194°F (90°C)"},{"en":"171°F (77°C)","es":"171°F (77°C)","ru":"171°F (77°C)","tr":"171°F (77°C)","hi":"171°F (77°C)","ar":"171°F (77°C)"}],"e":{"en":"Manual hot-water sanitizing requires immersing items for at least 30 seconds in water held at 171°F (77°C) or hotter.","es":"La desinfección manual con agua caliente requiere sumergir los artículos durante al menos 30 segundos en agua mantenida a 171°F (77°C) o más caliente.","ru":"Ручная дезинфекция горячей водой требует погружения предметов не менее чем на 30 секунд в воду, поддерживаемую при 171°F (77°C) или горячее.","tr":"Manuel sıcak su dezenfeksiyonu, eşyaların 171°F (77°C) veya daha sıcak suda en az 30 saniye daldırılmasını gerektirir.","hi":"मैनुअल गर्म-पानी सैनिटाइज़िंग के लिए वस्तुओं को 171°F (77°C) या उससे अधिक गर्म पानी में कम से कम 30 सेकंड के लिए डुबोना आवश्यक है।","ar":"يتطلب التطهير اليدوي بالماء الساخن غمر الأدوات لمدة 30 ثانية على الأقل في ماء محفوظ عند 171°F (77°C) أو أعلى."}},{"cat":"cleaning","a":1,"q":{"en":"How should the correct concentration of a chemical sanitizer solution be verified?","es":"¿Cómo debe verificarse la concentración correcta de una solución desinfectante química?","ru":"Как следует проверять правильную концентрацию раствора химического дезинфицирующего средства?","tr":"Bir kimyasal dezenfektan çözeltisinin doğru konsantrasyonu nasıl doğrulanmalıdır?","hi":"रासायनिक सैनिटाइज़र घोल की सही सांद्रता को कैसे सत्यापित किया जाना चाहिए?","ar":"كيف ينبغي التحقق من التركيز الصحيح لمحلول مطهِّر كيميائي؟"},"o":[{"en":"By smelling the solution for a strong chemical odor","es":"Oliendo la solución para detectar un fuerte olor químico","ru":"По запаху раствора на наличие сильного химического запаха","tr":"Çözeltiyi güçlü bir kimyasal koku için koklayarak","hi":"तेज़ रासायनिक गंध के लिए घोल को सूंघकर","ar":"بشمّ المحلول للكشف عن رائحة كيميائية قوية"},{"en":"By using a test kit or test strips made for that sanitizer","es":"Usando un kit de prueba o tiras reactivas hechas para ese desinfectante","ru":"С помощью тест-набора или тест-полосок, предназначенных для этого дезинфицирующего средства","tr":"O dezenfektan için yapılmış bir test kiti veya test şeritleri kullanarak","hi":"उस सैनिटाइज़र के लिए बने टेस्ट किट या टेस्ट स्ट्रिप्स का उपयोग करके","ar":"باستخدام مجموعة اختبار أو شرائح اختبار مصنوعة لذلك المطهِّر"},{"en":"By touching it to see if it feels slippery","es":"Tocándola para ver si se siente resbalosa","ru":"На ощупь, проверяя, скользкий ли он","tr":"Kaygan hissedip hissetmediğini anlamak için dokunarak","hi":"यह देखने के लिए उसे छूकर कि वह फिसलन भरा लगता है या नहीं","ar":"بلمسه لمعرفة ما إذا كان ملمسه زلِقاً"},{"en":"By checking that the water looks cloudy","es":"Comprobando que el agua se vea turbia","ru":"Проверяя, выглядит ли вода мутной","tr":"Suyun bulanık görünüp görünmediğini kontrol ederek","hi":"यह जांचकर कि पानी धुंधला दिखता है","ar":"بالتحقق من أن الماء يبدو عكراً"}],"e":{"en":"Sanitizer strength must be checked with the appropriate test kit or test strips, because the correct concentration cannot be judged by sight, smell, or touch.","es":"La concentración del desinfectante debe comprobarse con el kit de prueba o las tiras reactivas apropiadas, porque la concentración correcta no puede juzgarse por la vista, el olor o el tacto.","ru":"Крепость дезинфицирующего средства необходимо проверять с помощью соответствующего тест-набора или тест-полосок, поскольку правильную концентрацию нельзя определить на вид, по запаху или на ощупь.","tr":"Dezenfektan gücü uygun test kiti veya test şeritleriyle kontrol edilmelidir, çünkü doğru konsantrasyon görme, koku veya dokunmayla anlaşılamaz.","hi":"सैनिटाइज़र की मज़बूती को उपयुक्त टेस्ट किट या टेस्ट स्ट्रिप्स से जांचा जाना चाहिए, क्योंकि सही सांद्रता को दृष्टि, गंध या स्पर्श से नहीं आंका जा सकता।","ar":"يجب التحقق من قوة المطهِّر بمجموعة الاختبار أو شرائح الاختبار المناسبة، لأنه لا يمكن الحكم على التركيز الصحيح بالنظر أو الشمّ أو اللمس."}},{"cat":"cleaning","a":2,"q":{"en":"How often should food-contact surfaces be cleaned and sanitized during continuous use with the same food product?","es":"¿Con qué frecuencia deben limpiarse y desinfectarse las superficies en contacto con los alimentos durante el uso continuo con el mismo producto alimenticio?","ru":"Как часто следует очищать и дезинфицировать поверхности, контактирующие с пищей, при непрерывном использовании с одним и тем же пищевым продуктом?","tr":"Aynı gıda ürünüyle sürekli kullanım sırasında, gıdayla temas eden yüzeyler ne sıklıkla temizlenip dezenfekte edilmelidir?","hi":"एक ही खाद्य उत्पाद के साथ निरंतर उपयोग के दौरान खाद्य-संपर्क सतहों को कितनी बार साफ और सैनिटाइज़ किया जाना चाहिए?","ar":"كم مرة يجب تنظيف الأسطح الملامسة للطعام وتطهيرها أثناء الاستخدام المتواصل مع منتج الطعام نفسه؟"},"o":[{"en":"At least every 8 hours","es":"Por lo menos cada 8 horas","ru":"Не реже чем каждые 8 часов","tr":"En az her 8 saatte bir","hi":"कम से कम हर 8 घंटे में","ar":"كل 8 ساعات على الأقل"},{"en":"Once at the end of each shift","es":"Una vez al final de cada turno","ru":"Один раз в конце каждой смены","tr":"Her vardiyanın sonunda bir kez","hi":"प्रत्येक शिफ्ट के अंत में एक बार","ar":"مرة واحدة في نهاية كل وردية"},{"en":"At least every 4 hours","es":"Por lo menos cada 4 horas","ru":"Не реже чем каждые 4 часа","tr":"En az her 4 saatte bir","hi":"कम से कम हर 4 घंटे में","ar":"كل 4 ساعات على الأقل"},{"en":"Only when they look visibly dirty","es":"Solo cuando se vean visiblemente sucias","ru":"Только когда они выглядят явно грязными","tr":"Yalnızca gözle görülür şekilde kirli göründüklerinde","hi":"केवल जब वे दिखाई देने योग्य गंदी दिखें","ar":"فقط عندما تبدو متسخة بشكل مرئي"}],"e":{"en":"Surfaces in constant contact with TCS food must be cleaned and sanitized at least every 4 hours to limit pathogen growth.","es":"Las superficies en contacto constante con alimentos TCS deben limpiarse y desinfectarse por lo menos cada 4 horas para limitar el crecimiento de patógenos.","ru":"Поверхности, находящиеся в постоянном контакте с TCS-продуктами, должны очищаться и дезинфицироваться не реже чем каждые 4 часа, чтобы ограничить рост патогенов.","tr":"TCS gıdayla sürekli temas eden yüzeyler, patojen büyümesini sınırlamak için en az her 4 saatte bir temizlenip dezenfekte edilmelidir.","hi":"TCS भोजन के निरंतर संपर्क में रहने वाली सतहों को रोगजनक वृद्धि को सीमित करने के लिए कम से कम हर 4 घंटे में साफ और सैनिटाइज़ किया जाना चाहिए।","ar":"يجب تنظيف الأسطح الملامسة باستمرار لطعام TCS وتطهيرها كل 4 ساعات على الأقل للحد من نمو مسببات الأمراض."}},{"cat":"cleaning","a":3,"q":{"en":"A cook finishes cutting raw chicken on a board and now needs to slice lettuce. What must be done first?","es":"Un cocinero termina de cortar pollo crudo en una tabla y ahora necesita rebanar lechuga. ¿Qué debe hacerse primero?","ru":"Повар заканчивает резать сырую курицу на доске и теперь должен нарезать салат-латук. Что нужно сделать в первую очередь?","tr":"Bir aşçı bir tahta üzerinde çiğ tavuk kesmeyi bitiriyor ve şimdi marul dilimlemesi gerekiyor. Önce ne yapılmalıdır?","hi":"एक रसोइया एक बोर्ड पर कच्चा चिकन काटना समाप्त करता है और अब उसे सलाद-पत्ता (lettuce) काटने की आवश्यकता है। पहले क्या किया जाना चाहिए?","ar":"ينتهي طاهٍ من تقطيع دجاج نيء على لوح ويحتاج الآن إلى تقطيع الخس. ما الذي يجب فعله أولاً؟"},"o":[{"en":"Rinse the board with cold water and continue","es":"Enjuagar la tabla con agua fría y continuar","ru":"Сполоснуть доску холодной водой и продолжить","tr":"Tahtayı soğuk suyla durulayıp devam etmek","hi":"बोर्ड को ठंडे पानी से रिंस करें और जारी रखें","ar":"شطف اللوح بماء بارد والمتابعة"},{"en":"Just wipe the board with a dry towel and continue","es":"Solo limpiar la tabla con una toalla seca y continuar","ru":"Просто протереть доску сухим полотенцем и продолжить","tr":"Tahtayı yalnızca kuru bir havluyla silip devam etmek","hi":"बोर्ड को बस एक सूखे तौलिए से पोंछें और जारी रखें","ar":"فقط مسح اللوح بمنشفة جافة والمتابعة"},{"en":"Flip the cutting board over and use the other side","es":"Voltear la tabla de cortar y usar el otro lado","ru":"Перевернуть разделочную доску и использовать другую сторону","tr":"Kesme tahtasını ters çevirip diğer tarafını kullanmak","hi":"कटिंग बोर्ड को पलट दें और दूसरी तरफ का उपयोग करें","ar":"قلب لوح التقطيع واستخدام الجانب الآخر"},{"en":"Clean and sanitize the cutting board and knife before cutting the lettuce","es":"Limpiar y desinfectar la tabla de cortar y el cuchillo antes de cortar la lechuga","ru":"Очистить и продезинфицировать разделочную доску и нож перед нарезкой салата-латука","tr":"Marulu kesmeden önce kesme tahtasını ve bıçağı temizleyip dezenfekte etmek","hi":"सलाद-पत्ता काटने से पहले कटिंग बोर्ड और चाकू को साफ और सैनिटाइज़ करें","ar":"تنظيف لوح التقطيع والسكين وتطهيرهما قبل تقطيع الخس"}],"e":{"en":"Food-contact surfaces must be cleaned and sanitized when switching from raw meat to ready-to-eat food to prevent cross-contamination.","es":"Las superficies en contacto con los alimentos deben limpiarse y desinfectarse al cambiar de carne cruda a alimentos listos para comer para evitar la contaminación cruzada.","ru":"Поверхности, контактирующие с пищей, должны очищаться и дезинфицироваться при переходе от сырого мяса к готовым к употреблению продуктам, чтобы предотвратить перекрёстное загрязнение.","tr":"Çapraz bulaşmayı önlemek için, çiğ etten yemeye hazır gıdaya geçerken gıdayla temas eden yüzeyler temizlenmeli ve dezenfekte edilmelidir.","hi":"क्रॉस-कॉन्टैमिनेशन को रोकने के लिए कच्चे मांस से खाने के लिए तैयार भोजन पर स्विच करते समय खाद्य-संपर्क सतहों को साफ और सैनिटाइज़ किया जाना चाहिए।","ar":"يجب تنظيف الأسطح الملامسة للطعام وتطهيرها عند الانتقال من اللحم النيء إلى الطعام الجاهز للأكل لمنع التلوث المتبادل."}},{"cat":"cleaning","a":1,"q":{"en":"Besides every 4 hours of continuous use, when else must a food-contact surface be cleaned and sanitized?","es":"Además de cada 4 horas de uso continuo, ¿en qué otro momento debe limpiarse y desinfectarse una superficie en contacto con los alimentos?","ru":"Помимо каждых 4 часов непрерывного использования, когда ещё необходимо очищать и дезинфицировать поверхность, контактирующую с пищей?","tr":"Her 4 saatlik sürekli kullanımın yanı sıra, gıdayla temas eden bir yüzey başka ne zaman temizlenip dezenfekte edilmelidir?","hi":"निरंतर उपयोग के हर 4 घंटे के अलावा, खाद्य-संपर्क सतह को और कब साफ और सैनिटाइज़ किया जाना चाहिए?","ar":"بخلاف كل 4 ساعات من الاستخدام المتواصل، متى يجب أيضاً تنظيف السطح الملامس للطعام وتطهيره؟"},"o":[{"en":"Only at the very start of the day","es":"Solo al comienzo del día","ru":"Только в самом начале дня","tr":"Yalnızca günün en başında","hi":"केवल दिन की शुरुआत में","ar":"فقط في بداية اليوم تماماً"},{"en":"Whenever you begin working with a different type of food","es":"Cada vez que comience a trabajar con un tipo diferente de alimento","ru":"Каждый раз, когда вы начинаете работать с другим типом пищи","tr":"Farklı bir gıda türüyle çalışmaya başladığınızda her seferinde","hi":"जब भी आप किसी भिन्न प्रकार के भोजन के साथ काम करना शुरू करें","ar":"كلما بدأت العمل بنوع مختلف من الطعام"},{"en":"Only after the surface is visibly greasy","es":"Solo después de que la superficie esté visiblemente grasosa","ru":"Только после того, как поверхность станет явно жирной","tr":"Yalnızca yüzey gözle görülür şekilde yağlandığında","hi":"केवल सतह के दिखाई देने योग्य चिकना होने के बाद","ar":"فقط بعد أن يصبح السطح دهنياً بشكل مرئي"},{"en":"Once per week during deep cleaning","es":"Una vez por semana durante la limpieza profunda","ru":"Один раз в неделю во время генеральной уборки","tr":"Derin temizlik sırasında haftada bir kez","hi":"गहरी सफाई के दौरान सप्ताह में एक बार","ar":"مرة واحدة أسبوعياً أثناء التنظيف العميق"}],"e":{"en":"Surfaces must also be cleaned and sanitized when changing tasks or food types, after any interruption, and at least every 4 hours during continuous use.","es":"Las superficies también deben limpiarse y desinfectarse al cambiar de tarea o de tipo de alimento, después de cualquier interrupción, y por lo menos cada 4 horas durante el uso continuo.","ru":"Поверхности также должны очищаться и дезинфицироваться при смене задач или типов пищи, после любого перерыва, а также не реже чем каждые 4 часа при непрерывном использовании.","tr":"Yüzeyler ayrıca görev veya gıda türü değiştirildiğinde, herhangi bir kesintiden sonra ve sürekli kullanım sırasında en az her 4 saatte bir temizlenip dezenfekte edilmelidir.","hi":"कार्य या खाद्य प्रकार बदलते समय, किसी भी रुकावट के बाद, और निरंतर उपयोग के दौरान कम से कम हर 4 घंटे में भी सतहों को साफ और सैनिटाइज़ किया जाना चाहिए।","ar":"يجب أيضاً تنظيف الأسطح وتطهيرها عند تغيير المهام أو أنواع الطعام، وبعد أي انقطاع، وكل 4 ساعات على الأقل أثناء الاستخدام المتواصل."}},{"cat":"cleaning","a":0,"q":{"en":"At what maximum temperature should refrigerated (cold) TCS food be received at delivery?","es":"¿A qué temperatura máxima debe recibirse un alimento TCS refrigerado (frío) en la entrega?","ru":"При какой максимальной температуре следует принимать охлаждённые (холодные) TCS-продукты при доставке?","tr":"Soğutulmuş (soğuk) TCS gıda teslimat sırasında hangi azami sıcaklıkta teslim alınmalıdır?","hi":"डिलीवरी के समय रेफ्रिजरेटेड (ठंडे) TCS भोजन को अधिकतम किस तापमान पर प्राप्त किया जाना चाहिए?","ar":"عند أي درجة حرارة قصوى ينبغي استلام طعام TCS المبرّد (البارد) عند التوصيل؟"},"o":[{"en":"41°F (5°C) or lower","es":"41°F (5°C) o menos","ru":"41°F (5°C) или ниже","tr":"41°F (5°C) veya daha düşük","hi":"41°F (5°C) या उससे कम","ar":"41°F (5°C) أو أقل"},{"en":"45°F (7°C) or lower","es":"45°F (7°C) o menos","ru":"45°F (7°C) или ниже","tr":"45°F (7°C) veya daha düşük","hi":"45°F (7°C) या उससे कम","ar":"45°F (7°C) أو أقل"},{"en":"50°F (10°C) or lower","es":"50°F (10°C) o menos","ru":"50°F (10°C) или ниже","tr":"50°F (10°C) veya daha düşük","hi":"50°F (10°C) या उससे कम","ar":"50°F (10°C) أو أقل"},{"en":"32°F (0°C) or lower","es":"32°F (0°C) o menos","ru":"32°F (0°C) или ниже","tr":"32°F (0°C) veya daha düşük","hi":"32°F (0°C) या उससे कम","ar":"32°F (0°C) أو أقل"}],"e":{"en":"Cold TCS foods must be received at 41°F (5°C) or below to keep them out of the temperature danger zone.","es":"Los alimentos TCS fríos deben recibirse a 41°F (5°C) o menos para mantenerlos fuera de la zona de peligro de temperatura.","ru":"Холодные TCS-продукты должны приниматься при 41°F (5°C) или ниже, чтобы держать их вне опасной температурной зоны.","tr":"Soğuk TCS gıdalar, tehlikeli sıcaklık bölgesinin dışında tutmak için 41°F (5°C) veya altında teslim alınmalıdır.","hi":"ठंडे TCS भोजन को खतरनाक तापमान क्षेत्र से बाहर रखने के लिए 41°F (5°C) या उससे कम पर प्राप्त किया जाना चाहिए।","ar":"يجب استلام أطعمة TCS الباردة عند 41°F (5°C) أو أقل لإبقائها خارج منطقة الخطر الحرارية."}},{"cat":"cleaning","a":3,"q":{"en":"How should frozen food appear when it is received from a delivery?","es":"¿Cómo debe verse un alimento congelado cuando se recibe de una entrega?","ru":"Как должна выглядеть замороженная пища при получении от доставки?","tr":"Donmuş gıda bir teslimattan alındığında nasıl görünmelidir?","hi":"डिलीवरी से प्राप्त होने पर फ्रोज़न भोजन कैसा दिखना चाहिए?","ar":"كيف ينبغي أن يبدو الطعام المجمّد عند استلامه من التوصيل؟"},"o":[{"en":"Partially thawed but still cold to the touch","es":"Parcialmente descongelado pero todavía frío al tacto","ru":"Частично размороженной, но всё ещё холодной на ощупь","tr":"Kısmen çözülmüş ama hâlâ dokunulduğunda soğuk","hi":"आंशिक रूप से पिघला हुआ लेकिन फिर भी छूने पर ठंडा","ar":"مذاباً جزئياً لكنه لا يزال بارداً عند اللمس"},{"en":"Soft enough to bend the package","es":"Lo suficientemente blando para doblar el empaque","ru":"Достаточно мягкой, чтобы согнуть упаковку","tr":"Paketi bükecek kadar yumuşak","hi":"पैकेज को मोड़ने के लिए पर्याप्त नरम","ar":"ليّناً بما يكفي لثني العبوة"},{"en":"Coated in a thick layer of ice crystals","es":"Cubierto con una capa gruesa de cristales de hielo","ru":"Покрытой толстым слоем кристаллов льда","tr":"Kalın bir buz kristali tabakasıyla kaplı","hi":"बर्फ के क्रिस्टल की एक मोटी परत से ढका हुआ","ar":"مغطّى بطبقة سميكة من بلورات الثلج"},{"en":"Frozen solid, with no signs of thawing or refreezing","es":"Congelado sólido, sin señales de descongelamiento o recongelación","ru":"Полностью замороженной, без признаков размораживания или повторного замораживания","tr":"Çözülme veya yeniden donma belirtisi olmadan, katı şekilde donmuş","hi":"ठोस रूप से जमा हुआ, पिघलने या फिर से जमने के किसी संकेत के बिना","ar":"مجمّداً بالكامل، دون أي علامات على الذوبان أو إعادة التجميد"}],"e":{"en":"Frozen food must be received frozen solid; large ice crystals or fluids/stains on the packaging are signs of thawing and refreezing, and the food should be rejected.","es":"Los alimentos congelados deben recibirse congelados sólidos; los cristales de hielo grandes o los líquidos/manchas en el empaque son señales de descongelamiento y recongelación, y el alimento debe rechazarse.","ru":"Замороженная пища должна приниматься полностью замороженной; крупные кристаллы льда или жидкость/пятна на упаковке являются признаками размораживания и повторного замораживания, и такую пищу следует отклонить.","tr":"Donmuş gıda katı şekilde donmuş olarak teslim alınmalıdır; büyük buz kristalleri veya ambalajdaki sıvılar/lekeler çözülme ve yeniden donma belirtisidir ve gıda reddedilmelidir.","hi":"फ्रोज़न भोजन को ठोस रूप से जमा हुआ प्राप्त किया जाना चाहिए; बड़े बर्फ के क्रिस्टल या पैकेजिंग पर तरल/दाग पिघलने और फिर से जमने के संकेत हैं, और भोजन को अस्वीकार किया जाना चाहिए।","ar":"يجب استلام الطعام المجمّد مجمّداً بالكامل؛ فبلورات الثلج الكبيرة أو السوائل/البقع على العبوة هي علامات على الذوبان وإعادة التجميد، وينبغي رفض الطعام."}},{"cat":"cleaning","a":2,"q":{"en":"Which condition is a valid reason to REJECT a food delivery?","es":"¿Cuál condición es una razón válida para RECHAZAR una entrega de alimentos?","ru":"Какое условие является обоснованной причиной ОТКЛОНИТЬ доставку пищи?","tr":"Hangi durum bir gıda teslimatını REDDETMEK için geçerli bir nedendir?","hi":"कौन सी स्थिति किसी खाद्य डिलीवरी को अस्वीकार (REJECT) करने का एक वैध कारण है?","ar":"أي حالة تُعد سبباً صحيحاً لرفض توصيلة طعام؟"},"o":[{"en":"Boxes that are clean, dry, and intact","es":"Cajas que estén limpias, secas e intactas","ru":"Коробки, которые чистые, сухие и целые","tr":"Temiz, kuru ve sağlam kutular","hi":"ऐसे बॉक्स जो साफ, सूखे और बरकरार हों","ar":"صناديق نظيفة وجافة وسليمة"},{"en":"Cold milk delivered at 40°F","es":"Leche fría entregada a 40°F","ru":"Холодное молоко, доставленное при 40°F","tr":"40°F'de teslim edilen soğuk süt","hi":"40°F पर डिलीवर किया गया ठंडा दूध","ar":"حليب بارد يُسلَّم عند 40°F"},{"en":"Cans that are dented along the seam, swollen, or leaking","es":"Latas que estén abolladas a lo largo del borde, hinchadas o con fugas","ru":"Банки, которые вмяты по шву, вздуты или протекают","tr":"Dikiş boyunca ezik, şişmiş veya sızdıran konserveler","hi":"ऐसे कैन जो सीवन के साथ पिचके हुए, फूले हुए या रिसते हुए हों","ar":"علب مبعوجة على طول الحافة، أو منتفخة، أو مسرّبة"},{"en":"Frozen vegetables that are still solid","es":"Verduras congeladas que todavía estén sólidas","ru":"Замороженные овощи, которые всё ещё твёрдые","tr":"Hâlâ katı olan donmuş sebzeler","hi":"फ्रोज़न सब्ज़ियां जो अभी भी ठोस हों","ar":"خضروات مجمّدة لا تزال صلبة"}],"e":{"en":"Deliveries should be rejected for damaged, swollen, leaking, or seam-dented cans, as well as wrong temperatures, pests, or broken packaging.","es":"Las entregas deben rechazarse por latas dañadas, hinchadas, con fugas o abolladas en el borde, así como por temperaturas incorrectas, plagas o empaques rotos.","ru":"Доставки следует отклонять из-за повреждённых, вздутых, протекающих или вмятых по шву банок, а также из-за неправильной температуры, вредителей или повреждённой упаковки.","tr":"Teslimatlar; hasarlı, şişmiş, sızdıran veya dikişi ezik konserveler için, ayrıca yanlış sıcaklıklar, haşereler veya bozuk ambalaj için reddedilmelidir.","hi":"क्षतिग्रस्त, फूले हुए, रिसते हुए, या सीवन-पिचके हुए कैन, साथ ही गलत तापमान, कीट, या टूटी पैकेजिंग के लिए डिलीवरी को अस्वीकार किया जाना चाहिए।","ar":"ينبغي رفض التوصيلات بسبب العلب التالفة أو المنتفخة أو المسرّبة أو المبعوجة عند الحافة، وكذلك بسبب درجات الحرارة الخاطئة أو الآفات أو التغليف المكسور."}},{"cat":"cleaning","a":0,"q":{"en":"What does the FIFO (First In, First Out) method of stock rotation mean?","es":"¿Qué significa el método FIFO (Primero en Entrar, Primero en Salir) de rotación de existencias?","ru":"Что означает метод ротации запасов FIFO (First In, First Out — «первым пришёл, первым ушёл»)?","tr":"Stok rotasyonunun FIFO (İlk Giren, İlk Çıkar) yöntemi ne anlama gelir?","hi":"स्टॉक रोटेशन की FIFO (First In, First Out) विधि का क्या अर्थ है?","ar":"ماذا تعني طريقة FIFO (الوارد أولاً يخرج أولاً) في تدوير المخزون؟"},"o":[{"en":"Use the food with the earliest use-by date before newer stock","es":"Usar el alimento con la fecha de caducidad más próxima antes que las existencias más nuevas","ru":"Использовать продукт с самым ранним сроком годности раньше более новых запасов","tr":"En erken son kullanma tarihli gıdayı daha yeni stoktan önce kullanmak","hi":"नए स्टॉक से पहले सबसे पहले की use-by तारीख वाले भोजन का उपयोग करें","ar":"استخدام الطعام ذي أقرب تاريخ استخدام قبل المخزون الأحدث"},{"en":"Use the most recently delivered food first","es":"Usar primero el alimento entregado más recientemente","ru":"Использовать самый недавно доставленный продукт первым","tr":"En son teslim edilen gıdayı ilk kullanmak","hi":"सबसे हाल ही में डिलीवर किए गए भोजन का पहले उपयोग करें","ar":"استخدام الطعام الذي تم توصيله مؤخراً أولاً"},{"en":"Store the heaviest items on the lowest shelf","es":"Almacenar los artículos más pesados en el estante más bajo","ru":"Хранить самые тяжёлые предметы на нижней полке","tr":"En ağır eşyaları en alt rafa koymak","hi":"सबसे भारी वस्तुओं को सबसे निचली शेल्फ पर रखें","ar":"تخزين العناصر الأثقل على الرف الأسفل"},{"en":"Throw out all food after one week regardless of date","es":"Desechar todos los alimentos después de una semana sin importar la fecha","ru":"Выбрасывать всю пищу через неделю независимо от даты","tr":"Tarihe bakılmaksızın tüm gıdayı bir hafta sonra atmak","hi":"तारीख की परवाह किए बिना एक सप्ताह के बाद सभी भोजन फेंक दें","ar":"التخلص من كل الطعام بعد أسبوع واحد بغض النظر عن التاريخ"}],"e":{"en":"FIFO means rotating stock so the products with the soonest use-by or expiration dates are used before newer items, reducing spoilage and waste.","es":"FIFO significa rotar las existencias para que los productos con las fechas de caducidad o vencimiento más próximas se usen antes que los artículos más nuevos, reduciendo el deterioro y el desperdicio.","ru":"FIFO означает ротацию запасов так, чтобы продукты с ближайшими сроками годности или истечения использовались раньше более новых, что снижает порчу и отходы.","tr":"FIFO, stoku, en yakın son kullanma veya bitiş tarihli ürünler daha yeni eşyalardan önce kullanılacak şekilde döndürmek anlamına gelir, böylece bozulma ve israf azaltılır.","hi":"FIFO का अर्थ है स्टॉक को इस तरह घुमाना कि सबसे जल्दी की use-by या समाप्ति तारीख वाले उत्पादों का उपयोग नई वस्तुओं से पहले किया जाए, जिससे खराबी और बर्बादी कम हो।","ar":"تعني FIFO تدوير المخزون بحيث تُستخدم المنتجات ذات أقرب تواريخ الاستخدام أو انتهاء الصلاحية قبل العناصر الأحدث، مما يقلل التلف والهدر."}},{"cat":"cleaning","a":1,"q":{"en":"How far off the floor must stored food be kept in a dry or walk-in storage area?","es":"¿A qué distancia del piso deben mantenerse los alimentos almacenados en un área de almacenamiento seco o cámara de refrigeración?","ru":"На какой высоте от пола должна храниться пища в зоне сухого хранения или холодильной камере?","tr":"Kuru veya soğuk hava deposu alanında saklanan gıda zeminden ne kadar yüksekte tutulmalıdır?","hi":"सूखे या वॉक-इन भंडारण क्षेत्र में संग्रहीत भोजन को फर्श से कितना ऊपर रखा जाना चाहिए?","ar":"ما المسافة التي يجب أن يُحفظ بها الطعام المخزّن عن الأرض في منطقة تخزين جافة أو غرفة تبريد؟"},"o":[{"en":"At least 2 inches","es":"Por lo menos 2 pulgadas","ru":"Не менее 2 дюймов","tr":"En az 2 inç","hi":"कम से कम 2 इंच","ar":"2 بوصات على الأقل"},{"en":"At least 6 inches","es":"Por lo menos 6 pulgadas","ru":"Не менее 6 дюймов","tr":"En az 6 inç","hi":"कम से कम 6 इंच","ar":"6 بوصات على الأقل"},{"en":"At least 12 inches","es":"Por lo menos 12 pulgadas","ru":"Не менее 12 дюймов","tr":"En az 12 inç","hi":"कम से कम 12 इंच","ar":"12 بوصة على الأقل"},{"en":"Directly on the floor is acceptable if boxed","es":"Directamente en el piso es aceptable si está en cajas","ru":"Прямо на полу допустимо, если она в коробках","tr":"Kutuluysa doğrudan zeminde olması kabul edilebilir","hi":"यदि बॉक्स में हो तो सीधे फर्श पर रखना स्वीकार्य है","ar":"التخزين مباشرة على الأرض مقبول إذا كان في صناديق"}],"e":{"en":"Food must be stored at least 6 inches off the floor to protect it from contamination, splash, and pests, and to allow cleaning underneath.","es":"Los alimentos deben almacenarse por lo menos 6 pulgadas por encima del piso para protegerlos de la contaminación, las salpicaduras y las plagas, y para permitir la limpieza debajo de ellos.","ru":"Пища должна храниться на высоте не менее 6 дюймов от пола, чтобы защитить её от загрязнения, брызг и вредителей, а также чтобы можно было убирать под ней.","tr":"Gıda, kirlilik, sıçrama ve haşerelerden korumak ve altının temizlenmesine olanak tanımak için zeminden en az 6 inç yüksekte saklanmalıdır.","hi":"भोजन को संदूषण, छींटे और कीटों से बचाने के लिए, और नीचे सफाई की अनुमति देने के लिए फर्श से कम से कम 6 इंच ऊपर संग्रहीत किया जाना चाहिए।","ar":"يجب تخزين الطعام على ارتفاع 6 بوصات على الأقل عن الأرض لحمايته من التلوث والرذاذ والآفات، وللسماح بالتنظيف تحته."}},{"cat":"cleaning","a":3,"q":{"en":"In a cooler holding several raw and ready-to-eat foods, where should raw chicken be stored relative to the other items?","es":"En un refrigerador que contiene varios alimentos crudos y listos para comer, ¿dónde debe almacenarse el pollo crudo en relación con los demás artículos?","ru":"В холодильнике, где хранится несколько сырых и готовых к употреблению продуктов, где следует хранить сырую курицу относительно других продуктов?","tr":"Birkaç çiğ ve yemeye hazır gıda bulunan bir soğutucuda, çiğ tavuk diğer eşyalara göre nereye saklanmalıdır?","hi":"कई कच्चे और खाने के लिए तैयार भोजन रखने वाले कूलर में, कच्चे चिकन को अन्य वस्तुओं के सापेक्ष कहां संग्रहीत किया जाना चाहिए?","ar":"في ثلاجة تحتوي على عدة أطعمة نيئة وجاهزة للأكل، أين ينبغي تخزين الدجاج النيء بالنسبة إلى العناصر الأخرى؟"},"o":[{"en":"On the top shelf, above all other foods","es":"En el estante superior, por encima de todos los demás alimentos","ru":"На верхней полке, над всеми остальными продуктами","tr":"En üst rafa, tüm diğer gıdaların üstüne","hi":"सबसे ऊपरी शेल्फ पर, अन्य सभी भोजन के ऊपर","ar":"على الرف العلوي، فوق جميع الأطعمة الأخرى"},{"en":"On the same shelf as ready-to-eat salads","es":"En el mismo estante que las ensaladas listas para comer","ru":"На той же полке, что и готовые к употреблению салаты","tr":"Yemeye hazır salatalarla aynı rafa","hi":"खाने के लिए तैयार सलाद के समान शेल्फ पर","ar":"على الرف نفسه مع السلطات الجاهزة للأكل"},{"en":"Anywhere, as long as it is wrapped","es":"En cualquier lugar, siempre que esté envuelto","ru":"Где угодно, лишь бы она была завёрнута","tr":"Sarılı olduğu sürece herhangi bir yere","hi":"कहीं भी, जब तक यह लपेटा हुआ है","ar":"في أي مكان، ما دام مغلّفاً"},{"en":"On the bottom shelf, below all ready-to-eat foods","es":"En el estante inferior, por debajo de todos los alimentos listos para comer","ru":"На нижней полке, ниже всех готовых к употреблению продуктов","tr":"En alt rafa, tüm yemeye hazır gıdaların altına","hi":"सबसे निचली शेल्फ पर, सभी खाने के लिए तैयार भोजन के नीचे","ar":"على الرف السفلي، أسفل جميع الأطعمة الجاهزة للأكل"}],"e":{"en":"Raw poultry has the highest cooking temperature requirement and must be stored on the lowest shelf so its juices cannot drip onto ready-to-eat or other raw foods.","es":"El pollo crudo tiene el requisito de temperatura de cocción más alto y debe almacenarse en el estante más bajo para que sus jugos no goteen sobre los alimentos listos para comer u otros alimentos crudos.","ru":"Сырая птица требует самой высокой температуры приготовления и должна храниться на нижней полке, чтобы её соки не могли капать на готовые к употреблению или другие сырые продукты.","tr":"Çiğ kümes hayvanı en yüksek pişirme sıcaklığı gereksinimine sahiptir ve suları yemeye hazır veya diğer çiğ gıdalara damlayamaması için en alt rafa saklanmalıdır.","hi":"कच्चे पोल्ट्री की पकाने के तापमान की आवश्यकता सबसे अधिक होती है और इसे सबसे निचली शेल्फ पर संग्रहीत किया जाना चाहिए ताकि इसका रस खाने के लिए तैयार या अन्य कच्चे भोजन पर न टपके।","ar":"يتطلب الدواجن النيئة أعلى درجة حرارة طهي ويجب تخزينها على الرف الأسفل بحيث لا تستطيع عصارتها التنقيط على الأطعمة الجاهزة للأكل أو الأطعمة النيئة الأخرى."}},{"cat":"cleaning","a":2,"q":{"en":"How should cleaning chemicals and pesticides be stored in relation to food and food equipment?","es":"¿Cómo deben almacenarse los químicos de limpieza y los pesticidas en relación con los alimentos y el equipo de alimentos?","ru":"Как следует хранить чистящие химикаты и пестициды относительно пищи и пищевого оборудования?","tr":"Temizlik kimyasalları ve böcek ilaçları, gıda ve gıda ekipmanına göre nasıl saklanmalıdır?","hi":"सफाई के रसायनों और कीटनाशकों को भोजन और खाद्य उपकरण के संबंध में कैसे संग्रहीत किया जाना चाहिए?","ar":"كيف ينبغي تخزين مواد التنظيف الكيميائية والمبيدات بالنسبة إلى الطعام ومعدات الطعام؟"},"o":[{"en":"On the shelf directly above the food prep table","es":"En el estante directamente arriba de la mesa de preparación de alimentos","ru":"На полке прямо над столом для приготовления пищи","tr":"Gıda hazırlama tezgâhının tam üstündeki rafta","hi":"फूड प्रेप टेबल के ठीक ऊपर की शेल्फ पर","ar":"على الرف مباشرة فوق طاولة تحضير الطعام"},{"en":"Mixed in with dry food storage to save space","es":"Mezclados con el almacenamiento de alimentos secos para ahorrar espacio","ru":"Вперемешку с сухими продуктами, чтобы сэкономить место","tr":"Yerden tasarruf etmek için kuru gıda deposuyla karışık","hi":"जगह बचाने के लिए सूखे भोजन भंडारण के साथ मिलाकर","ar":"مخلوطة مع تخزين الطعام الجاف لتوفير المساحة"},{"en":"In a separate area, below and away from food, utensils, and equipment","es":"En un área separada, por debajo y lejos de los alimentos, los utensilios y el equipo","ru":"В отдельной зоне, ниже еды и отдельно от пищи, посуды и оборудования","tr":"Ayrı bir alanda, gıdanın, mutfak aletlerinin ve ekipmanın altında ve uzağında","hi":"एक अलग क्षेत्र में, भोजन, बर्तनों और उपकरण के नीचे और उनसे दूर","ar":"في منطقة منفصلة، أسفل الطعام والأدوات والمعدات وبعيداً عنها"},{"en":"Inside the walk-in cooler next to the produce","es":"Dentro de la cámara de refrigeración junto a los productos agrícolas","ru":"Внутри холодильной камеры рядом с продуктами","tr":"Soğuk hava deposunun içinde sebzelerin yanında","hi":"वॉक-इन कूलर के अंदर उपज के बगल में","ar":"داخل غرفة التبريد بجوار المنتجات الطازجة"}],"e":{"en":"Chemicals must be stored in a designated area physically separated from and below food, single-use items, and equipment to prevent contamination.","es":"Los químicos deben almacenarse en un área designada físicamente separada de y por debajo de los alimentos, los artículos de un solo uso y el equipo para evitar la contaminación.","ru":"Химикаты должны храниться в специально отведённой зоне, физически отделённой от пищи, одноразовых предметов и оборудования и ниже их, чтобы предотвратить загрязнение.","tr":"Kimyasallar, bulaşmayı önlemek için gıdadan, tek kullanımlık ürünlerden ve ekipmandan fiziksel olarak ayrılmış ve onların altında, belirlenmiş bir alanda saklanmalıdır.","hi":"संदूषण को रोकने के लिए रसायनों को भोजन, एकल-उपयोग वस्तुओं और उपकरण से भौतिक रूप से अलग और उनके नीचे एक निर्दिष्ट क्षेत्र में संग्रहीत किया जाना चाहिए।","ar":"يجب تخزين المواد الكيميائية في منطقة مخصصة منفصلة فيزيائياً عن الطعام والعناصر أحادية الاستخدام والمعدات وأسفلها، لمنع التلوث."}},{"cat":"cleaning","a":1,"q":{"en":"When a cleaning chemical is transferred from its original container into a spray bottle, what must be done?","es":"Cuando un químico de limpieza se transfiere de su recipiente original a una botella rociadora, ¿qué debe hacerse?","ru":"Когда чистящий химикат переливается из его оригинального контейнера в распылитель, что необходимо сделать?","tr":"Bir temizlik kimyasalı orijinal kabından bir sprey şişeye aktarıldığında ne yapılmalıdır?","hi":"जब किसी सफाई रसायन को उसके मूल कंटेनर से एक स्प्रे बोतल में स्थानांतरित किया जाता है, तो क्या किया जाना चाहिए?","ar":"عند نقل مادة كيميائية للتنظيف من حاويتها الأصلية إلى زجاجة رذاذ، ما الذي يجب فعله؟"},"o":[{"en":"Leave it unlabeled since staff will recognize it","es":"Dejarlo sin etiqueta ya que el personal lo reconocerá","ru":"Оставить его без маркировки, так как персонал его узнает","tr":"Personel tanıyacağı için etiketsiz bırakmak","hi":"इसे बिना लेबल के छोड़ दें क्योंकि स्टाफ इसे पहचान लेगा","ar":"تركها دون ملصق لأن الموظفين سيتعرّفون عليها"},{"en":"Label the working container with the common name of the chemical","es":"Etiquetar el recipiente de trabajo con el nombre común del químico","ru":"Промаркировать рабочий контейнер общепринятым названием химиката","tr":"Kullanım kabını kimyasalın yaygın adıyla etiketlemek","hi":"कार्यशील कंटेनर पर रसायन के सामान्य नाम के साथ लेबल लगाएं","ar":"وضع ملصق على حاوية العمل بالاسم الشائع للمادة الكيميائية"},{"en":"Mark it only with the date it was filled","es":"Marcarlo solo con la fecha en que se llenó","ru":"Отметить его только датой заполнения","tr":"Yalnızca dolduruldğu tarihle işaretlemek","hi":"इसे केवल उस तारीख से चिह्नित करें जिस दिन इसे भरा गया था","ar":"تمييزها فقط بتاريخ تعبئتها"},{"en":"Cover any original label so it cannot be read","es":"Cubrir cualquier etiqueta original para que no pueda leerse","ru":"Закрыть любую оригинальную этикетку, чтобы её нельзя было прочитать","tr":"Okunamayacak şekilde orijinal etiketi kapatmak","hi":"किसी भी मूल लेबल को ढक दें ताकि इसे पढ़ा न जा सके","ar":"تغطية أي ملصق أصلي بحيث لا يمكن قراءته"}],"e":{"en":"Any working container of a chemical must be clearly labeled with the common name of its contents to prevent dangerous mix-ups.","es":"Cualquier recipiente de trabajo de un químico debe estar claramente etiquetado con el nombre común de su contenido para evitar confusiones peligrosas.","ru":"Любой рабочий контейнер с химикатом должен быть чётко промаркирован общепринятым названием его содержимого, чтобы предотвратить опасную путаницу.","tr":"Bir kimyasalın herhangi bir kullanım kabı, tehlikeli karışıklıkları önlemek için içindekinin yaygın adıyla açıkça etiketlenmelidir.","hi":"किसी रसायन के किसी भी कार्यशील कंटेनर पर खतरनाक मिश्रण को रोकने के लिए उसकी सामग्री के सामान्य नाम के साथ स्पष्ट रूप से लेबल लगाया जाना चाहिए।","ar":"يجب وضع ملصق واضح على أي حاوية عمل لمادة كيميائية بالاسم الشائع لمحتوياتها لمنع الخلط الخطير."}},{"cat":"cleaning","a":0,"q":{"en":"Which approach best describes effective pest control in a food establishment?","es":"¿Cuál enfoque describe mejor el control eficaz de plagas en un establecimiento de alimentos?","ru":"Какой подход лучше всего описывает эффективную борьбу с вредителями на пищевом предприятии?","tr":"Bir gıda işletmesinde etkili haşere kontrolünü en iyi hangi yaklaşım tanımlar?","hi":"कौन सा दृष्टिकोण किसी खाद्य प्रतिष्ठान में प्रभावी कीट नियंत्रण का सबसे अच्छा वर्णन करता है?","ar":"أي نهج يصف على أفضل نحو مكافحة الآفات الفعّالة في منشأة غذائية؟"},"o":[{"en":"Deny pests access, food, water, and shelter, and work with a licensed pest control operator","es":"Negar a las plagas el acceso, el alimento, el agua y el refugio, y trabajar con un operador de control de plagas con licencia","ru":"Лишить вредителей доступа, пищи, воды и убежища и работать с лицензированным специалистом по борьбе с вредителями","tr":"Haşerelerin erişimini, gıdayı, suyu ve barınağı engellemek ve lisanslı bir haşere kontrol operatörüyle çalışmak","hi":"कीटों को प्रवेश, भोजन, पानी और आश्रय से वंचित करें, और एक लाइसेंस प्राप्त कीट नियंत्रण ऑपरेटर के साथ काम करें","ar":"منع الآفات من الوصول إلى الدخول والطعام والماء والمأوى، والعمل مع مشغّل مكافحة آفات مرخّص"},{"en":"Spray store-bought insecticide over food prep tables daily","es":"Rociar insecticida comprado en tienda sobre las mesas de preparación de alimentos a diario","ru":"Ежедневно распылять купленный в магазине инсектицид на столы для приготовления пищи","tr":"Gıda hazırlama tezgâhlarına her gün marketten alınan böcek ilacı püskürtmek","hi":"फूड प्रेप टेबल पर रोज़ाना दुकान से खरीदा हुआ कीटनाशक छिड़कें","ar":"رشّ مبيد حشري متجري فوق طاولات تحضير الطعام يومياً"},{"en":"Leave doors propped open so pests can leave on their own","es":"Dejar las puertas abiertas para que las plagas se vayan por sí solas","ru":"Оставлять двери открытыми, чтобы вредители могли уйти сами","tr":"Haşerelerin kendi başlarına çıkabilmesi için kapıları açık bırakmak","hi":"दरवाज़ों को खुला छोड़ दें ताकि कीट स्वयं चले जाएं","ar":"ترك الأبواب مفتوحة كي تخرج الآفات من تلقاء نفسها"},{"en":"Ignore droppings unless a live pest is actually seen","es":"Ignorar los excrementos a menos que realmente se vea una plaga viva","ru":"Игнорировать помёт, пока действительно не увидят живого вредителя","tr":"Canlı bir haşere gerçekten görülmedikçe dışkıları görmezden gelmek","hi":"जब तक कोई जीवित कीट वास्तव में दिखाई न दे तब तक मल को अनदेखा करें","ar":"تجاهل الفضلات ما لم تُرَ آفة حية فعلاً"}],"e":{"en":"An integrated pest management program denies pests entry, food, water, and shelter, and relies on a licensed pest control operator (PCO) for treatment; signs like droppings, gnaw marks, or egg cases indicate an infestation.","es":"Un programa de manejo integrado de plagas niega a las plagas la entrada, el alimento, el agua y el refugio, y depende de un operador de control de plagas con licencia (PCO) para el tratamiento; señales como excrementos, marcas de roeduras o cápsulas de huevos indican una infestación.","ru":"Программа интегрированной борьбы с вредителями лишает вредителей доступа, пищи, воды и убежища и полагается на лицензированного специалиста по борьбе с вредителями (PCO) для обработки; такие признаки, как помёт, следы погрызов или яйцекладки, указывают на заражение.","tr":"Entegre bir haşere yönetimi programı haşerelerin girişini, gıdayı, suyu ve barınağı engeller ve tedavi için lisanslı bir haşere kontrol operatörüne (PCO) dayanır; dışkı, kemirme izleri veya yumurta kılıfları gibi belirtiler bir istilaya işaret eder.","hi":"एक एकीकृत कीट प्रबंधन कार्यक्रम कीटों को प्रवेश, भोजन, पानी और आश्रय से वंचित करता है, और उपचार के लिए एक लाइसेंस प्राप्त कीट नियंत्रण ऑपरेटर (PCO) पर निर्भर करता है; मल, कुतरने के निशान, या अंडे के खोल जैसे संकेत संक्रमण का संकेत देते हैं।","ar":"يمنع برنامج الإدارة المتكاملة للآفات الآفات من الدخول والطعام والماء والمأوى، ويعتمد على مشغّل مكافحة آفات مرخّص (PCO) للمعالجة؛ وتشير علامات مثل الفضلات أو آثار القرض أو حافظات البيض إلى وجود إصابة."}},{"cat":"hygiene","a":3,"q":{"en":"What is the correct sequence of steps for proper handwashing?","es":"¿Cuál es la secuencia correcta de pasos para un lavado de manos adecuado?","ru":"Какова правильная последовательность шагов при правильном мытье рук?","tr":"Doğru el yıkamanın adımlarının doğru sırası nedir?","hi":"उचित हाथ धोने के चरणों का सही क्रम क्या है?","ar":"ما التسلسل الصحيح لخطوات غسل اليدين بطريقة سليمة؟"},"o":[{"en":"Dry hands, apply soap, then rinse","es":"Secar las manos, aplicar jabón y luego enjuagar","ru":"Высушить руки, нанести мыло, затем ополоснуть","tr":"Elleri kurula, sabun sür, sonra durula","hi":"हाथ सुखाएं, साबुन लगाएं, फिर धोएं","ar":"جفّف اليدين، ضع الصابون، ثم اشطف"},{"en":"Apply soap first, then wet hands","es":"Aplicar jabón primero y luego mojar las manos","ru":"Сначала нанести мыло, затем намочить руки","tr":"Önce sabun sür, sonra elleri ıslat","hi":"पहले साबुन लगाएं, फिर हाथ गीले करें","ar":"ضع الصابون أولًا ثم بلّل اليدين"},{"en":"Rinse, scrub, then wet","es":"Enjuagar, restregar y luego mojar","ru":"Ополоснуть, потереть, затем намочить","tr":"Durula, ovala, sonra ıslat","hi":"धोएं, रगड़ें, फिर गीला करें","ar":"اشطف، افرك، ثم بلّل"},{"en":"Wet hands, apply soap, scrub, rinse, then dry","es":"Mojar las manos, aplicar jabón, restregar, enjuagar y secar","ru":"Намочить руки, нанести мыло, потереть, ополоснуть, затем высушить","tr":"Elleri ıslat, sabun sür, ovala, durula, sonra kurula","hi":"हाथ गीले करें, साबुन लगाएं, रगड़ें, धोएं, फिर सुखाएं","ar":"بلّل اليدين، ضع الصابون، افرك، اشطف، ثم جفّف"}],"e":{"en":"Proper handwashing is: wet with warm water, apply soap, scrub for 10–15 seconds, rinse, and dry with a single-use towel or air dryer.","es":"El lavado correcto es: mojar con agua tibia, aplicar jabón, restregar de 10 a 15 segundos, enjuagar y secar con toalla de un solo uso o secador de aire.","ru":"Правильное мытьё: смочить тёплой водой, нанести мыло, тереть 10–15 секунд, ополоснуть и высушить одноразовым полотенцем или сушилкой.","tr":"Doğru yıkama: ılık suyla ıslatın, sabun sürün, 10–15 saniye ovalayın, durulayın ve tek kullanımlık havlu ya da hava kurutucuyla kurulayın.","hi":"सही तरीका: गर्म पानी से गीला करें, साबुन लगाएं, 10–15 सेकंड रगड़ें, धोएं और एक-बार-इस्तेमाल तौलिये या एयर ड्रायर से सुखाएं।","ar":"الغسل الصحيح: بلّل بماء دافئ، ضع الصابون، افرك 10–15 ثانية، اشطف، وجفّف بمنديل يُستعمل مرة واحدة أو بمجفف هواء."}},{"cat":"hygiene","a":0,"q":{"en":"Where must a food handler wash their hands?","es":"¿Dónde debe lavarse las manos un manipulador de alimentos?","ru":"Где работник пищевого производства должен мыть руки?","tr":"Bir gıda çalışanı ellerini nerede yıkamalıdır?","hi":"एक फूड हैंडलर को अपने हाथ कहां धोने चाहिए?","ar":"أين يجب على متداول الطعام غسل يديه؟"},"o":[{"en":"At a designated handwashing sink only","es":"Solo en un lavamanos designado","ru":"Только в специальной раковине для мытья рук","tr":"Yalnızca el yıkamaya ayrılmış lavaboda","hi":"केवल निर्दिष्ट हाथ धोने वाले सिंक पर","ar":"في حوض مخصص لغسل اليدين فقط"},{"en":"In the food-prep sink","es":"En el fregadero de preparación de alimentos","ru":"В раковине для приготовления пищи","tr":"Gıda hazırlama evyesinde","hi":"फूड-प्रेप सिंक में","ar":"في حوض تحضير الطعام"},{"en":"In the three-compartment sink","es":"En el fregadero de tres compartimentos","ru":"В трёхсекционной раковине","tr":"Üç bölmeli evyede","hi":"तीन-कम्पार्टमेंट सिंक में","ar":"في الحوض ذي الثلاث حجرات"},{"en":"In any available sink","es":"En cualquier fregadero disponible","ru":"В любой доступной раковине","tr":"Mevcut herhangi bir evyede","hi":"किसी भी उपलब्ध सिंक में","ar":"في أي حوض متاح"}],"e":{"en":"Hands must be washed only at a handwashing sink, never in sinks used for food, dishes, or utensils, to avoid contaminating them.","es":"Las manos deben lavarse solo en un lavamanos, nunca en fregaderos usados para alimentos, platos o utensilios, para no contaminarlos.","ru":"Руки нужно мыть только в раковине для рук, а не в раковинах для еды, посуды или инвентаря, чтобы не загрязнять их.","tr":"Eller yalnızca el yıkama lavabosunda yıkanmalı; kirletmemek için gıda, bulaşık veya alet evyelerinde asla yıkanmamalıdır.","hi":"हाथ केवल हाथ धोने वाले सिंक पर धोने चाहिए, कभी भी भोजन, बर्तन या उपकरण वाले सिंक में नहीं, ताकि वे दूषित न हों।","ar":"يجب غسل اليدين في حوض غسل اليدين فقط، وليس في أحواض الطعام أو الأطباق أو الأدوات حتى لا تتلوث."}},{"cat":"hygiene","a":1,"q":{"en":"After using the restroom, where should a food handler begin washing their hands?","es":"Después de usar el baño, ¿dónde debe empezar a lavarse las manos un manipulador de alimentos?","ru":"После посещения туалета, где работник должен начать мыть руки?","tr":"Tuvaleti kullandıktan sonra bir gıda çalışanı ellerini nerede yıkamaya başlamalıdır?","hi":"शौचालय का उपयोग करने के बाद, एक फूड हैंडलर को हाथ धोना कहां शुरू करना चाहिए?","ar":"بعد استخدام دورة المياه، أين يجب أن يبدأ متداول الطعام غسل يديه؟"},"o":[{"en":"Only at the kitchen handwashing sink","es":"Solo en el lavamanos de la cocina","ru":"Только у раковины на кухне","tr":"Yalnızca mutfaktaki el yıkama lavabosunda","hi":"केवल रसोई के हाथ धोने वाले सिंक पर","ar":"في حوض غسل اليدين بالمطبخ فقط"},{"en":"In the restroom, then again at the kitchen handwashing sink","es":"En el baño y luego otra vez en el lavamanos de la cocina","ru":"В туалете, а затем ещё раз у кухонной раковины","tr":"Tuvalette, sonra tekrar mutfaktaki el yıkama lavabosunda","hi":"शौचालय में, फिर रसोई के हाथ धोने वाले सिंक पर दोबारा","ar":"في دورة المياه، ثم مرة أخرى في حوض غسل اليدين بالمطبخ"},{"en":"Hands only need washing once, in the restroom","es":"Las manos solo se lavan una vez, en el baño","ru":"Руки моют только один раз, в туалете","tr":"Eller sadece bir kez, tuvalette yıkanır","hi":"हाथ केवल एक बार, शौचालय में धोने चाहिए","ar":"تُغسل اليدان مرة واحدة فقط، في دورة المياه"},{"en":"No washing is needed if gloves are worn","es":"No hace falta lavarse si se usan guantes","ru":"Мыть не нужно, если надеты перчатки","tr":"Eldiven giyiliyorsa yıkamaya gerek yok","hi":"यदि दस्ताने पहने हों तो धोने की जरूरत नहीं","ar":"لا حاجة للغسل إذا كانت القفازات مرتدَاة"}],"e":{"en":"Best practice is to wash in the restroom and again at a food-area handwashing sink, since door handles and other surfaces can recontaminate the hands.","es":"Lo mejor es lavarse en el baño y otra vez en un lavamanos del área de alimentos, ya que las manijas y otras superficies pueden volver a contaminar las manos.","ru":"Лучше вымыть руки в туалете и снова у раковины в зоне продуктов, так как дверные ручки и другие поверхности могут заново загрязнить руки.","tr":"En iyisi tuvalette, ardından gıda alanındaki el yıkama lavabosunda tekrar yıkamaktır; çünkü kapı kolları ve diğer yüzeyler elleri yeniden kirletebilir.","hi":"सबसे अच्छा तरीका है शौचालय में और फिर भोजन क्षेत्र के सिंक पर दोबारा धोना, क्योंकि दरवाजे के हैंडल और अन्य सतहें हाथों को फिर से दूषित कर सकती हैं।","ar":"الأفضل الغسل في دورة المياه ثم مرة أخرى في حوض منطقة الطعام، لأن مقابض الأبواب والأسطح الأخرى قد تعيد تلويث اليدين."}},{"cat":"hygiene","a":2,"q":{"en":"How many times may a pair of single-use gloves be used?","es":"¿Cuántas veces se puede usar un par de guantes de un solo uso?","ru":"Сколько раз можно использовать одноразовые перчатки?","tr":"Tek kullanımlık bir çift eldiven kaç kez kullanılabilir?","hi":"एक-बार-इस्तेमाल दस्तानों की एक जोड़ी कितनी बार इस्तेमाल की जा सकती है?","ar":"كم مرة يمكن استخدام زوج من القفازات ذات الاستعمال الواحد؟"},"o":[{"en":"Until they look dirty","es":"Hasta que se vean sucios","ru":"Пока они не станут грязными на вид","tr":"Kirli görünene kadar","hi":"जब तक वे गंदे न दिखें","ar":"حتى تبدو متسخة"},{"en":"For a full shift","es":"Durante todo un turno","ru":"В течение всей смены","tr":"Bütün bir vardiya boyunca","hi":"पूरी शिफ्ट के लिए","ar":"طوال نوبة العمل كاملة"},{"en":"Once, then discard them","es":"Una vez, luego desecharlos","ru":"Один раз, затем выбросить","tr":"Bir kez, sonra atılır","hi":"एक बार, फिर उन्हें फेंक दें","ar":"مرة واحدة، ثم تُرمى"},{"en":"Until you switch food types","es":"Hasta que cambie de tipo de alimento","ru":"Пока не смените вид продукта","tr":"Gıda türünü değiştirene kadar","hi":"जब तक आप भोजन का प्रकार न बदलें","ar":"حتى تغيّر نوع الطعام"}],"e":{"en":"Single-use gloves are worn for one task and then thrown away; they are never washed and reused. Hands are washed before putting on a new pair.","es":"Los guantes de un solo uso se usan para una tarea y luego se desechan; nunca se lavan ni se reutilizan. Las manos se lavan antes de ponerse un par nuevo.","ru":"Одноразовые перчатки используют для одной задачи и выбрасывают; их никогда не моют и не используют повторно. Перед новой парой руки моют.","tr":"Tek kullanımlık eldivenler tek bir iş için giyilir, sonra atılır; asla yıkanıp yeniden kullanılmaz. Yeni çift takmadan önce eller yıkanır.","hi":"एक-बार-इस्तेमाल दस्ताने एक काम के लिए पहने जाते हैं और फिर फेंक दिए जाते हैं; इन्हें कभी धोकर दोबारा इस्तेमाल नहीं किया जाता। नई जोड़ी पहनने से पहले हाथ धोए जाते हैं।","ar":"القفازات ذات الاستعمال الواحد تُلبس لمهمة واحدة ثم تُرمى؛ ولا تُغسل ولا يُعاد استخدامها. وتُغسل اليدان قبل ارتداء زوج جديد."}},{"cat":"hygiene","a":0,"q":{"en":"What does the Food Code say about touching ready-to-eat food with bare hands?","es":"¿Qué dice el Código de Alimentos sobre tocar alimentos listos para comer con las manos desnudas?","ru":"Что говорит Пищевой кодекс о прикосновении к готовой к употреблению пище голыми руками?","tr":"Gıda Kanunu, yenmeye hazır gıdaya çıplak elle dokunma konusunda ne der?","hi":"खाने-के-लिए-तैयार भोजन को नंगे हाथों से छूने के बारे में फूड कोड क्या कहता है?","ar":"ماذا يقول قانون الغذاء بشأن لمس الطعام الجاهز للأكل باليد العارية؟"},"o":[{"en":"It is not allowed; use gloves, tongs, or other utensils","es":"No está permitido; use guantes, pinzas u otros utensilios","ru":"Это запрещено; используйте перчатки, щипцы или другой инвентарь","tr":"İzin verilmez; eldiven, maşa veya başka alet kullanın","hi":"यह अनुमत नहीं है; दस्ताने, चिमटे या अन्य उपकरण उपयोग करें","ar":"غير مسموح؛ استخدم القفازات أو الملقط أو أدوات أخرى"},{"en":"It is fine if hands were just washed","es":"Está bien si acaba de lavarse las manos","ru":"Можно, если руки только что вымыты","tr":"Eller yeni yıkandıysa sorun yok","hi":"ठीक है यदि हाथ अभी धोए गए हों","ar":"لا بأس إذا غُسلت اليدان للتو"},{"en":"It is allowed for cold foods only","es":"Se permite solo para alimentos fríos","ru":"Разрешено только для холодных блюд","tr":"Yalnızca soğuk gıdalar için izin verilir","hi":"केवल ठंडे भोजन के लिए अनुमत है","ar":"مسموح للأطعمة الباردة فقط"},{"en":"It is allowed during busy periods","es":"Se permite en momentos de mucho trabajo","ru":"Разрешено в часы пик","tr":"Yoğun dönemlerde izin verilir","hi":"व्यस्त समय के दौरान अनुमत है","ar":"مسموح في أوقات الازدحام"}],"e":{"en":"Food handlers may not touch ready-to-eat food with bare hands. They must use gloves, tongs, deli tissue, or other utensils as a barrier.","es":"Los manipuladores no deben tocar alimentos listos para comer con las manos desnudas. Deben usar guantes, pinzas, papel de charcutería u otros utensilios como barrera.","ru":"Работники не должны трогать готовую пищу голыми руками. Нужно использовать перчатки, щипцы, бумагу или другой инвентарь как барьер.","tr":"Çalışanlar yenmeye hazır gıdaya çıplak elle dokunamaz. Bariyer olarak eldiven, maşa, kağıt veya başka alet kullanmalıdır.","hi":"फूड हैंडलर खाने-के-लिए-तैयार भोजन को नंगे हाथों से नहीं छू सकते। उन्हें बाधा के रूप में दस्ताने, चिमटे, कागज या अन्य उपकरण उपयोग करने चाहिए।","ar":"لا يجوز للعاملين لمس الطعام الجاهز للأكل باليد العارية. عليهم استخدام القفازات أو الملقط أو الورق أو أدوات أخرى كحاجز."}},{"cat":"hygiene","a":3,"q":{"en":"A food handler notices their glove is torn. What should they do?","es":"Un manipulador de alimentos nota que su guante está roto. ¿Qué debe hacer?","ru":"Работник заметил, что его перчатка порвана. Что ему делать?","tr":"Bir gıda çalışanı eldiveninin yırtıldığını fark ediyor. Ne yapmalı?","hi":"एक फूड हैंडलर देखता है कि उसका दस्ताना फट गया है। उसे क्या करना चाहिए?","ar":"لاحظ متداول طعام أن قفازه ممزق. ماذا يجب أن يفعل؟"},"o":[{"en":"Keep using it until the task is done","es":"Seguir usándolo hasta terminar la tarea","ru":"Продолжать использовать до конца задачи","tr":"İş bitene kadar kullanmaya devam etmek","hi":"काम पूरा होने तक इसका उपयोग जारी रखें","ar":"يواصل استخدامه حتى انتهاء المهمة"},{"en":"Cover the tear with tape","es":"Cubrir el desgarro con cinta","ru":"Заклеить разрыв скотчем","tr":"Yırtığı bantla kapatmak","hi":"फटे हिस्से को टेप से ढकें","ar":"يغطي التمزق بشريط لاصق"},{"en":"Rinse the glove and continue","es":"Enjuagar el guante y continuar","ru":"Сполоснуть перчатку и продолжить","tr":"Eldiveni durulayıp devam etmek","hi":"दस्ताने को धोकर जारी रखें","ar":"يشطف القفاز ويتابع"},{"en":"Remove it, wash hands, and put on a new pair","es":"Quitárselo, lavarse las manos y ponerse un par nuevo","ru":"Снять её, вымыть руки и надеть новую пару","tr":"Çıkarıp elleri yıkamak ve yeni çift takmak","hi":"इसे हटाएं, हाथ धोएं और नई जोड़ी पहनें","ar":"ينزعه، ويغسل يديه، ويرتدي زوجًا جديدًا"}],"e":{"en":"Torn, soiled, or contaminated gloves must be removed. The handler washes their hands and puts on a fresh pair before continuing.","es":"Los guantes rotos, sucios o contaminados deben quitarse. El manipulador se lava las manos y se pone un par nuevo antes de continuar.","ru":"Порванные, грязные или загрязнённые перчатки нужно снять. Работник моет руки и надевает новую пару перед продолжением.","tr":"Yırtık, kirli veya bulaşmış eldivenler çıkarılmalıdır. Çalışan ellerini yıkar ve devam etmeden önce yeni bir çift takar.","hi":"फटे, गंदे या दूषित दस्ताने हटाने चाहिए। हैंडलर हाथ धोता है और जारी रखने से पहले नई जोड़ी पहनता है।","ar":"يجب نزع القفازات الممزقة أو المتسخة أو الملوثة. يغسل العامل يديه ويرتدي زوجًا جديدًا قبل المتابعة."}},{"cat":"hygiene","a":0,"q":{"en":"What does the Food Code say about a food handler wearing nail polish or artificial nails?","es":"¿Qué dice el Código de Alimentos sobre que un manipulador use esmalte de uñas o uñas artificiales?","ru":"Что говорит Пищевой кодекс о лаке для ногтей или искусственных ногтях у работника?","tr":"Gıda Kanunu, bir gıda çalışanının oje ya da takma tırnak takması hakkında ne der?","hi":"नेल पॉलिश या कृत्रिम नाखून पहनने वाले फूड हैंडलर के बारे में फूड कोड क्या कहता है?","ar":"ماذا يقول قانون الغذاء بشأن ارتداء متداول الطعام لطلاء الأظافر أو الأظافر الاصطناعية؟"},"o":[{"en":"They are allowed only if intact gloves are worn","es":"Se permiten solo si se usan guantes intactos","ru":"Разрешены только при использовании целых перчаток","tr":"Yalnızca sağlam eldiven giyilirse izin verilir","hi":"अनुमत हैं केवल यदि सही दस्ताने पहने जाएं","ar":"مسموح بها فقط إذا ارتُديت قفازات سليمة"},{"en":"They are always forbidden","es":"Siempre están prohibidos","ru":"Всегда запрещены","tr":"Her zaman yasaktır","hi":"हमेशा निषिद्ध हैं","ar":"ممنوعة دائمًا"},{"en":"They are fine with no restrictions","es":"Están bien sin restricciones","ru":"Разрешены без ограничений","tr":"Hiçbir kısıtlama olmadan uygundur","hi":"बिना किसी प्रतिबंध के ठीक हैं","ar":"مقبولة دون أي قيود"},{"en":"They are allowed only for servers","es":"Se permiten solo para meseros","ru":"Разрешены только официантам","tr":"Yalnızca servis elemanları için izin verilir","hi":"केवल सर्वर के लिए अनुमत हैं","ar":"مسموح بها لعمال التقديم فقط"}],"e":{"en":"Food handlers may wear nail polish or artificial nails only when wearing intact gloves, because chips or pieces can fall into food and harbor bacteria.","es":"Los manipuladores pueden usar esmalte o uñas artificiales solo con guantes intactos, porque las esquirlas o pedazos pueden caer en los alimentos y albergar bacterias.","ru":"Работники могут носить лак или искусственные ногти только в целых перчатках, так как осколки могут попасть в пищу и содержать бактерии.","tr":"Çalışanlar oje ya da takma tırnağı yalnızca sağlam eldivenle takabilir; çünkü kırıntı veya parçalar gıdaya düşüp bakteri barındırabilir.","hi":"फूड हैंडलर नेल पॉलिश या कृत्रिम नाखून केवल सही दस्ताने पहनकर रख सकते हैं, क्योंकि टुकड़े भोजन में गिर सकते हैं और बैक्टीरिया रख सकते हैं।","ar":"يجوز للعاملين وضع طلاء الأظافر أو الأظافر الاصطناعية فقط عند ارتداء قفازات سليمة، لأن الشظايا قد تسقط في الطعام وتحمل البكتيريا."}},{"cat":"hygiene","a":1,"q":{"en":"What should a food handler do with a dirty apron before using the restroom?","es":"¿Qué debe hacer un manipulador con un delantal sucio antes de usar el baño?","ru":"Что работник должен сделать с грязным фартуком перед посещением туалета?","tr":"Bir gıda çalışanı tuvaleti kullanmadan önce kirli önlüğünü ne yapmalı?","hi":"शौचालय का उपयोग करने से पहले एक फूड हैंडलर को गंदे एप्रन का क्या करना चाहिए?","ar":"ماذا يجب أن يفعل متداول الطعام بمريلته المتسخة قبل استخدام دورة المياه؟"},"o":[{"en":"Keep it on to save time","es":"Dejárselo puesto para ahorrar tiempo","ru":"Оставить его, чтобы сэкономить время","tr":"Zaman kazanmak için üzerinde bırakmak","hi":"समय बचाने के लिए इसे पहने रहें","ar":"يُبقيها عليه لتوفير الوقت"},{"en":"Remove it and leave it in the food area","es":"Quitárselo y dejarlo en el área de alimentos","ru":"Снять и оставить его в зоне продуктов","tr":"Çıkarıp gıda alanında bırakmak","hi":"इसे हटाएं और भोजन क्षेत्र में छोड़ दें","ar":"ينزعها ويتركها في منطقة الطعام"},{"en":"Wear it over their street clothes","es":"Ponérselo sobre la ropa de calle","ru":"Надеть его поверх уличной одежды","tr":"Sokak kıyafetinin üzerine giymek","hi":"इसे अपने बाहरी कपड़ों के ऊपर पहनें","ar":"يرتديها فوق ملابس الخروج"},{"en":"Turn it inside out first","es":"Voltearlo al revés primero","ru":"Сначала вывернуть наизнанку","tr":"Önce ters çevirmek","hi":"पहले इसे उल्टा करें","ar":"يقلبها من الداخل أولًا"}],"e":{"en":"Aprons should be removed and left in the food area, never worn into the restroom, to prevent carrying contaminants back onto food surfaces.","es":"Los delantales deben quitarse y dejarse en el área de alimentos, nunca llevarse al baño, para evitar traer contaminantes de vuelta a las superficies de alimentos.","ru":"Фартук нужно снимать и оставлять в зоне продуктов, а не носить в туалет, чтобы не заносить загрязнения обратно на рабочие поверхности.","tr":"Önlükler çıkarılıp gıda alanında bırakılmalı, asla tuvalete girilirken giyilmemelidir; böylece kirleticiler gıda yüzeylerine geri taşınmaz.","hi":"एप्रन हटाकर भोजन क्षेत्र में छोड़ना चाहिए, कभी भी शौचालय में पहनकर नहीं जाना चाहिए, ताकि दूषक भोजन सतहों पर वापस न आएं।","ar":"يجب نزع المرايل وتركها في منطقة الطعام، وعدم ارتدائها إلى دورة المياه، لمنع نقل الملوثات إلى أسطح الطعام."}},{"cat":"hygiene","a":2,"q":{"en":"Which activity is prohibited for food handlers in food preparation and service areas?","es":"¿Qué actividad está prohibida para los manipuladores en áreas de preparación y servicio de alimentos?","ru":"Какое действие запрещено работникам в зонах приготовления и подачи пищи?","tr":"Gıda hazırlama ve servis alanlarında gıda çalışanları için hangi eylem yasaktır?","hi":"भोजन तैयारी और सेवा क्षेत्रों में फूड हैंडलर के लिए कौन-सी गतिविधि निषिद्ध है?","ar":"أي نشاط محظور على العاملين في مناطق تحضير وتقديم الطعام؟"},"o":[{"en":"Wearing a clean uniform","es":"Usar un uniforme limpio","ru":"Носить чистую форму","tr":"Temiz üniforma giymek","hi":"साफ वर्दी पहनना","ar":"ارتداء زي نظيف"},{"en":"Washing hands frequently","es":"Lavarse las manos con frecuencia","ru":"Часто мыть руки","tr":"Elleri sık yıkamak","hi":"बार-बार हाथ धोना","ar":"غسل اليدين بشكل متكرر"},{"en":"Chewing gum or eating","es":"Masticar chicle o comer","ru":"Жевать жвачку или есть","tr":"Sakız çiğnemek veya yemek yemek","hi":"च्युइंग गम चबाना या खाना","ar":"مضغ العلكة أو الأكل"},{"en":"Using a thermometer","es":"Usar un termómetro","ru":"Использовать термометр","tr":"Termometre kullanmak","hi":"थर्मामीटर का उपयोग करना","ar":"استخدام ميزان حرارة"}],"e":{"en":"Eating, drinking (except from a covered container with a straw in designated areas), smoking, and chewing gum are not allowed where food is prepared, to prevent contamination.","es":"Comer, beber (salvo de un recipiente cubierto con pajilla en áreas designadas), fumar y masticar chicle no se permiten donde se prepara comida, para evitar la contaminación.","ru":"Есть, пить (кроме закрытой ёмкости с трубочкой в отведённых местах), курить и жевать жвачку нельзя там, где готовят пищу, чтобы избежать загрязнения.","tr":"Yemek yemek, içmek (belirli alanlarda pipetli kapalı kap hariç), sigara içmek ve sakız çiğnemek, bulaşmayı önlemek için gıda hazırlanan yerlerde yasaktır.","hi":"भोजन तैयार होने वाली जगह पर खाना, पीना (निर्दिष्ट क्षेत्रों में स्ट्रॉ वाले ढके बर्तन को छोड़कर), धूम्रपान और गम चबाना दूषण रोकने के लिए अनुमत नहीं है।","ar":"الأكل والشرب (باستثناء وعاء مغطى بماصّة في مناطق مخصصة) والتدخين ومضغ العلكة ممنوعة حيث يُحضَّر الطعام لمنع التلوث."}},{"cat":"hygiene","a":3,"q":{"en":"What is the correct way for a cook to taste food while preparing it?","es":"¿Cuál es la forma correcta de que un cocinero pruebe la comida mientras la prepara?","ru":"Как повару правильно пробовать еду во время её приготовления?","tr":"Bir aşçının yemeği hazırlarken tatması için doğru yol nedir?","hi":"भोजन तैयार करते समय रसोइए के लिए इसे चखने का सही तरीका क्या है?","ar":"ما الطريقة الصحيحة ليتذوق الطاهي الطعام أثناء تحضيره؟"},"o":[{"en":"Dip a finger in and taste it","es":"Meter un dedo y probarlo","ru":"Обмакнуть палец и попробовать","tr":"Parmağını batırıp tatmak","hi":"उंगली डुबोकर चखें","ar":"يغمس إصبعه ويتذوق"},{"en":"Taste from the cooking spoon, then keep stirring","es":"Probar con la cuchara de cocinar y seguir revolviendo","ru":"Попробовать с ложки для готовки и продолжить помешивать","tr":"Pişirme kaşığından tadıp karıştırmaya devam etmek","hi":"पकाने वाले चम्मच से चखें, फिर हिलाते रहें","ar":"يتذوق من ملعقة الطهي ثم يواصل التحريك"},{"en":"Pour some back after sipping","es":"Verter un poco de vuelta después de un sorbo","ru":"Отпить и вылить остаток обратно","tr":"Yudumladıktan sonra bir kısmını geri dökmek","hi":"चुस्की के बाद कुछ वापस डालें","ar":"يعيد بعضه بعد رشفة"},{"en":"Use a clean, single-use spoon each time","es":"Usar una cuchara limpia de un solo uso cada vez","ru":"Каждый раз использовать чистую одноразовую ложку","tr":"Her seferinde temiz, tek kullanımlık kaşık kullanmak","hi":"हर बार साफ, एक-बार-इस्तेमाल चम्मच का उपयोग करें","ar":"يستخدم ملعقة نظيفة تُستعمل مرة واحدة في كل مرة"}],"e":{"en":"Food should be tasted with a clean, single-use spoon that is not reused or returned to the food. Never taste with fingers or the stirring utensil.","es":"La comida debe probarse con una cuchara limpia de un solo uso que no se reutilice ni se devuelva al alimento. Nunca pruebe con los dedos ni con el utensilio de revolver.","ru":"Пробовать еду нужно чистой одноразовой ложкой, которую не используют повторно и не возвращают в блюдо. Нельзя пробовать пальцами или ложкой для помешивания.","tr":"Yemek, yeniden kullanılmayan ve gıdaya geri konmayan temiz, tek kullanımlık bir kaşıkla tadılmalıdır. Asla parmakla veya karıştırma aletiyle tadılmaz.","hi":"भोजन को साफ, एक-बार-इस्तेमाल चम्मच से चखना चाहिए जिसे दोबारा इस्तेमाल या भोजन में वापस न डाला जाए। कभी उंगलियों या हिलाने वाले उपकरण से न चखें।","ar":"يجب تذوق الطعام بملعقة نظيفة تُستعمل مرة واحدة ولا يُعاد استخدامها أو وضعها في الطعام. لا تتذوق أبدًا بالأصابع أو بأداة التحريك."}},{"cat":"hygiene","a":0,"q":{"en":"A food handler has a beard. What does the Food Code generally require?","es":"Un manipulador tiene barba. ¿Qué exige generalmente el Código de Alimentos?","ru":"У работника есть борода. Что обычно требует Пищевой кодекс?","tr":"Bir gıda çalışanının sakalı var. Gıda Kanunu genellikle ne gerektirir?","hi":"एक फूड हैंडलर की दाढ़ी है। फूड कोड आमतौर पर क्या आवश्यक करता है?","ar":"لدى متداول طعام لحية. ماذا يتطلب قانون الغذاء عمومًا؟"},"o":[{"en":"Wearing a beard restraint (beard net)","es":"Usar una redecilla para la barba","ru":"Носить сетку для бороды","tr":"Sakal filesi takmak","hi":"दाढ़ी का जाल पहनना","ar":"ارتداء غطاء للحية"},{"en":"Shaving the beard off","es":"Afeitarse la barba","ru":"Сбрить бороду","tr":"Sakalı tıraş etmek","hi":"दाढ़ी मुंडवाना","ar":"حلق اللحية"},{"en":"Nothing, beards are exempt","es":"Nada, las barbas están exentas","ru":"Ничего, бороды не регулируются","tr":"Hiçbir şey, sakallar muaftır","hi":"कुछ नहीं, दाढ़ी को छूट है","ar":"لا شيء، اللحى معفاة"},{"en":"Applying beard oil","es":"Aplicarse aceite para barba","ru":"Наносить масло для бороды","tr":"Sakal yağı sürmek","hi":"दाढ़ी का तेल लगाना","ar":"وضع زيت للحية"}],"e":{"en":"Effective hair restraints include beard restraints. Facial hair must be covered so hair does not fall into food or cause the handler to touch their face.","es":"Los medios eficaces de sujeción del cabello incluyen redecillas para la barba. El vello facial debe cubrirse para que no caiga en la comida ni haga que el manipulador se toque la cara.","ru":"К эффективным средствам защиты волос относятся сетки для бороды. Растительность на лице нужно закрывать, чтобы волосы не падали в пищу.","tr":"Etkili saç örtüleri sakal filelerini de kapsar. Yüz kılları örtülmeli ki saç gıdaya düşmesin veya çalışan yüzüne dokunmasın.","hi":"प्रभावी बाल-आवरण में दाढ़ी के जाल शामिल हैं। चेहरे के बाल ढके जाने चाहिए ताकि बाल भोजन में न गिरें या हैंडलर अपना चेहरा न छुए।","ar":"تشمل وسائل تغطية الشعر الفعالة أغطية اللحية. يجب تغطية شعر الوجه حتى لا يسقط في الطعام أو يدفع العامل للمس وجهه."}},{"cat":"hygiene","a":1,"q":{"en":"Can hand sanitizer be used instead of handwashing?","es":"¿Se puede usar desinfectante de manos en lugar del lavado de manos?","ru":"Можно ли использовать антисептик для рук вместо мытья рук?","tr":"El dezenfektanı, el yıkamanın yerine kullanılabilir mi?","hi":"क्या हाथ धोने के बजाय हैंड सैनिटाइज़र का उपयोग किया जा सकता है?","ar":"هل يمكن استخدام معقّم اليدين بدلًا من غسل اليدين؟"},"o":[{"en":"Yes, sanitizer replaces washing","es":"Sí, el desinfectante reemplaza el lavado","ru":"Да, антисептик заменяет мытьё","tr":"Evet, dezenfektan yıkamanın yerini alır","hi":"हां, सैनिटाइज़र धोने की जगह लेता है","ar":"نعم، المعقّم يحل محل الغسل"},{"en":"No; it may only be used after proper handwashing","es":"No; solo puede usarse después del lavado adecuado","ru":"Нет; его можно применять только после правильного мытья рук","tr":"Hayır; yalnızca doğru el yıkamadan sonra kullanılabilir","hi":"नहीं; इसे केवल उचित हाथ धोने के बाद उपयोग किया जा सकता है","ar":"لا؛ يُستخدم فقط بعد غسل اليدين بطريقة صحيحة"},{"en":"Yes, if hands are not visibly dirty","es":"Sí, si las manos no están visiblemente sucias","ru":"Да, если руки не выглядят грязными","tr":"Evet, eller gözle görülür kirli değilse","hi":"हां, यदि हाथ स्पष्ट रूप से गंदे न हों","ar":"نعم، إذا لم تكن اليدان متسختين بشكل واضح"},{"en":"Yes, but only in the morning","es":"Sí, pero solo por la mañana","ru":"Да, но только утром","tr":"Evet, ama yalnızca sabah","hi":"हां, लेकिन केवल सुबह","ar":"نعم، لكن في الصباح فقط"}],"e":{"en":"Hand sanitizer never replaces handwashing. It may only be applied to hands that have already been properly washed and dried.","es":"El desinfectante nunca reemplaza el lavado de manos. Solo puede aplicarse en manos que ya se lavaron y secaron correctamente.","ru":"Антисептик никогда не заменяет мытьё рук. Его можно наносить только на уже правильно вымытые и высушенные руки.","tr":"El dezenfektanı asla el yıkamanın yerini almaz. Yalnızca zaten doğru şekilde yıkanıp kurulanmış ellere uygulanabilir.","hi":"हैंड सैनिटाइज़र कभी हाथ धोने की जगह नहीं लेता। इसे केवल उन हाथों पर लगाया जा सकता है जो पहले से ठीक से धोए और सुखाए गए हों।","ar":"لا يحل معقّم اليدين محل الغسل أبدًا. يُطبَّق فقط على يدين سبق غسلهما وتجفيفهما بطريقة صحيحة."}},{"cat":"hygiene","a":2,"q":{"en":"A food handler touches their hair and face while working. What must they do next?","es":"Un manipulador se toca el cabello y la cara mientras trabaja. ¿Qué debe hacer a continuación?","ru":"Работник во время работы дотронулся до волос и лица. Что ему делать дальше?","tr":"Bir gıda çalışanı çalışırken saçına ve yüzüne dokunuyor. Sonra ne yapmalı?","hi":"एक फूड हैंडलर काम करते समय अपने बाल और चेहरे को छूता है। उसे आगे क्या करना चाहिए?","ar":"يلمس متداول طعام شعره ووجهه أثناء العمل. ماذا يجب أن يفعل بعد ذلك؟"},"o":[{"en":"Nothing, it is harmless","es":"Nada, es inofensivo","ru":"Ничего, это безвредно","tr":"Hiçbir şey, zararsızdır","hi":"कुछ नहीं, यह हानिरहित है","ar":"لا شيء، فهو غير ضار"},{"en":"Wipe hands on the apron","es":"Limpiarse las manos en el delantal","ru":"Вытереть руки о фартук","tr":"Elleri önlüğe silmek","hi":"हाथ एप्रन पर पोंछें","ar":"يمسح يديه بالمريلة"},{"en":"Wash their hands before handling food again","es":"Lavarse las manos antes de volver a manipular alimentos","ru":"Вымыть руки перед тем, как снова работать с продуктами","tr":"Yeniden gıdaya dokunmadan önce ellerini yıkamak","hi":"फिर से भोजन संभालने से पहले हाथ धोएं","ar":"يغسل يديه قبل ملامسة الطعام مرة أخرى"},{"en":"Rinse hands with water only","es":"Enjuagarse las manos solo con agua","ru":"Ополоснуть руки только водой","tr":"Elleri yalnızca suyla durulamak","hi":"हाथों को केवल पानी से धोएं","ar":"يشطف يديه بالماء فقط"}],"e":{"en":"Touching the hair, face, or body contaminates the hands. The handler must wash hands before returning to food handling.","es":"Tocarse el cabello, la cara o el cuerpo contamina las manos. El manipulador debe lavarse las manos antes de volver a manipular alimentos.","ru":"Прикосновение к волосам, лицу или телу загрязняет руки. Работник должен вымыть руки перед возвращением к продуктам.","tr":"Saça, yüze veya vücuda dokunmak elleri kirletir. Çalışan gıdaya dönmeden önce ellerini yıkamalıdır.","hi":"बाल, चेहरा या शरीर छूने से हाथ दूषित होते हैं। हैंडलर को भोजन संभालने पर लौटने से पहले हाथ धोने चाहिए।","ar":"لمس الشعر أو الوجه أو الجسم يلوّث اليدين. يجب على العامل غسل يديه قبل العودة إلى ملامسة الطعام."}},{"cat":"hygiene","a":3,"q":{"en":"A handwashing sink must supply water at a minimum temperature of about:","es":"Un lavamanos debe suministrar agua a una temperatura mínima de aproximadamente:","ru":"Раковина для мытья рук должна подавать воду с минимальной температурой около:","tr":"El yıkama lavabosu suyu en az yaklaşık kaç derecede sağlamalıdır:","hi":"हाथ धोने वाले सिंक को न्यूनतम लगभग किस तापमान पर पानी देना चाहिए:","ar":"يجب أن يوفر حوض غسل اليدين ماءً بدرجة حرارة لا تقل عن نحو:"},"o":[{"en":"32°F (0°C)","es":"32°F (0°C)","ru":"32°F (0°C)","tr":"32°F (0°C)","hi":"32°F (0°C)","ar":"32°F (0°C)"},{"en":"212°F (100°C)","es":"212°F (100°C)","ru":"212°F (100°C)","tr":"212°F (100°C)","hi":"212°F (100°C)","ar":"212°F (100°C)"},{"en":"41°F (5°C)","es":"41°F (5°C)","ru":"41°F (5°C)","tr":"41°F (5°C)","hi":"41°F (5°C)","ar":"41°F (5°C)"},{"en":"100°F (38°C)","es":"100°F (38°C)","ru":"100°F (38°C)","tr":"100°F (38°C)","hi":"100°F (38°C)","ar":"100°F (38°C)"}],"e":{"en":"The Food Code requires handwashing sinks to deliver water at a minimum of 100°F (38°C) so handlers can wash effectively and comfortably.","es":"El Código exige que los lavamanos suministren agua a un mínimo de 100°F (38°C) para que los manipuladores puedan lavarse de forma eficaz y cómoda.","ru":"Пищевой кодекс требует, чтобы раковины подавали воду не ниже 100°F (38°C), чтобы работники могли мыть руки эффективно и комфортно.","tr":"Gıda Kanunu, çalışanların etkili ve rahat yıkanabilmesi için lavaboların en az 100°F (38°C) su vermesini ister.","hi":"फूड कोड के अनुसार हाथ धोने वाले सिंक को कम से कम 100°F (38°C) पर पानी देना चाहिए ताकि हैंडलर प्रभावी और आराम से धो सकें।","ar":"يشترط القانون أن توفر أحواض غسل اليدين ماءً بحد أدنى 100°F (38°C) حتى يغسل العاملون بفعالية وراحة."}},{"cat":"hygiene","a":0,"q":{"en":"Which is the general Food Code rule about jewelry on the arms and hands during food prep?","es":"¿Cuál es la regla general del Código de Alimentos sobre joyas en brazos y manos durante la preparación?","ru":"Каково общее правило Пищевого кодекса об украшениях на руках при приготовлении пищи?","tr":"Gıda hazırlığı sırasında kol ve ellerdeki takılara ilişkin genel Gıda Kanunu kuralı nedir?","hi":"भोजन तैयारी के दौरान बांहों और हाथों पर आभूषण के बारे में सामान्य फूड कोड नियम क्या है?","ar":"ما القاعدة العامة في قانون الغذاء بشأن المجوهرات على الذراعين واليدين أثناء تحضير الطعام؟"},"o":[{"en":"Remove them; only a plain band ring is generally allowed","es":"Quitárselas; en general solo se permite una alianza lisa","ru":"Снять их; обычно разрешается только гладкое обручальное кольцо","tr":"Çıkarın; genellikle yalnızca düz bir alyans yüzüğe izin verilir","hi":"उन्हें हटा दें; आमतौर पर केवल एक सादा बैंड रिंग अनुमत है","ar":"انزعها؛ يُسمح عمومًا بخاتم أملس فقط"},{"en":"All rings are fine if cleaned","es":"Todos los anillos están bien si se limpian","ru":"Любые кольца допустимы, если их чистят","tr":"Temizlenirse tüm yüzükler uygundur","hi":"सभी अंगूठियां ठीक हैं यदि साफ की जाएं","ar":"كل الخواتم مقبولة إذا نُظّفت"},{"en":"Watches are required","es":"Se requieren relojes","ru":"Часы обязательны","tr":"Kol saati zorunludur","hi":"घड़ियां आवश्यक हैं","ar":"الساعات مطلوبة"},{"en":"Bracelets are encouraged","es":"Se recomiendan las pulseras","ru":"Браслеты рекомендуются","tr":"Bileklikler tavsiye edilir","hi":"कंगन को प्रोत्साहित किया जाता है","ar":"يُشجَّع على الأساور"}],"e":{"en":"During food prep, handlers remove bracelets, watches, and stone rings. Only a plain band ring is generally allowed, since jewelry harbors pathogens and can fall into food.","es":"Durante la preparación, los manipuladores se quitan pulseras, relojes y anillos con piedras. Solo se permite en general una alianza lisa, pues las joyas albergan patógenos y pueden caer en la comida.","ru":"Во время готовки работники снимают браслеты, часы и кольца с камнями. Обычно разрешено только гладкое кольцо, так как украшения содержат патогены и могут попасть в пищу.","tr":"Hazırlık sırasında çalışanlar bileklik, saat ve taşlı yüzükleri çıkarır. Genellikle yalnızca düz bir alyansa izin verilir; çünkü takılar patojen barındırır ve gıdaya düşebilir.","hi":"तैयारी के दौरान हैंडलर कंगन, घड़ियां और नग वाली अंगूठियां हटाते हैं। आमतौर पर केवल सादा बैंड रिंग अनुमत है, क्योंकि आभूषण रोगाणु रखते हैं और भोजन में गिर सकते हैं।","ar":"أثناء التحضير ينزع العاملون الأساور والساعات والخواتم ذات الأحجار. يُسمح عمومًا بخاتم أملس فقط، لأن المجوهرات تحمل مسببات المرض وقد تسقط في الطعام."}},{"cat":"hygiene","a":1,"q":{"en":"When a food handler first arrives to start their shift, what should they do before handling food?","es":"Cuando un manipulador llega para iniciar su turno, ¿qué debe hacer antes de manipular alimentos?","ru":"Когда работник приходит в начале смены, что он должен сделать перед работой с продуктами?","tr":"Bir gıda çalışanı vardiyasına başlamak için ilk geldiğinde gıdaya dokunmadan önce ne yapmalı?","hi":"जब एक फूड हैंडलर अपनी शिफ्ट शुरू करने पहुंचता है, तो भोजन संभालने से पहले उसे क्या करना चाहिए?","ar":"عندما يصل متداول الطعام لبدء نوبته، ماذا يجب أن يفعل قبل ملامسة الطعام؟"},"o":[{"en":"Put on gloves right away","es":"Ponerse guantes de inmediato","ru":"Сразу надеть перчатки","tr":"Hemen eldiven takmak","hi":"तुरंत दस्ताने पहनें","ar":"يرتدي القفازات فورًا"},{"en":"Wash their hands","es":"Lavarse las manos","ru":"Вымыть руки","tr":"Ellerini yıkamak","hi":"अपने हाथ धोएं","ar":"يغسل يديه"},{"en":"Taste the prepared food","es":"Probar la comida preparada","ru":"Попробовать готовую еду","tr":"Hazır yemeği tatmak","hi":"तैयार भोजन चखें","ar":"يتذوق الطعام المُعدّ"},{"en":"Check the schedule","es":"Revisar el horario","ru":"Проверить расписание","tr":"Programı kontrol etmek","hi":"शेड्यूल जांचें","ar":"يتحقق من الجدول"}],"e":{"en":"Handlers must wash their hands when arriving at work and before starting any food task, along with after any activity that contaminates the hands.","es":"Los manipuladores deben lavarse las manos al llegar al trabajo y antes de iniciar cualquier tarea con alimentos, además de tras cualquier actividad que contamine las manos.","ru":"Работники должны мыть руки по приходе на работу и перед началом любой работы с продуктами, а также после действий, загрязняющих руки.","tr":"Çalışanlar işe geldiklerinde ve herhangi bir gıda işine başlamadan önce, ayrıca elleri kirleten her eylemden sonra ellerini yıkamalıdır.","hi":"हैंडलर को काम पर पहुंचने पर और किसी भी भोजन कार्य से पहले, साथ ही हाथ दूषित करने वाली किसी भी गतिविधि के बाद हाथ धोने चाहिए।","ar":"يجب على العاملين غسل أيديهم عند الوصول للعمل وقبل بدء أي مهمة طعام، وكذلك بعد أي نشاط يلوّث اليدين."}},{"cat":"hygiene","a":2,"q":{"en":"How should a food handler dry their hands after washing?","es":"¿Cómo debe secarse las manos un manipulador después de lavárselas?","ru":"Как работник должен сушить руки после мытья?","tr":"Bir gıda çalışanı yıkadıktan sonra ellerini nasıl kurulamalıdır?","hi":"धोने के बाद एक फूड हैंडलर को अपने हाथ कैसे सुखाने चाहिए?","ar":"كيف يجب أن يجفف متداول الطعام يديه بعد الغسل؟"},"o":[{"en":"On their apron or clothing","es":"En su delantal o ropa","ru":"О фартук или одежду","tr":"Önlüğüne veya giysisine","hi":"अपने एप्रन या कपड़ों पर","ar":"على مريلته أو ملابسه"},{"en":"By shaking them in the air","es":"Sacudiéndolas en el aire","ru":"Стряхнув их в воздухе","tr":"Havada sallayarak","hi":"उन्हें हवा में झटककर","ar":"بهزّها في الهواء"},{"en":"With a single-use paper towel or a hand dryer","es":"Con una toalla de papel de un solo uso o un secador de manos","ru":"Одноразовым бумажным полотенцем или сушилкой для рук","tr":"Tek kullanımlık kağıt havlu veya el kurutucusuyla","hi":"एक-बार-इस्तेमाल पेपर टॉवल या हैंड ड्रायर से","ar":"بمنديل ورقي يُستعمل مرة واحدة أو مجفف يدين"},{"en":"With a shared cloth towel","es":"Con una toalla de tela compartida","ru":"Общим тканевым полотенцем","tr":"Ortak bez havluyla","hi":"साझा कपड़े के तौलिये से","ar":"بمنشفة قماش مشتركة"}],"e":{"en":"Hands are dried with a single-use paper towel or an air dryer. Wiping on aprons, clothing, or a shared towel recontaminates clean hands.","es":"Las manos se secan con una toalla de papel de un solo uso o un secador de aire. Secarse en delantales, ropa o una toalla compartida vuelve a contaminar las manos limpias.","ru":"Руки сушат одноразовым бумажным полотенцем или сушилкой. Вытирание о фартук, одежду или общее полотенце заново загрязняет чистые руки.","tr":"Eller tek kullanımlık kağıt havlu veya hava kurutucuyla kurulanır. Önlüğe, giysiye veya ortak havluya silmek temiz elleri yeniden kirletir.","hi":"हाथ एक-बार-इस्तेमाल पेपर टॉवल या एयर ड्रायर से सुखाए जाते हैं। एप्रन, कपड़ों या साझा तौलिये पर पोंछना साफ हाथों को फिर से दूषित करता है।","ar":"تُجفَّف اليدان بمنديل ورقي يُستعمل مرة واحدة أو بمجفف هواء. المسح على المريلة أو الملابس أو منشفة مشتركة يعيد تلويث اليدين النظيفتين."}},{"cat":"hygiene","a":3,"q":{"en":"A cook has a small cut on their hand. How should it be managed before working with food?","es":"Un cocinero tiene un pequeño corte en la mano. ¿Cómo debe manejarse antes de trabajar con alimentos?","ru":"У повара небольшой порез на руке. Как с этим поступить перед работой с продуктами?","tr":"Bir aşçının elinde küçük bir kesik var. Gıdayla çalışmadan önce bu nasıl yönetilmeli?","hi":"एक रसोइए के हाथ पर छोटा कट है। भोजन के साथ काम करने से पहले इसे कैसे संभालना चाहिए?","ar":"لدى طاهٍ جرح صغير في يده. كيف يجب التعامل معه قبل العمل بالطعام؟"},"o":[{"en":"Leave it open to dry","es":"Dejarlo abierto para que seque","ru":"Оставить открытым, чтобы подсох","tr":"Kuruması için açık bırakmak","hi":"सूखने के लिए इसे खुला छोड़ें","ar":"يتركه مكشوفًا ليجف"},{"en":"Just wash the hand more often","es":"Solo lavarse la mano más seguido","ru":"Просто чаще мыть руку","tr":"Sadece eli daha sık yıkamak","hi":"बस हाथ को अधिक बार धोएं","ar":"يكتفي بغسل اليد بشكل أكثر"},{"en":"Cover it with a bandage only","es":"Cubrirlo solo con una venda","ru":"Закрыть только пластырем","tr":"Yalnızca yara bandıyla kapatmak","hi":"केवल पट्टी से ढकें","ar":"يغطيه بضمادة فقط"},{"en":"Cover with a bandage, then a finger cot or glove","es":"Cubrir con una venda y luego un dedil o guante","ru":"Закрыть пластырем, затем напальчником или перчаткой","tr":"Yara bandıyla, sonra parmaklık ya da eldivenle kapatmak","hi":"पट्टी से ढकें, फिर फिंगर कॉट या दस्ताना पहनें","ar":"يغطيه بضمادة ثم كمّ إصبع أو قفاز"}],"e":{"en":"Cuts on the hand are covered with a bandage and then a finger cot or single-use glove, providing a durable, cleanable barrier over the wound.","es":"Los cortes en la mano se cubren con una venda y luego un dedil o guante de un solo uso, creando una barrera duradera y limpiable sobre la herida.","ru":"Порезы на руке закрывают пластырем, а сверху напальчником или одноразовой перчаткой, создавая прочный моющийся барьер над раной.","tr":"El kesikleri yara bandıyla, ardından parmaklık ya da tek kullanımlık eldivenle kapatılır; bu, yara üzerinde dayanıklı, temizlenebilir bir bariyer sağlar.","hi":"हाथ के कट को पट्टी से और फिर फिंगर कॉट या एक-बार-इस्तेमाल दस्ताने से ढका जाता है, जो घाव पर टिकाऊ, साफ करने योग्य बाधा देता है।","ar":"تُغطى جروح اليد بضمادة ثم بكمّ إصبع أو قفاز يُستعمل مرة واحدة، مما يوفر حاجزًا متينًا قابلًا للتنظيف فوق الجرح."}},{"cat":"hygiene","a":0,"q":{"en":"Where are food handlers generally allowed to eat their own meals?","es":"¿Dónde se permite generalmente que los manipuladores coman sus propias comidas?","ru":"Где работникам обычно разрешено есть свою пищу?","tr":"Gıda çalışanlarının kendi yemeklerini yemesine genellikle nerede izin verilir?","hi":"फूड हैंडलर को आमतौर पर अपना भोजन कहां खाने की अनुमति है?","ar":"أين يُسمح عمومًا لمتداولي الطعام بتناول وجباتهم؟"},"o":[{"en":"In a designated break area away from food","es":"En un área de descanso designada lejos de los alimentos","ru":"В отведённой зоне отдыха вдали от продуктов","tr":"Gıdadan uzak, ayrılmış bir mola alanında","hi":"भोजन से दूर एक निर्दिष्ट ब्रेक क्षेत्र में","ar":"في منطقة استراحة مخصصة بعيدًا عن الطعام"},{"en":"At the prep table between tasks","es":"En la mesa de preparación entre tareas","ru":"За разделочным столом между задачами","tr":"Görevler arasında hazırlık masasında","hi":"कार्यों के बीच प्रेप टेबल पर","ar":"على طاولة التحضير بين المهام"},{"en":"At the cook line","es":"En la línea de cocción","ru":"На линии готовки","tr":"Pişirme hattında","hi":"कुक लाइन पर","ar":"عند خط الطهي"},{"en":"Anywhere, if they are quick","es":"En cualquier lugar, si son rápidos","ru":"Где угодно, если быстро","tr":"Hızlı olurlarsa her yerde","hi":"कहीं भी, यदि वे तेज़ हों","ar":"في أي مكان، إن كانوا سريعين"}],"e":{"en":"Employees eat only in designated break areas separated from food, equipment, and utensils, so crumbs, saliva, and hands do not contaminate food.","es":"Los empleados comen solo en áreas de descanso designadas, separadas de alimentos, equipo y utensilios, para que migas, saliva y manos no contaminen la comida.","ru":"Сотрудники едят только в отведённых зонах отдыха, отделённых от продуктов, оборудования и инвентаря, чтобы крошки, слюна и руки не загрязняли пищу.","tr":"Çalışanlar yalnızca gıdadan, ekipmandan ve aletlerden ayrılmış mola alanlarında yemek yer; böylece kırıntılar, tükürük ve eller gıdayı kirletmez.","hi":"कर्मचारी केवल निर्दिष्ट ब्रेक क्षेत्रों में खाते हैं जो भोजन, उपकरण और बर्तनों से अलग होते हैं, ताकि टुकड़े, लार और हाथ भोजन को दूषित न करें।","ar":"يأكل الموظفون فقط في مناطق استراحة مخصصة منفصلة عن الطعام والمعدات والأدوات، حتى لا تلوّث الفتات واللعاب واليدان الطعام."}},{"cat":"hygiene","a":1,"q":{"en":"How may a food handler drink a beverage while on the line, if at all?","es":"¿Cómo puede beber una bebida un manipulador mientras está en la línea, si acaso?","ru":"Как работник может пить напиток на линии, если это вообще разрешено?","tr":"Bir gıda çalışanı hatta çalışırken içeceğini nasıl içebilir, içebilirse?","hi":"यदि अनुमत हो, तो लाइन पर रहते हुए एक फूड हैंडलर पेय कैसे पी सकता है?","ar":"كيف يمكن لمتداول الطعام شرب مشروب أثناء وجوده على الخط، إن أمكن؟"},"o":[{"en":"From any open cup on the counter","es":"De cualquier vaso abierto en la barra","ru":"Из любой открытой чашки на прилавке","tr":"Tezgahtaki herhangi bir açık bardaktan","hi":"काउंटर पर किसी भी खुले कप से","ar":"من أي كوب مفتوح على الطاولة"},{"en":"From a covered container with a straw, stored away from food","es":"De un recipiente cubierto con pajilla, guardado lejos de la comida","ru":"Из закрытой ёмкости с трубочкой, хранящейся вдали от продуктов","tr":"Gıdadan uzakta saklanan, pipetli kapalı bir kaptan","hi":"स्ट्रॉ वाले ढके बर्तन से, भोजन से दूर रखे हुए","ar":"من وعاء مغطى بماصّة، يُحفظ بعيدًا عن الطعام"},{"en":"Drinking is never allowed under any condition","es":"Beber nunca se permite bajo ninguna condición","ru":"Пить не разрешено ни при каких условиях","tr":"İçmeye hiçbir koşulda izin verilmez","hi":"किसी भी स्थिति में पीना कभी अनुमत नहीं है","ar":"الشرب غير مسموح مطلقًا تحت أي ظرف"},{"en":"From a shared water bottle","es":"De una botella de agua compartida","ru":"Из общей бутылки с водой","tr":"Ortak bir su şişesinden","hi":"साझा पानी की बोतल से","ar":"من زجاجة ماء مشتركة"}],"e":{"en":"Some jurisdictions allow drinking from a covered container with a straw or lid, stored away from food and prep surfaces, to prevent hand and food contamination.","es":"Algunas jurisdicciones permiten beber de un recipiente cubierto con pajilla o tapa, guardado lejos de alimentos y superficies de preparación, para evitar contaminar manos y comida.","ru":"В некоторых юрисдикциях разрешено пить из закрытой ёмкости с трубочкой или крышкой, хранящейся вдали от продуктов и поверхностей, чтобы не загрязнять руки и пищу.","tr":"Bazı bölgeler, gıda ve hazırlık yüzeylerinden uzakta saklanan pipetli ya da kapaklı kapalı bir kaptan içmeye izin verir; böylece el ve gıda bulaşması önlenir.","hi":"कुछ अधिकार-क्षेत्र स्ट्रॉ या ढक्कन वाले ढके बर्तन से पीने की अनुमति देते हैं, जो भोजन और प्रेप सतहों से दूर रखा हो, ताकि हाथ और भोजन दूषित न हों।","ar":"تسمح بعض الجهات بالشرب من وعاء مغطى بماصّة أو غطاء، يُحفظ بعيدًا عن الطعام وأسطح التحضير، لمنع تلوث اليدين والطعام."}},{"cat":"hygiene","a":2,"q":{"en":"A food handler sneezes into a tissue while preparing food. What is the next required step?","es":"Un manipulador estornuda en un pañuelo mientras prepara comida. ¿Cuál es el siguiente paso requerido?","ru":"Работник чихнул в салфетку во время приготовления пищи. Какой следующий обязательный шаг?","tr":"Bir gıda çalışanı yemek hazırlarken bir mendile hapşırıyor. Gereken sonraki adım nedir?","hi":"एक फूड हैंडलर भोजन तैयार करते समय टिश्यू में छींकता है। अगला आवश्यक कदम क्या है?","ar":"يعطس متداول طعام في منديل أثناء تحضير الطعام. ما الخطوة المطلوبة التالية؟"},"o":[{"en":"Continue working; a tissue was used","es":"Seguir trabajando; se usó un pañuelo","ru":"Продолжать работу; салфетка была использована","tr":"Çalışmaya devam etmek; mendil kullanıldı","hi":"काम जारी रखें; टिश्यू इस्तेमाल हुआ","ar":"يتابع العمل؛ فقد استُخدم منديل"},{"en":"Rinse hands with water","es":"Enjuagarse las manos con agua","ru":"Ополоснуть руки водой","tr":"Elleri suyla durulamak","hi":"हाथों को पानी से धोएं","ar":"يشطف يديه بالماء"},{"en":"Discard the tissue and wash their hands","es":"Desechar el pañuelo y lavarse las manos","ru":"Выбросить салфетку и вымыть руки","tr":"Mendili atıp ellerini yıkamak","hi":"टिश्यू फेंकें और अपने हाथ धोएं","ar":"يتخلص من المنديل ويغسل يديه"},{"en":"Change gloves without washing","es":"Cambiarse los guantes sin lavarse","ru":"Сменить перчатки без мытья","tr":"Yıkamadan eldiven değiştirmek","hi":"बिना धोए दस्ताने बदलें","ar":"يغيّر القفازات دون غسل"}],"e":{"en":"Coughing or sneezing contaminates the hands even when a tissue is used. The tissue is discarded and hands must be washed before touching food again.","es":"Toser o estornudar contamina las manos incluso al usar un pañuelo. Se desecha el pañuelo y hay que lavarse las manos antes de volver a tocar alimentos.","ru":"Кашель или чихание загрязняет руки, даже если использована салфетка. Салфетку выбрасывают, а руки нужно вымыть перед прикосновением к пище.","tr":"Öksürmek ya da hapşırmak, mendil kullanılsa bile elleri kirletir. Mendil atılır ve gıdaya tekrar dokunmadan önce eller yıkanmalıdır.","hi":"खांसना या छींकना टिश्यू इस्तेमाल करने पर भी हाथ दूषित करता है। टिश्यू फेंका जाता है और भोजन छूने से पहले हाथ धोने चाहिए।","ar":"السعال أو العطس يلوّث اليدين حتى مع استخدام منديل. يُرمى المنديل ويجب غسل اليدين قبل ملامسة الطعام مجددًا."}},{"cat":"hygiene","a":3,"q":{"en":"Do single-use gloves remove the need to wash hands?","es":"¿Los guantes de un solo uso eliminan la necesidad de lavarse las manos?","ru":"Отменяют ли одноразовые перчатки необходимость мыть руки?","tr":"Tek kullanımlık eldivenler el yıkama ihtiyacını ortadan kaldırır mı?","hi":"क्या एक-बार-इस्तेमाल दस्ताने हाथ धोने की आवश्यकता को समाप्त करते हैं?","ar":"هل تُلغي القفازات ذات الاستعمال الواحد الحاجة إلى غسل اليدين؟"},"o":[{"en":"Yes, gloves make washing unnecessary","es":"Sí, los guantes hacen innecesario lavarse","ru":"Да, перчатки делают мытьё ненужным","tr":"Evet, eldiven yıkamayı gereksiz kılar","hi":"हां, दस्ताने धोना अनावश्यक बनाते हैं","ar":"نعم، القفازات تُغني عن الغسل"},{"en":"Yes, as long as gloves are changed","es":"Sí, siempre que se cambien los guantes","ru":"Да, если менять перчатки","tr":"Evet, eldivenler değiştirildiği sürece","hi":"हां, जब तक दस्ताने बदले जाएं","ar":"نعم، ما دامت القفازات تُغيَّر"},{"en":"Yes, gloves are cleaner than skin","es":"Sí, los guantes son más limpios que la piel","ru":"Да, перчатки чище кожи","tr":"Evet, eldiven deriden daha temizdir","hi":"हां, दस्ताने त्वचा से साफ होते हैं","ar":"نعم، القفازات أنظف من الجلد"},{"en":"No; hands must be washed before putting gloves on","es":"No; hay que lavarse las manos antes de ponerse guantes","ru":"Нет; руки нужно мыть перед надеванием перчаток","tr":"Hayır; eldiven takmadan önce eller yıkanmalıdır","hi":"नहीं; दस्ताने पहनने से पहले हाथ धोने चाहिए","ar":"لا؛ يجب غسل اليدين قبل ارتداء القفازات"}],"e":{"en":"Gloves are a supplement, not a substitute, for handwashing. Hands must be washed before gloving up and whenever gloves are changed.","es":"Los guantes son un complemento, no un sustituto, del lavado de manos. Hay que lavarse las manos antes de ponerse guantes y siempre que se cambien.","ru":"Перчатки — дополнение, а не замена мытью рук. Руки нужно мыть перед надеванием перчаток и при каждой их смене.","tr":"Eldivenler el yıkamanın yerine değil, tamamlayıcısıdır. Eldiven takmadan önce ve her değiştirildiğinde eller yıkanmalıdır.","hi":"दस्ताने हाथ धोने के पूरक हैं, विकल्प नहीं। दस्ताने पहनने से पहले और हर बार बदलते समय हाथ धोने चाहिए।","ar":"القفازات مكمّل وليست بديلًا عن غسل اليدين. يجب غسل اليدين قبل ارتداء القفازات وكلما تم تغييرها."}},{"cat":"hygiene","a":0,"q":{"en":"How should a food handler keep their fingernails?","es":"¿Cómo debe mantener sus uñas un manipulador de alimentos?","ru":"Какими работник должен держать свои ногти?","tr":"Bir gıda çalışanı tırnaklarını nasıl tutmalıdır?","hi":"एक फूड हैंडलर को अपने नाखून कैसे रखने चाहिए?","ar":"كيف يجب أن يحافظ متداول الطعام على أظافره؟"},"o":[{"en":"Trimmed short, clean, and smooth","es":"Cortas, limpias y lisas","ru":"Коротко подстриженными, чистыми и гладкими","tr":"Kısa kesilmiş, temiz ve pürüzsüz","hi":"छोटे कटे, साफ और चिकने","ar":"مقصوصة قصيرة ونظيفة وملساء"},{"en":"Long for better grip","es":"Largas para mejor agarre","ru":"Длинными для лучшего захвата","tr":"Daha iyi kavrama için uzun","hi":"बेहतर पकड़ के लिए लंबे","ar":"طويلة لقبضة أفضل"},{"en":"Polished with dark colors","es":"Pintadas con colores oscuros","ru":"Покрытыми тёмным лаком","tr":"Koyu renklerle ojeli","hi":"गहरे रंगों से रंगे","ar":"مطلية بألوان داكنة"},{"en":"Any length is fine","es":"Cualquier largo está bien","ru":"Любая длина допустима","tr":"Her uzunluk uygundur","hi":"कोई भी लंबाई ठीक है","ar":"أي طول مقبول"}],"e":{"en":"Fingernails must be trimmed short, kept clean, and smoothly filed, so dirt and bacteria cannot collect underneath or in rough edges.","es":"Las uñas deben mantenerse cortas, limpias y bien limadas, para que la suciedad y las bacterias no se acumulen debajo ni en bordes ásperos.","ru":"Ногти должны быть коротко подстрижены, чистыми и гладко подпилены, чтобы грязь и бактерии не скапливались под ними или на неровных краях.","tr":"Tırnaklar kısa kesilmeli, temiz tutulmalı ve pürüzsüzce törpülenmelidir; böylece kir ve bakteri altında ya da pürüzlü kenarlarda birikemez.","hi":"नाखून छोटे कटे, साफ और चिकने रखे जाने चाहिए, ताकि गंदगी और बैक्टीरिया उनके नीचे या खुरदरे किनारों में जमा न हों।","ar":"يجب أن تكون الأظافر مقصوصة قصيرة ونظيفة ومبرودة بنعومة، حتى لا تتجمع الأوساخ والبكتيريا تحتها أو في الحواف الخشنة."}},{"cat":"hygiene","a":1,"q":{"en":"May a handwashing sink be used to rinse produce or fill pots?","es":"¿Se puede usar un lavamanos para enjuagar verduras o llenar ollas?","ru":"Можно ли использовать раковину для мытья рук, чтобы мыть овощи или наполнять кастрюли?","tr":"El yıkama lavabosu sebze yıkamak veya tencere doldurmak için kullanılabilir mi?","hi":"क्या हाथ धोने वाले सिंक का उपयोग सब्जियां धोने या बर्तन भरने के लिए किया जा सकता है?","ar":"هل يجوز استخدام حوض غسل اليدين لشطف الخضار أو ملء القدور؟"},"o":[{"en":"Yes, if it is cleaned first","es":"Sí, si se limpia primero","ru":"Да, если сначала его вымыть","tr":"Evet, önce temizlenirse","hi":"हां, यदि इसे पहले साफ किया जाए","ar":"نعم، إذا نُظّف أولًا"},{"en":"No; handwashing sinks are only for washing hands","es":"No; los lavamanos son solo para lavarse las manos","ru":"Нет; раковины для рук предназначены только для мытья рук","tr":"Hayır; el yıkama lavaboları yalnızca el yıkamak içindir","hi":"नहीं; हाथ धोने वाले सिंक केवल हाथ धोने के लिए हैं","ar":"لا؛ أحواض غسل اليدين مخصصة لغسل اليدين فقط"},{"en":"Yes, during busy times","es":"Sí, en momentos de mucho trabajo","ru":"Да, в часы пик","tr":"Evet, yoğun zamanlarda","hi":"हां, व्यस्त समय के दौरान","ar":"نعم، في أوقات الازدحام"},{"en":"Yes, for produce only","es":"Sí, solo para verduras","ru":"Да, только для овощей","tr":"Evet, yalnızca sebze için","hi":"हां, केवल सब्जियों के लिए","ar":"نعم، للخضار فقط"}],"e":{"en":"Handwashing sinks are reserved exclusively for washing hands. Using them to rinse food or fill containers can contaminate the sink and the food.","es":"Los lavamanos se reservan exclusivamente para lavarse las manos. Usarlos para enjuagar alimentos o llenar recipientes puede contaminar el fregadero y la comida.","ru":"Раковины для рук предназначены исключительно для мытья рук. Использование их для мытья продуктов или наполнения ёмкостей может загрязнить раковину и пищу.","tr":"El yıkama lavaboları yalnızca el yıkamaya ayrılmıştır. Gıda yıkamak veya kap doldurmak için kullanmak lavaboyu ve gıdayı kirletebilir.","hi":"हाथ धोने वाले सिंक विशेष रूप से हाथ धोने के लिए आरक्षित हैं। इन्हें भोजन धोने या बर्तन भरने के लिए उपयोग करने से सिंक और भोजन दूषित हो सकते हैं।","ar":"أحواض غسل اليدين مخصصة حصريًا لغسل اليدين. استخدامها لشطف الطعام أو ملء الأوعية قد يلوّث الحوض والطعام."}},{"cat":"hygiene","a":2,"q":{"en":"What is the requirement for a food handler's work clothing?","es":"¿Cuál es el requisito para la ropa de trabajo de un manipulador de alimentos?","ru":"Каково требование к рабочей одежде работника пищевого производства?","tr":"Bir gıda çalışanının iş kıyafetine ilişkin gereklilik nedir?","hi":"एक फूड हैंडलर के काम के कपड़ों के लिए क्या आवश्यकता है?","ar":"ما المطلوب بشأن ملابس عمل متداول الطعام؟"},"o":[{"en":"It only matters that it fits","es":"Solo importa que le quede bien","ru":"Важно только, чтобы она подходила по размеру","tr":"Yalnızca üzerine uyması önemlidir","hi":"केवल यह मायने रखता है कि यह फिट हो","ar":"المهم فقط أن تكون بمقاسه"},{"en":"It may be worn several days without washing","es":"Puede usarse varios días sin lavar","ru":"Её можно носить несколько дней без стирки","tr":"Yıkanmadan birkaç gün giyilebilir","hi":"इसे बिना धोए कई दिन पहना जा सकता है","ar":"يمكن ارتداؤها عدة أيام دون غسل"},{"en":"It must be clean and changed when soiled","es":"Debe estar limpia y cambiarse cuando se ensucie","ru":"Она должна быть чистой и меняться при загрязнении","tr":"Temiz olmalı ve kirlendiğinde değiştirilmelidir","hi":"यह साफ होनी चाहिए और गंदी होने पर बदली जानी चाहिए","ar":"يجب أن تكون نظيفة وتُغيَّر عند اتساخها"},{"en":"It must be white in color","es":"Debe ser de color blanco","ru":"Она должна быть белого цвета","tr":"Beyaz renkte olmalıdır","hi":"यह सफेद रंग की होनी चाहिए","ar":"يجب أن تكون بيضاء اللون"}],"e":{"en":"Work clothing and aprons must be clean and changed whenever they become soiled, since dirty clothing can transfer contaminants to food and surfaces.","es":"La ropa de trabajo y los delantales deben estar limpios y cambiarse cuando se ensucien, ya que la ropa sucia puede transferir contaminantes a alimentos y superficies.","ru":"Рабочая одежда и фартуки должны быть чистыми и меняться при загрязнении, так как грязная одежда может переносить загрязнения на пищу и поверхности.","tr":"İş kıyafeti ve önlükler temiz olmalı ve kirlendiğinde değiştirilmelidir; çünkü kirli giysi gıdaya ve yüzeylere kirletici taşıyabilir.","hi":"काम के कपड़े और एप्रन साफ होने चाहिए और गंदे होने पर बदले जाने चाहिए, क्योंकि गंदे कपड़े भोजन और सतहों पर दूषक स्थानांतरित कर सकते हैं।","ar":"يجب أن تكون ملابس العمل والمرايل نظيفة وأن تُغيَّر عند اتساخها، لأن الملابس المتسخة قد تنقل الملوثات إلى الطعام والأسطح."}},{"cat":"hygiene","a":3,"q":{"en":"After taking out the garbage, what must a food handler do before returning to work?","es":"Después de sacar la basura, ¿qué debe hacer un manipulador antes de volver al trabajo?","ru":"После выноса мусора что работник должен сделать перед возвращением к работе?","tr":"Çöpü çıkardıktan sonra bir gıda çalışanı işe dönmeden önce ne yapmalı?","hi":"कचरा बाहर निकालने के बाद, काम पर लौटने से पहले एक फूड हैंडलर को क्या करना चाहिए?","ar":"بعد إخراج القمامة، ماذا يجب أن يفعل متداول الطعام قبل العودة إلى العمل؟"},"o":[{"en":"Nothing special is needed","es":"No hace falta nada especial","ru":"Ничего особенного не нужно","tr":"Özel bir şey gerekmez","hi":"कुछ खास करने की जरूरत नहीं","ar":"لا حاجة لأي شيء خاص"},{"en":"Put on gloves immediately","es":"Ponerse guantes de inmediato","ru":"Сразу надеть перчатки","tr":"Hemen eldiven takmak","hi":"तुरंत दस्ताने पहनें","ar":"يرتدي القفازات فورًا"},{"en":"Wipe hands on a towel","es":"Limpiarse las manos en una toalla","ru":"Вытереть руки полотенцем","tr":"Elleri bir havluya silmek","hi":"हाथ तौलिये पर पोंछें","ar":"يمسح يديه بمنشفة"},{"en":"Wash their hands","es":"Lavarse las manos","ru":"Вымыть руки","tr":"Ellerini yıkamak","hi":"अपने हाथ धोएं","ar":"يغسل يديه"}],"e":{"en":"Handling garbage contaminates the hands, so the food handler must wash their hands before touching food, utensils, or clean equipment again.","es":"Manejar la basura contamina las manos, por lo que el manipulador debe lavarse las manos antes de volver a tocar alimentos, utensilios o equipo limpio.","ru":"Работа с мусором загрязняет руки, поэтому работник должен вымыть руки перед тем, как снова касаться пищи, инвентаря или чистого оборудования.","tr":"Çöple uğraşmak elleri kirletir; bu yüzden çalışan gıdaya, aletlere veya temiz ekipmana tekrar dokunmadan önce ellerini yıkamalıdır.","hi":"कचरा संभालने से हाथ दूषित होते हैं, इसलिए हैंडलर को भोजन, बर्तन या साफ उपकरण फिर से छूने से पहले हाथ धोने चाहिए।","ar":"مناولة القمامة تلوّث اليدين، لذا يجب على العامل غسل يديه قبل ملامسة الطعام أو الأدوات أو المعدات النظيفة مجددًا."}},{"cat":"hygiene","a":0,"q":{"en":"A food handler wears a plain wedding band. What is the correct practice when putting on gloves?","es":"Un manipulador usa una alianza lisa. ¿Cuál es la práctica correcta al ponerse guantes?","ru":"Работник носит гладкое обручальное кольцо. Какова правильная практика при надевании перчаток?","tr":"Bir gıda çalışanı düz bir alyans takıyor. Eldiven takarken doğru uygulama nedir?","hi":"एक फूड हैंडलर सादा शादी का छल्ला पहनता है। दस्ताने पहनते समय सही तरीका क्या है?","ar":"يرتدي متداول طعام خاتم زواج أملس. ما الممارسة الصحيحة عند ارتداء القفازات؟"},"o":[{"en":"Wash hands, then glove over the plain band","es":"Lavarse las manos y luego enguantarse sobre la alianza lisa","ru":"Вымыть руки, затем надеть перчатку поверх гладкого кольца","tr":"Elleri yıkayıp düz alyansın üzerine eldiven takmak","hi":"हाथ धोएं, फिर सादे छल्ले के ऊपर दस्ताना पहनें","ar":"يغسل يديه ثم يرتدي القفاز فوق الخاتم الأملس"},{"en":"Remove the glove fingers around the ring","es":"Quitar los dedos del guante alrededor del anillo","ru":"Убрать пальцы перчатки вокруг кольца","tr":"Yüzük çevresindeki eldiven parmaklarını çıkarmak","hi":"अंगूठी के आसपास दस्ताने की उंगलियां हटाएं","ar":"يزيل أصابع القفاز حول الخاتم"},{"en":"Skip gloves because a ring is worn","es":"Omitir los guantes porque se usa un anillo","ru":"Не надевать перчатки, потому что надето кольцо","tr":"Yüzük takıldığı için eldiveni atlamak","hi":"अंगूठी पहनने के कारण दस्ताने छोड़ दें","ar":"يتجاوز القفازات بسبب ارتداء الخاتم"},{"en":"Wear the glove without washing hands","es":"Ponerse el guante sin lavarse las manos","ru":"Надеть перчатку без мытья рук","tr":"Elleri yıkamadan eldiven takmak","hi":"बिना हाथ धोए दस्ताना पहनें","ar":"يرتدي القفاز دون غسل اليدين"}],"e":{"en":"A plain band ring is permitted; hands are still washed, then a glove is worn over the ring so the food contact surface stays a clean barrier.","es":"Se permite una alianza lisa; aún así se lavan las manos y luego se pone el guante sobre el anillo para que la superficie de contacto siga siendo una barrera limpia.","ru":"Гладкое кольцо разрешено; руки всё равно моют, затем поверх кольца надевают перчатку, чтобы поверхность контакта оставалась чистым барьером.","tr":"Düz alyansa izin verilir; yine de eller yıkanır, sonra yüzüğün üzerine eldiven takılır; böylece gıdayla temas eden yüzey temiz bir bariyer olarak kalır.","hi":"सादा छल्ला अनुमत है; फिर भी हाथ धोए जाते हैं, फिर अंगूठी के ऊपर दस्ताना पहना जाता है ताकि भोजन-संपर्क सतह साफ बाधा बनी रहे।","ar":"يُسمح بخاتم أملس؛ ومع ذلك تُغسل اليدان، ثم يُرتدى القفاز فوق الخاتم حتى يبقى سطح ملامسة الطعام حاجزًا نظيفًا."}},{"cat":"hygiene","a":1,"q":{"en":"A food handler asks why hair nets are required. What is the best reason?","es":"Un manipulador pregunta por qué se requieren redecillas para el cabello. ¿Cuál es la mejor razón?","ru":"Работник спрашивает, зачем нужны сетки для волос. Какова лучшая причина?","tr":"Bir gıda çalışanı saç fileleri neden gerekli diye soruyor. En iyi neden nedir?","hi":"एक फूड हैंडलर पूछता है कि हेयर नेट क्यों आवश्यक हैं। सबसे अच्छा कारण क्या है?","ar":"يسأل متداول طعام عن سبب اشتراط شبكات الشعر. ما أفضل سبب؟"},"o":[{"en":"To keep hair styled neatly","es":"Para mantener el cabello bien peinado","ru":"Чтобы волосы были аккуратно уложены","tr":"Saçı düzgün tutmak için","hi":"बालों को साफ-सुथरा रखने के लिए","ar":"للحفاظ على تصفيف الشعر بأناقة"},{"en":"To keep hair out of food and reduce touching the hair","es":"Para mantener el cabello fuera de la comida y reducir tocárselo","ru":"Чтобы волосы не попадали в пищу и работник реже трогал их","tr":"Saçı gıdadan uzak tutmak ve saça dokunmayı azaltmak için","hi":"बालों को भोजन से दूर रखने और बाल छूना कम करने के लिए","ar":"لإبقاء الشعر بعيدًا عن الطعام وتقليل لمسه"},{"en":"To meet the dress code only","es":"Solo para cumplir el código de vestimenta","ru":"Только чтобы соблюсти дресс-код","tr":"Yalnızca kıyafet kuralına uymak için","hi":"केवल ड्रेस कोड पूरा करने के लिए","ar":"لتلبية قواعد الزي فقط"},{"en":"To keep the head warm","es":"Para mantener la cabeza caliente","ru":"Чтобы держать голову в тепле","tr":"Başı sıcak tutmak için","hi":"सिर को गर्म रखने के लिए","ar":"لإبقاء الرأس دافئًا"}],"e":{"en":"Hair restraints keep loose hair from falling into food and discourage handlers from touching their hair, both of which prevent contamination.","es":"Los medios de sujeción del cabello evitan que caiga en la comida y desalientan que el manipulador se lo toque, lo que previene la contaminación.","ru":"Сетки не дают волосам падать в пищу и снижают вероятность того, что работник дотронется до волос, что предотвращает загрязнение.","tr":"Saç örtüleri, dökülen saçın gıdaya düşmesini önler ve çalışanı saçına dokunmaktan alıkoyar; her ikisi de bulaşmayı engeller.","hi":"बाल-आवरण खुले बालों को भोजन में गिरने से रोकते हैं और हैंडलर को बाल छूने से हतोत्साहित करते हैं, जो दोनों दूषण रोकते हैं।","ar":"أغطية الشعر تمنع الشعر المتساقط من الوقوع في الطعام وتثني العامل عن لمس شعره، وكلاهما يمنع التلوث."}},{"cat":"hygiene","a":2,"q":{"en":"Why are artificial nails a food safety concern?","es":"¿Por qué las uñas artificiales son una preocupación de seguridad alimentaria?","ru":"Почему искусственные ногти вызывают беспокойство для безопасности пищи?","tr":"Takma tırnaklar neden gıda güvenliği açısından bir endişedir?","hi":"कृत्रिम नाखून खाद्य सुरक्षा की चिंता क्यों हैं?","ar":"لماذا تُعدّ الأظافر الاصطناعية مصدر قلق لسلامة الغذاء؟"},"o":[{"en":"They slow down work","es":"Ralentizan el trabajo","ru":"Они замедляют работу","tr":"İşi yavaşlatır","hi":"वे काम धीमा करते हैं","ar":"تبطئ العمل"},{"en":"They are too expensive","es":"Son demasiado caras","ru":"Они слишком дорогие","tr":"Çok pahalıdır","hi":"वे बहुत महंगे हैं","ar":"باهظة الثمن"},{"en":"They can break off into food and trap bacteria","es":"Pueden desprenderse en la comida y atrapar bacterias","ru":"Они могут отломиться в пищу и удерживать бактерии","tr":"Gıdaya kırılıp düşebilir ve bakteri tutabilir","hi":"वे भोजन में टूटकर गिर सकते हैं और बैक्टीरिया रोक सकते हैं","ar":"قد تنكسر في الطعام وتحبس البكتيريا"},{"en":"They look unprofessional","es":"Se ven poco profesionales","ru":"Они выглядят непрофессионально","tr":"Profesyonelce görünmez","hi":"वे गैर-पेशेवर दिखते हैं","ar":"تبدو غير احترافية"}],"e":{"en":"Artificial nails can break off and become a physical hazard in food, and they trap bacteria underneath, so they may be worn only under intact gloves.","es":"Las uñas artificiales pueden desprenderse y ser un peligro físico en la comida, y atrapan bacterias debajo, por lo que solo pueden usarse bajo guantes intactos.","ru":"Искусственные ногти могут отломиться и стать физической опасностью в пище, а также удерживают бактерии под собой, поэтому их носят только под целыми перчатками.","tr":"Takma tırnaklar kırılıp gıdada fiziksel tehlike oluşturabilir ve altlarında bakteri tutar; bu yüzden yalnızca sağlam eldiven altında takılabilir.","hi":"कृत्रिम नाखून टूटकर भोजन में भौतिक खतरा बन सकते हैं और नीचे बैक्टीरिया रोकते हैं, इसलिए इन्हें केवल सही दस्ताने के नीचे पहना जा सकता है।","ar":"قد تنكسر الأظافر الاصطناعية وتصبح خطرًا فيزيائيًا في الطعام، وتحبس البكتيريا تحتها، لذا لا تُلبس إلا تحت قفازات سليمة."}},{"cat":"hygiene","a":3,"q":{"en":"Who should a food handler notify when they are experiencing symptoms like vomiting or diarrhea?","es":"¿A quién debe notificar un manipulador cuando presenta síntomas como vómitos o diarrea?","ru":"Кого работник должен уведомить при симптомах вроде рвоты или диареи?","tr":"Bir gıda çalışanı kusma ya da ishal gibi belirtiler yaşadığında kime haber vermeli?","hi":"जब एक फूड हैंडलर को उल्टी या दस्त जैसे लक्षण हों तो उसे किसे सूचित करना चाहिए?","ar":"من الذي يجب أن يبلغه متداول الطعام عند إصابته بأعراض مثل القيء أو الإسهال؟"},"o":[{"en":"A coworker on the line","es":"Un compañero en la línea","ru":"Коллегу на линии","tr":"Hattaki bir iş arkadaşı","hi":"लाइन पर एक सहकर्मी","ar":"زميل على الخط"},{"en":"No one, if they feel able to work","es":"A nadie, si se sienten capaces de trabajar","ru":"Никого, если чувствуют, что могут работать","tr":"Çalışabilecek hissediyorsa hiç kimse","hi":"किसी को नहीं, यदि वे काम करने में सक्षम महसूस करें","ar":"لا أحد، إن شعروا بالقدرة على العمل"},{"en":"A customer","es":"Un cliente","ru":"Клиента","tr":"Bir müşteri","hi":"एक ग्राहक","ar":"أحد الزبائن"},{"en":"The person in charge (manager)","es":"La persona a cargo (gerente)","ru":"Ответственное лицо (менеджера)","tr":"Sorumlu kişi (yönetici)","hi":"प्रभारी व्यक्ति (प्रबंधक)","ar":"الشخص المسؤول (المدير)"}],"e":{"en":"Food handlers must report certain symptoms and diagnoses to the person in charge, who then decides whether to restrict or exclude the employee.","es":"Los manipuladores deben informar ciertos síntomas y diagnósticos a la persona a cargo, quien decide si restringe o excluye al empleado.","ru":"Работники должны сообщать об определённых симптомах и диагнозах ответственному лицу, которое решает, ограничить или отстранить сотрудника.","tr":"Çalışanlar belirli belirtileri ve teşhisleri sorumlu kişiye bildirmeli; sorumlu kişi çalışanı kısıtlayıp kısıtlamayacağına ya da işten uzaklaştırıp uzaklaştırmayacağına karar verir.","hi":"हैंडलर को कुछ लक्षण और निदान प्रभारी व्यक्ति को बताने चाहिए, जो फिर तय करता है कि कर्मचारी को प्रतिबंधित करना है या बाहर करना है।","ar":"يجب على العاملين إبلاغ الشخص المسؤول ببعض الأعراض والتشخيصات، الذي يقرر بعدها تقييد الموظف أو استبعاده."}},{"cat":"hygiene","a":0,"q":{"en":"A food handler switches from handling raw meat to plating cooked food. What must happen first?","es":"Un manipulador pasa de manejar carne cruda a emplatar comida cocida. ¿Qué debe ocurrir primero?","ru":"Работник переходит от сырого мяса к сервировке готовой еды. Что должно произойти сначала?","tr":"Bir gıda çalışanı çiğ etle çalışmaktan pişmiş yemeği tabaklamaya geçiyor. Önce ne olmalı?","hi":"एक फूड हैंडलर कच्चे मांस को संभालने से पके भोजन की प्लेटिंग पर जाता है। पहले क्या होना चाहिए?","ar":"ينتقل متداول طعام من مناولة اللحم النيئ إلى تقديم الطعام المطهو. ماذا يجب أن يحدث أولًا؟"},"o":[{"en":"Wash hands and put on clean gloves","es":"Lavarse las manos y ponerse guantes limpios","ru":"Вымыть руки и надеть чистые перчатки","tr":"Elleri yıkayıp temiz eldiven takmak","hi":"हाथ धोएं और साफ दस्ताने पहनें","ar":"يغسل يديه ويرتدي قفازات نظيفة"},{"en":"Rinse gloves under water","es":"Enjuagar los guantes bajo el agua","ru":"Сполоснуть перчатки под водой","tr":"Eldivenleri suyun altında durulamak","hi":"दस्तानों को पानी के नीचे धोएं","ar":"يشطف القفازات تحت الماء"},{"en":"Change aprons only","es":"Cambiarse solo el delantal","ru":"Сменить только фартук","tr":"Yalnızca önlüğü değiştirmek","hi":"केवल एप्रन बदलें","ar":"يغيّر المريلة فقط"},{"en":"Nothing, the food is already cooked","es":"Nada, la comida ya está cocida","ru":"Ничего, еда уже приготовлена","tr":"Hiçbir şey, yemek zaten pişmiş","hi":"कुछ नहीं, भोजन पहले से पका है","ar":"لا شيء، فالطعام مطهو بالفعل"}],"e":{"en":"Switching from raw meat to ready-to-eat food requires washing hands and putting on clean gloves to prevent transferring pathogens from the raw product.","es":"Pasar de carne cruda a alimentos listos para comer exige lavarse las manos y ponerse guantes limpios para evitar transferir patógenos del producto crudo.","ru":"Переход от сырого мяса к готовой пище требует мытья рук и чистых перчаток, чтобы не перенести патогены с сырого продукта.","tr":"Çiğ etten yenmeye hazır gıdaya geçmek, çiğ üründeki patojenleri taşımamak için elleri yıkamayı ve temiz eldiven takmayı gerektirir.","hi":"कच्चे मांस से खाने-के-लिए-तैयार भोजन पर जाने के लिए हाथ धोना और साफ दस्ताने पहनना आवश्यक है ताकि कच्चे उत्पाद से रोगाणु स्थानांतरित न हों।","ar":"الانتقال من اللحم النيئ إلى الطعام الجاهز للأكل يتطلب غسل اليدين وارتداء قفازات نظيفة لمنع نقل مسببات المرض من المنتج النيئ."}},{"cat":"hygiene","a":1,"q":{"en":"A food handler has an open, infected sore on their forearm that keeps weeping. What is the appropriate action?","es":"Un manipulador tiene una llaga abierta e infectada en el antebrazo que sigue supurando. ¿Cuál es la acción adecuada?","ru":"У работника открытая инфицированная язва на предплечье, которая мокнет. Каково правильное действие?","tr":"Bir gıda çalışanının önkolunda akıntısı devam eden açık, iltihaplı bir yara var. Uygun eylem nedir?","hi":"एक फूड हैंडलर के अग्रबाहु पर खुला, संक्रमित घाव है जो रिसता रहता है। उचित कार्रवाई क्या है?","ar":"لدى متداول طعام قرحة مفتوحة ملتهبة على ساعده تستمر في النزّ. ما الإجراء المناسب؟"},"o":[{"en":"Let them keep working with a bandage","es":"Dejarlo seguir trabajando con una venda","ru":"Позволить продолжать работать с повязкой","tr":"Bir bandajla çalışmasına devam etmesine izin vermek","hi":"पट्टी के साथ उसे काम करने दें","ar":"يتركه يعمل بضمادة"},{"en":"Restrict or exclude them until it is properly covered or healed","es":"Restringirlo o excluirlo hasta que esté bien cubierta o sanada","ru":"Ограничить или отстранить его, пока рана не будет закрыта или заживёт","tr":"Yara düzgün kapatılana ya da iyileşene kadar onu kısıtlamak veya işten uzaklaştırmak","hi":"जब तक इसे ठीक से ढका या भर न जाए, उसे प्रतिबंधित या बाहर करें","ar":"يقيده أو يستبعده حتى تُغطّى بشكل سليم أو تُشفى"},{"en":"Move them to dishwashing with the sore uncovered","es":"Pasarlo a lavar platos con la llaga descubierta","ru":"Перевести на мытьё посуды с открытой раной","tr":"Yarası açıkken bulaşıkçılığa geçirmek","hi":"घाव खुला रखकर उसे बर्तन धोने पर भेजें","ar":"ينقله إلى غسل الأطباق والقرحة مكشوفة"},{"en":"Ignore it if it does not hurt","es":"Ignorarla si no duele","ru":"Игнорировать, если не болит","tr":"Ağrımıyorsa görmezden gelmek","hi":"यदि दर्द न हो तो इसे अनदेखा करें","ar":"يتجاهلها إن لم تكن مؤلمة"}],"e":{"en":"An open, weeping infected wound that cannot be reliably covered means the employee is restricted or excluded until it is properly covered with an impermeable barrier or healed.","es":"Una herida infectada, abierta y supurante que no puede cubrirse de forma confiable implica restringir o excluir al empleado hasta que se cubra con una barrera impermeable o sane.","ru":"Открытая мокнущая инфицированная рана, которую нельзя надёжно закрыть, означает, что сотрудника ограничивают или отстраняют, пока рана не будет закрыта непроницаемым барьером или не заживёт.","tr":"Güvenilir biçimde kapatılamayan açık, akıntılı ve iltihaplı bir yara, çalışanın geçirimsiz bir bariyerle düzgün kapatılana ya da iyileşene kadar kısıtlanması veya işten uzaklaştırılması demektir.","hi":"खुला, रिसता संक्रमित घाव जिसे भरोसेमंद तरीके से ढका न जा सके, का अर्थ है कर्मचारी को तब तक प्रतिबंधित या बाहर करना जब तक इसे अभेद्य बाधा से ढका या भर न जाए।","ar":"الجرح المفتوح النازّ الملتهب الذي لا يمكن تغطيته بشكل موثوق يعني تقييد الموظف أو استبعاده حتى يُغطّى بحاجز غير منفذ أو يُشفى."}},{"cat":"temp","a":3,"q":{"en":"What temperature range does the FDA Food Code define as the temperature danger zone?","es":"¿Qué rango de temperatura define el Código de Alimentos de la FDA como zona de peligro de temperatura?","ru":"Какой диапазон температур Пищевой кодекс FDA определяет как температурную опасную зону?","tr":"FDA Gıda Kanunu, sıcaklık tehlike bölgesini hangi sıcaklık aralığı olarak tanımlar?","hi":"एफडीए फूड कोड तापमान खतरनाक क्षेत्र को किस तापमान सीमा के रूप में परिभाषित करता है?","ar":"ما نطاق درجة الحرارة الذي يعرّفه قانون الغذاء (FDA) كمنطقة خطر درجة الحرارة؟"},"o":[{"en":"0°F to 32°F (-18°C to 0°C)","es":"0°F a 32°F (-18°C a 0°C)","ru":"0°F до 32°F (-18°C до 0°C)","tr":"0°F–32°F (-18°C–0°C)","hi":"0°F से 32°F (-18°C से 0°C)","ar":"0°F إلى 32°F (-18°C إلى 0°C)"},{"en":"70°F to 125°F (21°C to 52°C)","es":"70°F a 125°F (21°C a 52°C)","ru":"70°F до 125°F (21°C до 52°C)","tr":"70°F–125°F (21°C–52°C)","hi":"70°F से 125°F (21°C से 52°C)","ar":"70°F إلى 125°F (21°C إلى 52°C)"},{"en":"32°F to 100°F (0°C to 38°C)","es":"32°F a 100°F (0°C a 38°C)","ru":"32°F до 100°F (0°C до 38°C)","tr":"32°F–100°F (0°C–38°C)","hi":"32°F से 100°F (0°C से 38°C)","ar":"32°F إلى 100°F (0°C إلى 38°C)"},{"en":"41°F to 135°F (5°C to 57°C)","es":"41°F a 135°F (5°C a 57°C)","ru":"41°F до 135°F (5°C до 57°C)","tr":"41°F–135°F (5°C–57°C)","hi":"41°F से 135°F (5°C से 57°C)","ar":"41°F إلى 135°F (5°C إلى 57°C)"}],"e":{"en":"The danger zone is 41°F to 135°F (5°C to 57°C). TCS foods held in this range let pathogens grow rapidly, so time in the zone must be minimized.","es":"La zona de peligro es de 41°F a 135°F (5°C a 57°C). Los alimentos TCS en este rango permiten que los patógenos crezcan rápido, por lo que hay que minimizar el tiempo en la zona.","ru":"Опасная зона — от 41°F до 135°F (5°C до 57°C). В этом диапазоне патогены в TCS-продуктах быстро растут, поэтому время в зоне нужно минимизировать.","tr":"Tehlike bölgesi 41°F–135°F (5°C–57°C) arasıdır. Bu aralıkta tutulan TCS gıdalarda patojenler hızla ürer; bu nedenle bölgede geçen süre en aza indirilmelidir.","hi":"खतरनाक क्षेत्र 41°F से 135°F (5°C से 57°C) है। इस सीमा में रखे TCS भोजन में रोगाणु तेजी से बढ़ते हैं, इसलिए इस क्षेत्र में समय कम रखना चाहिए।","ar":"منطقة الخطر هي 41°F إلى 135°F (5°C إلى 57°C). أطعمة TCS المحفوظة ضمن هذا النطاق تسمح بنمو المسببات المرضية بسرعة، لذا يجب تقليل الوقت داخل المنطقة."}},{"cat":"temp","a":0,"q":{"en":"Chicken breasts must be cooked to a minimum internal temperature of 165°F for how long?","es":"Las pechugas de pollo deben cocinarse a una temperatura interna mínima de 165°F ¿por cuánto tiempo?","ru":"Куриные грудки нужно готовить до минимальной внутренней температуры 165°F в течение какого времени?","tr":"Tavuk göğsü en az 165°F iç sıcaklığa ne kadar süreyle pişirilmelidir?","hi":"चिकन ब्रेस्ट को न्यूनतम आंतरिक तापमान 165°F पर कितनी देर तक पकाना चाहिए?","ar":"يجب طهي صدور الدجاج إلى درجة حرارة داخلية لا تقل عن 165°F لمدة كم؟"},"o":[{"en":"1 second (instantaneous)","es":"1 segundo (instantáneo)","ru":"1 секунда (мгновенно)","tr":"1 saniye (anlık)","hi":"1 सेकंड (तत्काल)","ar":"ثانية واحدة (لحظيًا)"},{"en":"3 minutes","es":"3 minutos","ru":"3 минуты","tr":"3 dakika","hi":"3 मिनट","ar":"3 دقائق"},{"en":"15 seconds","es":"15 segundos","ru":"15 секунд","tr":"15 saniye","hi":"15 सेकंड","ar":"15 ثانية"},{"en":"10 minutes","es":"10 minutos","ru":"10 минут","tr":"10 dakika","hi":"10 मिनट","ar":"10 دقائق"}],"e":{"en":"Poultry must reach 165°F (74°C) held for at least 1 second (instantaneous). This kills Salmonella and other pathogens common in poultry.","es":"Las aves deben alcanzar 165°F (74°C) mantenidos al menos 1 segundo (instantáneo). Esto elimina Salmonella y otros patógenos comunes en aves.","ru":"Птица должна достичь 165°F (74°C) с выдержкой не менее 1 секунды (мгновенно). Это уничтожает сальмонеллу и другие патогены птицы.","tr":"Kümes hayvanları en az 1 saniye (anlık) tutularak 165°F (74°C) sıcaklığa ulaşmalıdır. Bu, Salmonella ve kümes hayvanlarında yaygın diğer patojenleri öldürür.","hi":"पोल्ट्री को कम से कम 1 सेकंड (तत्काल) के लिए 165°F (74°C) तक पहुंचना चाहिए। यह साल्मोनेला और पोल्ट्री में आम अन्य रोगाणुओं को मारता है।","ar":"يجب أن تصل الدواجن إلى 165°F (74°C) لمدة ثانية واحدة على الأقل (لحظيًا). هذا يقتل السالمونيلا وغيرها من المسببات الشائعة في الدواجن."}},{"cat":"temp","a":1,"q":{"en":"Ground beef and other comminuted meats must be cooked to 155°F held for at least:","es":"La carne molida y otras carnes picadas deben cocinarse a 155°F mantenidos al menos:","ru":"Фарш и другое измельчённое мясо нужно готовить до 155°F с выдержкой не менее:","tr":"Kıyma ve diğer parçalanmış etler en az şu süreyle 155°F'e pişirilmelidir:","hi":"पिसा हुआ बीफ और अन्य कीमा मांस को 155°F पर कम से कम इतनी देर तक पकाना चाहिए:","ar":"يجب طهي اللحم المفروم واللحوم المجروشة الأخرى إلى 155°F لمدة لا تقل عن:"},"o":[{"en":"1 second","es":"1 segundo","ru":"1 секунда","tr":"1 saniye","hi":"1 सेकंड","ar":"ثانية واحدة"},{"en":"17 seconds","es":"17 segundos","ru":"17 секунд","tr":"17 saniye","hi":"17 सेकंड","ar":"17 ثانية"},{"en":"4 minutes","es":"4 minutos","ru":"4 минуты","tr":"4 dakika","hi":"4 मिनट","ar":"4 دقائق"},{"en":"30 minutes","es":"30 minutos","ru":"30 минут","tr":"30 dakika","hi":"30 मिनट","ar":"30 دقيقة"}],"e":{"en":"Ground meats must reach 155°F (68°C) held for 17 seconds. Grinding spreads surface bacteria throughout the meat, so a higher combined time and temperature is needed.","es":"Las carnes molidas deben alcanzar 155°F (68°C) durante 17 segundos. Moler distribuye bacterias de la superficie por toda la carne, por lo que se necesita más tiempo y temperatura combinados.","ru":"Фарш должен достичь 155°F (68°C) с выдержкой 17 секунд. Измельчение распределяет поверхностные бактерии по всему мясу, поэтому нужны более высокие время и температура.","tr":"Kıyma etleri 17 saniye tutularak 155°F (68°C) sıcaklığa ulaşmalıdır. Öğütme, yüzey bakterilerini etin her yerine yayar; bu yüzden daha yüksek birleşik süre ve sıcaklık gerekir.","hi":"पिसे मांस को 17 सेकंड के लिए 155°F (68°C) तक पहुंचना चाहिए। पीसने से सतह के बैक्टीरिया पूरे मांस में फैल जाते हैं, इसलिए अधिक संयुक्त समय और तापमान चाहिए।","ar":"يجب أن يصل اللحم المفروم إلى 155°F (68°C) لمدة 17 ثانية. الفرم ينشر بكتيريا السطح في كامل اللحم، لذا يلزم زمن ودرجة حرارة مجتمعان أعلى."}},{"cat":"temp","a":2,"q":{"en":"A whole fish fillet cooked for immediate service must reach a minimum internal temperature of:","es":"Un filete de pescado entero cocido para servicio inmediato debe alcanzar una temperatura interna mínima de:","ru":"Целое рыбное филе, приготовленное для немедленной подачи, должно достичь минимальной внутренней температуры:","tr":"Hemen servis için pişirilen bütün balık fileto en az kaç derece iç sıcaklığa ulaşmalıdır:","hi":"तुरंत परोसने के लिए पकाई गई पूरी मछली की पट्टी को न्यूनतम आंतरिक तापमान तक पहुंचना चाहिए:","ar":"يجب أن تصل شريحة السمك الكاملة المطهوة للتقديم الفوري إلى درجة حرارة داخلية لا تقل عن:"},"o":[{"en":"125°F (52°C)","es":"125°F (52°C)","ru":"125°F (52°C)","tr":"125°F (52°C)","hi":"125°F (52°C)","ar":"125°F (52°C)"},{"en":"165°F (74°C)","es":"165°F (74°C)","ru":"165°F (74°C)","tr":"165°F (74°C)","hi":"165°F (74°C)","ar":"165°F (74°C)"},{"en":"145°F (63°C)","es":"145°F (63°C)","ru":"145°F (63°C)","tr":"145°F (63°C)","hi":"145°F (63°C)","ar":"145°F (63°C)"},{"en":"155°F (68°C)","es":"155°F (68°C)","ru":"155°F (68°C)","tr":"155°F (68°C)","hi":"155°F (68°C)","ar":"155°F (68°C)"}],"e":{"en":"Fish (that is not ground) must be cooked to 145°F (63°C) for 15 seconds, the same as whole cuts of beef, pork, and eggs cooked for immediate service.","es":"El pescado (no molido) debe cocinarse a 145°F (63°C) durante 15 segundos, igual que los cortes enteros de res, cerdo y los huevos para servicio inmediato.","ru":"Рыбу (не измельчённую) готовят до 145°F (63°C) в течение 15 секунд, как и цельные куски говядины, свинины и яйца для немедленной подачи.","tr":"Balık (öğütülmemiş) 15 saniye boyunca 145°F (63°C) sıcaklığa pişirilmelidir; hemen servis için pişirilen bütün sığır, domuz parçaları ve yumurtayla aynıdır.","hi":"मछली (जो पिसी न हो) को 15 सेकंड के लिए 145°F (63°C) तक पकाना चाहिए, जैसे तुरंत परोसने के लिए बीफ, पोर्क के पूरे टुकड़े और अंडे।","ar":"يجب طهي السمك (غير المفروم) إلى 145°F (63°C) لمدة 15 ثانية، مثل القطع الكاملة من اللحم البقري والخنزير والبيض المطهو للتقديم الفوري."}},{"cat":"temp","a":3,"q":{"en":"Eggs that will be hot-held for later service (not immediate) must be cooked to at least:","es":"Los huevos que se mantendrán calientes para servir después (no inmediato) deben cocinarse al menos a:","ru":"Яйца, которые будут храниться в горячем виде для последующей подачи (не сразу), нужно готовить не менее чем до:","tr":"Sonradan servis için sıcak tutulacak yumurtalar (hemen değil) en az kaç dereceye pişirilmelidir:","hi":"अंडे जो बाद में परोसने के लिए गर्म रखे जाएंगे (तुरंत नहीं) को कम से कम इतने तक पकाना चाहिए:","ar":"يجب طهي البيض الذي سيُحفظ ساخنًا للتقديم لاحقًا (وليس فورًا) إلى ما لا يقل عن:"},"o":[{"en":"135°F (57°C)","es":"135°F (57°C)","ru":"135°F (57°C)","tr":"135°F (57°C)","hi":"135°F (57°C)","ar":"135°F (57°C)"},{"en":"145°F (63°C)","es":"145°F (63°C)","ru":"145°F (63°C)","tr":"145°F (63°C)","hi":"145°F (63°C)","ar":"145°F (63°C)"},{"en":"165°F (74°C)","es":"165°F (74°C)","ru":"165°F (74°C)","tr":"165°F (74°C)","hi":"165°F (74°C)","ar":"165°F (74°C)"},{"en":"155°F (68°C)","es":"155°F (68°C)","ru":"155°F (68°C)","tr":"155°F (68°C)","hi":"155°F (68°C)","ar":"155°F (68°C)"}],"e":{"en":"Eggs cooked and then hot-held must reach 155°F (68°C) for 17 seconds, higher than the 145°F used for eggs cooked to order and served immediately.","es":"Los huevos cocidos y luego mantenidos calientes deben alcanzar 155°F (68°C) durante 17 segundos, más que los 145°F usados para huevos hechos al momento y servidos de inmediato.","ru":"Яйца, приготовленные и затем хранящиеся горячими, должны достичь 155°F (68°C) в течение 17 секунд — выше, чем 145°F для яиц под заказ, подаваемых сразу.","tr":"Pişirilip sonra sıcak tutulan yumurtalar 17 saniye boyunca 155°F (68°C) sıcaklığa ulaşmalıdır; bu, sipariş üzerine pişirilip hemen servis edilen yumurtalarda kullanılan 145°F'ten daha yüksektir.","hi":"पकाए और फिर गर्म रखे अंडों को 17 सेकंड के लिए 155°F (68°C) तक पहुंचना चाहिए, जो तुरंत परोसे जाने वाले अंडों के 145°F से अधिक है।","ar":"البيض المطهو ثم المحفوظ ساخنًا يجب أن يصل إلى 155°F (68°C) لمدة 17 ثانية، وهي أعلى من 145°F المستخدمة للبيض المطهو حسب الطلب والمقدَّم فورًا."}},{"cat":"temp","a":0,"q":{"en":"A commercially processed, ready-to-eat food (like canned soup) is being reheated for hot holding. To what temperature must it be reheated?","es":"Un alimento listo para comer procesado comercialmente (como sopa enlatada) se recalienta para conservación caliente. ¿A qué temperatura debe recalentarse?","ru":"Промышленно обработанный готовый продукт (например, суп из банки) разогревают для горячего хранения. До какой температуры его нужно разогреть?","tr":"Ticari olarak işlenmiş, yenmeye hazır bir gıda (konserve çorba gibi) sıcak tutma için yeniden ısıtılıyor. Hangi sıcaklığa kadar ısıtılmalıdır?","hi":"एक व्यावसायिक रूप से प्रसंस्कृत, खाने-के-लिए-तैयार भोजन (जैसे डिब्बाबंद सूप) को गर्म रखने के लिए फिर से गर्म किया जा रहा है। इसे किस तापमान तक गर्म करना चाहिए?","ar":"يُعاد تسخين طعام جاهز للأكل مُصنَّع تجاريًا (كشوربة معلبة) للحفظ الساخن. إلى أي درجة يجب إعادة تسخينه؟"},"o":[{"en":"135°F (57°C)","es":"135°F (57°C)","ru":"135°F (57°C)","tr":"135°F (57°C)","hi":"135°F (57°C)","ar":"135°F (57°C)"},{"en":"145°F (63°C)","es":"145°F (63°C)","ru":"145°F (63°C)","tr":"145°F (63°C)","hi":"145°F (63°C)","ar":"145°F (63°C)"},{"en":"165°F (74°C)","es":"165°F (74°C)","ru":"165°F (74°C)","tr":"165°F (74°C)","hi":"165°F (74°C)","ar":"165°F (74°C)"},{"en":"155°F (68°C)","es":"155°F (68°C)","ru":"155°F (68°C)","tr":"155°F (68°C)","hi":"155°F (68°C)","ar":"155°F (68°C)"}],"e":{"en":"Commercially processed, packaged food reheated for hot holding only needs to reach 135°F (57°C). Foods cooked and cooled on site must be reheated to 165°F.","es":"Un alimento envasado y procesado comercialmente que se recalienta para conservación caliente solo debe llegar a 135°F (57°C). Los alimentos cocinados y enfriados en el lugar deben recalentarse a 165°F.","ru":"Промышленно упакованный продукт, разогреваемый для горячего хранения, должен достичь лишь 135°F (57°C). Приготовленную и охлаждённую на месте пищу разогревают до 165°F.","tr":"Ticari olarak işlenmiş, ambalajlı gıda sıcak tutma için yalnızca 135°F (57°C) sıcaklığa ulaşmalıdır. Yerinde pişirilip soğutulan gıdalar 165°F'e ısıtılmalıdır.","hi":"व्यावसायिक रूप से प्रसंस्कृत, पैक भोजन को गर्म रखने के लिए केवल 135°F (57°C) तक पहुंचना चाहिए। साइट पर पकाए और ठंडे किए गए भोजन को 165°F तक फिर से गर्म करना चाहिए।","ar":"الطعام المعبأ المُصنَّع تجاريًا والمُعاد تسخينه للحفظ الساخن يحتاج فقط إلى 135°F (57°C). أما الطعام المطهو والمبرَّد في الموقع فيُعاد تسخينه إلى 165°F."}},{"cat":"temp","a":1,"q":{"en":"What effect does freezing have on most bacteria in food?","es":"¿Qué efecto tiene la congelación sobre la mayoría de las bacterias en los alimentos?","ru":"Как замораживание влияет на большинство бактерий в пище?","tr":"Dondurma, gıdadaki çoğu bakteriye ne yapar?","hi":"जमाने का भोजन में अधिकांश बैक्टीरिया पर क्या प्रभाव पड़ता है?","ar":"ما تأثير التجميد على معظم البكتيريا في الطعام؟"},"o":[{"en":"It kills all bacteria instantly","es":"Mata todas las bacterias al instante","ru":"Мгновенно убивает все бактерии","tr":"Tüm bakterileri anında öldürür","hi":"तुरंत सभी बैक्टीरिया मार देता है","ar":"يقتل كل البكتيريا فورًا"},{"en":"It stops most bacteria from growing but does not kill them","es":"Detiene el crecimiento de la mayoría pero no las mata","ru":"Останавливает рост большинства, но не убивает их","tr":"Çoğunun üremesini durdurur ama öldürmez","hi":"अधिकांश की वृद्धि रोकता है पर उन्हें मारता नहीं","ar":"يوقف نمو معظمها لكنه لا يقتلها"},{"en":"It makes bacteria grow faster","es":"Hace que las bacterias crezcan más rápido","ru":"Заставляет бактерии расти быстрее","tr":"Bakterilerin daha hızlı üremesini sağlar","hi":"बैक्टीरिया को तेजी से बढ़ाता है","ar":"يجعل البكتيريا تنمو أسرع"},{"en":"It has no effect at all","es":"No tiene ningún efecto","ru":"Не оказывает никакого влияния","tr":"Hiçbir etkisi yoktur","hi":"इसका कोई प्रभाव नहीं होता","ar":"ليس له أي تأثير"}],"e":{"en":"Freezing stops most bacteria from multiplying, but it does not kill them. When the food thaws, surviving bacteria can grow again, so proper handling still matters.","es":"La congelación detiene la multiplicación de la mayoría de las bacterias, pero no las mata. Al descongelarse, las que sobreviven pueden crecer de nuevo, por lo que el manejo adecuado sigue importando.","ru":"Замораживание останавливает размножение большинства бактерий, но не убивает их. При оттаивании выжившие бактерии снова растут, поэтому правильное обращение по-прежнему важно.","tr":"Dondurma çoğu bakterinin çoğalmasını durdurur, ama onları öldürmez. Gıda çözüldüğünde hayatta kalan bakteriler yeniden ürer; bu yüzden doğru işleme yine de önemlidir.","hi":"जमाना अधिकांश बैक्टीरिया के गुणन को रोकता है, पर उन्हें मारता नहीं। भोजन पिघलने पर बचे बैक्टीरिया फिर बढ़ सकते हैं, इसलिए सही संभाल फिर भी मायने रखती है।","ar":"التجميد يوقف تكاثر معظم البكتيريا لكنه لا يقتلها. عند ذوبان الطعام يمكن للبكتيريا الناجية أن تنمو مجددًا، لذا يبقى التعامل السليم مهمًا."}},{"cat":"temp","a":2,"q":{"en":"Which is an approved method for thawing frozen TCS food?","es":"¿Cuál es un método aprobado para descongelar alimentos TCS congelados?","ru":"Какой метод размораживания замороженной TCS-пищи является одобренным?","tr":"Dondurulmuş TCS gıdayı çözmek için onaylanmış yöntem hangisidir?","hi":"जमे हुए TCS भोजन को पिघलाने का कौन-सा स्वीकृत तरीका है?","ar":"أي طريقة معتمدة لإذابة أطعمة TCS المجمدة؟"},"o":[{"en":"On the counter at room temperature","es":"En la barra a temperatura ambiente","ru":"На столе при комнатной температуре","tr":"Tezgahta oda sıcaklığında","hi":"काउंटर पर कमरे के तापमान पर","ar":"على الطاولة في درجة حرارة الغرفة"},{"en":"In a warm oven","es":"En un horno tibio","ru":"В тёплой духовке","tr":"Ilık fırında","hi":"गर्म ओवन में","ar":"في فرن دافئ"},{"en":"In the refrigerator at 41°F (5°C) or below","es":"En el refrigerador a 41°F (5°C) o menos","ru":"В холодильнике при 41°F (5°C) или ниже","tr":"Buzdolabında 41°F (5°C) veya altında","hi":"रेफ्रिजरेटर में 41°F (5°C) या नीचे","ar":"في الثلاجة عند 41°F (5°C) أو أقل"},{"en":"In a sink of warm standing water","es":"En un fregadero con agua tibia estancada","ru":"В раковине со стоячей тёплой водой","tr":"Ilık durgun su dolu bir evyede","hi":"गर्म ठहरे पानी के सिंक में","ar":"في حوض ماء دافئ راكد"}],"e":{"en":"Approved thawing methods include the refrigerator at 41°F (5°C) or below, under running water at 70°F (21°C) or below, in a microwave if cooked immediately, or as part of cooking.","es":"Los métodos aprobados incluyen el refrigerador a 41°F (5°C) o menos, bajo agua corriente a 70°F (21°C) o menos, en el microondas si se cocina de inmediato, o como parte de la cocción.","ru":"Одобренные методы: холодильник при 41°F (5°C) или ниже, под проточной водой при 70°F (21°C) или ниже, в микроволновке при немедленной готовке или в процессе приготовления.","tr":"Onaylı yöntemler: 41°F (5°C) veya altında buzdolabı, 70°F (21°C) veya altında akan su, hemen pişirilecekse mikrodalga ya da pişirmenin bir parçası olarak çözme.","hi":"स्वीकृत तरीकों में 41°F (5°C) या नीचे रेफ्रिजरेटर, 70°F (21°C) या नीचे बहते पानी के नीचे, तुरंत पकाने पर माइक्रोवेव में, या पकाने के हिस्से के रूप में शामिल हैं।","ar":"تشمل الطرق المعتمدة الثلاجة عند 41°F (5°C) أو أقل، أو تحت ماء جارٍ عند 70°F (21°C) أو أقل، أو الميكروويف إذا طُهي فورًا، أو كجزء من الطهي."}},{"cat":"temp","a":3,"q":{"en":"Cold TCS food should be received at a temperature of:","es":"Los alimentos TCS fríos deben recibirse a una temperatura de:","ru":"Холодную TCS-пищу следует принимать при температуре:","tr":"Soğuk TCS gıdalar hangi sıcaklıkta teslim alınmalıdır:","hi":"ठंडे TCS भोजन को इस तापमान पर प्राप्त किया जाना चाहिए:","ar":"يجب استلام أطعمة TCS الباردة عند درجة حرارة:"},"o":[{"en":"70°F (21°C) or below","es":"70°F (21°C) o menos","ru":"70°F (21°C) или ниже","tr":"70°F (21°C) veya altı","hi":"70°F (21°C) या नीचे","ar":"70°F (21°C) أو أقل"},{"en":"50°F (10°C) or below","es":"50°F (10°C) o menos","ru":"50°F (10°C) или ниже","tr":"50°F (10°C) veya altı","hi":"50°F (10°C) या नीचे","ar":"50°F (10°C) أو أقل"},{"en":"135°F (57°C) or above","es":"135°F (57°C) o más","ru":"135°F (57°C) или выше","tr":"135°F (57°C) veya üstü","hi":"135°F (57°C) या ऊपर","ar":"135°F (57°C) أو أعلى"},{"en":"41°F (5°C) or below","es":"41°F (5°C) o menos","ru":"41°F (5°C) или ниже","tr":"41°F (5°C) veya altı","hi":"41°F (5°C) या नीचे","ar":"41°F (5°C) أو أقل"}],"e":{"en":"Cold TCS foods must be received at 41°F (5°C) or below. Check temperatures at delivery and reject items that are too warm.","es":"Los alimentos TCS fríos deben recibirse a 41°F (5°C) o menos. Verifique las temperaturas al recibir y rechace los artículos demasiado tibios.","ru":"Холодную TCS-пищу нужно принимать при 41°F (5°C) или ниже. Проверяйте температуру при доставке и отклоняйте слишком тёплые товары.","tr":"Soğuk TCS gıdalar 41°F (5°C) veya altında teslim alınmalıdır. Teslimatta sıcaklıkları kontrol edin ve fazla ılık ürünleri reddedin.","hi":"ठंडे TCS भोजन को 41°F (5°C) या नीचे प्राप्त करना चाहिए। डिलीवरी पर तापमान जांचें और बहुत गर्म वस्तुओं को अस्वीकार करें।","ar":"يجب استلام أطعمة TCS الباردة عند 41°F (5°C) أو أقل. تحقق من درجات الحرارة عند التسليم وارفض الأصناف الدافئة جدًا."}},{"cat":"temp","a":0,"q":{"en":"Hot TCS food should be received at a temperature of:","es":"Los alimentos TCS calientes deben recibirse a una temperatura de:","ru":"Горячую TCS-пищу следует принимать при температуре:","tr":"Sıcak TCS gıdalar hangi sıcaklıkta teslim alınmalıdır:","hi":"गर्म TCS भोजन को इस तापमान पर प्राप्त किया जाना चाहिए:","ar":"يجب استلام أطعمة TCS الساخنة عند درجة حرارة:"},"o":[{"en":"135°F (57°C) or above","es":"135°F (57°C) o más","ru":"135°F (57°C) или выше","tr":"135°F (57°C) veya üstü","hi":"135°F (57°C) या ऊपर","ar":"135°F (57°C) أو أعلى"},{"en":"110°F (43°C) or above","es":"110°F (43°C) o más","ru":"110°F (43°C) или выше","tr":"110°F (43°C) veya üstü","hi":"110°F (43°C) या ऊपर","ar":"110°F (43°C) أو أعلى"},{"en":"41°F (5°C) or below","es":"41°F (5°C) o menos","ru":"41°F (5°C) или ниже","tr":"41°F (5°C) veya altı","hi":"41°F (5°C) या नीचे","ar":"41°F (5°C) أو أقل"},{"en":"70°F (21°C) or above","es":"70°F (21°C) o más","ru":"70°F (21°C) или выше","tr":"70°F (21°C) veya üstü","hi":"70°F (21°C) या ऊपर","ar":"70°F (21°C) أو أعلى"}],"e":{"en":"Hot TCS foods must be received at 135°F (57°C) or above. Anything that has dropped into the danger zone should be rejected.","es":"Los alimentos TCS calientes deben recibirse a 135°F (57°C) o más. Cualquier cosa que haya caído en la zona de peligro debe rechazarse.","ru":"Горячую TCS-пищу нужно принимать при 135°F (57°C) или выше. Всё, что опустилось в опасную зону, следует отклонить.","tr":"Sıcak TCS gıdalar 135°F (57°C) veya üstünde teslim alınmalıdır. Tehlike bölgesine düşen her şey reddedilmelidir.","hi":"गर्म TCS भोजन को 135°F (57°C) या ऊपर प्राप्त करना चाहिए। जो कुछ भी खतरनाक क्षेत्र में गिर गया हो उसे अस्वीकार किया जाना चाहिए।","ar":"يجب استلام أطعمة TCS الساخنة عند 135°F (57°C) أو أعلى. وأي صنف انخفض إلى منطقة الخطر يجب رفضه."}},{"cat":"temp","a":1,"q":{"en":"How often should the temperature of TCS food on a hot- or cold-holding line be checked?","es":"¿Con qué frecuencia debe verificarse la temperatura de los alimentos TCS en una línea de conservación caliente o fría?","ru":"Как часто нужно проверять температуру TCS-пищи на линии горячего или холодного хранения?","tr":"Sıcak veya soğuk tutma hattındaki TCS gıdanın sıcaklığı ne sıklıkta kontrol edilmelidir?","hi":"गर्म या ठंडे-होल्डिंग लाइन पर TCS भोजन का तापमान कितनी बार जांचना चाहिए?","ar":"كم مرة يجب فحص درجة حرارة أطعمة TCS على خط الحفظ الساخن أو البارد؟"},"o":[{"en":"Only once at the start of service","es":"Solo una vez al inicio del servicio","ru":"Только один раз в начале обслуживания","tr":"Yalnızca servis başında bir kez","hi":"केवल सेवा की शुरुआत में एक बार","ar":"مرة واحدة فقط في بداية الخدمة"},{"en":"At least every 4 hours","es":"Al menos cada 4 horas","ru":"Не реже чем каждые 4 часа","tr":"En az her 4 saatte bir","hi":"कम से कम हर 4 घंटे में","ar":"كل 4 ساعات على الأقل"},{"en":"Once a day","es":"Una vez al día","ru":"Один раз в день","tr":"Günde bir kez","hi":"दिन में एक बार","ar":"مرة واحدة يوميًا"},{"en":"Only when a customer complains","es":"Solo cuando un cliente se queja","ru":"Только когда жалуется клиент","tr":"Yalnızca bir müşteri şikayet ettiğinde","hi":"केवल जब कोई ग्राहक शिकायत करे","ar":"فقط عند شكوى الزبون"}],"e":{"en":"Best practice is to check holding temperatures at least every 4 hours (many operations check every 2 hours), so problems are caught before food must be discarded.","es":"Lo mejor es verificar las temperaturas de conservación al menos cada 4 horas (muchos lo hacen cada 2 horas), para detectar problemas antes de tener que desechar la comida.","ru":"Лучше проверять температуру хранения не реже чем каждые 4 часа (многие — каждые 2 часа), чтобы выявить проблемы до того, как пищу придётся выбросить.","tr":"En iyisi tutma sıcaklıklarını en az her 4 saatte bir kontrol etmektir (birçok işletme her 2 saatte bir yapar); böylece sorunlar gıda atılmadan önce yakalanır.","hi":"सबसे अच्छा तरीका है होल्डिंग तापमान को कम से कम हर 4 घंटे में जांचना (कई प्रतिष्ठान हर 2 घंटे में), ताकि भोजन फेंकने से पहले समस्याएं पकड़ी जाएं।","ar":"الأفضل فحص درجات حرارة الحفظ كل 4 ساعات على الأقل (كثير من المنشآت كل ساعتين)، حتى تُكتشف المشكلات قبل الاضطرار للتخلص من الطعام."}},{"cat":"temp","a":2,"q":{"en":"A pot of hot chili is at 135°F. Under the two-stage cooling rule, by when must it reach 70°F?","es":"Una olla de chili caliente está a 135°F. Según la regla de enfriamiento de dos etapas, ¿para cuándo debe llegar a 70°F?","ru":"Кастрюля горячего чили при 135°F. По правилу двухэтапного охлаждения, к какому времени она должна достичь 70°F?","tr":"Bir tencere sıcak biberli yemek 135°F'te. İki aşamalı soğutma kuralına göre ne zamana kadar 70°F'e ulaşmalı?","hi":"गर्म चिली का एक बर्तन 135°F पर है। दो-चरण शीतलन नियम के तहत, इसे 70°F तक कब तक पहुंचना चाहिए?","ar":"قدر من الفلفل الحار الساخن عند 135°F. وفق قاعدة التبريد بمرحلتين، متى يجب أن يصل إلى 70°F؟"},"o":[{"en":"Within 6 hours","es":"En 6 horas","ru":"В течение 6 часов","tr":"6 saat içinde","hi":"6 घंटे के भीतर","ar":"خلال 6 ساعات"},{"en":"Within 30 minutes","es":"En 30 minutos","ru":"В течение 30 минут","tr":"30 dakika içinde","hi":"30 मिनट के भीतर","ar":"خلال 30 دقيقة"},{"en":"Within 2 hours","es":"En 2 horas","ru":"В течение 2 часов","tr":"2 saat içinde","hi":"2 घंटे के भीतर","ar":"خلال ساعتين"},{"en":"Within 4 hours","es":"En 4 horas","ru":"В течение 4 часов","tr":"4 saat içinde","hi":"4 घंटे के भीतर","ar":"خلال 4 ساعات"}],"e":{"en":"Stage one: hot food must cool from 135°F to 70°F (57°C to 21°C) within 2 hours. If it does not, it must be reheated or discarded.","es":"Etapa uno: la comida caliente debe enfriarse de 135°F a 70°F (57°C a 21°C) en 2 horas. Si no, debe recalentarse o desecharse.","ru":"Первый этап: горячая пища должна остыть с 135°F до 70°F (57°C до 21°C) за 2 часа. Иначе её нужно повторно нагреть или выбросить.","tr":"Birinci aşama: sıcak gıda 2 saat içinde 135°F'ten 70°F'e (57°C'den 21°C'ye) soğumalıdır. Aksi halde yeniden ısıtılmalı ya da atılmalıdır.","hi":"चरण एक: गर्म भोजन को 2 घंटे के भीतर 135°F से 70°F (57°C से 21°C) तक ठंडा होना चाहिए। यदि नहीं, तो इसे फिर से गर्म या फेंकना चाहिए।","ar":"المرحلة الأولى: يجب أن يبرد الطعام الساخن من 135°F إلى 70°F (57°C إلى 21°C) خلال ساعتين. وإلا وجب إعادة تسخينه أو التخلص منه."}},{"cat":"temp","a":3,"q":{"en":"After food cools to 70°F, the second cooling stage must bring it to 41°F within:","es":"Después de enfriarse a 70°F, la segunda etapa debe llevar la comida a 41°F en:","ru":"После охлаждения до 70°F второй этап должен довести пищу до 41°F в течение:","tr":"Gıda 70°F'e soğuduktan sonra ikinci aşama onu şu süre içinde 41°F'e getirmelidir:","hi":"70°F तक ठंडा होने के बाद, दूसरे चरण को इसे इतने समय में 41°F तक लाना चाहिए:","ar":"بعد أن يبرد الطعام إلى 70°F، يجب أن تصل المرحلة الثانية به إلى 41°F خلال:"},"o":[{"en":"1 additional hour","es":"1 hora adicional","ru":"ещё 1 час","tr":"1 saat daha","hi":"1 अतिरिक्त घंटा","ar":"ساعة إضافية واحدة"},{"en":"6 additional hours","es":"6 horas adicionales","ru":"ещё 6 часов","tr":"6 saat daha","hi":"6 अतिरिक्त घंटे","ar":"6 ساعات إضافية"},{"en":"2 additional hours","es":"2 horas adicionales","ru":"ещё 2 часа","tr":"2 saat daha","hi":"2 अतिरिक्त घंटे","ar":"ساعتان إضافيتان"},{"en":"4 additional hours","es":"4 horas adicionales","ru":"ещё 4 часа","tr":"4 saat daha","hi":"4 अतिरिक्त घंटे","ar":"4 ساعات إضافية"}],"e":{"en":"Stage two: from 70°F to 41°F (21°C to 5°C) within 4 more hours, for a total cooling time of no more than 6 hours from 135°F.","es":"Etapa dos: de 70°F a 41°F (21°C a 5°C) en 4 horas más, para un total de no más de 6 horas de enfriamiento desde 135°F.","ru":"Второй этап: с 70°F до 41°F (21°C до 5°C) ещё за 4 часа, при общем времени охлаждения не более 6 часов от 135°F.","tr":"İkinci aşama: 4 saat daha içinde 70°F'ten 41°F'e (21°C'den 5°C'ye), 135°F'ten itibaren toplam en fazla 6 saatlik soğutma süresiyle.","hi":"चरण दो: 4 और घंटों में 70°F से 41°F (21°C से 5°C) तक, 135°F से कुल 6 घंटे से अधिक नहीं शीतलन समय के लिए।","ar":"المرحلة الثانية: من 70°F إلى 41°F (21°C إلى 5°C) خلال 4 ساعات إضافية، بإجمالي زمن تبريد لا يتجاوز 6 ساعات من 135°F."}},{"cat":"temp","a":0,"q":{"en":"When reheating food to 165°F for hot holding, the required temperature must be reached within:","es":"Al recalentar comida a 165°F para conservación caliente, la temperatura requerida debe alcanzarse en:","ru":"При разогреве пищи до 165°F для горячего хранения нужную температуру нужно достичь в течение:","tr":"Sıcak tutma için gıda 165°F'e ısıtılırken gereken sıcaklığa şu süre içinde ulaşılmalıdır:","hi":"गर्म रखने के लिए भोजन को 165°F तक फिर से गर्म करते समय, आवश्यक तापमान इतने समय में पहुंचना चाहिए:","ar":"عند إعادة تسخين الطعام إلى 165°F للحفظ الساخن، يجب بلوغ الحرارة المطلوبة خلال:"},"o":[{"en":"2 hours","es":"2 horas","ru":"2 часов","tr":"2 saat","hi":"2 घंटे","ar":"ساعتين"},{"en":"8 hours","es":"8 horas","ru":"8 часов","tr":"8 saat","hi":"8 घंटे","ar":"8 ساعات"},{"en":"6 hours","es":"6 horas","ru":"6 часов","tr":"6 saat","hi":"6 घंटे","ar":"6 ساعات"},{"en":"30 minutes","es":"30 minutos","ru":"30 минут","tr":"30 dakika","hi":"30 मिनट","ar":"30 دقيقة"}],"e":{"en":"Food reheated for hot holding must reach 165°F (74°C) within 2 hours, limiting the time it spends passing through the danger zone.","es":"La comida recalentada para conservación caliente debe alcanzar 165°F (74°C) en 2 horas, limitando el tiempo que pasa por la zona de peligro.","ru":"Пища, разогреваемая для горячего хранения, должна достичь 165°F (74°C) за 2 часа, чтобы ограничить время прохождения через опасную зону.","tr":"Sıcak tutma için ısıtılan gıda, tehlike bölgesinde geçirdiği süreyi sınırlamak için 2 saat içinde 165°F'e (74°C) ulaşmalıdır.","hi":"गर्म रखने के लिए फिर से गर्म किए गए भोजन को 2 घंटे के भीतर 165°F (74°C) तक पहुंचना चाहिए, ताकि खतरनाक क्षेत्र से गुजरने का समय सीमित हो।","ar":"الطعام المُعاد تسخينه للحفظ الساخن يجب أن يصل إلى 165°F (74°C) خلال ساعتين، مما يحد من الوقت الذي يقضيه مارًا عبر منطقة الخطر."}},{"cat":"temp","a":1,"q":{"en":"Which practice helps cool a large batch of hot soup quickly and safely?","es":"¿Qué práctica ayuda a enfriar rápida y seguramente una gran cantidad de sopa caliente?","ru":"Какая практика помогает быстро и безопасно охладить большую партию горячего супа?","tr":"Büyük bir tencere sıcak çorbayı hızlı ve güvenli soğutmaya hangi uygulama yardımcı olur?","hi":"कौन-सी प्रथा गर्म सूप के बड़े बैच को जल्दी और सुरक्षित रूप से ठंडा करने में मदद करती है?","ar":"أي ممارسة تساعد على تبريد كمية كبيرة من الشوربة الساخنة بسرعة وأمان؟"},"o":[{"en":"Leave the full pot on the counter","es":"Dejar la olla llena en la barra","ru":"Оставить полную кастрюлю на столе","tr":"Dolu tencereyi tezgahta bırakmak","hi":"भरा बर्तन काउंटर पर छोड़ें","ar":"ترك القدر الممتلئ على الطاولة"},{"en":"Divide it into shallow pans and use an ice bath","es":"Dividirla en bandejas poco profundas y usar un baño de hielo","ru":"Разделить на неглубокие ёмкости и использовать ледяную баню","tr":"Sığ kaplara bölmek ve buz banyosu kullanmak","hi":"इसे उथले पैन में बांटें और आइस बाथ का उपयोग करें","ar":"تقسيمها في صواني ضحلة واستخدام حمام ثلجي"},{"en":"Cover it tightly and refrigerate hot","es":"Taparla bien y refrigerarla caliente","ru":"Плотно накрыть и охладить горячей","tr":"Sıkıca kapatıp sıcakken buzdolabına koymak","hi":"इसे कसकर ढकें और गर्म रेफ्रिजरेट करें","ar":"تغطيتها بإحكام وتبريدها ساخنة"},{"en":"Add warm water to thin it","es":"Añadir agua tibia para diluirla","ru":"Добавить тёплой воды, чтобы разбавить","tr":"İnceltmek için ılık su eklemek","hi":"इसे पतला करने के लिए गर्म पानी डालें","ar":"إضافة ماء دافئ لتخفيفها"}],"e":{"en":"Dividing food into shallow pans, using an ice-water bath or ice paddles, and stirring all speed cooling. Deep containers of hot food cool too slowly and stay in the danger zone.","es":"Dividir la comida en bandejas poco profundas, usar un baño de agua helada o paletas de hielo, y revolver aceleran el enfriamiento. Los recipientes hondos se enfrían muy lento y quedan en la zona de peligro.","ru":"Разделение на неглубокие ёмкости, ледяная баня или ледяные лопатки и помешивание ускоряют охлаждение. Глубокие ёмкости остывают слишком медленно и задерживаются в опасной зоне.","tr":"Gıdayı sığ kaplara bölmek, buzlu su banyosu ya da buz kürekleri kullanmak ve karıştırmak soğumayı hızlandırır. Derin kaplar çok yavaş soğur ve tehlike bölgesinde kalır.","hi":"भोजन को उथले पैन में बांटना, आइस-वॉटर बाथ या आइस पैडल का उपयोग करना और हिलाना शीतलन को तेज करते हैं। गहरे बर्तन बहुत धीरे ठंडे होते हैं और खतरनाक क्षेत्र में रहते हैं।","ar":"تقسيم الطعام في صواني ضحلة واستخدام حمام ماء مثلج أو مجاديف ثلج والتحريك كلها تسرّع التبريد. الأوعية العميقة تبرد ببطء شديد وتبقى في منطقة الخطر."}},{"cat":"temp","a":2,"q":{"en":"Using the boiling-point method at sea level, a properly calibrated thermometer should read:","es":"Con el método del punto de ebullición a nivel del mar, un termómetro bien calibrado debe marcar:","ru":"По методу точки кипения на уровне моря правильно откалиброванный термометр должен показывать:","tr":"Deniz seviyesinde kaynama noktası yöntemiyle, doğru kalibre edilmiş bir termometre kaç göstermelidir:","hi":"समुद्र तल पर उबलते-बिंदु विधि से, ठीक से कैलिब्रेट किया थर्मामीटर दिखाना चाहिए:","ar":"باستخدام طريقة نقطة الغليان عند مستوى سطح البحر، يجب أن يقرأ الميزان المعاير بشكل صحيح:"},"o":[{"en":"32°F (0°C)","es":"32°F (0°C)","ru":"32°F (0°C)","tr":"32°F (0°C)","hi":"32°F (0°C)","ar":"32°F (0°C)"},{"en":"165°F (74°C)","es":"165°F (74°C)","ru":"165°F (74°C)","tr":"165°F (74°C)","hi":"165°F (74°C)","ar":"165°F (74°C)"},{"en":"212°F (100°C)","es":"212°F (100°C)","ru":"212°F (100°C)","tr":"212°F (100°C)","hi":"212°F (100°C)","ar":"212°F (100°C)"},{"en":"180°F (82°C)","es":"180°F (82°C)","ru":"180°F (82°C)","tr":"180°F (82°C)","hi":"180°F (82°C)","ar":"180°F (82°C)"}],"e":{"en":"With the boiling-point method, water boils at 212°F (100°C) at sea level, so the thermometer should read 212°F. Adjust for altitude, where water boils at a lower temperature.","es":"Con el método del punto de ebullición, el agua hierve a 212°F (100°C) a nivel del mar, así que el termómetro debe marcar 212°F. Ajuste por la altitud, donde el agua hierve a menor temperatura.","ru":"По методу точки кипения вода кипит при 212°F (100°C) на уровне моря, поэтому термометр должен показывать 212°F. Учитывайте высоту, где вода кипит при более низкой температуре.","tr":"Kaynama noktası yönteminde su deniz seviyesinde 212°F'te (100°C) kaynar; termometre 212°F göstermelidir. Suyun daha düşük sıcaklıkta kaynadığı yüksek rakımlar için ayarlama yapın.","hi":"उबलते-बिंदु विधि में, समुद्र तल पर पानी 212°F (100°C) पर उबलता है, इसलिए थर्मामीटर 212°F दिखाना चाहिए। ऊंचाई के लिए समायोजित करें, जहां पानी कम तापमान पर उबलता है।","ar":"بطريقة نقطة الغليان، يغلي الماء عند 212°F (100°C) عند مستوى سطح البحر، لذا يجب أن يقرأ الميزان 212°F. عدّل حسب الارتفاع حيث يغلي الماء بدرجة أقل."}},{"cat":"temp","a":3,"q":{"en":"What must a food handler do to a probe thermometer between checking different foods?","es":"¿Qué debe hacer un manipulador con un termómetro de sonda entre la medición de diferentes alimentos?","ru":"Что работник должен сделать с щупом термометра между измерениями разных продуктов?","tr":"Bir gıda çalışanı farklı gıdaları ölçerken problu termometreye ne yapmalı?","hi":"अलग-अलग भोजन जांचने के बीच एक फूड हैंडलर को प्रोब थर्मामीटर के साथ क्या करना चाहिए?","ar":"ماذا يجب أن يفعل متداول الطعام بميزان المسبار بين فحص أطعمة مختلفة؟"},"o":[{"en":"Wipe it on a towel only","es":"Limpiarlo solo con una toalla","ru":"Только протереть его полотенцем","tr":"Yalnızca bir havluya silmek","hi":"केवल तौलिये पर पोंछें","ar":"مسحه بمنشفة فقط"},{"en":"Nothing between uses","es":"Nada entre usos","ru":"Ничего между использованиями","tr":"Kullanımlar arası hiçbir şey","hi":"उपयोगों के बीच कुछ नहीं","ar":"لا شيء بين الاستخدامات"},{"en":"Rinse it with cold water","es":"Enjuagarlo con agua fría","ru":"Сполоснуть холодной водой","tr":"Soğuk suyla durulamak","hi":"ठंडे पानी से धोएं","ar":"شطفه بماء بارد"},{"en":"Clean and sanitize the probe","es":"Limpiar y desinfectar la sonda","ru":"Вымыть и продезинфицировать щуп","tr":"Probu temizleyip dezenfekte etmek","hi":"प्रोब को साफ और सैनिटाइज़ करें","ar":"تنظيف المسبار وتعقيمه"}],"e":{"en":"The probe must be cleaned and sanitized before and after checking each food, otherwise it can transfer pathogens from one food to another.","es":"La sonda debe limpiarse y desinfectarse antes y después de medir cada alimento; de lo contrario puede transferir patógenos de un alimento a otro.","ru":"Щуп нужно мыть и дезинфицировать до и после каждого продукта, иначе он может переносить патогены от одного продукта к другому.","tr":"Prob, her gıdayı ölçmeden önce ve sonra temizlenip dezenfekte edilmelidir; aksi halde bir gıdadan diğerine patojen taşıyabilir.","hi":"प्रत्येक भोजन जांचने से पहले और बाद में प्रोब को साफ और सैनिटाइज़ करना चाहिए, अन्यथा यह एक भोजन से दूसरे में रोगाणु स्थानांतरित कर सकता है।","ar":"يجب تنظيف المسبار وتعقيمه قبل وبعد فحص كل طعام، وإلا فقد ينقل مسببات المرض من طعام إلى آخر."}},{"cat":"temp","a":0,"q":{"en":"If ready-to-eat TCS food is held using time alone as a control starting at 135°F or above, it must be served or discarded within:","es":"Si un alimento TCS listo para comer se mantiene solo con el tiempo como control, comenzando a 135°F o más, debe servirse o desecharse en:","ru":"Если готовая TCS-пища хранится только с контролем по времени, начиная при 135°F или выше, её нужно подать или выбросить в течение:","tr":"Yenmeye hazır TCS gıda, 135°F veya üzerinden başlayarak yalnızca zaman kontrolüyle tutuluyorsa şu süre içinde servis edilmeli veya atılmalıdır:","hi":"यदि खाने-के-लिए-तैयार TCS भोजन को केवल समय नियंत्रण के साथ 135°F या ऊपर से शुरू करके रखा जाए, तो इसे इतने समय में परोसा या फेंका जाना चाहिए:","ar":"إذا حُفظ طعام TCS جاهز للأكل باستخدام الوقت وحده كضابط بدءًا من 135°F أو أعلى، فيجب تقديمه أو التخلص منه خلال:"},"o":[{"en":"4 hours","es":"4 horas","ru":"4 часов","tr":"4 saat","hi":"4 घंटे","ar":"4 ساعات"},{"en":"12 hours","es":"12 horas","ru":"12 часов","tr":"12 saat","hi":"12 घंटे","ar":"12 ساعة"},{"en":"24 hours","es":"24 horas","ru":"24 часов","tr":"24 saat","hi":"24 घंटे","ar":"24 ساعة"},{"en":"1 hour","es":"1 hora","ru":"1 час","tr":"1 saat","hi":"1 घंटा","ar":"ساعة واحدة"}],"e":{"en":"When time alone is the control and food starts at 135°F or above, it may be held up to 4 hours, then must be served or thrown out. It cannot be returned to temperature control.","es":"Cuando el tiempo es el único control y la comida comienza a 135°F o más, puede mantenerse hasta 4 horas y luego debe servirse o desecharse. No puede regresar al control de temperatura.","ru":"Когда контроль только по времени и пища начинается при 135°F или выше, её можно держать до 4 часов, затем подать или выбросить. Вернуть к температурному контролю нельзя.","tr":"Kontrol yalnızca zamansa ve gıda 135°F veya üzerinden başlıyorsa en fazla 4 saat tutulabilir, sonra servis edilmeli ya da atılmalıdır. Sıcaklık kontrolüne geri döndürülemez.","hi":"जब नियंत्रण केवल समय हो और भोजन 135°F या ऊपर से शुरू हो, तो इसे 4 घंटे तक रखा जा सकता है, फिर परोसा या फेंका जाना चाहिए। इसे तापमान नियंत्रण में वापस नहीं किया जा सकता।","ar":"عندما يكون الوقت وحده هو الضابط ويبدأ الطعام من 135°F أو أعلى، يمكن حفظه حتى 4 ساعات ثم يجب تقديمه أو التخلص منه. ولا يمكن إعادته إلى ضبط الحرارة."}},{"cat":"temp","a":1,"q":{"en":"Why should hot-holding equipment like a steam table NOT be used to reheat food?","es":"¿Por qué NO debe usarse un equipo de conservación caliente como una mesa de vapor para recalentar comida?","ru":"Почему оборудование для горячего хранения, например паровой стол, НЕ следует использовать для разогрева пищи?","tr":"Buharlı tezgah gibi sıcak tutma ekipmanı gıdayı yeniden ısıtmak için neden KULLANILMAMALIDIR?","hi":"स्टीम टेबल जैसे गर्म-होल्डिंग उपकरण का उपयोग भोजन फिर से गर्म करने के लिए क्यों नहीं करना चाहिए?","ar":"لماذا يجب ألا تُستخدم معدات الحفظ الساخن مثل طاولة البخار لإعادة تسخين الطعام؟"},"o":[{"en":"It heats food too fast","es":"Calienta la comida demasiado rápido","ru":"Она греет пищу слишком быстро","tr":"Gıdayı çok hızlı ısıtır","hi":"यह भोजन को बहुत तेजी से गर्म करता है","ar":"يسخّن الطعام بسرعة كبيرة"},{"en":"It heats too slowly and food stays too long in the danger zone","es":"Calienta muy lento y la comida pasa demasiado tiempo en la zona de peligro","ru":"Она греет слишком медленно, и пища слишком долго остаётся в опасной зоне","tr":"Çok yavaş ısıtır ve gıda tehlike bölgesinde fazla kalır","hi":"यह बहुत धीरे गर्म करता है और भोजन खतरनाक क्षेत्र में बहुत देर रहता है","ar":"يسخّن ببطء شديد فيبقى الطعام مدة طويلة في منطقة الخطر"},{"en":"It uses too much electricity","es":"Consume demasiada electricidad","ru":"Она потребляет слишком много электричества","tr":"Çok fazla elektrik harcar","hi":"यह बहुत बिजली उपयोग करता है","ar":"يستهلك كهرباء كثيرة"},{"en":"It changes the food's flavor","es":"Cambia el sabor de la comida","ru":"Она меняет вкус пищи","tr":"Gıdanın tadını değiştirir","hi":"यह भोजन का स्वाद बदलता है","ar":"يغيّر نكهة الطعام"}],"e":{"en":"Steam tables and other hot-holding units heat food too slowly, letting it linger in the danger zone. Food must be reheated to 165°F on a stove, oven, or microwave first.","es":"Las mesas de vapor y otros equipos de conservación caliente calientan muy lento, dejando la comida en la zona de peligro. Debe recalentarse a 165°F en estufa, horno o microondas primero.","ru":"Паровые столы и другое оборудование для горячего хранения греют слишком медленно, оставляя пищу в опасной зоне. Сначала её нужно разогреть до 165°F на плите, в духовке или микроволновке.","tr":"Buharlı tezgahlar ve diğer sıcak tutma üniteleri gıdayı çok yavaş ısıtır ve tehlike bölgesinde bırakır. Gıda önce ocak, fırın ya da mikrodalgada 165°F'e ısıtılmalıdır.","hi":"स्टीम टेबल और अन्य गर्म-होल्डिंग इकाइयां भोजन को बहुत धीरे गर्म करती हैं, इसे खतरनाक क्षेत्र में छोड़ती हैं। भोजन को पहले स्टोव, ओवन या माइक्रोवेव में 165°F तक फिर से गर्म करना चाहिए।","ar":"طاولات البخار ووحدات الحفظ الساخن الأخرى تسخّن الطعام ببطء شديد فتبقيه في منطقة الخطر. يجب أولًا إعادة تسخين الطعام إلى 165°F على موقد أو فرن أو ميكروويف."}},{"cat":"temp","a":2,"q":{"en":"Raw animal foods cooked in a microwave oven must be heated to a minimum internal temperature of:","es":"Los alimentos de origen animal crudos cocinados en microondas deben calentarse a una temperatura interna mínima de:","ru":"Сырые продукты животного происхождения, приготовленные в микроволновке, нужно нагреть до минимальной внутренней температуры:","tr":"Mikrodalga fırında pişirilen çiğ hayvansal gıdalar en az kaç derece iç sıcaklığa ısıtılmalıdır:","hi":"माइक्रोवेव ओवन में पकाए गए कच्चे पशु खाद्य को न्यूनतम आंतरिक तापमान तक गर्म करना चाहिए:","ar":"يجب تسخين الأطعمة الحيوانية النيئة المطهوة في الميكروويف إلى درجة حرارة داخلية لا تقل عن:"},"o":[{"en":"135°F (57°C)","es":"135°F (57°C)","ru":"135°F (57°C)","tr":"135°F (57°C)","hi":"135°F (57°C)","ar":"135°F (57°C)"},{"en":"145°F (63°C)","es":"145°F (63°C)","ru":"145°F (63°C)","tr":"145°F (63°C)","hi":"145°F (63°C)","ar":"145°F (63°C)"},{"en":"165°F (74°C)","es":"165°F (74°C)","ru":"165°F (74°C)","tr":"165°F (74°C)","hi":"165°F (74°C)","ar":"165°F (74°C)"},{"en":"155°F (68°C)","es":"155°F (68°C)","ru":"155°F (68°C)","tr":"155°F (68°C)","hi":"155°F (68°C)","ar":"155°F (68°C)"}],"e":{"en":"Because microwaves heat unevenly, raw animal foods must reach 165°F (74°C). The food should be covered, rotated or stirred, and allowed to stand to even out temperatures.","es":"Como los microondas calientan de forma despareja, los alimentos animales crudos deben llegar a 165°F (74°C). Cúbralos, gírelos o revuélvalos, y déjelos reposar para igualar la temperatura.","ru":"Поскольку микроволновка греет неравномерно, сырые продукты животного происхождения должны достичь 165°F (74°C). Пищу накрывают, поворачивают или помешивают и дают постоять для выравнивания температуры.","tr":"Mikrodalgalar eşit ısıtmadığından, çiğ hayvansal gıdalar 165°F'e (74°C) ulaşmalıdır. Gıda örtülmeli, döndürülüp karıştırılmalı ve sıcaklıkların eşitlenmesi için bekletilmelidir.","hi":"चूंकि माइक्रोवेव असमान रूप से गर्म करते हैं, कच्चे पशु खाद्य को 165°F (74°C) तक पहुंचना चाहिए। भोजन को ढका, घुमाया या हिलाया जाए, और तापमान समान करने के लिए छोड़ा जाए।","ar":"لأن الميكروويف يسخّن بشكل غير متساوٍ، يجب أن تصل الأطعمة الحيوانية النيئة إلى 165°F (74°C). ويُغطى الطعام ويُدار أو يُحرّك ويُترك ليرتاح حتى تتساوى الحرارة."}},{"cat":"temp","a":3,"q":{"en":"Which of the following is a TCS food requiring time and temperature control?","es":"¿Cuál de los siguientes es un alimento TCS que requiere control de tiempo y temperatura?","ru":"Что из перечисленного является TCS-продуктом, требующим контроля времени и температуры?","tr":"Aşağıdakilerden hangisi zaman ve sıcaklık kontrolü gerektiren bir TCS gıdadır?","hi":"निम्न में से कौन-सा एक TCS भोजन है जिसे समय और तापमान नियंत्रण की आवश्यकता है?","ar":"أي مما يلي طعام TCS يتطلب ضبط الوقت ودرجة الحرارة؟"},"o":[{"en":"Dry white rice (uncooked)","es":"Arroz blanco seco (crudo)","ru":"Сухой белый рис (сырой)","tr":"Kuru beyaz pirinç (pişmemiş)","hi":"सूखा सफेद चावल (कच्चा)","ar":"أرز أبيض جاف (غير مطهو)"},{"en":"Granulated sugar","es":"Azúcar granulada","ru":"Сахарный песок","tr":"Toz şeker","hi":"दानेदार चीनी","ar":"سكر محبب"},{"en":"Whole coffee beans","es":"Granos de café enteros","ru":"Цельные кофейные зёрна","tr":"Bütün kahve çekirdekleri","hi":"साबुत कॉफी बीन्स","ar":"حبوب قهوة كاملة"},{"en":"Milk","es":"Leche","ru":"Молоко","tr":"Süt","hi":"दूध","ar":"الحليب"}],"e":{"en":"Milk is a classic TCS food. Moist, protein-rich, low-acid foods like milk, cooked rice, cut melons, and eggs support rapid pathogen growth and need temperature control.","es":"La leche es un alimento TCS clásico. Los alimentos húmedos, ricos en proteína y de baja acidez, como leche, arroz cocido, melón cortado y huevos, favorecen el crecimiento rápido de patógenos y requieren control de temperatura.","ru":"Молоко — классический TCS-продукт. Влажные, богатые белком, малокислотные продукты (молоко, варёный рис, нарезанная дыня, яйца) способствуют быстрому росту патогенов и требуют контроля температуры.","tr":"Süt klasik bir TCS gıdadır. Süt, pişmiş pirinç, kesilmiş kavun ve yumurta gibi nemli, proteince zengin, düşük asitli gıdalar patojenlerin hızlı üremesini destekler ve sıcaklık kontrolü gerektirir.","hi":"दूध एक क्लासिक TCS भोजन है। दूध, पका चावल, कटे खरबूजे और अंडे जैसे नम, प्रोटीन-समृद्ध, कम-अम्ल भोजन तेजी से रोगाणु वृद्धि का समर्थन करते हैं और तापमान नियंत्रण चाहिए।","ar":"الحليب طعام TCS كلاسيكي. الأطعمة الرطبة الغنية بالبروتين منخفضة الحموضة مثل الحليب والأرز المطهو والبطيخ المقطّع والبيض تدعم نمو المسببات بسرعة وتحتاج ضبط الحرارة."}},{"cat":"temp","a":0,"q":{"en":"A bimetallic stem thermometer used for food should be accurate to within about:","es":"Un termómetro bimetálico de vástago usado para alimentos debe tener una precisión de aproximadamente:","ru":"Биметаллический стержневой термометр для пищи должен быть точен примерно в пределах:","tr":"Gıda için kullanılan bimetal saplı termometre yaklaşık ne kadar hassas olmalıdır:","hi":"भोजन के लिए उपयोग किया जाने वाला बाईमेटैलिक स्टेम थर्मामीटर लगभग इतना सटीक होना चाहिए:","ar":"يجب أن يكون ميزان الحرارة ذو الساق ثنائي المعدن المستخدم للطعام دقيقًا في حدود نحو:"},"o":[{"en":"±2°F (±1°C)","es":"±2°F (±1°C)","ru":"±2°F (±1°C)","tr":"±2°F (±1°C)","hi":"±2°F (±1°C)","ar":"±2°F (±1°C)"},{"en":"±20°F (±11°C)","es":"±20°F (±11°C)","ru":"±20°F (±11°C)","tr":"±20°F (±11°C)","hi":"±20°F (±11°C)","ar":"±20°F (±11°C)"},{"en":"±50°F (±28°C)","es":"±50°F (±28°C)","ru":"±50°F (±28°C)","tr":"±50°F (±28°C)","hi":"±50°F (±28°C)","ar":"±50°F (±28°C)"},{"en":"±0.01°F","es":"±0.01°F","ru":"±0.01°F","tr":"±0.01°F","hi":"±0.01°F","ar":"±0.01°F"}],"e":{"en":"Food thermometers should be accurate to within about ±2°F (±1°C). They are calibrated regularly using the ice-point or boiling-point method to stay accurate.","es":"Los termómetros de alimentos deben tener precisión de aproximadamente ±2°F (±1°C). Se calibran con frecuencia con el método del punto de hielo o de ebullición para mantenerse exactos.","ru":"Пищевые термометры должны быть точны примерно до ±2°F (±1°C). Их регулярно калибруют методом точки льда или кипения, чтобы сохранить точность.","tr":"Gıda termometreleri yaklaşık ±2°F (±1°C) hassasiyette olmalıdır. Doğru kalmaları için buz noktası ya da kaynama noktası yöntemiyle düzenli kalibre edilir.","hi":"भोजन थर्मामीटर लगभग ±2°F (±1°C) तक सटीक होने चाहिए। सटीक बने रहने के लिए इन्हें बर्फ-बिंदु या उबलते-बिंदु विधि से नियमित कैलिब्रेट किया जाता है।","ar":"يجب أن تكون موازين الطعام دقيقة في حدود نحو ±2°F (±1°C). وتُعاير بانتظام بطريقة نقطة الثلج أو الغليان للحفاظ على دقتها."}},{"cat":"temp","a":1,"q":{"en":"When thawing food under running water, the water must be at or below:","es":"Al descongelar alimentos bajo agua corriente, el agua debe estar a o por debajo de:","ru":"При размораживании пищи под проточной водой вода должна быть не выше:","tr":"Gıda akan su altında çözülürken su en fazla kaç derece olmalıdır:","hi":"बहते पानी के नीचे भोजन पिघलाते समय, पानी इससे नीचे या बराबर होना चाहिए:","ar":"عند إذابة الطعام تحت ماء جارٍ، يجب أن يكون الماء عند أو أقل من:"},"o":[{"en":"41°F (5°C)","es":"41°F (5°C)","ru":"41°F (5°C)","tr":"41°F (5°C)","hi":"41°F (5°C)","ar":"41°F (5°C)"},{"en":"70°F (21°C)","es":"70°F (21°C)","ru":"70°F (21°C)","tr":"70°F (21°C)","hi":"70°F (21°C)","ar":"70°F (21°C)"},{"en":"100°F (38°C)","es":"100°F (38°C)","ru":"100°F (38°C)","tr":"100°F (38°C)","hi":"100°F (38°C)","ar":"100°F (38°C)"},{"en":"135°F (57°C)","es":"135°F (57°C)","ru":"135°F (57°C)","tr":"135°F (57°C)","hi":"135°F (57°C)","ar":"135°F (57°C)"}],"e":{"en":"Running-water thawing uses potable water at 70°F (21°C) or below, flowing fast enough to wash away loose food, and the food may not rise above 41°F in the outer layers for too long.","es":"El descongelado con agua corriente usa agua potable a 70°F (21°C) o menos, con flujo suficiente para arrastrar restos, y las capas externas del alimento no deben superar 41°F por mucho tiempo.","ru":"Размораживание проточной водой использует питьевую воду при 70°F (21°C) или ниже с достаточным потоком, чтобы смывать частицы; наружные слои не должны долго быть выше 41°F.","tr":"Akan suyla çözme, 70°F (21°C) veya altında içme suyu kullanır; su, gevşek gıdayı yıkayacak kadar hızlı akmalı ve gıdanın dış katmanları uzun süre 41°F'in üzerine çıkmamalıdır.","hi":"बहते पानी से पिघलाने में 70°F (21°C) या नीचे पीने योग्य पानी उपयोग होता है, जो ढीले भोजन को धोने के लिए पर्याप्त तेज बहता हो, और भोजन की बाहरी परतें बहुत देर 41°F से ऊपर न हों।","ar":"إذابة الماء الجاري تستخدم ماءً صالحًا للشرب عند 70°F (21°C) أو أقل، بتدفق يكفي لجرف بقايا الطعام، وألا ترتفع الطبقات الخارجية للطعام فوق 41°F لفترة طويلة."}},{"cat":"temp","a":2,"q":{"en":"Ready-to-eat TCS food held cold in the cooler must be date-marked and used within how many days (including the prep day)?","es":"Un alimento TCS listo para comer, mantenido en frío en el refrigerador, debe marcarse con fecha y usarse en cuántos días (incluido el día de preparación)?","ru":"Готовая холодная TCS-пища в холодильнике должна быть маркирована датой и использована в течение скольких дней (включая день приготовления)?","tr":"Soğukta tutulan yenmeye hazır TCS gıda, tarih etiketlenip (hazırlama günü dahil) kaç gün içinde kullanılmalıdır?","hi":"कूलर में ठंडा रखा खाने-के-लिए-तैयार TCS भोजन तारीख-चिह्नित होना चाहिए और कितने दिनों (तैयारी दिन सहित) में उपयोग किया जाना चाहिए?","ar":"الطعام الجاهز للأكل من نوع TCS المحفوظ باردًا في المبرّد يجب تأريخه واستخدامه خلال كم يومًا (بما في ذلك يوم التحضير)؟"},"o":[{"en":"14 days","es":"14 días","ru":"14 дней","tr":"14 gün","hi":"14 दिन","ar":"14 يومًا"},{"en":"3 days","es":"3 días","ru":"3 дня","tr":"3 gün","hi":"3 दिन","ar":"3 أيام"},{"en":"7 days","es":"7 días","ru":"7 дней","tr":"7 gün","hi":"7 दिन","ar":"7 أيام"},{"en":"30 days","es":"30 días","ru":"30 дней","tr":"30 gün","hi":"30 दिन","ar":"30 يومًا"}],"e":{"en":"Ready-to-eat TCS food kept at 41°F (5°C) or below may be stored for up to 7 days, counting the day of preparation as day 1. After that it must be discarded.","es":"Un alimento TCS listo para comer a 41°F (5°C) o menos puede almacenarse hasta 7 días, contando el día de preparación como día 1. Después debe desecharse.","ru":"Готовую TCS-пищу при 41°F (5°C) или ниже можно хранить до 7 дней, считая день приготовления первым. После этого её нужно выбросить.","tr":"41°F (5°C) veya altında tutulan yenmeye hazır TCS gıda, hazırlama günü 1. gün sayılarak en fazla 7 gün saklanabilir. Sonrasında atılmalıdır.","hi":"41°F (5°C) या नीचे रखा खाने-के-लिए-तैयार TCS भोजन 7 दिनों तक संग्रहीत किया जा सकता है, तैयारी दिन को दिन 1 गिनते हुए। इसके बाद इसे फेंकना चाहिए।","ar":"الطعام الجاهز للأكل TCS المحفوظ عند 41°F (5°C) أو أقل يمكن تخزينه حتى 7 أيام، مع اعتبار يوم التحضير اليوم الأول. بعدها يجب التخلص منه."}},{"cat":"temp","a":3,"q":{"en":"Why may a large beef roast be cooked to a lower temperature (like 130°F) than a hamburger?","es":"¿Por qué se puede cocinar un asado de res grande a menor temperatura (como 130°F) que una hamburguesa?","ru":"Почему большой кусок говядины можно готовить при более низкой температуре (например, 130°F), чем гамбургер?","tr":"Büyük bir dana rosto neden hamburgerden daha düşük sıcaklığa (örneğin 130°F) pişirilebilir?","hi":"बड़े बीफ रोस्ट को हैमबर्गर की तुलना में कम तापमान (जैसे 130°F) पर क्यों पकाया जा सकता है?","ar":"لماذا يمكن طهي قطعة لحم بقري كبيرة إلى درجة حرارة أقل (مثل 130°F) من الهامبرغر؟"},"o":[{"en":"Roasts contain no bacteria","es":"Los asados no contienen bacterias","ru":"В жарком нет бактерий","tr":"Rostolarda hiç bakteri yoktur","hi":"रोस्ट में कोई बैक्टीरिया नहीं होता","ar":"لا تحتوي القطع المشوية على بكتيريا"},{"en":"Roasts are always safe","es":"Los asados siempre son seguros","ru":"Жаркое всегда безопасно","tr":"Rostolar her zaman güvenlidir","hi":"रोस्ट हमेशा सुरक्षित होते हैं","ar":"القطع المشوية آمنة دائمًا"},{"en":"Lower temperatures taste better","es":"Las temperaturas más bajas saben mejor","ru":"Более низкие температуры вкуснее","tr":"Düşük sıcaklıklar daha lezzetlidir","hi":"कम तापमान अधिक स्वादिष्ट होते हैं","ar":"الحرارة الأقل ألذّ طعمًا"},{"en":"Bacteria are on the surface, and roasts use lower temperature held for a longer time","es":"Las bacterias están en la superficie, y los asados usan menor temperatura mantenida por más tiempo","ru":"Бактерии на поверхности, а для жаркого используют более низкую температуру с большей выдержкой","tr":"Bakteriler yüzeydedir ve rostolarda daha uzun süre tutulan daha düşük sıcaklık kullanılır","hi":"बैक्टीरिया सतह पर होते हैं, और रोस्ट लंबे समय तक रखे कम तापमान का उपयोग करते हैं","ar":"البكتيريا على السطح، والقطع المشوية تُطهى بحرارة أقل لمدة أطول"}],"e":{"en":"In an intact whole muscle roast, bacteria are only on the surface, so a roast may be cooked to a lower temperature held for a longer time (for example 130°F for about 112 minutes) to make it safe.","es":"En un asado de músculo entero, las bacterias están solo en la superficie, así que puede cocinarse a menor temperatura mantenida por más tiempo (por ejemplo 130°F durante unos 112 minutos) para hacerlo seguro.","ru":"В цельном куске мышцы бактерии только на поверхности, поэтому жаркое можно готовить при более низкой температуре с большей выдержкой (например, 130°F около 112 минут), чтобы обеспечить безопасность.","tr":"Bütün kas rostoda bakteriler yalnızca yüzeydedir; bu yüzden rosto güvenli hale gelmesi için daha uzun süre tutulan daha düşük sıcaklıkta (örneğin yaklaşık 112 dakika 130°F) pişirilebilir.","hi":"साबुत मांसपेशी रोस्ट में बैक्टीरिया केवल सतह पर होते हैं, इसलिए रोस्ट को सुरक्षित बनाने के लिए लंबे समय तक रखे कम तापमान (जैसे लगभग 112 मिनट 130°F) पर पकाया जा सकता है।","ar":"في القطعة العضلية الكاملة تكون البكتيريا على السطح فقط، لذا يمكن طهي القطعة بحرارة أقل لمدة أطول (مثلًا 130°F لنحو 112 دقيقة) لجعلها آمنة."}},{"cat":"temp","a":0,"q":{"en":"During cooling, food that has not reached 70°F within the first 2 hours should be:","es":"Durante el enfriamiento, la comida que no ha llegado a 70°F en las primeras 2 horas debe:","ru":"Во время охлаждения пищу, не достигшую 70°F за первые 2 часа, следует:","tr":"Soğutma sırasında ilk 2 saatte 70°F'e ulaşmamış gıda ne yapılmalıdır:","hi":"शीतलन के दौरान, वह भोजन जो पहले 2 घंटों में 70°F तक नहीं पहुंचा हो, उसे:","ar":"أثناء التبريد، الطعام الذي لم يصل إلى 70°F خلال أول ساعتين يجب:"},"o":[{"en":"Reheated to 165°F and cooled again, or discarded","es":"Recalentarse a 165°F y enfriarse de nuevo, o desecharse","ru":"Разогреть до 165°F и снова охладить или выбросить","tr":"165°F'e ısıtılıp yeniden soğutulmalı ya da atılmalıdır","hi":"165°F तक फिर से गर्म कर दोबारा ठंडा किया जाए, या फेंका जाए","ar":"إعادة تسخينه إلى 165°F وتبريده مجددًا، أو التخلص منه"},{"en":"Left to finish cooling slowly","es":"Dejarse enfriar lentamente hasta el final","ru":"Оставить медленно доохлаждаться","tr":"Yavaşça soğumaya bırakılmalı","hi":"धीरे-धीरे ठंडा होने के लिए छोड़ा जाए","ar":"يُترك ليكمل التبريد ببطء"},{"en":"Served immediately","es":"Servirse de inmediato","ru":"Немедленно подать","tr":"Hemen servis edilmeli","hi":"तुरंत परोसा जाए","ar":"يُقدَّم فورًا"},{"en":"Frozen as-is","es":"Congelarse tal cual","ru":"Заморозить как есть","tr":"Olduğu gibi dondurulmalı","hi":"जैसा है वैसा जमाया जाए","ar":"يُجمَّد كما هو"}],"e":{"en":"If food fails the first cooling stage (135°F to 70°F within 2 hours), it can be safely reheated to 165°F and the cooling restarted, or it must be discarded.","es":"Si la comida no cumple la primera etapa de enfriamiento (de 135°F a 70°F en 2 horas), puede recalentarse con seguridad a 165°F y reiniciar el enfriamiento, o debe desecharse.","ru":"Если пища не прошла первый этап охлаждения (135°F до 70°F за 2 часа), её можно безопасно разогреть до 165°F и начать охлаждение заново или выбросить.","tr":"Gıda ilk soğutma aşamasını (2 saatte 135°F'ten 70°F'e) geçemezse güvenle 165°F'e ısıtılıp soğutma yeniden başlatılabilir ya da atılmalıdır.","hi":"यदि भोजन पहला शीतलन चरण (2 घंटे में 135°F से 70°F) पूरा न कर पाए, तो इसे सुरक्षित रूप से 165°F तक फिर से गर्म कर शीतलन पुनः शुरू किया जा सकता है, या इसे फेंका जाना चाहिए।","ar":"إذا فشل الطعام في المرحلة الأولى من التبريد (135°F إلى 70°F خلال ساعتين)، فيمكن بأمان إعادة تسخينه إلى 165°F وإعادة بدء التبريد، أو يجب التخلص منه."}},{"cat":"temp","a":1,"q":{"en":"When calibrating a thermometer with the ice-point method, the reading should be:","es":"Al calibrar un termómetro con el método del punto de hielo, la lectura debe ser:","ru":"При калибровке термометра методом точки льда показание должно быть:","tr":"Termometreyi buz noktası yöntemiyle kalibre ederken okuma kaç olmalı:","hi":"बर्फ-बिंदु विधि से थर्मामीटर कैलिब्रेट करते समय, रीडिंग होनी चाहिए:","ar":"عند معايرة الميزان بطريقة نقطة الثلج، يجب أن تكون القراءة:"},"o":[{"en":"41°F (5°C)","es":"41°F (5°C)","ru":"41°F (5°C)","tr":"41°F (5°C)","hi":"41°F (5°C)","ar":"41°F (5°C)"},{"en":"32°F (0°C)","es":"32°F (0°C)","ru":"32°F (0°C)","tr":"32°F (0°C)","hi":"32°F (0°C)","ar":"32°F (0°C)"},{"en":"0°F (-18°C)","es":"0°F (-18°C)","ru":"0°F (-18°C)","tr":"0°F (-18°C)","hi":"0°F (-18°C)","ar":"0°F (-18°C)"},{"en":"70°F (21°C)","es":"70°F (21°C)","ru":"70°F (21°C)","tr":"70°F (21°C)","hi":"70°F (21°C)","ar":"70°F (21°C)"}],"e":{"en":"In the ice-point method, the thermometer is placed in a slush of crushed ice and water; a properly calibrated thermometer reads 32°F (0°C).","es":"En el método del punto de hielo, el termómetro se coloca en una mezcla de hielo picado y agua; uno bien calibrado marca 32°F (0°C).","ru":"В методе точки льда термометр помещают в смесь колотого льда и воды; правильно откалиброванный показывает 32°F (0°C).","tr":"Buz noktası yönteminde termometre, kırılmış buz ve su karışımına konur; doğru kalibre edilmiş termometre 32°F (0°C) gösterir.","hi":"बर्फ-बिंदु विधि में, थर्मामीटर को कुचली बर्फ और पानी के घोल में रखा जाता है; ठीक से कैलिब्रेट किया थर्मामीटर 32°F (0°C) दिखाता है।","ar":"في طريقة نقطة الثلج، يُوضع الميزان في مزيج من الثلج المجروش والماء؛ والميزان المعاير بشكل صحيح يقرأ 32°F (0°C)."}},{"cat":"temp","a":2,"q":{"en":"Why should a walk-in cooler not be overloaded with warm food all at once?","es":"¿Por qué no debe sobrecargarse un refrigerador de acceso con comida caliente de golpe?","ru":"Почему нельзя перегружать холодильную камеру тёплой пищей сразу?","tr":"Bir soğuk oda neden bir anda sıcak gıdayla aşırı doldurulmamalıdır?","hi":"वॉक-इन कूलर को एक साथ गर्म भोजन से अधिक क्यों नहीं भरना चाहिए?","ar":"لماذا يجب عدم إفراط تحميل الغرفة المبرّدة بالطعام الدافئ دفعة واحدة؟"},"o":[{"en":"It wastes shelf space","es":"Desperdicia espacio de estante","ru":"Это тратит место на полках","tr":"Raf alanını israf eder","hi":"यह शेल्फ जगह बर्बाद करता है","ar":"يهدر مساحة الرفوف"},{"en":"It makes food harder to find","es":"Hace más difícil encontrar la comida","ru":"Это затрудняет поиск еды","tr":"Gıdayı bulmayı zorlaştırır","hi":"यह भोजन ढूंढना कठिन बनाता है","ar":"يصعّب العثور على الطعام"},{"en":"It raises the internal temperature and slows cooling for everything inside","es":"Eleva la temperatura interior y frena el enfriamiento de todo lo que hay dentro","ru":"Это повышает внутреннюю температуру и замедляет охлаждение всего содержимого","tr":"İç sıcaklığı yükseltir ve içerideki her şeyin soğumasını yavaşlatır","hi":"यह आंतरिक तापमान बढ़ाता है और अंदर की हर चीज का शीतलन धीमा करता है","ar":"يرفع درجة الحرارة الداخلية ويبطئ تبريد كل ما بالداخل"},{"en":"It uses less electricity","es":"Consume menos electricidad","ru":"Это потребляет меньше электричества","tr":"Daha az elektrik kullanır","hi":"यह कम बिजली उपयोग करता है","ar":"يستهلك كهرباء أقل"}],"e":{"en":"Overloading a cooler with warm food raises the internal air temperature and blocks airflow, slowing cooling for everything and pushing foods into the danger zone.","es":"Sobrecargar el refrigerador con comida caliente eleva la temperatura del aire y bloquea el flujo, frenando el enfriamiento de todo y llevando los alimentos a la zona de peligro.","ru":"Перегрузка холодильника тёплой пищей повышает температуру воздуха и блокирует поток воздуха, замедляя охлаждение всего и загоняя продукты в опасную зону.","tr":"Soğutucuyu sıcak gıdayla aşırı doldurmak iç hava sıcaklığını yükseltir ve hava akışını engeller; her şeyin soğumasını yavaşlatıp gıdaları tehlike bölgesine iter.","hi":"कूलर को गर्म भोजन से अधिक भरना आंतरिक हवा का तापमान बढ़ाता है और वायुप्रवाह रोकता है, हर चीज का शीतलन धीमा करता है और भोजन को खतरनाक क्षेत्र में धकेलता है।","ar":"الإفراط في تحميل المبرّد بالطعام الدافئ يرفع حرارة الهواء الداخلي ويعيق تدفق الهواء، فيبطئ تبريد كل شيء ويدفع الأطعمة إلى منطقة الخطر."}},{"cat":"temp","a":3,"q":{"en":"If raw chicken is partially cooked to be finished later, what does the Food Code require?","es":"Si el pollo crudo se cocina parcialmente para terminarlo después, ¿qué exige el Código de Alimentos?","ru":"Если сырую курицу частично готовят, чтобы завершить позже, что требует Пищевой кодекс?","tr":"Çiğ tavuk daha sonra tamamlanmak üzere kısmen pişirilirse Gıda Kanunu ne gerektirir?","hi":"यदि कच्चे चिकन को बाद में पूरा करने के लिए आंशिक रूप से पकाया जाए, तो फूड कोड क्या आवश्यक करता है?","ar":"إذا طُهي الدجاج النيئ جزئيًا لإكماله لاحقًا، فماذا يتطلب قانون الغذاء؟"},"o":[{"en":"Cook it once to any temperature","es":"Cocinarlo una vez a cualquier temperatura","ru":"Приготовить один раз до любой температуры","tr":"Bir kez herhangi bir sıcaklığa pişirmek","hi":"इसे किसी भी तापमान पर एक बार पकाएं","ar":"طهيه مرة واحدة إلى أي درجة"},{"en":"Leave it at room temperature between steps","es":"Dejarlo a temperatura ambiente entre pasos","ru":"Оставить при комнатной температуре между этапами","tr":"Adımlar arasında oda sıcaklığında bırakmak","hi":"चरणों के बीच इसे कमरे के तापमान पर छोड़ें","ar":"تركه في حرارة الغرفة بين الخطوات"},{"en":"Skip the final cook if it looks done","es":"Omitir la cocción final si parece hecho","ru":"Пропустить финальную готовку, если выглядит готовым","tr":"Pişmiş görünüyorsa son pişirmeyi atlamak","hi":"यदि पका लगे तो अंतिम पकाना छोड़ दें","ar":"تخطي الطهي النهائي إذا بدا ناضجًا"},{"en":"Heat no more than 60 minutes, cool, then finish cooking to 165°F later","es":"Calentar no más de 60 minutos, enfriar y luego terminar de cocinar a 165°F después","ru":"Нагревать не более 60 минут, охладить, затем позже дожарить до 165°F","tr":"En fazla 60 dakika ısıtmak, soğutmak, sonra daha sonra 165°F'e kadar pişirmeyi tamamlamak","hi":"60 मिनट से अधिक न गर्म करें, ठंडा करें, फिर बाद में 165°F तक पकाना पूरा करें","ar":"تسخينه لمدة لا تزيد عن 60 دقيقة، ثم تبريده، ثم إكمال طهيه لاحقًا إلى 165°F"}],"e":{"en":"With partial (interrupted) cooking, the initial heating is limited to 60 minutes, the food is cooled and stored properly, and it must be cooked to its full required temperature (165°F for chicken) before serving.","es":"En la cocción parcial (interrumpida), el calentamiento inicial se limita a 60 minutos, la comida se enfría y guarda bien, y debe cocinarse a su temperatura requerida completa (165°F para pollo) antes de servir.","ru":"При частичной (прерванной) готовке начальный нагрев ограничен 60 минутами, пищу правильно охлаждают и хранят, а перед подачей доводят до полной нужной температуры (165°F для курицы).","tr":"Kısmi (kesintili) pişirmede ilk ısıtma 60 dakikayla sınırlıdır, gıda uygun şekilde soğutulup saklanır ve servisten önce tam gereken sıcaklığına (tavuk için 165°F) pişirilmelidir.","hi":"आंशिक (बाधित) पकाने में प्रारंभिक हीटिंग 60 मिनट तक सीमित है, भोजन को ठीक से ठंडा और संग्रहीत किया जाता है, और परोसने से पहले इसे इसके पूर्ण आवश्यक तापमान (चिकन के लिए 165°F) तक पकाना चाहिए।","ar":"في الطهي الجزئي (المتقطع) يُحدَّد التسخين الأول بـ 60 دقيقة، ويُبرَّد الطعام ويُخزَّن بشكل سليم، ويجب طهيه إلى درجته المطلوبة الكاملة (165°F للدجاج) قبل التقديم."}},{"cat":"temp","a":0,"q":{"en":"Cold TCS food on a salad bar is found at 50°F and records show it has been there over 4 hours. What should be done?","es":"Un alimento TCS frío en la barra de ensaladas está a 50°F y los registros muestran más de 4 horas allí. ¿Qué debe hacerse?","ru":"Холодная TCS-пища на салат-баре при 50°F, и записи показывают, что она там более 4 часов. Что делать?","tr":"Salata barındaki soğuk TCS gıda 50°F bulunuyor ve kayıtlar 4 saatten uzun süredir orada olduğunu gösteriyor. Ne yapılmalı?","hi":"सलाद बार पर ठंडा TCS भोजन 50°F पर मिला और रिकॉर्ड दिखाते हैं कि यह 4 घंटे से अधिक वहां रहा है। क्या करना चाहिए?","ar":"وُجد طعام TCS بارد على شريط السلطة عند 50°F وتُظهر السجلات بقاءه أكثر من 4 ساعات. ماذا يجب أن يُفعل؟"},"o":[{"en":"Discard the food","es":"Desechar la comida","ru":"Выбросить пищу","tr":"Gıdayı atmak","hi":"भोजन को फेंकें","ar":"التخلص من الطعام"},{"en":"Move it to the cooler and keep it","es":"Pasarla al refrigerador y conservarla","ru":"Переместить в холодильник и оставить","tr":"Soğutucuya taşıyıp saklamak","hi":"इसे कूलर में ले जाएं और रखें","ar":"نقله إلى المبرّد والاحتفاظ به"},{"en":"Add ice and keep serving","es":"Añadir hielo y seguir sirviendo","ru":"Добавить лёд и продолжать подавать","tr":"Buz ekleyip servise devam etmek","hi":"बर्फ डालें और परोसना जारी रखें","ar":"إضافة ثلج ومواصلة التقديم"},{"en":"Reheat it to 165°F","es":"Recalentarla a 165°F","ru":"Разогреть до 165°F","tr":"165°F'e ısıtmak","hi":"इसे 165°F तक फिर से गर्म करें","ar":"إعادة تسخينه إلى 165°F"}],"e":{"en":"Cold TCS food above 41°F for more than 4 hours must be discarded. Cooling it down again is not allowed, because pathogens may already have grown to unsafe levels.","es":"Un alimento TCS frío por encima de 41°F durante más de 4 horas debe desecharse. Volver a enfriarlo no se permite, porque los patógenos ya pueden haber crecido a niveles inseguros.","ru":"Холодную TCS-пищу выше 41°F более 4 часов нужно выбросить. Повторно охлаждать нельзя, так как патогены могли вырасти до небезопасного уровня.","tr":"41°F üzerinde 4 saatten uzun kalan soğuk TCS gıda atılmalıdır. Yeniden soğutmaya izin verilmez; çünkü patojenler zaten güvensiz düzeye ulaşmış olabilir.","hi":"41°F से ऊपर 4 घंटे से अधिक रहा ठंडा TCS भोजन फेंका जाना चाहिए। इसे दोबारा ठंडा करना अनुमत नहीं है, क्योंकि रोगाणु पहले ही असुरक्षित स्तर तक बढ़ चुके हो सकते हैं।","ar":"الطعام البارد TCS الذي يتجاوز 41°F لأكثر من 4 ساعات يجب التخلص منه. لا يُسمح بإعادة تبريده لأن المسببات قد تكون نمت إلى مستويات غير آمنة."}},{"cat":"temp","a":1,"q":{"en":"What is the minimum internal cooking temperature for ground turkey or ground chicken?","es":"¿Cuál es la temperatura interna mínima de cocción para pavo o pollo molido?","ru":"Какова минимальная внутренняя температура готовки для фарша из индейки или курицы?","tr":"Kıyma hindi ya da kıyma tavuk için minimum iç pişirme sıcaklığı nedir?","hi":"पिसे टर्की या पिसे चिकन के लिए न्यूनतम आंतरिक पकाने का तापमान क्या है?","ar":"ما أدنى درجة حرارة داخلية لطهي الديك الرومي المفروم أو الدجاج المفروم؟"},"o":[{"en":"145°F (63°C)","es":"145°F (63°C)","ru":"145°F (63°C)","tr":"145°F (63°C)","hi":"145°F (63°C)","ar":"145°F (63°C)"},{"en":"165°F (74°C)","es":"165°F (74°C)","ru":"165°F (74°C)","tr":"165°F (74°C)","hi":"165°F (74°C)","ar":"165°F (74°C)"},{"en":"155°F (68°C)","es":"155°F (68°C)","ru":"155°F (68°C)","tr":"155°F (68°C)","hi":"155°F (68°C)","ar":"155°F (68°C)"},{"en":"135°F (57°C)","es":"135°F (57°C)","ru":"135°F (57°C)","tr":"135°F (57°C)","hi":"135°F (57°C)","ar":"135°F (57°C)"}],"e":{"en":"Poultry, whether whole or ground, must reach 165°F (74°C) for at least 1 second. Grinding does not lower the requirement because poultry itself demands the highest cook temperature.","es":"Las aves, enteras o molidas, deben alcanzar 165°F (74°C) por al menos 1 segundo. Moler no reduce el requisito porque las aves ya exigen la temperatura de cocción más alta.","ru":"Птица, целая или измельчённая, должна достичь 165°F (74°C) минимум на 1 секунду. Измельчение не снижает требование, так как птица требует самой высокой температуры готовки.","tr":"Kümes hayvanları, bütün ya da kıyma olsun, en az 1 saniye 165°F'e (74°C) ulaşmalıdır. Öğütmek gereksinimi düşürmez; çünkü kümes hayvanları zaten en yüksek pişirme sıcaklığını gerektirir.","hi":"पोल्ट्री, चाहे साबुत हो या पिसी, कम से कम 1 सेकंड के लिए 165°F (74°C) तक पहुंचनी चाहिए। पीसना आवश्यकता कम नहीं करता क्योंकि पोल्ट्री स्वयं सबसे अधिक पकाने का तापमान मांगती है।","ar":"يجب أن تصل الدواجن، كاملة كانت أم مفرومة، إلى 165°F (74°C) لمدة ثانية واحدة على الأقل. والفرم لا يخفض الشرط لأن الدواجن نفسها تتطلب أعلى درجة طهي."}},{"cat":"temp","a":2,"q":{"en":"To get an accurate reading, where should a food thermometer probe be placed?","es":"Para una lectura precisa, ¿dónde debe colocarse la sonda del termómetro?","ru":"Для точного показания куда нужно поместить щуп пищевого термометра?","tr":"Doğru okuma için gıda termometresinin probu nereye yerleştirilmeli?","hi":"सटीक रीडिंग के लिए, भोजन थर्मामीटर की प्रोब कहां रखी जानी चाहिए?","ar":"للحصول على قراءة دقيقة، أين يجب وضع مسبار ميزان الطعام؟"},"o":[{"en":"Touching the pan or bone","es":"Tocando la sartén o el hueso","ru":"Касаясь сковороды или кости","tr":"Tavaya ya da kemiğe değecek şekilde","hi":"पैन या हड्डी को छूते हुए","ar":"ملامسًا المقلاة أو العظم"},{"en":"Just under the surface","es":"Justo debajo de la superficie","ru":"Прямо под поверхностью","tr":"Yüzeyin hemen altına","hi":"सतह के ठीक नीचे","ar":"أسفل السطح مباشرة"},{"en":"In the thickest part, away from bone and fat","es":"En la parte más gruesa, lejos del hueso y la grasa","ru":"В самой толстой части, вдали от кости и жира","tr":"En kalın kısma, kemik ve yağdan uzağa","hi":"सबसे मोटे हिस्से में, हड्डी और वसा से दूर","ar":"في أسمك جزء، بعيدًا عن العظم والدهن"},{"en":"At the very edge of the food","es":"En el borde mismo del alimento","ru":"У самого края продукта","tr":"Gıdanın tam kenarına","hi":"भोजन के बिल्कुल किनारे पर","ar":"عند حافة الطعام تمامًا"}],"e":{"en":"Insert the probe into the thickest part of the food, avoiding bone, fat, and the pan, which conduct heat differently and give a false reading.","es":"Inserte la sonda en la parte más gruesa del alimento, evitando hueso, grasa y la sartén, que conducen el calor de forma distinta y dan una lectura falsa.","ru":"Вставляйте щуп в самую толстую часть продукта, избегая кости, жира и сковороды, которые проводят тепло иначе и дают ложное показание.","tr":"Probu gıdanın en kalın kısmına, ısıyı farklı ileten ve yanlış okuma veren kemik, yağ ve tavadan uzağa sokun.","hi":"प्रोब को भोजन के सबसे मोटे हिस्से में डालें, हड्डी, वसा और पैन से बचते हुए, जो ऊष्मा को अलग तरह से संचालित करते हैं और गलत रीडिंग देते हैं।","ar":"أدخل المسبار في أسمك جزء من الطعام، متجنبًا العظم والدهن والمقلاة التي تنقل الحرارة بشكل مختلف وتعطي قراءة خاطئة."}},{"cat":"crosscontam","a":3,"q":{"en":"In a cooler organized by cooking temperature, what should be stored on the top shelf?","es":"En un refrigerador organizado por temperatura de cocción, ¿qué debe guardarse en el estante superior?","ru":"В холодильнике, организованном по температуре готовки, что должно храниться на верхней полке?","tr":"Pişirme sıcaklığına göre düzenlenmiş bir soğutucuda üst rafta ne saklanmalı?","hi":"पकाने के तापमान के अनुसार व्यवस्थित कूलर में, ऊपरी शेल्फ पर क्या रखा जाना चाहिए?","ar":"في مبرّد مرتب حسب درجة حرارة الطهي، ماذا يُخزَّن على الرف العلوي؟"},"o":[{"en":"Raw poultry","es":"Aves crudas","ru":"Сырая птица","tr":"Çiğ kümes hayvanı","hi":"कच्ची पोल्ट्री","ar":"دواجن نيئة"},{"en":"Raw ground beef","es":"Carne molida cruda","ru":"Сырой говяжий фарш","tr":"Çiğ dana kıyma","hi":"कच्चा पिसा बीफ","ar":"لحم بقري مفروم نيء"},{"en":"Raw pork","es":"Cerdo crudo","ru":"Сырая свинина","tr":"Çiğ domuz eti","hi":"कच्चा पोर्क","ar":"لحم خنزير نيء"},{"en":"Ready-to-eat food","es":"Alimentos listos para comer","ru":"Готовая к употреблению пища","tr":"Yenmeye hazır gıda","hi":"खाने-के-लिए-तैयार भोजन","ar":"طعام جاهز للأكل"}],"e":{"en":"Ready-to-eat food goes on top so drips cannot fall onto it. Below it, raw foods are stacked in order of increasing cook temperature, with raw poultry on the bottom.","es":"Los alimentos listos para comer van arriba para que no les caigan goteos. Debajo, los crudos se ordenan por temperatura de cocción creciente, con las aves crudas al fondo.","ru":"Готовая пища ставится наверх, чтобы на неё ничего не капало. Ниже сырые продукты располагают по возрастанию температуры готовки, а сырая птица — внизу.","tr":"Yenmeye hazır gıda üste konur ki damlalar üzerine düşmesin. Altında çiğ gıdalar artan pişirme sıcaklığına göre dizilir; çiğ kümes hayvanı en altta olur.","hi":"खाने-के-लिए-तैयार भोजन ऊपर रखा जाता है ताकि टपकन इस पर न गिरे। नीचे, कच्चे भोजन बढ़ते पकाने के तापमान क्रम में रखे जाते हैं, कच्ची पोल्ट्री सबसे नीचे।","ar":"الطعام الجاهز للأكل يوضع في الأعلى حتى لا يسقط عليه أي تنقيط. وتحته تُرتَّب الأطعمة النيئة حسب تزايد درجة حرارة الطهي، مع الدواجن النيئة في الأسفل."}},{"cat":"crosscontam","a":0,"q":{"en":"Which food became the ninth major allergen recognized in the U.S. as of January 1, 2023?","es":"¿Qué alimento se convirtió en el noveno alérgeno principal reconocido en EE. UU. a partir del 1 de enero de 2023?","ru":"Какой продукт стал девятым основным аллергеном, признанным в США с 1 января 2023 года?","tr":"1 Ocak 2023 itibarıyla ABD'de tanınan dokuzuncu başlıca alerjen hangi gıda oldu?","hi":"1 जनवरी 2023 से अमेरिका में मान्यता प्राप्त नौवां प्रमुख एलर्जेन कौन-सा भोजन बना?","ar":"أي طعام أصبح مسبب الحساسية التاسع الرئيسي المعترف به في الولايات المتحدة اعتبارًا من 1 يناير 2023؟"},"o":[{"en":"Sesame","es":"Sésamo (ajonjolí)","ru":"Кунжут","tr":"Susam","hi":"तिल","ar":"السمسم"},{"en":"Corn","es":"Maíz","ru":"Кукуруза","tr":"Mısır","hi":"मक्का","ar":"الذرة"},{"en":"Garlic","es":"Ajo","ru":"Чеснок","tr":"Sarımsak","hi":"लहसुन","ar":"الثوم"},{"en":"Strawberries","es":"Fresas","ru":"Клубника","tr":"Çilek","hi":"स्ट्रॉबेरी","ar":"الفراولة"}],"e":{"en":"Sesame became the ninth major allergen in the U.S. under the FASTER Act, effective January 1, 2023, joining milk, eggs, fish, shellfish, tree nuts, peanuts, wheat, and soy.","es":"El sésamo pasó a ser el noveno alérgeno principal en EE. UU. bajo la Ley FASTER, vigente el 1 de enero de 2023, junto a leche, huevos, pescado, mariscos, frutos secos de árbol, cacahuetes, trigo y soja.","ru":"Кунжут стал девятым основным аллергеном в США по закону FASTER с 1 января 2023 года, присоединившись к молоку, яйцам, рыбе, моллюскам, древесным орехам, арахису, пшенице и сое.","tr":"Susam, FASTER Yasası kapsamında 1 Ocak 2023'te ABD'de dokuzuncu başlıca alerjen oldu; süt, yumurta, balık, kabuklu deniz ürünleri, ağaç kuruyemişleri, yer fıstığı, buğday ve soyaya katıldı.","hi":"तिल FASTER अधिनियम के तहत 1 जनवरी 2023 से अमेरिका में नौवां प्रमुख एलर्जेन बना, जो दूध, अंडे, मछली, शेलफिश, ट्री नट्स, मूंगफली, गेहूं और सोया के साथ जुड़ा।","ar":"أصبح السمسم مسبب الحساسية التاسع الرئيسي في الولايات المتحدة بموجب قانون FASTER اعتبارًا من 1 يناير 2023، منضمًا إلى الحليب والبيض والسمك والمحار والمكسرات الشجرية والفول السوداني والقمح والصويا."}},{"cat":"crosscontam","a":1,"q":{"en":"What is the best way to prevent raw meat from contaminating ready-to-eat food during prep?","es":"¿Cuál es la mejor forma de evitar que la carne cruda contamine los alimentos listos para comer durante la preparación?","ru":"Как лучше всего предотвратить загрязнение готовой пищи сырым мясом при приготовлении?","tr":"Hazırlık sırasında çiğ etin yenmeye hazır gıdayı kirletmesini önlemenin en iyi yolu nedir?","hi":"तैयारी के दौरान कच्चे मांस को खाने-के-लिए-तैयार भोजन को दूषित करने से रोकने का सबसे अच्छा तरीका क्या है?","ar":"ما أفضل طريقة لمنع اللحم النيئ من تلويث الطعام الجاهز للأكل أثناء التحضير؟"},"o":[{"en":"Prep them at the same time on one board","es":"Prepararlos al mismo tiempo en una sola tabla","ru":"Готовить их одновременно на одной доске","tr":"Aynı anda tek tahtada hazırlamak","hi":"उन्हें एक साथ एक बोर्ड पर तैयार करें","ar":"تحضيرهما في الوقت نفسه على لوح واحد"},{"en":"Prep them at different times or on separate, cleaned surfaces","es":"Prepararlos en momentos distintos o en superficies separadas y limpias","ru":"Готовить их в разное время или на отдельных вымытых поверхностях","tr":"Farklı zamanlarda ya da ayrı, temizlenmiş yüzeylerde hazırlamak","hi":"उन्हें अलग-अलग समय पर या अलग, साफ सतहों पर तैयार करें","ar":"تحضيرهما في أوقات مختلفة أو على أسطح منفصلة ومنظفة"},{"en":"Rinse the raw meat first","es":"Enjuagar primero la carne cruda","ru":"Сначала промыть сырое мясо","tr":"Önce çiğ eti durulamak","hi":"पहले कच्चे मांस को धोएं","ar":"شطف اللحم النيئ أولًا"},{"en":"Use the same knife for both","es":"Usar el mismo cuchillo para ambos","ru":"Использовать один нож для обоих","tr":"İkisi için aynı bıçağı kullanmak","hi":"दोनों के लिए एक ही चाकू का उपयोग करें","ar":"استخدام السكين نفسه لكليهما"}],"e":{"en":"Keep raw and ready-to-eat foods apart by preparing them at different times or on separate, cleaned and sanitized surfaces and equipment to prevent cross-contamination.","es":"Mantenga separados los alimentos crudos y listos para comer preparándolos en momentos distintos o en superficies y equipos separados, limpios y desinfectados, para evitar la contaminación cruzada.","ru":"Разделяйте сырые и готовые продукты, готовя их в разное время или на отдельных, вымытых и продезинфицированных поверхностях, чтобы предотвратить перекрёстное загрязнение.","tr":"Çapraz bulaşmayı önlemek için çiğ ve yenmeye hazır gıdaları farklı zamanlarda ya da ayrı, temizlenmiş ve dezenfekte edilmiş yüzey ve ekipmanlarda hazırlayarak ayrı tutun.","hi":"क्रॉस-कॉन्टैमिनेशन रोकने के लिए कच्चे और खाने-के-लिए-तैयार भोजन को अलग-अलग समय पर या अलग, साफ और सैनिटाइज़ की गई सतहों और उपकरणों पर तैयार करके अलग रखें।","ar":"افصل الأطعمة النيئة عن الجاهزة للأكل بتحضيرها في أوقات مختلفة أو على أسطح ومعدات منفصلة ومنظفة ومعقمة لمنع التلوث المتبادل."}},{"cat":"crosscontam","a":2,"q":{"en":"A customer orders a peanut-free dish. Which step best prevents allergen cross-contact?","es":"Un cliente pide un platillo sin cacahuate. ¿Qué paso previene mejor el contacto cruzado con alérgenos?","ru":"Клиент заказывает блюдо без арахиса. Какой шаг лучше всего предотвращает перекрёстный контакт с аллергеном?","tr":"Bir müşteri yer fıstığı içermeyen bir yemek istiyor. Alerjen çapraz temasını en iyi hangi adım önler?","hi":"एक ग्राहक मूंगफली-मुक्त व्यंजन ऑर्डर करता है। कौन-सा कदम एलर्जेन क्रॉस-कॉन्टैक्ट को सबसे अच्छा रोकता है?","ar":"يطلب زبون طبقًا خاليًا من الفول السوداني. أي خطوة تمنع التلامس المتبادل لمسببات الحساسية أفضل؟"},"o":[{"en":"Wipe the old pan with a cloth","es":"Limpiar la sartén usada con un paño","ru":"Протереть старую сковороду тряпкой","tr":"Eski tavayı bezle silmek","hi":"पुराने पैन को कपड़े से पोंछें","ar":"مسح المقلاة القديمة بقطعة قماش"},{"en":"Pick the peanuts off the finished plate","es":"Quitar los cacahuates del plato terminado","ru":"Убрать арахис с готовой тарелки","tr":"Bitmiş tabaktan yer fıstıklarını ayıklamak","hi":"तैयार प्लेट से मूंगफली निकालें","ar":"إزالة الفول السوداني عن الطبق الجاهز"},{"en":"Use cleaned, sanitized equipment and fresh ingredients, and wash hands","es":"Usar equipo limpio y desinfectado con ingredientes frescos, y lavarse las manos","ru":"Использовать вымытое, продезинфицированное оборудование и свежие ингредиенты, и вымыть руки","tr":"Temizlenmiş, dezenfekte edilmiş ekipman ve taze malzeme kullanmak ve elleri yıkamak","hi":"साफ, सैनिटाइज़ किए उपकरण और ताजे सामग्री का उपयोग करें, और हाथ धोएं","ar":"استخدام معدات منظفة ومعقمة ومكونات طازجة، وغسل اليدين"},{"en":"Cook the dish at a higher temperature","es":"Cocinar el platillo a mayor temperatura","ru":"Готовить блюдо при более высокой температуре","tr":"Yemeği daha yüksek sıcaklıkta pişirmek","hi":"व्यंजन को अधिक तापमान पर पकाएं","ar":"طهي الطبق بحرارة أعلى"}],"e":{"en":"Allergens are proteins, not germs, so heat does not destroy them. Prevention means clean, sanitized equipment, fresh ingredients, washed hands, and no shared surfaces or utensils.","es":"Los alérgenos son proteínas, no gérmenes, así que el calor no los destruye. La prevención implica equipo limpio y desinfectado, ingredientes frescos, manos lavadas y no compartir superficies ni utensilios.","ru":"Аллергены — это белки, а не микробы, поэтому нагрев их не уничтожает. Профилактика — чистое, продезинфицированное оборудование, свежие ингредиенты, вымытые руки и никаких общих поверхностей.","tr":"Alerjenler mikrop değil proteindir; ısı onları yok etmez. Önleme; temiz, dezenfekte edilmiş ekipman, taze malzeme, yıkanmış eller ve ortak yüzey ya da alet kullanmamak demektir.","hi":"एलर्जेन प्रोटीन हैं, रोगाणु नहीं, इसलिए गर्मी उन्हें नष्ट नहीं करती। रोकथाम का अर्थ है साफ, सैनिटाइज़ उपकरण, ताजी सामग्री, धुले हाथ और साझा सतह या बर्तन न होना।","ar":"مسببات الحساسية بروتينات وليست جراثيم، لذا لا تدمرها الحرارة. الوقاية تعني معدات نظيفة ومعقمة ومكونات طازجة ويدين مغسولتين وعدم مشاركة الأسطح أو الأدوات."}},{"cat":"crosscontam","a":3,"q":{"en":"If one prep table must be used for both salad and raw chicken on the same day, what is the safest order?","es":"Si una sola mesa debe usarse para ensalada y pollo crudo el mismo día, ¿cuál es el orden más seguro?","ru":"Если один разделочный стол нужно использовать и для салата, и для сырой курицы в один день, каков самый безопасный порядок?","tr":"Aynı gün tek bir hazırlık masası hem salata hem çiğ tavuk için kullanılmak zorundaysa en güvenli sıra nedir?","hi":"यदि एक ही प्रेप टेबल को एक ही दिन सलाद और कच्चे चिकन दोनों के लिए उपयोग करना हो, तो सबसे सुरक्षित क्रम क्या है?","ar":"إذا وجب استخدام طاولة تحضير واحدة للسلطة والدجاج النيئ في اليوم نفسه، فما الترتيب الأكثر أمانًا؟"},"o":[{"en":"Chicken first, then salad without cleaning","es":"Pollo primero, luego ensalada sin limpiar","ru":"Сначала курица, затем салат без мытья","tr":"Önce tavuk, sonra temizlemeden salata","hi":"पहले चिकन, फिर बिना सफाई सलाद","ar":"الدجاج أولًا ثم السلطة دون تنظيف"},{"en":"Both at once to save time","es":"Ambos a la vez para ahorrar tiempo","ru":"Оба сразу, чтобы сэкономить время","tr":"Zaman kazanmak için ikisini birden","hi":"समय बचाने के लिए दोनों एक साथ","ar":"كلاهما معًا لتوفير الوقت"},{"en":"Order does not matter","es":"El orden no importa","ru":"Порядок не важен","tr":"Sıra önemli değil","hi":"क्रम मायने नहीं रखता","ar":"الترتيب لا يهم"},{"en":"Salad first, then chicken, cleaning and sanitizing between","es":"Ensalada primero, luego pollo, limpiando y desinfectando entre medio","ru":"Сначала салат, затем курица, с мытьём и дезинфекцией между ними","tr":"Önce salata, sonra tavuk; arada temizleyip dezenfekte ederek","hi":"पहले सलाद, फिर चिकन, बीच में सफाई और सैनिटाइज़ करते हुए","ar":"السلطة أولًا ثم الدجاج مع التنظيف والتعقيم بينهما"}],"e":{"en":"Prepare ready-to-eat foods like salad before raw meat, then clean and sanitize the surface. This limits the chance that raw poultry pathogens end up on food that is not cooked.","es":"Prepare primero los alimentos listos para comer, como la ensalada, antes de la carne cruda, y luego limpie y desinfecte la superficie. Así se reduce que los patógenos del pollo crudo lleguen a alimentos sin cocinar.","ru":"Готовьте готовую пищу, например салат, до сырого мяса, затем вымойте и продезинфицируйте поверхность. Это снижает риск попадания патогенов птицы на некипячёную пищу.","tr":"Salata gibi yenmeye hazır gıdaları çiğ etten önce hazırlayın, sonra yüzeyi temizleyip dezenfekte edin. Bu, çiğ tavuk patojenlerinin pişmeyen gıdaya ulaşma olasılığını azaltır.","hi":"सलाद जैसे खाने-के-लिए-तैयार भोजन को कच्चे मांस से पहले तैयार करें, फिर सतह को साफ और सैनिटाइज़ करें। यह कच्ची पोल्ट्री के रोगाणुओं के बिना पके भोजन तक पहुंचने की संभावना सीमित करता है।","ar":"حضّر الأطعمة الجاهزة للأكل مثل السلطة قبل اللحم النيئ، ثم نظّف السطح وعقّمه. هذا يقلل فرصة وصول مسببات الدجاج النيئ إلى طعام لا يُطهى."}},{"cat":"crosscontam","a":0,"q":{"en":"In many color-coded systems, which color cutting board is designated for raw poultry?","es":"En muchos sistemas de colores, ¿qué color de tabla se destina a las aves crudas?","ru":"Во многих системах цветовой кодировки какая по цвету доска предназначена для сырой птицы?","tr":"Birçok renk kodlu sistemde çiğ kümes hayvanı için hangi renk kesme tahtası ayrılmıştır?","hi":"कई रंग-कोडित प्रणालियों में, कच्ची पोल्ट्री के लिए किस रंग का कटिंग बोर्ड निर्धारित है?","ar":"في كثير من الأنظمة اللونية، أي لون من ألواح التقطيع مخصص للدواجن النيئة؟"},"o":[{"en":"Yellow","es":"Amarillo","ru":"Жёлтый","tr":"Sarı","hi":"पीला","ar":"الأصفر"},{"en":"Green","es":"Verde","ru":"Зелёный","tr":"Yeşil","hi":"हरा","ar":"الأخضر"},{"en":"Blue","es":"Azul","ru":"Синий","tr":"Mavi","hi":"नीला","ar":"الأزرق"},{"en":"White","es":"Blanco","ru":"Белый","tr":"Beyaz","hi":"सफेद","ar":"الأبيض"}],"e":{"en":"In a common color-coding scheme, yellow boards are used for raw poultry, red for raw meat, blue for seafood, green for produce, and white for dairy or bread. Colors help prevent cross-contamination.","es":"En un esquema común de colores, las tablas amarillas se usan para aves crudas, rojas para carne cruda, azules para mariscos, verdes para verduras y blancas para lácteos o pan. Los colores ayudan a evitar la contaminación cruzada.","ru":"В распространённой цветовой схеме жёлтые доски — для сырой птицы, красные — для сырого мяса, синие — для морепродуктов, зелёные — для овощей, белые — для молочного или хлеба. Цвета помогают избежать перекрёстного загрязнения.","tr":"Yaygın bir renk şemasında sarı tahtalar çiğ kümes hayvanı, kırmızı çiğ et, mavi deniz ürünleri, yeşil sebze-meyve, beyaz süt ürünü ya da ekmek içindir. Renkler çapraz bulaşmayı önlemeye yardımcı olur.","hi":"एक सामान्य रंग-कोडिंग योजना में, पीले बोर्ड कच्ची पोल्ट्री, लाल कच्चे मांस, नीले सीफूड, हरे उत्पाद और सफेद डेयरी या ब्रेड के लिए उपयोग होते हैं। रंग क्रॉस-कॉन्टैमिनेशन रोकने में मदद करते हैं।","ar":"في نظام لوني شائع، الألواح الصفراء للدواجن النيئة، والحمراء للحوم النيئة، والزرقاء للمأكولات البحرية، والخضراء للخضار، والبيضاء للألبان أو الخبز. الألوان تساعد على منع التلوث المتبادل."}},{"cat":"crosscontam","a":1,"q":{"en":"Where should a flat of raw shell eggs be stored relative to a container of washed lettuce in the same cooler?","es":"¿Dónde debe guardarse una bandeja de huevos crudos con cáscara respecto a un recipiente de lechuga lavada en el mismo refrigerador?","ru":"Где хранить лоток сырых яиц в скорлупе относительно ёмкости с мытым салатом в том же холодильнике?","tr":"Aynı soğutucuda yıkanmış marul kabına göre çiğ kabuklu yumurta tepsisi nereye konmalı?","hi":"एक ही कूलर में धुली लेट्यूस के डिब्बे के सापेक्ष कच्चे शेल अंडों की ट्रे कहां रखी जानी चाहिए?","ar":"أين يجب تخزين صينية بيض نيء بقشره بالنسبة لوعاء خس مغسول في المبرّد نفسه؟"},"o":[{"en":"Above the lettuce","es":"Encima de la lechuga","ru":"Выше салата","tr":"Marulun üstünde","hi":"लेट्यूस के ऊपर","ar":"فوق الخس"},{"en":"Below the lettuce","es":"Debajo de la lechuga","ru":"Ниже салата","tr":"Marulun altında","hi":"लेट्यूस के नीचे","ar":"أسفل الخس"},{"en":"It does not matter","es":"No importa","ru":"Это не важно","tr":"Fark etmez","hi":"इससे फर्क नहीं पड़ता","ar":"لا فرق"},{"en":"On the same shelf touching","es":"En el mismo estante en contacto","ru":"На той же полке, касаясь","tr":"Aynı rafta değecek şekilde","hi":"एक ही शेल्फ पर छूते हुए","ar":"على الرف نفسه ومتلامسان"}],"e":{"en":"Raw shell eggs are cooked to 145°F, higher than ready-to-eat lettuce, so they are stored below the lettuce. This keeps any drips off the ready-to-eat produce.","es":"Los huevos crudos con cáscara se cocinan a 145°F, más que la lechuga lista para comer, así que se guardan debajo de ella. Así ningún goteo cae sobre las verduras listas para comer.","ru":"Сырые яйца в скорлупе готовят до 145°F — выше, чем готовый салат, поэтому их хранят ниже салата. Это удерживает капли от готовых овощей.","tr":"Çiğ kabuklu yumurta 145°F'e pişirilir; bu, yenmeye hazır maruldan yüksektir, bu yüzden marulun altında saklanır. Böylece damlalar yenmeye hazır sebzeye düşmez.","hi":"कच्चे शेल अंडे 145°F पर पकाए जाते हैं, जो खाने-के-लिए-तैयार लेट्यूस से अधिक है, इसलिए इन्हें लेट्यूस के नीचे रखा जाता है। यह किसी भी टपकन को तैयार उत्पाद से दूर रखता है।","ar":"البيض النيئ بقشره يُطهى إلى 145°F، وهي أعلى من الخس الجاهز للأكل، لذا يُخزَّن أسفل الخس. هذا يمنع أي تنقيط عن الخضار الجاهزة للأكل."}},{"cat":"crosscontam","a":2,"q":{"en":"Which of the following is an example of a chemical contaminant in food?","es":"¿Cuál de los siguientes es un ejemplo de contaminante químico en los alimentos?","ru":"Что из перечисленного является примером химического загрязнителя пищи?","tr":"Aşağıdakilerden hangisi gıdadaki kimyasal kirletici örneğidir?","hi":"निम्न में से कौन-सा भोजन में रासायनिक दूषक का उदाहरण है?","ar":"أي مما يلي مثال على ملوث كيميائي في الطعام؟"},"o":[{"en":"A piece of glass","es":"Un trozo de vidrio","ru":"Кусок стекла","tr":"Bir cam parçası","hi":"कांच का टुकड़ा","ar":"قطعة زجاج"},{"en":"A strand of hair","es":"Un cabello","ru":"Волос","tr":"Bir saç teli","hi":"बाल का एक धागा","ar":"شعرة"},{"en":"Cleaning solution sprayed near open food","es":"Solución de limpieza rociada cerca de comida destapada","ru":"Чистящий раствор, распылённый рядом с открытой пищей","tr":"Açık gıdanın yanına püskürtülen temizlik solüsyonu","hi":"खुले भोजन के पास छिड़का गया सफाई घोल","ar":"محلول تنظيف يُرشّ قرب طعام مكشوف"},{"en":"A metal shaving","es":"Una viruta de metal","ru":"Металлическая стружка","tr":"Bir metal talaşı","hi":"धातु की छीलन","ar":"برادة معدنية"}],"e":{"en":"Chemical contaminants include cleaners, sanitizers, pesticides, and toxic-metal residues. Glass, hair, and metal shavings are physical hazards, not chemical.","es":"Los contaminantes químicos incluyen limpiadores, desinfectantes, pesticidas y residuos de metales tóxicos. El vidrio, el cabello y las virutas de metal son peligros físicos, no químicos.","ru":"Химические загрязнители — это чистящие средства, санитайзеры, пестициды и остатки токсичных металлов. Стекло, волосы и металлическая стружка — физические, а не химические опасности.","tr":"Kimyasal kirleticiler; temizleyiciler, dezenfektanlar, pestisitler ve toksik metal kalıntılarını içerir. Cam, saç ve metal talaşı kimyasal değil fiziksel tehlikedir.","hi":"रासायनिक दूषकों में क्लीनर, सैनिटाइज़र, कीटनाशक और विषैले-धातु अवशेष शामिल हैं। कांच, बाल और धातु की छीलन भौतिक खतरे हैं, रासायनिक नहीं।","ar":"الملوثات الكيميائية تشمل المنظفات والمعقمات والمبيدات وبقايا المعادن السامة. أما الزجاج والشعر وبرادة المعدن فهي مخاطر فيزيائية وليست كيميائية."}},{"cat":"crosscontam","a":3,"q":{"en":"On a self-service buffet, how should utensils be handled to prevent cross-contamination?","es":"En un bufé de autoservicio, ¿cómo deben manejarse los utensilios para evitar la contaminación cruzada?","ru":"На шведском столе самообслуживания как обращаться с приборами, чтобы избежать перекрёстного загрязнения?","tr":"Self servis açık büfede çapraz bulaşmayı önlemek için servis aletleri nasıl kullanılmalı?","hi":"स्व-सेवा बुफे पर, क्रॉस-कॉन्टैमिनेशन रोकने के लिए बर्तनों को कैसे संभाला जाना चाहिए?","ar":"في بوفيه الخدمة الذاتية، كيف يجب التعامل مع الأدوات لمنع التلوث المتبادل؟"},"o":[{"en":"Use one set of tongs for all dishes","es":"Usar un solo juego de pinzas para todos los platos","ru":"Использовать одни щипцы для всех блюд","tr":"Tüm yemekler için tek maşa kullanmak","hi":"सभी व्यंजनों के लिए एक ही चिमटे का उपयोग करें","ar":"استخدام ملقط واحد لكل الأطباق"},{"en":"Let guests use their own forks to serve","es":"Dejar que los clientes sirvan con sus propios tenedores","ru":"Позволить гостям накладывать своими вилками","tr":"Misafirlerin kendi çatallarıyla almasına izin vermek","hi":"मेहमानों को उनके अपने कांटे से परोसने दें","ar":"ترك الضيوف يخدمون بشوكهم الخاصة"},{"en":"Store serving spoons in the food overnight","es":"Guardar las cucharas de servir en la comida toda la noche","ru":"Оставлять сервировочные ложки в еде на ночь","tr":"Servis kaşıklarını gece boyu gıdanın içinde bırakmak","hi":"सर्विंग चम्मचों को रातभर भोजन में रखें","ar":"ترك ملاعق التقديم داخل الطعام طوال الليل"},{"en":"Provide a separate clean utensil for each dish","es":"Proporcionar un utensilio limpio separado para cada plato","ru":"Предоставить отдельный чистый прибор для каждого блюда","tr":"Her yemek için ayrı temiz bir servis aleti sağlamak","hi":"प्रत्येक व्यंजन के लिए अलग साफ बर्तन प्रदान करें","ar":"توفير أداة نظيفة منفصلة لكل طبق"}],"e":{"en":"Each dish should have its own clean serving utensil, and guests must not use personal utensils to serve. This prevents transferring allergens and pathogens between foods.","es":"Cada plato debe tener su propio utensilio de servir limpio, y los clientes no deben usar utensilios personales para servirse. Esto evita transferir alérgenos y patógenos entre alimentos.","ru":"У каждого блюда должен быть свой чистый сервировочный прибор, а гости не должны накладывать личными приборами. Это предотвращает перенос аллергенов и патогенов между продуктами.","tr":"Her yemeğin kendi temiz servis aleti olmalı ve misafirler kişisel çatal-kaşıkla servis yapmamalıdır. Bu, gıdalar arasında alerjen ve patojen taşınmasını önler.","hi":"प्रत्येक व्यंजन का अपना साफ सर्विंग बर्तन होना चाहिए, और मेहमानों को परोसने के लिए व्यक्तिगत बर्तन का उपयोग नहीं करना चाहिए। यह भोजन के बीच एलर्जेन और रोगाणु स्थानांतरण रोकता है।","ar":"يجب أن يكون لكل طبق أداة تقديم نظيفة خاصة، وألا يستخدم الضيوف أدواتهم الشخصية للخدمة. هذا يمنع نقل مسببات الحساسية والمرض بين الأطعمة."}},{"cat":"crosscontam","a":0,"q":{"en":"Why is rinsing raw chicken in the prep sink discouraged?","es":"¿Por qué se desaconseja enjuagar el pollo crudo en el fregadero de preparación?","ru":"Почему не рекомендуется ополаскивать сырую курицу в раковине для приготовления?","tr":"Çiğ tavuğu hazırlık evyesinde durulamak neden önerilmez?","hi":"कच्चे चिकन को प्रेप सिंक में धोना क्यों हतोत्साहित किया जाता है?","ar":"لماذا يُنصح بعدم شطف الدجاج النيئ في حوض التحضير؟"},"o":[{"en":"Splashing water spreads bacteria to nearby surfaces and foods","es":"El agua que salpica esparce bacterias a superficies y alimentos cercanos","ru":"Брызги воды разносят бактерии на соседние поверхности и продукты","tr":"Sıçrayan su bakterileri yakındaki yüzeylere ve gıdalara yayar","hi":"छींटे मारता पानी बैक्टीरिया को पास की सतहों और भोजन तक फैलाता है","ar":"رذاذ الماء ينشر البكتيريا إلى الأسطح والأطعمة القريبة"},{"en":"It makes the chicken taste worse","es":"Hace que el pollo sepa peor","ru":"Это ухудшает вкус курицы","tr":"Tavuğun tadını kötüleştirir","hi":"यह चिकन का स्वाद बिगाड़ता है","ar":"يجعل طعم الدجاج أسوأ"},{"en":"It wastes too much water","es":"Desperdicia demasiada agua","ru":"Это тратит слишком много воды","tr":"Çok fazla su israf eder","hi":"यह बहुत पानी बर्बाद करता है","ar":"يهدر ماءً كثيرًا"},{"en":"It cooks the chicken unevenly","es":"Cocina el pollo de forma despareja","ru":"Это неравномерно готовит курицу","tr":"Tavuğu eşitsiz pişirir","hi":"यह चिकन को असमान रूप से पकाता है","ar":"يطهو الدجاج بشكل غير متساوٍ"}],"e":{"en":"Washing raw poultry does not remove pathogens but splashes contaminated water up to several feet, spreading Salmonella and Campylobacter to nearby surfaces, utensils, and foods.","es":"Lavar el pollo crudo no elimina patógenos, pero salpica agua contaminada varios metros, esparciendo Salmonella y Campylobacter a superficies, utensilios y alimentos cercanos.","ru":"Мытьё сырой птицы не удаляет патогены, но разбрызгивает загрязнённую воду на несколько метров, разнося сальмонеллу и кампилобактер на поверхности, инвентарь и продукты рядом.","tr":"Çiğ kümes hayvanını yıkamak patojenleri gidermez; kirli suyu metrelerce sıçratarak Salmonella ve Campylobacter'i yakındaki yüzeylere, aletlere ve gıdalara yayar.","hi":"कच्ची पोल्ट्री धोने से रोगाणु नहीं हटते, बल्कि दूषित पानी कई फीट तक छींटे मारता है, साल्मोनेला और कैम्पिलोबैक्टर को पास की सतहों, बर्तनों और भोजन तक फैलाता है।","ar":"غسل الدواجن النيئة لا يزيل المسببات، بل يرشّ الماء الملوث لعدة أقدام، ناشرًا السالمونيلا والكامبيلوباكتر إلى الأسطح والأدوات والأطعمة القريبة."}},{"cat":"crosscontam","a":1,"q":{"en":"Which of these is NOT one of the Big 9 major food allergens?","es":"¿Cuál de estos NO es uno de los 9 alérgenos alimentarios principales?","ru":"Что из этого НЕ входит в девятку основных пищевых аллергенов?","tr":"Aşağıdakilerden hangisi Büyük 9 başlıca gıda alerjeninden biri DEĞİLDİR?","hi":"इनमें से कौन-सा बिग 9 प्रमुख खाद्य एलर्जेन में से एक नहीं है?","ar":"أي مما يلي ليس من مسببات الحساسية الغذائية التسعة الكبرى؟"},"o":[{"en":"Tree nuts","es":"Frutos secos de árbol","ru":"Древесные орехи","tr":"Ağaç kuruyemişleri","hi":"ट्री नट्स","ar":"المكسرات الشجرية"},{"en":"Chicken","es":"Pollo","ru":"Курица","tr":"Tavuk","hi":"चिकन","ar":"الدجاج"},{"en":"Soy","es":"Soja","ru":"Соя","tr":"Soya","hi":"सोया","ar":"الصويا"},{"en":"Shellfish","es":"Mariscos","ru":"Моллюски","tr":"Kabuklu deniz ürünleri","hi":"शेलफिश","ar":"المحار"}],"e":{"en":"The Big 9 allergens are milk, eggs, fish, shellfish (crustacean), tree nuts, peanuts, wheat, soy, and sesame. Chicken is not on the list.","es":"Los 9 alérgenos principales son leche, huevos, pescado, mariscos (crustáceos), frutos secos de árbol, cacahuetes, trigo, soja y sésamo. El pollo no está en la lista.","ru":"Девятка аллергенов: молоко, яйца, рыба, ракообразные моллюски, древесные орехи, арахис, пшеница, соя и кунжут. Курицы в списке нет.","tr":"Büyük 9 alerjen: süt, yumurta, balık, kabuklu deniz ürünleri (kabuklular), ağaç kuruyemişleri, yer fıstığı, buğday, soya ve susam. Tavuk listede yoktur.","hi":"बिग 9 एलर्जेन हैं दूध, अंडे, मछली, शेलफिश (क्रस्टेशियन), ट्री नट्स, मूंगफली, गेहूं, सोया और तिल। चिकन सूची में नहीं है।","ar":"مسببات الحساسية التسعة هي الحليب والبيض والسمك والمحار (القشريات) والمكسرات الشجرية والفول السوداني والقمح والصويا والسمسم. الدجاج ليس ضمن القائمة."}},{"cat":"crosscontam","a":2,"q":{"en":"Storing chemicals on a shelf above prepped vegetables risks which type of contamination?","es":"Guardar químicos en un estante encima de verduras preparadas arriesga qué tipo de contaminación?","ru":"Хранение химикатов на полке над подготовленными овощами создаёт риск какого типа загрязнения?","tr":"Kimyasalları hazırlanmış sebzelerin üstündeki rafta saklamak hangi tür bulaşma riskini doğurur?","hi":"तैयार सब्जियों के ऊपर शेल्फ पर रसायन रखना किस प्रकार के दूषण का जोखिम पैदा करता है?","ar":"تخزين المواد الكيميائية على رف فوق الخضار المُحضَّرة يعرّض لأي نوع من التلوث؟"},"o":[{"en":"Biological","es":"Biológica","ru":"Биологического","tr":"Biyolojik","hi":"जैविक","ar":"بيولوجي"},{"en":"Physical","es":"Física","ru":"Физического","tr":"Fiziksel","hi":"भौतिक","ar":"فيزيائي"},{"en":"Chemical","es":"Química","ru":"Химического","tr":"Kimyasal","hi":"रासायनिक","ar":"كيميائي"},{"en":"No contamination risk","es":"Sin riesgo de contaminación","ru":"Никакого риска загрязнения","tr":"Bulaşma riski yok","hi":"कोई दूषण जोखिम नहीं","ar":"لا خطر تلوث"}],"e":{"en":"A leaking or spilled chemical dripping onto food is a chemical contamination hazard. Chemicals must be stored below and away from food, never above it.","es":"Un químico que gotea o se derrama sobre la comida es un peligro de contaminación química. Los químicos deben guardarse debajo y lejos de la comida, nunca encima.","ru":"Протекающий или пролитый химикат, капающий на пищу, — это химическая опасность загрязнения. Химикаты хранят ниже и отдельно от пищи, никогда над ней.","tr":"Sızan ya da dökülen bir kimyasalın gıdaya damlaması kimyasal bulaşma tehlikesidir. Kimyasallar gıdanın altında ve uzağında saklanmalı, asla üstünde değil.","hi":"रिसता या गिरा हुआ रसायन भोजन पर टपकना एक रासायनिक दूषण खतरा है। रसायन भोजन के नीचे और दूर रखे जाने चाहिए, कभी ऊपर नहीं।","ar":"تسرّب مادة كيميائية أو انسكابها على الطعام يمثل خطر تلوث كيميائي. يجب تخزين المواد الكيميائية أسفل الطعام وبعيدًا عنه، وليس فوقه أبدًا."}},{"cat":"crosscontam","a":3,"q":{"en":"When a server takes an order from a guest who reports a food allergy, what should they do?","es":"Cuando un mesero toma un pedido de un cliente que informa una alergia alimentaria, ¿qué debe hacer?","ru":"Когда официант принимает заказ у гостя, сообщившего о пищевой аллергии, что ему делать?","tr":"Bir garson, gıda alerjisi olduğunu belirten bir misafirden sipariş alırken ne yapmalı?","hi":"जब एक सर्वर उस मेहमान से ऑर्डर लेता है जो खाद्य एलर्जी बताता है, तो उसे क्या करना चाहिए?","ar":"عندما يأخذ العامل طلبًا من ضيف يبلغ عن حساسية غذائية، ماذا يجب أن يفعل؟"},"o":[{"en":"Guess which items are safe","es":"Adivinar qué platillos son seguros","ru":"Угадать, какие блюда безопасны","tr":"Hangi ürünlerin güvenli olduğunu tahmin etmek","hi":"अनुमान लगाएं कि कौन-सी वस्तुएं सुरक्षित हैं","ar":"يخمّن أي الأصناف آمنة"},{"en":"Tell the guest all food is allergen-free","es":"Decir al cliente que toda la comida es libre de alérgenos","ru":"Сказать гостю, что вся еда без аллергенов","tr":"Misafire tüm yemeklerin alerjensiz olduğunu söylemek","hi":"मेहमान को बताएं कि सारा भोजन एलर्जेन-मुक्त है","ar":"يخبر الضيف أن كل الطعام خالٍ من مسببات الحساسية"},{"en":"Ignore it if the kitchen is busy","es":"Ignorarlo si la cocina está ocupada","ru":"Игнорировать, если кухня занята","tr":"Mutfak yoğunsa görmezden gelmek","hi":"यदि रसोई व्यस्त हो तो अनदेखा करें","ar":"يتجاهله إذا كان المطبخ مشغولًا"},{"en":"Inform the kitchen and confirm ingredients before serving","es":"Informar a la cocina y confirmar los ingredientes antes de servir","ru":"Сообщить на кухню и уточнить ингредиенты перед подачей","tr":"Mutfağı bilgilendirmek ve servisten önce içerikleri doğrulamak","hi":"रसोई को सूचित करें और परोसने से पहले सामग्री की पुष्टि करें","ar":"يبلّغ المطبخ ويؤكد المكونات قبل التقديم"}],"e":{"en":"The server must tell the kitchen about the allergy and verify the ingredients and preparation before serving, so the guest is not exposed to an allergen they cannot eat.","es":"El mesero debe informar a la cocina sobre la alergia y verificar los ingredientes y la preparación antes de servir, para que el cliente no quede expuesto a un alérgeno que no puede comer.","ru":"Официант должен сообщить кухне об аллергии и проверить ингредиенты и приготовление перед подачей, чтобы гость не столкнулся с аллергеном, который ему нельзя.","tr":"Garson, alerjiyi mutfağa bildirmeli ve servisten önce içerikleri ve hazırlamayı doğrulamalıdır; böylece misafir yiyemeyeceği bir alerjene maruz kalmaz.","hi":"सर्वर को एलर्जी के बारे में रसोई को बताना चाहिए और परोसने से पहले सामग्री और तैयारी की पुष्टि करनी चाहिए, ताकि मेहमान उस एलर्जेन के संपर्क में न आए जो वह नहीं खा सकता।","ar":"يجب على العامل إبلاغ المطبخ بالحساسية والتحقق من المكونات والتحضير قبل التقديم، حتى لا يتعرض الضيف لمسبب حساسية لا يستطيع تناوله."}},{"cat":"crosscontam","a":0,"q":{"en":"Raw meat is thawing in the cooler. How should it be positioned relative to other foods?","es":"Se está descongelando carne cruda en el refrigerador. ¿Cómo debe colocarse respecto a otros alimentos?","ru":"Сырое мясо размораживается в холодильнике. Как его расположить относительно других продуктов?","tr":"Çiğ et soğutucuda çözülüyor. Diğer gıdalara göre nasıl konumlandırılmalı?","hi":"कच्चा मांस कूलर में पिघल रहा है। इसे अन्य भोजन के सापेक्ष कैसे रखा जाना चाहिए?","ar":"لحم نيء يذوب في المبرّد. كيف يجب وضعه بالنسبة للأطعمة الأخرى؟"},"o":[{"en":"On the bottom shelf in a tray to catch drips","es":"En el estante inferior, en una bandeja para recoger goteos","ru":"На нижней полке в поддоне, чтобы ловить капли","tr":"Damlaları toplamak için alt rafta bir tepside","hi":"नीचे शेल्फ पर, टपकन पकड़ने के लिए एक ट्रे में","ar":"على الرف السفلي في صينية لالتقاط التنقيط"},{"en":"On the top shelf uncovered","es":"En el estante superior sin tapar","ru":"На верхней полке без крышки","tr":"Üst rafta üzeri açık","hi":"ऊपरी शेल्फ पर बिना ढके","ar":"على الرف العلوي مكشوفًا"},{"en":"Stacked on top of the vegetables","es":"Apilada encima de las verduras","ru":"Сложенным поверх овощей","tr":"Sebzelerin üstüne istiflenmiş","hi":"सब्जियों के ऊपर ढेर किया","ar":"مكدسًا فوق الخضار"},{"en":"Anywhere it fits","es":"En cualquier lugar donde quepa","ru":"Где угодно, где помещается","tr":"Sığdığı herhangi bir yere","hi":"जहां भी फिट हो","ar":"في أي مكان يتسع"}],"e":{"en":"Thawing raw meat is placed on the bottom shelf in a tray or pan so that thaw liquids and juices cannot drip down onto ready-to-eat or lower-cook-temperature foods.","es":"La carne cruda que se descongela se coloca en el estante inferior, en una bandeja, para que los líquidos y jugos no goteen sobre alimentos listos para comer o de menor temperatura de cocción.","ru":"Размораживаемое сырое мясо кладут на нижнюю полку в поддон, чтобы жидкости и соки не капали на готовую пищу или продукты с меньшей температурой готовки.","tr":"Çözülen çiğ et, çözülme sıvıları ve suları yenmeye hazır ya da daha düşük pişirme sıcaklıklı gıdaların üzerine damlamasın diye alt rafta bir tepsiye konur.","hi":"पिघलता कच्चा मांस नीचे शेल्फ पर एक ट्रे में रखा जाता है ताकि पिघलने वाले तरल और रस खाने-के-लिए-तैयार या कम पकाने-तापमान वाले भोजन पर न टपकें।","ar":"يوضع اللحم النيئ الذي يذوب على الرف السفلي في صينية حتى لا تسقط سوائل الذوبان والعصارة على الأطعمة الجاهزة للأكل أو الأطعمة الأقل درجة طهي."}},{"cat":"crosscontam","a":1,"q":{"en":"A cook wipes up raw egg with a cloth, then uses the same cloth on a clean counter. What is the risk?","es":"Un cocinero limpia huevo crudo con un paño y luego usa el mismo paño en una barra limpia. ¿Cuál es el riesgo?","ru":"Повар вытирает сырое яйцо тряпкой, затем использует ту же тряпку на чистом столе. В чём риск?","tr":"Bir aşçı çiğ yumurtayı bir bezle siler, sonra aynı bezi temiz tezgahta kullanır. Risk nedir?","hi":"एक रसोइया कपड़े से कच्चा अंडा पोंछता है, फिर उसी कपड़े को साफ काउंटर पर उपयोग करता है। जोखिम क्या है?","ar":"يمسح طاهٍ بيضًا نيئًا بقطعة قماش ثم يستخدم القماش نفسه على طاولة نظيفة. ما الخطر؟"},"o":[{"en":"The cloth will smell bad","es":"El paño olerá mal","ru":"Тряпка будет плохо пахнуть","tr":"Bez kötü kokacak","hi":"कपड़े से बदबू आएगी","ar":"ستنبعث رائحة كريهة من القماش"},{"en":"The cloth spreads pathogens from the raw egg onto the clean counter","es":"El paño esparce patógenos del huevo crudo a la barra limpia","ru":"Тряпка разносит патогены от сырого яйца на чистый стол","tr":"Bez, çiğ yumurtadaki patojenleri temiz tezgaha yayar","hi":"कपड़ा कच्चे अंडे के रोगाणुओं को साफ काउंटर पर फैलाता है","ar":"ينشر القماش مسببات المرض من البيض النيئ إلى الطاولة النظيفة"},{"en":"The counter will get too wet","es":"La barra quedará demasiado mojada","ru":"Стол станет слишком мокрым","tr":"Tezgah fazla ıslanacak","hi":"काउंटर बहुत गीला हो जाएगा","ar":"ستصبح الطاولة مبللة جدًا"},{"en":"There is no real risk","es":"No hay riesgo real","ru":"Реального риска нет","tr":"Gerçek bir risk yok","hi":"कोई वास्तविक जोखिम नहीं","ar":"لا يوجد خطر حقيقي"}],"e":{"en":"A cloth used on raw egg carries pathogens and will contaminate any surface it touches next. Wiping cloths must be cleaned and kept in sanitizer solution between uses.","es":"Un paño usado en huevo crudo lleva patógenos y contaminará la siguiente superficie que toque. Los paños deben limpiarse y guardarse en solución desinfectante entre usos.","ru":"Тряпка, использованная для сырого яйца, несёт патогены и загрязнит следующую поверхность. Салфетки нужно мыть и держать в растворе санитайзера между использованиями.","tr":"Çiğ yumurtada kullanılan bez patojen taşır ve dokunduğu bir sonraki yüzeyi kirletir. Bez, kullanımlar arasında temizlenmeli ve dezenfektan solüsyonunda tutulmalıdır.","hi":"कच्चे अंडे पर उपयोग किया कपड़ा रोगाणु ले जाता है और अगली सतह को दूषित करेगा। पोंछने वाले कपड़े साफ किए जाने चाहिए और उपयोगों के बीच सैनिटाइज़र घोल में रखे जाने चाहिए।","ar":"القماش المستخدم على البيض النيئ يحمل مسببات المرض ويلوّث أي سطح يلمسه بعده. يجب تنظيف أقمشة المسح وحفظها في محلول معقّم بين الاستخدامات."}},{"cat":"crosscontam","a":2,"q":{"en":"A cutting board is deeply scratched and grooved. Why should it be resurfaced or replaced?","es":"Una tabla de cortar está muy rayada y con surcos. ¿Por qué debe reacondicionarse o reemplazarse?","ru":"Разделочная доска сильно поцарапана и в бороздах. Почему её нужно отшлифовать или заменить?","tr":"Bir kesme tahtası derin çizik ve oluklarla dolu. Neden yenilenmeli ya da değiştirilmeli?","hi":"एक कटिंग बोर्ड गहराई से खरोंचा और खांचेदार है। इसे फिर से सतह किया या बदला क्यों जाना चाहिए?","ar":"لوح تقطيع مخدوش بعمق وبه أخاديد. لماذا يجب تجديد سطحه أو استبداله؟"},"o":[{"en":"Scratches make it look old","es":"Los rayones lo hacen ver viejo","ru":"Царапины делают её старой на вид","tr":"Çizikler onu eski gösterir","hi":"खरोंच इसे पुराना दिखाते हैं","ar":"الخدوش تجعله يبدو قديمًا"},{"en":"Grooves make cutting slower","es":"Los surcos hacen más lento el corte","ru":"Борозды замедляют резку","tr":"Oluklar kesmeyi yavaşlatır","hi":"खांचे काटना धीमा करते हैं","ar":"الأخاديد تبطئ التقطيع"},{"en":"Grooves trap food and bacteria that are hard to clean out","es":"Los surcos atrapan comida y bacterias difíciles de limpiar","ru":"Борозды удерживают пищу и бактерии, которые трудно вымыть","tr":"Oluklar, temizlenmesi zor gıda ve bakteri tutar","hi":"खांचे भोजन और बैक्टीरिया रोकते हैं जिन्हें साफ करना कठिन है","ar":"الأخاديد تحبس الطعام والبكتيريا التي يصعب تنظيفها"},{"en":"Scratches dull the knife","es":"Los rayones desafilan el cuchillo","ru":"Царапины тупят нож","tr":"Çizikler bıçağı köreltir","hi":"खरोंच चाकू को कुंद करते हैं","ar":"الخدوش تثلم السكين"}],"e":{"en":"Deep cuts and grooves in a board trap food particles and bacteria that cleaning and sanitizing cannot reliably reach, so scratched boards must be resurfaced or replaced.","es":"Los cortes y surcos profundos atrapan partículas de comida y bacterias que la limpieza y desinfección no alcanzan de forma confiable, por eso las tablas rayadas deben reacondicionarse o reemplazarse.","ru":"Глубокие порезы и борозды удерживают частицы пищи и бактерии, до которых мытьё и дезинфекция не достают надёжно, поэтому поцарапанные доски нужно шлифовать или заменять.","tr":"Tahtadaki derin kesikler ve oluklar, temizlik ve dezenfeksiyonun güvenilir biçimde ulaşamadığı gıda parçacıkları ve bakteri tutar; bu yüzden çizik tahtalar yenilenmeli ya da değiştirilmelidir.","hi":"बोर्ड में गहरे कट और खांचे भोजन कण और बैक्टीरिया रोकते हैं जहां सफाई और सैनिटाइज़िंग भरोसे से नहीं पहुंच सकती, इसलिए खरोंचे बोर्ड फिर से सतह किए या बदले जाने चाहिए।","ar":"القطوع والأخاديد العميقة في اللوح تحبس جزيئات الطعام والبكتيريا التي لا يصل إليها التنظيف والتعقيم بشكل موثوق، لذا يجب تجديد الألواح المخدوشة أو استبدالها."}},{"cat":"crosscontam","a":3,"q":{"en":"Raw salmon, raw ground beef, and raw whole-muscle beef steak share a cooler. From top to bottom, the correct order is:","es":"Salmón crudo, carne molida cruda y bistec de res entero crudo comparten un refrigerador. De arriba a abajo, el orden correcto es:","ru":"Сырой лосось, сырой говяжий фарш и сырой цельный стейк из говядины в одном холодильнике. Сверху вниз правильный порядок:","tr":"Çiğ somon, çiğ dana kıyma ve çiğ bütün kas dana biftek aynı soğutucuda. Yukarıdan aşağıya doğru sıra nedir:","hi":"कच्चा सैल्मन, कच्चा पिसा बीफ और कच्चा साबुत-मांसपेशी बीफ स्टेक एक कूलर साझा करते हैं। ऊपर से नीचे सही क्रम है:","ar":"سلمون نيء، لحم بقري مفروم نيء، وشريحة لحم بقري كاملة نيئة تشترك في مبرّد. من الأعلى للأسفل الترتيب الصحيح هو:"},"o":[{"en":"Ground beef, salmon, steak","es":"Carne molida, salmón, bistec","ru":"Фарш, лосось, стейк","tr":"Kıyma, somon, biftek","hi":"पिसा बीफ, सैल्मन, स्टेक","ar":"لحم مفروم، سلمون، شريحة"},{"en":"Ground beef, steak, salmon","es":"Carne molida, bistec, salmón","ru":"Фарш, стейк, лосось","tr":"Kıyma, biftek, somon","hi":"पिसा बीफ, स्टेक, सैल्मन","ar":"لحم مفروم، شريحة، سلمون"},{"en":"Salmon, ground beef, steak","es":"Salmón, carne molida, bistec","ru":"Лосось, фарш, стейк","tr":"Somon, kıyma, biftek","hi":"सैल्मन, पिसा बीफ, स्टेक","ar":"سلمون، لحم مفروم، شريحة"},{"en":"Salmon, steak, ground beef","es":"Salmón, bistec, carne molida","ru":"Лосось, стейк, фарш","tr":"Somon, biftek, kıyma","hi":"सैल्मन, स्टेक, पिसा बीफ","ar":"سلمون، شريحة، لحم مفروم"}],"e":{"en":"Order by cook temperature, lowest on top: salmon and whole-muscle steak both cook to 145°F, so they go above ground beef (155°F). By convention fish is placed above whole beef, giving salmon, steak, ground beef.","es":"Ordene por temperatura de cocción, la más baja arriba: el salmón y el bistec entero se cocinan a 145°F, así que van sobre la carne molida (155°F). Por convención el pescado va sobre la res entera: salmón, bistec, carne molida.","ru":"Порядок по температуре готовки, самая низкая наверху: лосось и цельный стейк готовят до 145°F, поэтому они выше фарша (155°F). По правилу рыбу кладут выше цельной говядины: лосось, стейк, фарш.","tr":"Pişirme sıcaklığına göre sırala, en düşük üstte: somon ve bütün kas biftek 145°F'e pişer, bu yüzden kıymanın (155°F) üstündedir. Teamülen balık bütün etin üstüne konur: somon, biftek, kıyma.","hi":"पकाने के तापमान के अनुसार क्रम, सबसे कम ऊपर: सैल्मन और साबुत-मांसपेशी स्टेक दोनों 145°F पर पकते हैं, इसलिए वे पिसे बीफ (155°F) के ऊपर हैं। परंपरा से मछली साबुत बीफ के ऊपर रखी जाती है: सैल्मन, स्टेक, पिसा बीफ।","ar":"رتّب حسب درجة الطهي، الأقل في الأعلى: السلمون وشريحة العضلة الكاملة كلاهما يُطهى إلى 145°F، فيكونان فوق اللحم المفروم (155°F). وعرفًا يُوضع السمك فوق اللحم الكامل: سلمون، شريحة، لحم مفروم."}},{"cat":"crosscontam","a":0,"q":{"en":"After making a dish with wheat flour, what should be done before preparing a gluten-free order?","es":"Después de preparar un platillo con harina de trigo, ¿qué debe hacerse antes de preparar un pedido sin gluten?","ru":"После приготовления блюда с пшеничной мукой что нужно сделать перед приготовлением безглютенового заказа?","tr":"Buğday unuyla bir yemek yaptıktan sonra glütensiz bir sipariş hazırlamadan önce ne yapılmalı?","hi":"गेहूं के आटे वाला व्यंजन बनाने के बाद, ग्लूटेन-मुक्त ऑर्डर तैयार करने से पहले क्या किया जाना चाहिए?","ar":"بعد تحضير طبق بدقيق القمح، ماذا يجب فعله قبل تحضير طلب خالٍ من الغلوتين؟"},"o":[{"en":"Wash hands and clean and sanitize surfaces and tools","es":"Lavarse las manos y limpiar y desinfectar superficies y utensilios","ru":"Вымыть руки, вымыть и продезинфицировать поверхности и инструменты","tr":"Elleri yıkamak, yüzeyleri ve aletleri temizleyip dezenfekte etmek","hi":"हाथ धोएं और सतहों व औजारों को साफ और सैनिटाइज़ करें","ar":"غسل اليدين وتنظيف وتعقيم الأسطح والأدوات"},{"en":"Just brush the flour off","es":"Solo sacudir la harina","ru":"Просто смахнуть муку","tr":"Sadece unu silkelemek","hi":"बस आटा झाड़ दें","ar":"مجرد نفض الدقيق"},{"en":"Change the menu label","es":"Cambiar la etiqueta del menú","ru":"Изменить этикетку меню","tr":"Menü etiketini değiştirmek","hi":"मेनू लेबल बदलें","ar":"تغيير ملصق القائمة"},{"en":"Cook the gluten-free dish hotter","es":"Cocinar más caliente el platillo sin gluten","ru":"Готовить безглютеновое блюдо горячее","tr":"Glütensiz yemeği daha sıcak pişirmek","hi":"ग्लूटेन-मुक्त व्यंजन को अधिक गर्म पकाएं","ar":"طهي الطبق الخالي من الغلوتين بحرارة أعلى"}],"e":{"en":"Wheat is an allergen and flour dust lingers, so hands must be washed and surfaces and tools cleaned and sanitized before a gluten-free order to avoid allergen cross-contact.","es":"El trigo es un alérgeno y el polvo de harina permanece, por lo que hay que lavarse las manos y limpiar y desinfectar superficies y utensilios antes de un pedido sin gluten para evitar el contacto cruzado.","ru":"Пшеница — аллерген, а мучная пыль остаётся, поэтому перед безглютеновым заказом нужно вымыть руки и вымыть и продезинфицировать поверхности и инструменты, чтобы избежать перекрёстного контакта.","tr":"Buğday bir alerjendir ve un tozu havada kalır; bu yüzden alerjen çapraz temasını önlemek için glütensiz siparişten önce eller yıkanmalı ve yüzeyler ile aletler temizlenip dezenfekte edilmelidir.","hi":"गेहूं एक एलर्जेन है और आटे की धूल बनी रहती है, इसलिए एलर्जेन क्रॉस-कॉन्टैक्ट से बचने के लिए ग्लूटेन-मुक्त ऑर्डर से पहले हाथ धोए और सतहें व औजार साफ और सैनिटाइज़ किए जाने चाहिए।","ar":"القمح مسبب حساسية وغبار الدقيق يبقى عالقًا، لذا يجب غسل اليدين وتنظيف وتعقيم الأسطح والأدوات قبل الطلب الخالي من الغلوتين لتجنب التلامس المتبادل."}},{"cat":"crosscontam","a":1,"q":{"en":"Why should food stored in the cooler be kept covered?","es":"¿Por qué debe mantenerse cubierta la comida guardada en el refrigerador?","ru":"Почему пищу, хранящуюся в холодильнике, нужно держать накрытой?","tr":"Soğutucuda saklanan gıda neden üzeri kapalı tutulmalı?","hi":"कूलर में संग्रहीत भोजन को ढका क्यों रखना चाहिए?","ar":"لماذا يجب إبقاء الطعام المخزّن في المبرّد مغطى؟"},"o":[{"en":"To keep it looking neat","es":"Para que se vea ordenado","ru":"Чтобы выглядело аккуратно","tr":"Düzgün görünmesi için","hi":"इसे साफ-सुथरा दिखाने के लिए","ar":"ليبدو مرتبًا"},{"en":"To protect it from drips, spills, and contaminants","es":"Para protegerla de goteos, derrames y contaminantes","ru":"Чтобы защитить от капель, проливов и загрязнителей","tr":"Damla, dökülme ve kirleticilerden korumak için","hi":"इसे टपकन, गिराव और दूषकों से बचाने के लिए","ar":"لحمايته من التنقيط والانسكاب والملوثات"},{"en":"To make the cooler colder","es":"Para que el refrigerador esté más frío","ru":"Чтобы холодильник был холоднее","tr":"Soğutucuyu daha soğuk yapmak için","hi":"कूलर को अधिक ठंडा करने के लिए","ar":"لجعل المبرّد أبرد"},{"en":"To speed up cooling","es":"Para acelerar el enfriamiento","ru":"Чтобы ускорить охлаждение","tr":"Soğumayı hızlandırmak için","hi":"शीतलन तेज करने के लिए","ar":"لتسريع التبريد"}],"e":{"en":"Covering food in storage protects it from drips, spills, condensation, and other contaminants, and keeps it from picking up or spreading odors and cross-contamination.","es":"Cubrir la comida guardada la protege de goteos, derrames, condensación y otros contaminantes, y evita que absorba o esparza olores y contaminación cruzada.","ru":"Накрывание пищи при хранении защищает её от капель, проливов, конденсата и других загрязнителей и не даёт впитывать или распространять запахи и перекрёстное загрязнение.","tr":"Saklanan gıdanın üzerini örtmek onu damla, dökülme, yoğuşma ve diğer kirleticilerden korur; koku ve çapraz bulaşma almasını ya da yaymasını önler.","hi":"भंडारण में भोजन को ढकना इसे टपकन, गिराव, संघनन और अन्य दूषकों से बचाता है, और इसे गंध व क्रॉस-कॉन्टैमिनेशन ग्रहण करने या फैलाने से रोकता है।","ar":"تغطية الطعام أثناء التخزين تحميه من التنقيط والانسكاب والتكاثف والملوثات الأخرى، وتمنعه من التقاط أو نشر الروائح والتلوث المتبادل."}},{"cat":"crosscontam","a":2,"q":{"en":"Which is a common source of biological cross-contamination in a kitchen?","es":"¿Cuál es una fuente común de contaminación cruzada biológica en una cocina?","ru":"Что является распространённым источником биологического перекрёстного загрязнения на кухне?","tr":"Mutfakta biyolojik çapraz bulaşmanın yaygın bir kaynağı hangisidir?","hi":"रसोई में जैविक क्रॉस-कॉन्टैमिनेशन का एक सामान्य स्रोत कौन-सा है?","ar":"أي مما يلي مصدر شائع للتلوث المتبادل البيولوجي في المطبخ؟"},"o":[{"en":"A calibrated thermometer","es":"Un termómetro calibrado","ru":"Откалиброванный термометр","tr":"Kalibre edilmiş bir termometre","hi":"एक कैलिब्रेटेड थर्मामीटर","ar":"ميزان حرارة معاير"},{"en":"A clean, sanitized counter","es":"Una barra limpia y desinfectada","ru":"Чистый, продезинфицированный стол","tr":"Temiz, dezenfekte edilmiş tezgah","hi":"साफ, सैनिटाइज़ किया काउंटर","ar":"طاولة نظيفة ومعقمة"},{"en":"Unwashed hands after handling raw meat","es":"Manos sin lavar después de manejar carne cruda","ru":"Немытые руки после работы с сырым мясом","tr":"Çiğ ete dokunduktan sonra yıkanmamış eller","hi":"कच्चा मांस संभालने के बाद बिना धुले हाथ","ar":"أيدٍ غير مغسولة بعد مناولة اللحم النيئ"},{"en":"A covered container of leftovers","es":"Un recipiente tapado de sobras","ru":"Закрытая ёмкость с остатками","tr":"Kapaklı bir artık yemek kabı","hi":"बचे भोजन का ढका बर्तन","ar":"وعاء مغطى من البقايا"}],"e":{"en":"Unwashed hands, contaminated utensils, and dirty equipment transfer pathogens from raw foods to ready-to-eat foods. Handwashing and cleaning between tasks break this chain.","es":"Las manos sin lavar, los utensilios contaminados y el equipo sucio transfieren patógenos de alimentos crudos a listos para comer. Lavarse las manos y limpiar entre tareas rompe esa cadena.","ru":"Немытые руки, загрязнённый инвентарь и грязное оборудование переносят патогены с сырых продуктов на готовые. Мытьё рук и уборка между задачами разрывают эту цепь.","tr":"Yıkanmamış eller, kirli aletler ve pis ekipman, patojenleri çiğ gıdalardan yenmeye hazır gıdalara taşır. Görevler arası el yıkama ve temizlik bu zinciri kırar.","hi":"बिना धुले हाथ, दूषित बर्तन और गंदे उपकरण कच्चे भोजन से खाने-के-लिए-तैयार भोजन तक रोगाणु स्थानांतरित करते हैं। कार्यों के बीच हाथ धोना और सफाई इस श्रृंखला को तोड़ते हैं।","ar":"الأيدي غير المغسولة والأدوات الملوثة والمعدات المتسخة تنقل المسببات من الأطعمة النيئة إلى الجاهزة للأكل. غسل اليدين والتنظيف بين المهام يكسر هذه السلسلة."}},{"cat":"crosscontam","a":3,"q":{"en":"A guest is allergic to milk. Which ingredient must be avoided because it contains a milk protein?","es":"Un cliente es alérgico a la leche. ¿Qué ingrediente debe evitarse porque contiene una proteína de leche?","ru":"У гостя аллергия на молоко. Какого ингредиента нужно избегать, так как он содержит молочный белок?","tr":"Bir misafir süte alerjik. Süt proteini içerdiği için hangi malzemeden kaçınılmalı?","hi":"एक मेहमान को दूध से एलर्जी है। कौन-सी सामग्री टाली जानी चाहिए क्योंकि इसमें दूध प्रोटीन है?","ar":"ضيف لديه حساسية من الحليب. أي مكوّن يجب تجنبه لأنه يحتوي على بروتين حليب؟"},"o":[{"en":"Olive oil","es":"Aceite de oliva","ru":"Оливковое масло","tr":"Zeytinyağı","hi":"जैतून का तेल","ar":"زيت الزيتون"},{"en":"White rice","es":"Arroz blanco","ru":"Белый рис","tr":"Beyaz pirinç","hi":"सफेद चावल","ar":"أرز أبيض"},{"en":"Table salt","es":"Sal de mesa","ru":"Поваренная соль","tr":"Sofra tuzu","hi":"टेबल नमक","ar":"ملح الطعام"},{"en":"Whey (a dairy protein)","es":"Suero de leche (proteína láctea)","ru":"Сыворотка (молочный белок)","tr":"Peynir altı suyu (süt proteini)","hi":"व्हे (एक डेयरी प्रोटीन)","ar":"مصل اللبن (بروتين حليب)"}],"e":{"en":"Milk allergens hide in ingredients like whey, casein, butter, and many baked goods. Staff must read labels and recipes, since milk protein may appear under different names.","es":"Los alérgenos de la leche se esconden en ingredientes como suero, caseína, mantequilla y muchos horneados. El personal debe leer etiquetas y recetas, pues la proteína láctea aparece con distintos nombres.","ru":"Молочные аллергены скрываются в таких ингредиентах, как сыворотка, казеин, масло и многая выпечка. Персонал должен читать этикетки и рецепты, ведь молочный белок может называться по-разному.","tr":"Süt alerjenleri peynir altı suyu, kazein, tereyağı ve birçok fırın ürünü gibi malzemelerde gizlenir. Personel etiketleri ve tarifleri okumalı; çünkü süt proteini farklı adlarla görünebilir.","hi":"दूध एलर्जेन व्हे, केसीन, मक्खन और कई बेक्ड सामान जैसी सामग्री में छिपे होते हैं। स्टाफ को लेबल और रेसिपी पढ़ने चाहिए, क्योंकि दूध प्रोटीन अलग नामों से दिख सकता है।","ar":"مسببات حساسية الحليب تختبئ في مكونات مثل مصل اللبن والكازين والزبدة وكثير من المخبوزات. على الموظفين قراءة الملصقات والوصفات، فقد يظهر بروتين الحليب بأسماء مختلفة."}},{"cat":"crosscontam","a":0,"q":{"en":"A cook handles raw beef with gloves, then needs to build a sandwich. What is the correct action?","es":"Un cocinero maneja res cruda con guantes y luego debe armar un sándwich. ¿Cuál es la acción correcta?","ru":"Повар в перчатках работает с сырой говядиной, затем должен собрать сэндвич. Каково правильное действие?","tr":"Bir aşçı eldivenle çiğ dana eti tutuyor, sonra sandviç hazırlaması gerekiyor. Doğru eylem nedir?","hi":"एक रसोइया दस्ताने के साथ कच्चा बीफ संभालता है, फिर उसे सैंडविच बनाना है। सही कार्रवाई क्या है?","ar":"يتعامل طاهٍ مع لحم بقري نيء بالقفازات، ثم يحتاج لتحضير شطيرة. ما الإجراء الصحيح؟"},"o":[{"en":"Remove gloves, wash hands, and put on new gloves","es":"Quitarse los guantes, lavarse las manos y ponerse guantes nuevos","ru":"Снять перчатки, вымыть руки и надеть новые перчатки","tr":"Eldivenleri çıkarmak, elleri yıkamak ve yeni eldiven takmak","hi":"दस्ताने हटाएं, हाथ धोएं और नए दस्ताने पहनें","ar":"نزع القفازات وغسل اليدين وارتداء قفازات جديدة"},{"en":"Rinse the gloves and keep going","es":"Enjuagar los guantes y continuar","ru":"Сполоснуть перчатки и продолжить","tr":"Eldivenleri durulayıp devam etmek","hi":"दस्तानों को धोएं और जारी रखें","ar":"شطف القفازات والمتابعة"},{"en":"Wipe gloves on the apron","es":"Limpiar los guantes en el delantal","ru":"Вытереть перчатки о фартук","tr":"Eldivenleri önlüğe silmek","hi":"दस्तानों को एप्रन पर पोंछें","ar":"مسح القفازات بالمريلة"},{"en":"Keep the same gloves; beef is safe","es":"Mantener los mismos guantes; la res es segura","ru":"Оставить те же перчатки; говядина безопасна","tr":"Aynı eldivenleri tutmak; dana eti güvenli","hi":"वही दस्ताने रखें; बीफ सुरक्षित है","ar":"الإبقاء على القفازات نفسها؛ اللحم آمن"}],"e":{"en":"Gloves used on raw beef are contaminated. The cook must remove them, wash hands, and put on new gloves before handling ready-to-eat sandwich ingredients.","es":"Los guantes usados en res cruda están contaminados. El cocinero debe quitárselos, lavarse las manos y ponerse guantes nuevos antes de manejar ingredientes listos para comer.","ru":"Перчатки после сырой говядины загрязнены. Повар должен их снять, вымыть руки и надеть новые перед работой с готовыми ингредиентами сэндвича.","tr":"Çiğ dana etinde kullanılan eldivenler kirlidir. Aşçı bunları çıkarmalı, ellerini yıkamalı ve yenmeye hazır sandviç malzemelerine dokunmadan önce yeni eldiven takmalıdır.","hi":"कच्चे बीफ पर उपयोग किए दस्ताने दूषित हैं। रसोइए को इन्हें हटाना चाहिए, हाथ धोने चाहिए और खाने-के-लिए-तैयार सैंडविच सामग्री संभालने से पहले नए दस्ताने पहनने चाहिए।","ar":"القفازات المستخدمة على اللحم النيئ ملوثة. على الطاهي نزعها وغسل يديه وارتداء قفازات جديدة قبل التعامل مع مكونات الشطيرة الجاهزة للأكل."}},{"cat":"crosscontam","a":1,"q":{"en":"A knife used to trim raw pork will next be used to slice bread. What must happen first?","es":"Un cuchillo usado para limpiar cerdo crudo se usará luego para rebanar pan. ¿Qué debe ocurrir primero?","ru":"Нож, которым обрезали сырую свинину, дальше будут использовать для хлеба. Что должно произойти сначала?","tr":"Çiğ domuz etini temizlemek için kullanılan bıçak sonra ekmek dilimlemede kullanılacak. Önce ne olmalı?","hi":"कच्चे पोर्क को छांटने के लिए उपयोग किया चाकू अगली बार ब्रेड काटने के लिए उपयोग होगा। पहले क्या होना चाहिए?","ar":"سكين استُخدم لتقليم لحم خنزير نيء سيُستخدم بعده لتقطيع الخبز. ماذا يجب أن يحدث أولًا؟"},"o":[{"en":"Wipe it on a towel","es":"Limpiarlo con una toalla","ru":"Протереть его полотенцем","tr":"Bir havluya silmek","hi":"इसे तौलिये पर पोंछें","ar":"مسحه بمنشفة"},{"en":"Wash, rinse, and sanitize the knife","es":"Lavar, enjuagar y desinfectar el cuchillo","ru":"Вымыть, ополоснуть и продезинфицировать нож","tr":"Bıçağı yıkamak, durulamak ve dezenfekte etmek","hi":"चाकू को धोएं, धोकर साफ करें और सैनिटाइज़ करें","ar":"غسل السكين وشطفه وتعقيمه"},{"en":"Rinse it in cold water","es":"Enjuagarlo con agua fría","ru":"Сполоснуть в холодной воде","tr":"Soğuk suyla durulamak","hi":"इसे ठंडे पानी में धोएं","ar":"شطفه بماء بارد"},{"en":"Nothing, pork is cooked later","es":"Nada, el cerdo se cocina después","ru":"Ничего, свинину готовят позже","tr":"Hiçbir şey, domuz eti sonra pişer","hi":"कुछ नहीं, पोर्क बाद में पकता है","ar":"لا شيء، الخنزير يُطهى لاحقًا"}],"e":{"en":"The knife must be washed, rinsed, and sanitized before slicing ready-to-eat bread. Bread will not be cooked, so any pathogens left on the knife would reach the guest.","es":"El cuchillo debe lavarse, enjuagarse y desinfectarse antes de rebanar pan listo para comer. El pan no se cocinará, así que cualquier patógeno en el cuchillo llegaría al cliente.","ru":"Нож нужно вымыть, ополоснуть и продезинфицировать перед нарезкой готового хлеба. Хлеб не будут готовить, поэтому оставшиеся на ноже патогены попадут к гостю.","tr":"Bıçak, yenmeye hazır ekmeği dilimlemeden önce yıkanmalı, durulanmalı ve dezenfekte edilmelidir. Ekmek pişmeyeceği için bıçakta kalan patojenler misafire ulaşır.","hi":"खाने-के-लिए-तैयार ब्रेड काटने से पहले चाकू को धोना, धोकर साफ करना और सैनिटाइज़ करना चाहिए। ब्रेड नहीं पकेगी, इसलिए चाकू पर बचे रोगाणु मेहमान तक पहुंचेंगे।","ar":"يجب غسل السكين وشطفه وتعقيمه قبل تقطيع الخبز الجاهز للأكل. الخبز لن يُطهى، لذا أي مسببات تبقى على السكين ستصل إلى الضيف."}},{"cat":"crosscontam","a":2,"q":{"en":"When putting away a delivery, where should raw ground meat go relative to cartons of milk and juice?","es":"Al guardar una entrega, ¿dónde debe ir la carne molida cruda respecto a los cartones de leche y jugo?","ru":"При раскладке доставки где должен находиться сырой фарш относительно упаковок молока и сока?","tr":"Bir teslimatı yerleştirirken çiğ kıyma, süt ve meyve suyu kartonlarına göre nereye konmalı?","hi":"डिलीवरी रखते समय, दूध और जूस के डिब्बों के सापेक्ष कच्चा पिसा मांस कहां जाना चाहिए?","ar":"عند تخزين شحنة، أين يجب وضع اللحم المفروم النيء بالنسبة لعبوات الحليب والعصير؟"},"o":[{"en":"Above the milk and juice","es":"Encima de la leche y el jugo","ru":"Выше молока и сока","tr":"Süt ve meyve suyunun üstünde","hi":"दूध और जूस के ऊपर","ar":"فوق الحليب والعصير"},{"en":"Next to them on the same shelf","es":"Junto a ellos en el mismo estante","ru":"Рядом с ними на той же полке","tr":"Aynı rafta yanlarında","hi":"उनके बगल में एक ही शेल्फ पर","ar":"بجانبهما على الرف نفسه"},{"en":"Below the milk and juice","es":"Debajo de la leche y el jugo","ru":"Ниже молока и сока","tr":"Süt ve meyve suyunun altında","hi":"दूध और जूस के नीचे","ar":"أسفل الحليب والعصير"},{"en":"It does not matter where","es":"No importa dónde","ru":"Неважно где","tr":"Nereye olduğu önemli değil","hi":"कहां रखें इससे फर्क नहीं","ar":"لا يهم أين"}],"e":{"en":"Raw ground meat cooks to 155°F, higher than ready-to-drink milk and juice, so it is stored below them so any drips fall away from the ready-to-eat products.","es":"La carne molida cruda se cocina a 155°F, más que la leche y el jugo listos para beber, así que se guarda debajo para que los goteos no caigan sobre los productos listos para consumir.","ru":"Сырой фарш готовят до 155°F — выше, чем готовые к употреблению молоко и сок, поэтому его хранят ниже, чтобы капли не попадали на готовые продукты.","tr":"Çiğ kıyma 155°F'e pişer; içmeye hazır süt ve meyve suyundan yüksektir, bu yüzden altlarında saklanır ki damlalar yenmeye/içilmeye hazır ürünlere düşmesin.","hi":"कच्चा पिसा मांस 155°F पर पकता है, पीने-के-लिए-तैयार दूध और जूस से अधिक, इसलिए इसे उनके नीचे रखा जाता है ताकि टपकन तैयार उत्पादों से दूर गिरे।","ar":"اللحم المفروم النيء يُطهى إلى 155°F، أعلى من الحليب والعصير الجاهزين للشرب، لذا يُخزَّن أسفلهما حتى يسقط أي تنقيط بعيدًا عن المنتجات الجاهزة."}},{"cat":"crosscontam","a":3,"q":{"en":"Which practice helps prevent physical contamination of food?","es":"¿Qué práctica ayuda a prevenir la contaminación física de los alimentos?","ru":"Какая практика помогает предотвратить физическое загрязнение пищи?","tr":"Hangi uygulama gıdanın fiziksel bulaşmasını önlemeye yardımcı olur?","hi":"कौन-सी प्रथा भोजन के भौतिक दूषण को रोकने में मदद करती है?","ar":"أي ممارسة تساعد على منع التلوث الفيزيائي للطعام؟"},"o":[{"en":"Storing chemicals above food","es":"Guardar químicos encima de la comida","ru":"Хранить химикаты над пищей","tr":"Kimyasalları gıdanın üstünde saklamak","hi":"रसायनों को भोजन के ऊपर रखना","ar":"تخزين المواد الكيميائية فوق الطعام"},{"en":"Cooling food slowly","es":"Enfriar la comida lentamente","ru":"Медленно охлаждать пищу","tr":"Gıdayı yavaş soğutmak","hi":"भोजन को धीरे ठंडा करना","ar":"تبريد الطعام ببطء"},{"en":"Reusing single-use gloves","es":"Reutilizar guantes de un solo uso","ru":"Повторно использовать одноразовые перчатки","tr":"Tek kullanımlık eldivenleri yeniden kullanmak","hi":"एक-बार-इस्तेमाल दस्तानों का पुन: उपयोग","ar":"إعادة استخدام القفازات ذات الاستعمال الواحد"},{"en":"Removing jewelry and using shatterproof containers","es":"Quitarse las joyas y usar recipientes irrompibles","ru":"Снимать украшения и использовать небьющиеся ёмкости","tr":"Takıları çıkarmak ve kırılmaz kaplar kullanmak","hi":"आभूषण हटाना और न-टूटने वाले बर्तन उपयोग करना","ar":"نزع المجوهرات واستخدام أوعية غير قابلة للكسر"}],"e":{"en":"Physical contamination comes from objects like glass, metal, jewelry, and bandages. Removing jewelry, using shatterproof containers, and keeping hardware maintained keep these out of food.","es":"La contaminación física proviene de objetos como vidrio, metal, joyas y vendas. Quitarse las joyas, usar recipientes irrompibles y mantener el equipo evita que lleguen a la comida.","ru":"Физическое загрязнение исходит от предметов: стекла, металла, украшений, пластырей. Снятие украшений, небьющиеся ёмкости и исправное оборудование не дают им попасть в пищу.","tr":"Fiziksel bulaşma cam, metal, takı ve bandaj gibi nesnelerden gelir. Takıları çıkarmak, kırılmaz kap kullanmak ve donanımı bakımlı tutmak bunları gıdadan uzak tutar.","hi":"भौतिक दूषण कांच, धातु, आभूषण और पट्टियों जैसी वस्तुओं से आता है। आभूषण हटाना, न-टूटने वाले बर्तन उपयोग करना और उपकरण बनाए रखना इन्हें भोजन से बाहर रखते हैं।","ar":"التلوث الفيزيائي يأتي من أشياء كالزجاج والمعدن والمجوهرات والضمادات. نزع المجوهرات واستخدام أوعية غير قابلة للكسر وصيانة المعدات يبقيها بعيدة عن الطعام."}},{"cat":"crosscontam","a":0,"q":{"en":"Frying breaded fish and French fries in the same oil is a concern for a guest with which allergy?","es":"Freír pescado empanizado y papas fritas en el mismo aceite es una preocupación para un cliente con qué alergia?","ru":"Жарка панированной рыбы и картофеля фри в одном масле — проблема для гостя с какой аллергией?","tr":"Galetalı balık ve patates kızartmasını aynı yağda kızartmak hangi alerjisi olan misafir için endişe kaynağıdır?","hi":"ब्रेडेड मछली और फ्रेंच फ्राइज़ को एक ही तेल में तलना किस एलर्जी वाले मेहमान के लिए चिंता है?","ar":"قلي السمك المغطى بالبقسماط والبطاطس المقلية في الزيت نفسه يمثل قلقًا لضيف لديه أي حساسية؟"},"o":[{"en":"Fish and wheat (from breading)","es":"Pescado y trigo (del empanizado)","ru":"Рыба и пшеница (из панировки)","tr":"Balık ve buğday (galeta ununden)","hi":"मछली और गेहूं (ब्रेडिंग से)","ar":"السمك والقمح (من التغطية)"},{"en":"Only potato allergy","es":"Solo alergia a la papa","ru":"Только аллергия на картофель","tr":"Yalnızca patates alerjisi","hi":"केवल आलू एलर्जी","ar":"حساسية البطاطس فقط"},{"en":"No allergy concern exists","es":"No existe preocupación por alergia","ru":"Нет проблемы с аллергией","tr":"Alerji endişesi yoktur","hi":"कोई एलर्जी चिंता नहीं","ar":"لا يوجد قلق حساسية"},{"en":"Only oil sensitivity","es":"Solo sensibilidad al aceite","ru":"Только чувствительность к маслу","tr":"Yalnızca yağ hassasiyeti","hi":"केवल तेल संवेदनशीलता","ar":"حساسية الزيت فقط"}],"e":{"en":"Shared fryer oil transfers fish and wheat proteins (from breading) into the fries, so those fries are unsafe for guests allergic to fish or wheat. Use a dedicated fryer for allergen-free items.","es":"El aceite compartido transfiere proteínas de pescado y trigo (del empanizado) a las papas, por lo que no son seguras para clientes alérgicos a pescado o trigo. Use una freidora dedicada para platos sin alérgenos.","ru":"Общее масло переносит белки рыбы и пшеницы (из панировки) в картофель, поэтому он небезопасен для гостей с аллергией на рыбу или пшеницу. Используйте отдельную фритюрницу для безаллергенных блюд.","tr":"Ortak kızartma yağı balık ve buğday proteinlerini (galetadan) patateslere taşır; bu yüzden balık veya buğdaya alerjisi olan misafirler için güvensizdir. Alerjensiz ürünler için ayrı fritöz kullanın.","hi":"साझा फ्रायर तेल मछली और गेहूं प्रोटीन (ब्रेडिंग से) को फ्राइज़ में स्थानांतरित करता है, इसलिए मछली या गेहूं से एलर्जी वाले मेहमानों के लिए ये असुरक्षित हैं। एलर्जेन-मुक्त वस्तुओं के लिए समर्पित फ्रायर उपयोग करें।","ar":"زيت المقلاة المشترك ينقل بروتينات السمك والقمح (من التغطية) إلى البطاطس، فتصبح غير آمنة لضيوف لديهم حساسية من السمك أو القمح. استخدم مقلاة مخصصة للأصناف الخالية من مسببات الحساسية."}},{"cat":"crosscontam","a":1,"q":{"en":"Some kitchens use purple-colored gloves and tools. What do these typically indicate?","es":"Algunas cocinas usan guantes y utensilios de color morado. ¿Qué indican normalmente?","ru":"В некоторых кухнях используют фиолетовые перчатки и инструменты. Что они обычно обозначают?","tr":"Bazı mutfaklar mor renkli eldiven ve alet kullanır. Bunlar genellikle neyi belirtir?","hi":"कुछ रसोई बैंगनी रंग के दस्ताने और औजार उपयोग करती हैं। ये आमतौर पर क्या दर्शाते हैं?","ar":"بعض المطابخ تستخدم قفازات وأدوات بنفسجية اللون. ماذا تشير عادةً؟"},"o":[{"en":"They are for raw poultry","es":"Son para aves crudas","ru":"Они для сырой птицы","tr":"Çiğ kümes hayvanı içindir","hi":"वे कच्ची पोल्ट्री के लिए हैं","ar":"مخصصة للدواجن النيئة"},{"en":"They are dedicated to allergen-free preparation","es":"Están dedicados a la preparación sin alérgenos","ru":"Они предназначены для приготовления без аллергенов","tr":"Alerjensiz hazırlığa ayrılmıştır","hi":"वे एलर्जेन-मुक्त तैयारी के लिए समर्पित हैं","ar":"مخصصة للتحضير الخالي من مسببات الحساسية"},{"en":"They are only decorative","es":"Son solo decorativos","ru":"Они только декоративные","tr":"Yalnızca dekoratiftir","hi":"वे केवल सजावटी हैं","ar":"للزينة فقط"},{"en":"They mean the tools are dirty","es":"Significan que los utensilios están sucios","ru":"Они означают, что инструменты грязные","tr":"Aletlerin kirli olduğunu gösterir","hi":"वे संकेत देते हैं कि औजार गंदे हैं","ar":"تعني أن الأدوات متسخة"}],"e":{"en":"Purple is a widely used color for allergen-dedicated gloves, cutting boards, and utensils. Keeping this equipment separate helps prevent allergen cross-contact.","es":"El morado es un color muy usado para guantes, tablas y utensilios dedicados a alérgenos. Mantener este equipo separado ayuda a prevenir el contacto cruzado con alérgenos.","ru":"Фиолетовый — широко используемый цвет для перчаток, досок и инвентаря, предназначенных для аллергенов. Отдельное хранение этого оборудования помогает предотвратить перекрёстный контакт.","tr":"Mor, alerjene ayrılmış eldiven, kesme tahtası ve aletler için yaygın kullanılan bir renktir. Bu ekipmanı ayrı tutmak alerjen çapraz temasını önlemeye yardımcı olur.","hi":"बैंगनी एलर्जेन-समर्पित दस्तानों, कटिंग बोर्ड और बर्तनों के लिए व्यापक रूप से उपयोग किया रंग है। इस उपकरण को अलग रखना एलर्जेन क्रॉस-कॉन्टैक्ट रोकने में मदद करता है।","ar":"البنفسجي لون شائع الاستخدام للقفازات وألواح التقطيع والأدوات المخصصة لمسببات الحساسية. إبقاء هذه المعدات منفصلة يساعد على منع التلامس المتبادل."}},{"cat":"crosscontam","a":2,"q":{"en":"Which single item, if placed on the top shelf, would still be correct in a raw-foods cooler?","es":"¿Qué artículo, si se coloca en el estante superior, seguiría siendo correcto en un refrigerador de alimentos crudos?","ru":"Какой один продукт, если поместить его на верхнюю полку, будет правильным в холодильнике для сырых продуктов?","tr":"Çiğ gıda soğutucusunda üst rafa konduğunda hâlâ doğru olacak tek ürün hangisidir?","hi":"कच्चे भोजन के कूलर में, ऊपरी शेल्फ पर रखने पर कौन-सी एक वस्तु फिर भी सही होगी?","ar":"أي صنف واحد، إذا وُضع على الرف العلوي، سيظل صحيحًا في مبرّد الأطعمة النيئة؟"},"o":[{"en":"Raw ground pork","es":"Cerdo molido crudo","ru":"Сырой свиной фарш","tr":"Çiğ domuz kıyması","hi":"कच्चा पिसा पोर्क","ar":"لحم خنزير مفروم نيء"},{"en":"Raw chicken","es":"Pollo crudo","ru":"Сырая курица","tr":"Çiğ tavuk","hi":"कच्चा चिकन","ar":"دجاج نيء"},{"en":"Raw fish fillets","es":"Filetes de pescado crudo","ru":"Сырое рыбное филе","tr":"Çiğ balık filetosu","hi":"कच्ची मछली की पट्टियां","ar":"شرائح سمك نيئة"},{"en":"Raw hamburger patties","es":"Hamburguesas crudas","ru":"Сырые котлеты для гамбургеров","tr":"Çiğ hamburger köftesi","hi":"कच्ची हैमबर्गर पैटी","ar":"أقراص همبرغر نيئة"}],"e":{"en":"Fish has the lowest cook temperature here (145°F), so raw fish fillets belong nearest the top among these raw items. Chicken (165°F) and ground meats (155°F) must be stored lower.","es":"El pescado tiene la temperatura de cocción más baja aquí (145°F), así que los filetes de pescado crudo van más arriba entre estos crudos. El pollo (165°F) y las carnes molidas (155°F) van más abajo.","ru":"У рыбы здесь самая низкая температура готовки (145°F), поэтому сырое филе располагают ближе всех к верху среди этих продуктов. Курицу (165°F) и фарш (155°F) хранят ниже.","tr":"Balık buradaki en düşük pişirme sıcaklığına sahiptir (145°F); bu yüzden bu çiğ ürünler arasında en üste çiğ balık fileto gelir. Tavuk (165°F) ve kıymalar (155°F) daha altta saklanmalıdır.","hi":"यहां मछली का पकाने का तापमान सबसे कम (145°F) है, इसलिए इन कच्चे वस्तुओं में कच्ची मछली की पट्टियां सबसे ऊपर के पास आती हैं। चिकन (165°F) और पिसे मांस (155°F) नीचे रखे जाने चाहिए।","ar":"للسمك أدنى درجة طهي هنا (145°F)، لذا شرائح السمك النيئة هي الأقرب للأعلى بين هذه الأصناف. أما الدجاج (165°F) واللحوم المفرومة (155°F) فتُخزَّن أسفل."}},{"cat":"crosscontam","a":3,"q":{"en":"Why is it important to tell guests when a recipe or ingredient supplier has changed?","es":"¿Por qué es importante avisar a los clientes cuando cambia una receta o el proveedor de un ingrediente?","ru":"Почему важно сообщать гостям об изменении рецепта или поставщика ингредиента?","tr":"Bir tarif ya da malzeme tedarikçisi değiştiğinde misafirlere söylemek neden önemlidir?","hi":"किसी रेसिपी या सामग्री आपूर्तिकर्ता के बदलने पर मेहमानों को बताना क्यों महत्वपूर्ण है?","ar":"لماذا من المهم إخبار الضيوف عند تغيّر وصفة أو مورّد مكوّن؟"},"o":[{"en":"To promote the new supplier","es":"Para promocionar al nuevo proveedor","ru":"Чтобы прорекламировать нового поставщика","tr":"Yeni tedarikçiyi tanıtmak için","hi":"नए आपूर्तिकर्ता का प्रचार करने के लिए","ar":"للترويج للمورّد الجديد"},{"en":"To raise the price","es":"Para subir el precio","ru":"Чтобы поднять цену","tr":"Fiyatı artırmak için","hi":"कीमत बढ़ाने के लिए","ar":"لرفع السعر"},{"en":"It is not important","es":"No es importante","ru":"Это не важно","tr":"Önemli değildir","hi":"यह महत्वपूर्ण नहीं है","ar":"ليس مهمًا"},{"en":"A new ingredient may introduce an allergen not previously present","es":"Un nuevo ingrediente puede introducir un alérgeno que antes no estaba","ru":"Новый ингредиент может добавить аллерген, которого раньше не было","tr":"Yeni bir malzeme, önceden olmayan bir alerjen getirebilir","hi":"नई सामग्री ऐसा एलर्जेन ला सकती है जो पहले मौजूद नहीं था","ar":"قد يُدخل مكوّن جديد مسبب حساسية لم يكن موجودًا سابقًا"}],"e":{"en":"Ingredient or recipe changes can introduce a new allergen that a returning guest does not expect, so staff must be informed and guests with allergies told before ordering.","es":"Los cambios de ingrediente o receta pueden introducir un nuevo alérgeno que un cliente habitual no espera, por eso hay que informar al personal y avisar a clientes con alergias antes de ordenar.","ru":"Изменения ингредиента или рецепта могут добавить новый аллерген, которого постоянный гость не ожидает, поэтому нужно информировать персонал и предупреждать гостей с аллергией до заказа.","tr":"Malzeme veya tarif değişiklikleri, düzenli bir misafirin beklemediği yeni bir alerjen getirebilir; bu yüzden personel bilgilendirilmeli ve alerjisi olan misafirlere sipariş öncesi söylenmelidir.","hi":"सामग्री या रेसिपी बदलाव ऐसा नया एलर्जेन ला सकते हैं जिसकी लौटने वाला मेहमान अपेक्षा नहीं करता, इसलिए स्टाफ को सूचित करना और ऑर्डर से पहले एलर्जी वाले मेहमानों को बताना चाहिए।","ar":"تغييرات المكونات أو الوصفات قد تُدخل مسبب حساسية جديدًا لا يتوقعه الزبون المعتاد، لذا يجب إبلاغ الموظفين وإخبار الضيوف ذوي الحساسية قبل الطلب."}},{"cat":"crosscontam","a":0,"q":{"en":"A pan of cooked ribs and a pan of raw ribs must share one cooler. Which goes on top?","es":"Una bandeja de costillas cocidas y otra de costillas crudas deben compartir un refrigerador. ¿Cuál va arriba?","ru":"Поддон с готовыми рёбрышками и поддон с сырыми должны быть в одном холодильнике. Какой ставят наверх?","tr":"Bir tepsi pişmiş kaburga ve bir tepsi çiğ kaburga aynı soğutucuyu paylaşacak. Hangisi üste konur?","hi":"पके पसलियों का एक पैन और कच्ची पसलियों का एक पैन एक कूलर साझा करते हैं। कौन-सा ऊपर जाता है?","ar":"صينية أضلاع مطهوة وصينية أضلاع نيئة يجب أن تتشاركا مبرّدًا واحدًا. أيهما في الأعلى؟"},"o":[{"en":"The cooked ribs","es":"Las costillas cocidas","ru":"Готовые рёбрышки","tr":"Pişmiş kaburga","hi":"पकी पसलियां","ar":"الأضلاع المطهوة"},{"en":"The raw ribs","es":"Las costillas crudas","ru":"Сырые рёбрышки","tr":"Çiğ kaburga","hi":"कच्ची पसलियां","ar":"الأضلاع النيئة"},{"en":"Whichever is larger","es":"La que sea más grande","ru":"Тот, что больше","tr":"Hangisi daha büyükse","hi":"जो भी बड़ा हो","ar":"الأكبر منهما"},{"en":"Whichever was made first","es":"La que se hizo primero","ru":"Тот, что сделан раньше","tr":"Hangisi önce yapıldıysa","hi":"जो भी पहले बना हो","ar":"الذي أُعدّ أولًا"}],"e":{"en":"Cooked, ready-to-eat ribs go on top, and raw ribs go below, so juices from the raw meat cannot drip onto the already-cooked food and contaminate it.","es":"Las costillas cocidas y listas para comer van arriba, y las crudas debajo, para que los jugos de la carne cruda no goteen sobre la comida ya cocinada y la contaminen.","ru":"Готовые к употреблению рёбрышки ставят наверх, а сырые — ниже, чтобы сок сырого мяса не капал на уже приготовленную пищу и не загрязнял её.","tr":"Pişmiş, yenmeye hazır kaburga üste, çiğ kaburga alta konur; böylece çiğ etin suları pişmiş gıdanın üzerine damlayıp onu kirletemez.","hi":"पकी, खाने-के-लिए-तैयार पसलियां ऊपर जाती हैं और कच्ची पसलियां नीचे, ताकि कच्चे मांस का रस पहले से पके भोजन पर न टपके और इसे दूषित न करे।","ar":"الأضلاع المطهوة الجاهزة للأكل توضع في الأعلى، والنيئة أسفلها، حتى لا تسقط عصارة اللحم النيئ على الطعام المطهو فتلوّثه."}},{"cat":"crosscontam","a":1,"q":{"en":"How does dedicating specific equipment to certain foods help food safety?","es":"¿Cómo ayuda a la seguridad alimentaria dedicar equipo específico a ciertos alimentos?","ru":"Как выделение конкретного оборудования под определённые продукты помогает безопасности пищи?","tr":"Belirli ekipmanı belirli gıdalara ayırmak gıda güvenliğine nasıl yardımcı olur?","hi":"कुछ खाद्य पदार्थों के लिए विशिष्ट उपकरण समर्पित करना खाद्य सुरक्षा में कैसे मदद करता है?","ar":"كيف يساعد تخصيص معدات معينة لأطعمة محددة في سلامة الغذاء؟"},"o":[{"en":"It makes the kitchen look organized","es":"Hace que la cocina se vea organizada","ru":"Это делает кухню организованной на вид","tr":"Mutfağı düzenli gösterir","hi":"यह रसोई को व्यवस्थित दिखाता है","ar":"يجعل المطبخ يبدو منظمًا"},{"en":"It reduces the chance of transferring pathogens or allergens between foods","es":"Reduce la posibilidad de transferir patógenos o alérgenos entre alimentos","ru":"Это снижает риск переноса патогенов или аллергенов между продуктами","tr":"Gıdalar arasında patojen ya da alerjen taşınma olasılığını azaltır","hi":"यह भोजन के बीच रोगाणु या एलर्जेन स्थानांतरण की संभावना कम करता है","ar":"يقلل فرصة نقل المسببات أو مسببات الحساسية بين الأطعمة"},{"en":"It saves money on equipment","es":"Ahorra dinero en equipo","ru":"Это экономит деньги на оборудовании","tr":"Ekipmanda para tasarrufu sağlar","hi":"यह उपकरण पर पैसा बचाता है","ar":"يوفر المال على المعدات"},{"en":"It speeds up cooking","es":"Acelera la cocción","ru":"Это ускоряет готовку","tr":"Pişirmeyi hızlandırır","hi":"यह पकाना तेज करता है","ar":"يُسرّع الطهي"}],"e":{"en":"Dedicated equipment, such as separate boards and utensils for raw meat, produce, and allergen-free items, keeps pathogens and allergens from moving from one food to another.","es":"El equipo dedicado, como tablas y utensilios separados para carne cruda, verduras y platos sin alérgenos, evita que patógenos y alérgenos pasen de un alimento a otro.","ru":"Выделенное оборудование — отдельные доски и инвентарь для сырого мяса, овощей и безаллергенных блюд — не даёт патогенам и аллергенам переходить с одного продукта на другой.","tr":"Çiğ et, sebze ve alerjensiz ürünler için ayrı tahta ve aletler gibi özel ekipman, patojen ve alerjenlerin bir gıdadan diğerine geçmesini önler.","hi":"समर्पित उपकरण, जैसे कच्चे मांस, उत्पाद और एलर्जेन-मुक्त वस्तुओं के लिए अलग बोर्ड और बर्तन, रोगाणुओं और एलर्जेन को एक भोजन से दूसरे में जाने से रोकते हैं।","ar":"المعدات المخصصة، مثل ألواح وأدوات منفصلة للحم النيئ والخضار والأصناف الخالية من مسببات الحساسية، تمنع انتقال المسببات ومسببات الحساسية من طعام إلى آخر."}},{"cat":"crosscontam","a":2,"q":{"en":"On an allergen chart, why are fish and shellfish listed as two separate allergens?","es":"En una tabla de alérgenos, ¿por qué se listan el pescado y los mariscos como dos alérgenos separados?","ru":"Почему в таблице аллергенов рыба и моллюски указаны как два отдельных аллергена?","tr":"Alerjen çizelgesinde balık ve kabuklu deniz ürünleri neden iki ayrı alerjen olarak listelenir?","hi":"एलर्जेन चार्ट पर, मछली और शेलफिश को दो अलग एलर्जेन के रूप में क्यों सूचीबद्ध किया जाता है?","ar":"في جدول مسببات الحساسية، لماذا يُدرَج السمك والمحار كمسبِّبَي حساسية منفصلين؟"},"o":[{"en":"Because they taste different","es":"Porque saben diferente","ru":"Потому что у них разный вкус","tr":"Farklı tat verdikleri için","hi":"क्योंकि उनका स्वाद अलग है","ar":"لأن طعمهما مختلف"},{"en":"Because shellfish is more expensive","es":"Porque los mariscos son más caros","ru":"Потому что моллюски дороже","tr":"Kabuklu deniz ürünleri daha pahalı olduğu için","hi":"क्योंकि शेलफिश अधिक महंगी है","ar":"لأن المحار أغلى ثمنًا"},{"en":"A person can react to one without reacting to the other","es":"Una persona puede reaccionar a uno sin reaccionar al otro","ru":"Человек может реагировать на один и не реагировать на другой","tr":"Bir kişi birine tepki verirken diğerine vermeyebilir","hi":"एक व्यक्ति एक पर प्रतिक्रिया कर सकता है बिना दूसरे पर किए","ar":"قد يتفاعل الشخص مع أحدهما دون الآخر"},{"en":"Because they are stored together","es":"Porque se guardan juntos","ru":"Потому что их хранят вместе","tr":"Birlikte saklandıkları için","hi":"क्योंकि उन्हें साथ रखा जाता है","ar":"لأنهما يُخزّنان معًا"}],"e":{"en":"Finned fish and crustacean shellfish are biologically different, so someone allergic to one may safely eat the other. Menus and staff must treat them as distinct allergens.","es":"Los peces con aletas y los mariscos crustáceos son biológicamente distintos, así que alguien alérgico a uno puede comer el otro con seguridad. Menús y personal deben tratarlos como alérgenos distintos.","ru":"Рыба с плавниками и ракообразные биологически различны, поэтому человек с аллергией на одно может безопасно есть другое. Меню и персонал должны считать их отдельными аллергенами.","tr":"Yüzgeçli balıklar ve kabuklu deniz ürünleri biyolojik olarak farklıdır; birine alerjisi olan diğerini güvenle yiyebilir. Menüler ve personel bunları ayrı alerjen olarak ele almalıdır.","hi":"पंख वाली मछली और क्रस्टेशियन शेलफिश जैविक रूप से अलग हैं, इसलिए एक से एलर्जी वाला व्यक्ति दूसरे को सुरक्षित रूप से खा सकता है। मेनू और स्टाफ को इन्हें अलग एलर्जेन मानना चाहिए।","ar":"الأسماك ذات الزعانف والقشريات مختلفة بيولوجيًا، لذا قد يتناول من لديه حساسية من أحدهما الآخر بأمان. يجب على القوائم والموظفين التعامل معهما كمسبِّبَي حساسية منفصلين."}},{"cat":"crosscontam","a":3,"q":{"en":"Why must serving utensils not be stored with the handle touching the food?","es":"¿Por qué los utensilios de servir no deben guardarse con el mango tocando la comida?","ru":"Почему сервировочные приборы нельзя хранить так, чтобы ручка касалась пищи?","tr":"Servis aletleri neden sapı gıdaya değecek şekilde saklanmamalı?","hi":"सर्विंग बर्तनों को हैंडल भोजन को छूते हुए क्यों नहीं रखा जाना चाहिए?","ar":"لماذا يجب ألا تُخزَّن أدوات التقديم ومقبضها يلامس الطعام؟"},"o":[{"en":"It makes them harder to grab","es":"Es más difícil tomarlos","ru":"Их труднее взять","tr":"Onları tutmayı zorlaştırır","hi":"उन्हें पकड़ना कठिन होता है","ar":"يصعّب الإمساك بها"},{"en":"It looks unprofessional","es":"Se ve poco profesional","ru":"Это выглядит непрофессионально","tr":"Profesyonelce görünmez","hi":"यह गैर-पेशेवर दिखता है","ar":"يبدو غير احترافي"},{"en":"It wastes food","es":"Desperdicia comida","ru":"Это тратит еду","tr":"Yemek israfına yol açar","hi":"यह भोजन बर्बाद करता है","ar":"يهدر الطعام"},{"en":"Hands touch the handle, so a handle in the food contaminates it","es":"Las manos tocan el mango, así que un mango en la comida la contamina","ru":"Руки касаются ручки, поэтому ручка в пище загрязняет её","tr":"Eller sapa değdiği için gıdanın içindeki sap onu kirletir","hi":"हाथ हैंडल को छूते हैं, इसलिए भोजन में हैंडल इसे दूषित करता है","ar":"الأيدي تلمس المقبض، لذا وجود المقبض في الطعام يلوّثه"}],"e":{"en":"Serving utensils are stored with the handle up and out of the food, because hands touch the handle and a handle resting in the food would transfer pathogens to it.","es":"Los utensilios de servir se guardan con el mango hacia arriba y fuera de la comida, porque las manos tocan el mango y uno apoyado en la comida le transferiría patógenos.","ru":"Сервировочные приборы хранят ручкой вверх, вне пищи, так как руки касаются ручки, и ручка в пище перенесла бы на неё патогены.","tr":"Servis aletleri sapı yukarıda ve gıdanın dışında saklanır; çünkü eller sapa değer ve gıdanın içinde duran bir sap ona patojen taşır.","hi":"सर्विंग बर्तन हैंडल ऊपर और भोजन से बाहर रखे जाते हैं, क्योंकि हाथ हैंडल को छूते हैं और भोजन में रखा हैंडल इसमें रोगाणु स्थानांतरित करेगा।","ar":"تُخزَّن أدوات التقديم بمقبضها لأعلى وخارج الطعام، لأن الأيدي تلمس المقبض، ووجود المقبض داخل الطعام ينقل إليه المسببات."}},{"cat":"crosscontam","a":0,"q":{"en":"Which storage arrangement is correct in a single cooler holding raw chicken, raw fish, and a tray of washed berries?","es":"¿Qué disposición de almacenamiento es correcta en un refrigerador con pollo crudo, pescado crudo y una bandeja de bayas lavadas?","ru":"Какое расположение верно в одном холодильнике с сырой курицей, сырой рыбой и лотком мытых ягод?","tr":"Çiğ tavuk, çiğ balık ve yıkanmış çilek tepsisi bulunan tek soğutucuda hangi yerleştirme doğrudur?","hi":"कच्चा चिकन, कच्ची मछली और धुली बेरी की ट्रे रखने वाले एक कूलर में कौन-सी भंडारण व्यवस्था सही है?","ar":"أي ترتيب تخزين صحيح في مبرّد واحد يحوي دجاجًا نيئًا وسمكًا نيئًا وصينية توت مغسول؟"},"o":[{"en":"Berries on top, fish in the middle, chicken on the bottom","es":"Bayas arriba, pescado en medio, pollo abajo","ru":"Ягоды сверху, рыба в середине, курица снизу","tr":"En üstte çilek, ortada balık, en altta tavuk","hi":"ऊपर बेरी, बीच में मछली, नीचे चिकन","ar":"التوت في الأعلى، السمك في الوسط، الدجاج في الأسفل"},{"en":"Chicken on top, berries in the middle, fish on the bottom","es":"Pollo arriba, bayas en medio, pescado abajo","ru":"Курица сверху, ягоды в середине, рыба снизу","tr":"En üstte tavuk, ortada çilek, en altta balık","hi":"ऊपर चिकन, बीच में बेरी, नीचे मछली","ar":"الدجاج في الأعلى، التوت في الوسط، السمك في الأسفل"},{"en":"Fish on top, chicken in the middle, berries on the bottom","es":"Pescado arriba, pollo en medio, bayas abajo","ru":"Рыба сверху, курица в середине, ягоды снизу","tr":"En üstte balık, ortada tavuk, en altta çilek","hi":"ऊपर मछली, बीच में चिकन, नीचे बेरी","ar":"السمك في الأعلى، الدجاج في الوسط، التوت في الأسفل"},{"en":"All three on the same shelf","es":"Los tres en el mismo estante","ru":"Все три на одной полке","tr":"Üçü de aynı rafta","hi":"तीनों एक ही शेल्फ पर","ar":"الثلاثة على الرف نفسه"}],"e":{"en":"Ready-to-eat berries go on top, then raw fish (145°F), then raw chicken (165°F) on the bottom, following ready-to-eat first and then increasing cook temperature downward.","es":"Las bayas listas para comer van arriba, luego el pescado crudo (145°F) y el pollo crudo (165°F) al fondo, siguiendo listo para comer primero y luego temperatura de cocción creciente hacia abajo.","ru":"Готовые ягоды сверху, затем сырая рыба (145°F), затем сырая курица (165°F) внизу — сначала готовое, затем по возрастанию температуры готовки вниз.","tr":"Yenmeye hazır çilek üste, sonra çiğ balık (145°F), en altta çiğ tavuk (165°F); önce yenmeye hazır, sonra aşağı doğru artan pişirme sıcaklığı sırasıyla.","hi":"खाने-के-लिए-तैयार बेरी ऊपर, फिर कच्ची मछली (145°F), फिर नीचे कच्चा चिकन (165°F), पहले तैयार और फिर नीचे की ओर बढ़ता पकाने का तापमान।","ar":"التوت الجاهز للأكل في الأعلى، ثم السمك النيئ (145°F)، ثم الدجاج النيئ (165°F) في الأسفل، وفق ترتيب الجاهز للأكل أولًا ثم تزايد درجة الطهي نزولًا."}},{"cat":"crosscontam","a":1,"q":{"en":"A deli slicer is used all day for the same product. How often should it be cleaned and sanitized?","es":"Una rebanadora de charcutería se usa todo el día para el mismo producto. ¿Con qué frecuencia debe limpiarse y desinfectarse?","ru":"Слайсер весь день режет один продукт. Как часто его нужно мыть и дезинфицировать?","tr":"Bir dilimleme makinesi bütün gün aynı ürün için kullanılıyor. Ne sıklıkta temizlenip dezenfekte edilmeli?","hi":"एक डेली स्लाइसर पूरे दिन एक ही उत्पाद के लिए उपयोग होता है। इसे कितनी बार साफ और सैनिटाइज़ किया जाना चाहिए?","ar":"تُستخدم شريحة الأطعمة طوال اليوم للمنتج نفسه. كم مرة يجب تنظيفها وتعقيمها؟"},"o":[{"en":"Only at the end of the day","es":"Solo al final del día","ru":"Только в конце дня","tr":"Yalnızca gün sonunda","hi":"केवल दिन के अंत में","ar":"في نهاية اليوم فقط"},{"en":"At least every 4 hours during continuous use","es":"Al menos cada 4 horas durante el uso continuo","ru":"Не реже чем каждые 4 часа при непрерывном использовании","tr":"Sürekli kullanımda en az her 4 saatte bir","hi":"निरंतर उपयोग के दौरान कम से कम हर 4 घंटे में","ar":"كل 4 ساعات على الأقل أثناء الاستخدام المستمر"},{"en":"Once a week","es":"Una vez a la semana","ru":"Один раз в неделю","tr":"Haftada bir kez","hi":"सप्ताह में एक बार","ar":"مرة في الأسبوع"},{"en":"Only when switching products","es":"Solo al cambiar de producto","ru":"Только при смене продукта","tr":"Yalnızca ürün değiştirirken","hi":"केवल उत्पाद बदलते समय","ar":"فقط عند تغيير المنتجات"}],"e":{"en":"Even with the same food, food-contact surfaces in continuous use must be cleaned and sanitized at least every 4 hours to keep bacteria from building up and cross-contaminating.","es":"Aun con el mismo alimento, las superficies de contacto en uso continuo deben limpiarse y desinfectarse al menos cada 4 horas para evitar que las bacterias se acumulen y contaminen.","ru":"Даже с одним продуктом поверхности контакта при непрерывном использовании нужно мыть и дезинфицировать не реже чем каждые 4 часа, чтобы бактерии не накапливались.","tr":"Aynı gıdayla bile, sürekli kullanılan gıda temas yüzeyleri, bakteri birikip çapraz bulaşma yapmasın diye en az her 4 saatte bir temizlenip dezenfekte edilmelidir.","hi":"एक ही भोजन के साथ भी, निरंतर उपयोग में भोजन-संपर्क सतहों को कम से कम हर 4 घंटे में साफ और सैनिटाइज़ किया जाना चाहिए ताकि बैक्टीरिया जमा और क्रॉस-कॉन्टैमिनेट न हों।","ar":"حتى مع الطعام نفسه، يجب تنظيف وتعقيم أسطح ملامسة الطعام قيد الاستخدام المستمر كل 4 ساعات على الأقل لمنع تراكم البكتيريا والتلوث المتبادل."}},{"cat":"illness","a":3,"q":{"en":"How many pathogens make up the FDA's list of 'Big 6' highly infectious foodborne pathogens?","es":"¿Cuántos patógenos componen la lista de los 'Big 6' altamente infecciosos de la FDA?","ru":"Сколько патогенов входит в список FDA «Большая шестёрка» высокозаразных пищевых патогенов?","tr":"FDA'nın son derece bulaşıcı 'Büyük 6' gıda kaynaklı patojen listesinde kaç patojen vardır?","hi":"एफडीए की 'बिग 6' अत्यधिक संक्रामक खाद्यजनित रोगाणुओं की सूची में कितने रोगाणु हैं?","ar":"كم عدد مسببات المرض في قائمة 'الستة الكبار' شديدة العدوى المنقولة بالغذاء لدى FDA؟"},"o":[{"en":"Three","es":"Tres","ru":"Три","tr":"Üç","hi":"तीन","ar":"ثلاثة"},{"en":"Nine","es":"Nueve","ru":"Девять","tr":"Dokuz","hi":"नौ","ar":"تسعة"},{"en":"Four","es":"Cuatro","ru":"Четыре","tr":"Dört","hi":"चार","ar":"أربعة"},{"en":"Six","es":"Seis","ru":"Шесть","tr":"Altı","hi":"छह","ar":"ستة"}],"e":{"en":"The Big 6 are Norovirus, Hepatitis A, Salmonella Typhi, nontyphoidal Salmonella, Shigella, and Shiga toxin-producing E. coli (STEC). They are so contagious that they are reportable.","es":"Los Big 6 son Norovirus, Hepatitis A, Salmonella Typhi, Salmonella no tifoidea, Shigella y E. coli productora de toxina Shiga (STEC). Son tan contagiosos que son de declaración obligatoria.","ru":"«Большая шестёрка»: норовирус, гепатит A, Salmonella Typhi, нетифоидная сальмонелла, шигелла и энтерогеморрагическая E. coli (STEC). Они настолько заразны, что подлежат отчётности.","tr":"Büyük 6: Norovirüs, Hepatit A, Salmonella Typhi, tifo dışı Salmonella, Shigella ve Shiga toksini üreten E. coli (STEC). O kadar bulaşıcıdırlar ki bildirimi zorunludur.","hi":"बिग 6 हैं नोरोवायरस, हेपेटाइटिस A, साल्मोनेला टाइफी, गैर-टाइफाइड साल्मोनेला, शिगेला और शिगा-टॉक्सिन बनाने वाला E. coli (STEC)। ये इतने संक्रामक हैं कि रिपोर्ट करने योग्य हैं।","ar":"الستة الكبار هي: نوروفيروس، والتهاب الكبد A، وسالمونيلا التيفية، والسالمونيلا غير التيفية، والشيغيلا، والإشريكية القولونية المنتجة لسم شيغا (STEC). وهي شديدة العدوى لدرجة وجوب الإبلاغ عنها."}},{"cat":"illness","a":0,"q":{"en":"A food employee reports jaundice (yellowing of the skin or eyes). What must the person in charge do?","es":"Un empleado reporta ictericia (piel u ojos amarillos). ¿Qué debe hacer la persona a cargo?","ru":"Работник сообщает о желтухе (пожелтение кожи или глаз). Что должно сделать ответственное лицо?","tr":"Bir gıda çalışanı sarılık (deri veya gözlerde sararma) bildiriyor. Sorumlu kişi ne yapmalı?","hi":"एक फूड कर्मचारी पीलिया (त्वचा या आंखों का पीला होना) की रिपोर्ट करता है। प्रभारी व्यक्ति को क्या करना चाहिए?","ar":"يبلّغ موظف طعام عن يرقان (اصفرار الجلد أو العينين). ماذا يجب أن يفعل الشخص المسؤول؟"},"o":[{"en":"Exclude the employee and notify the regulatory authority","es":"Excluir al empleado y notificar a la autoridad reguladora","ru":"Отстранить работника и уведомить регулирующий орган","tr":"Çalışanı işten uzaklaştırmak ve düzenleyici otoriteye bildirmek","hi":"कर्मचारी को बाहर करें और नियामक प्राधिकरण को सूचित करें","ar":"استبعاد الموظف وإبلاغ الجهة التنظيمية"},{"en":"Move them to the dish room","es":"Pasarlo al área de platos","ru":"Перевести его в моечную","tr":"Onu bulaşık odasına almak","hi":"उसे डिश रूम में भेजें","ar":"نقله إلى غرفة الأطباق"},{"en":"Let them keep working with gloves","es":"Dejarlo seguir trabajando con guantes","ru":"Позволить работать в перчатках","tr":"Eldivenle çalışmaya devam ettirmek","hi":"दस्तानों के साथ काम करने दें","ar":"تركه يعمل بالقفازات"},{"en":"Do nothing until symptoms worsen","es":"No hacer nada hasta que empeoren los síntomas","ru":"Ничего не делать, пока симптомы не ухудшатся","tr":"Belirtiler kötüleşene kadar hiçbir şey yapmamak","hi":"जब तक लक्षण न बिगड़ें कुछ न करें","ar":"عدم فعل شيء حتى تتفاقم الأعراض"}],"e":{"en":"Jaundice is a sign of possible Hepatitis A. An employee with jaundice must be excluded from the establishment, and the regulatory authority must be notified.","es":"La ictericia es señal de posible Hepatitis A. Un empleado con ictericia debe ser excluido del establecimiento y hay que notificar a la autoridad reguladora.","ru":"Желтуха — признак возможного гепатита A. Работника с желтухой нужно отстранить от заведения и уведомить регулирующий орган.","tr":"Sarılık olası Hepatit A belirtisidir. Sarılığı olan çalışan işletmeden uzaklaştırılmalı ve düzenleyici otorite bilgilendirilmelidir.","hi":"पीलिया संभावित हेपेटाइटिस A का संकेत है। पीलिया वाले कर्मचारी को प्रतिष्ठान से बाहर किया जाना चाहिए और नियामक प्राधिकरण को सूचित किया जाना चाहिए।","ar":"اليرقان علامة على احتمال التهاب الكبد A. يجب استبعاد الموظف المصاب باليرقان من المنشأة وإبلاغ الجهة التنظيمية."}},{"cat":"illness","a":1,"q":{"en":"Which pathogen is a virus commonly spread by infected food handlers who do not wash their hands after using the restroom?","es":"¿Qué patógeno es un virus que suelen propagar manipuladores infectados que no se lavan las manos tras usar el baño?","ru":"Какой патоген — вирус, который часто распространяют инфицированные работники, не моющие руки после туалета?","tr":"Hangi patojen, tuvaletten sonra ellerini yıkamayan enfekte gıda çalışanlarının yaygın olarak yaydığı bir virüstür?","hi":"कौन-सा रोगाणु एक वायरस है जो आमतौर पर उन संक्रमित फूड हैंडलर द्वारा फैलता है जो शौचालय के बाद हाथ नहीं धोते?","ar":"أي مسبب مرض هو فيروس ينتشر عادةً عبر عاملين مصابين لا يغسلون أيديهم بعد استخدام دورة المياه؟"},"o":[{"en":"Clostridium botulinum","es":"Clostridium botulinum","ru":"Clostridium botulinum","tr":"Clostridium botulinum","hi":"क्लॉस्ट्रिडियम बॉटुलिनम","ar":"المطثية الوشيقية"},{"en":"Norovirus","es":"Norovirus","ru":"Норовирус","tr":"Norovirüs","hi":"नोरोवायरस","ar":"نوروفيروس"},{"en":"Listeria monocytogenes","es":"Listeria monocytogenes","ru":"Listeria monocytogenes","tr":"Listeria monocytogenes","hi":"लिस्टेरिया मोनोसाइटोजीन्स","ar":"الليستيريا المستوحدة"},{"en":"Bacillus cereus","es":"Bacillus cereus","ru":"Bacillus cereus","tr":"Bacillus cereus","hi":"बैसिलस सेरेस","ar":"العصوية الشمعية"}],"e":{"en":"Norovirus is a highly contagious virus spread through the fecal-oral route, often by food handlers who fail to wash their hands. It is one of the Big 6 reportable pathogens.","es":"El Norovirus es un virus muy contagioso que se propaga por la ruta fecal-oral, a menudo por manipuladores que no se lavan las manos. Es uno de los Big 6 de declaración obligatoria.","ru":"Норовирус — очень заразный вирус, распространяющийся фекально-оральным путём, часто через работников, не моющих руки. Входит в «Большую шестёрку».","tr":"Norovirüs, fekal-oral yolla, çoğunlukla ellerini yıkamayan gıda çalışanlarıyla yayılan son derece bulaşıcı bir virüstür. Bildirimi zorunlu Büyük 6'dan biridir.","hi":"नोरोवायरस एक अत्यधिक संक्रामक वायरस है जो मल-मुख मार्ग से फैलता है, अक्सर उन हैंडलर से जो हाथ नहीं धोते। यह बिग 6 रिपोर्ट-योग्य रोगाणुओं में से एक है।","ar":"نوروفيروس فيروس شديد العدوى ينتشر عبر المسار البرازي-الفموي، غالبًا عبر عاملين لا يغسلون أيديهم. وهو أحد الستة الكبار الواجب الإبلاغ عنها."}},{"cat":"illness","a":2,"q":{"en":"A food employee has a fever with a sore throat and works in a nursing-home kitchen. What is the required action?","es":"Un empleado tiene fiebre con dolor de garganta y trabaja en la cocina de un asilo. ¿Cuál es la acción requerida?","ru":"У работника лихорадка с болью в горле, и он работает на кухне дома престарелых. Каково требуемое действие?","tr":"Bir çalışanın ateşi ve boğaz ağrısı var ve bir bakımevi mutfağında çalışıyor. Gereken eylem nedir?","hi":"एक कर्मचारी को बुखार के साथ गले में खराश है और वह नर्सिंग-होम रसोई में काम करता है। आवश्यक कार्रवाई क्या है?","ar":"لدى موظف حمى مع التهاب حلق ويعمل في مطبخ دار رعاية. ما الإجراء المطلوب؟"},"o":[{"en":"No action is needed","es":"No se necesita ninguna acción","ru":"Никаких действий не требуется","tr":"Herhangi bir işlem gerekmez","hi":"कोई कार्रवाई आवश्यक नहीं","ar":"لا حاجة لأي إجراء"},{"en":"Only wear a mask","es":"Solo usar mascarilla","ru":"Только надеть маску","tr":"Yalnızca maske takmak","hi":"केवल मास्क पहनें","ar":"ارتداء كمامة فقط"},{"en":"Exclude the employee, because the facility serves a highly susceptible population","es":"Excluir al empleado, porque el lugar sirve a una población altamente susceptible","ru":"Отстранить работника, так как учреждение обслуживает высоковосприимчивую группу","tr":"Çalışanı işten uzaklaştırmak; çünkü tesis yüksek riskli bir nüfusa hizmet veriyor","hi":"कर्मचारी को बाहर करें, क्योंकि सुविधा अत्यधिक संवेदनशील आबादी की सेवा करती है","ar":"استبعاد الموظف، لأن المنشأة تخدم فئة شديدة التأثر"},{"en":"Let them work the register","es":"Dejarlo trabajar en la caja","ru":"Позволить работать на кассе","tr":"Onu kasada çalıştırmak","hi":"उसे रजिस्टर पर काम करने दें","ar":"تركه يعمل على الصندوق"}],"e":{"en":"A sore throat with fever means restriction in most operations, but in facilities serving highly susceptible populations (like nursing homes), the employee must be excluded.","es":"Dolor de garganta con fiebre implica restricción en la mayoría de operaciones, pero en lugares que sirven poblaciones altamente susceptibles (como asilos), el empleado debe ser excluido.","ru":"Боль в горле с лихорадкой означает ограничение в большинстве заведений, но в учреждениях для высоковосприимчивых групп (домах престарелых) работника нужно отстранить.","tr":"Ateşli boğaz ağrısı çoğu işletmede kısıtlama demektir; ancak yüksek riskli nüfusa hizmet veren tesislerde (bakımevleri gibi) çalışan işten uzaklaştırılmalıdır.","hi":"बुखार के साथ गले में खराश अधिकांश प्रतिष्ठानों में प्रतिबंध का अर्थ है, पर अत्यधिक संवेदनशील आबादी (जैसे नर्सिंग होम) की सेवा करने वाली सुविधाओं में कर्मचारी को बाहर किया जाना चाहिए।","ar":"التهاب الحلق مع الحمى يعني التقييد في معظم المنشآت، لكن في المنشآت التي تخدم فئات شديدة التأثر (كدور الرعاية) يجب استبعاد الموظف."}},{"cat":"illness","a":3,"q":{"en":"Which bacterium is strongly associated with Typhoid fever and is one of the Big 6?","es":"¿Qué bacteria se asocia fuertemente con la fiebre tifoidea y es uno de los Big 6?","ru":"Какая бактерия тесно связана с брюшным тифом и входит в «Большую шестёрку»?","tr":"Hangi bakteri tifo hastalığıyla güçlü şekilde ilişkilidir ve Büyük 6'dan biridir?","hi":"कौन-सा जीवाणु टाइफाइड बुखार से दृढ़ता से जुड़ा है और बिग 6 में से एक है?","ar":"أي بكتيريا ترتبط بقوة بحمى التيفوئيد وهي من الستة الكبار؟"},"o":[{"en":"Listeria monocytogenes","es":"Listeria monocytogenes","ru":"Listeria monocytogenes","tr":"Listeria monocytogenes","hi":"लिस्टेरिया मोनोसाइटोजीन्स","ar":"الليستيريا المستوحدة"},{"en":"Clostridium perfringens","es":"Clostridium perfringens","ru":"Clostridium perfringens","tr":"Clostridium perfringens","hi":"क्लॉस्ट्रिडियम परफ्रिंजेन्स","ar":"المطثية الحاطمة"},{"en":"Staphylococcus aureus","es":"Staphylococcus aureus","ru":"Staphylococcus aureus","tr":"Staphylococcus aureus","hi":"स्टैफिलोकोकस ऑरियस","ar":"المكورات العنقودية الذهبية"},{"en":"Salmonella Typhi","es":"Salmonella Typhi","ru":"Salmonella Typhi","tr":"Salmonella Typhi","hi":"साल्मोनेला टाइफी","ar":"سالمونيلا التيفية"}],"e":{"en":"Salmonella Typhi causes typhoid fever and is one of the Big 6. A diagnosis requires exclusion from work and reporting to the regulatory authority.","es":"La Salmonella Typhi causa fiebre tifoidea y es uno de los Big 6. Un diagnóstico requiere exclusión del trabajo y notificación a la autoridad reguladora.","ru":"Salmonella Typhi вызывает брюшной тиф и входит в «Большую шестёрку». Диагноз требует отстранения от работы и уведомления регулирующего органа.","tr":"Salmonella Typhi tifo hastalığına yol açar ve Büyük 6'dan biridir. Teşhis, işten uzaklaştırmayı ve düzenleyici otoriteye bildirmeyi gerektirir.","hi":"साल्मोनेला टाइफी टाइफाइड बुखार का कारण बनती है और बिग 6 में से एक है। निदान के लिए काम से बहिष्करण और नियामक प्राधिकरण को रिपोर्टिंग आवश्यक है।","ar":"سالمونيلا التيفية تسبب حمى التيفوئيد وهي من الستة الكبار. يستلزم التشخيص الاستبعاد من العمل والإبلاغ للجهة التنظيمية."}},{"cat":"illness","a":0,"q":{"en":"A food handler is vomiting and has diarrhea. According to the Food Code, they should be:","es":"Un manipulador tiene vómitos y diarrea. Según el Código de Alimentos, debe:","ru":"У работника рвота и диарея. Согласно Пищевому кодексу, его следует:","tr":"Bir gıda çalışanında kusma ve ishal var. Gıda Kanunu'na göre nasıl davranılmalı:","hi":"एक फूड हैंडलर को उल्टी और दस्त है। फूड कोड के अनुसार, उसे:","ar":"متداول طعام يعاني من قيء وإسهال. وفق قانون الغذاء، يجب أن يكون:"},"o":[{"en":"Excluded from working with or around food","es":"Excluido de trabajar con o cerca de alimentos","ru":"Отстранён от работы с пищей и рядом с ней","tr":"Gıdayla veya gıda çevresinde çalışmaktan uzaklaştırılmış","hi":"भोजन के साथ या आसपास काम करने से बाहर","ar":"مستبعَدًا من العمل بالطعام أو قربه"},{"en":"Allowed to cook but not serve","es":"Autorizado a cocinar pero no a servir","ru":"Допущен готовить, но не подавать","tr":"Pişirmesine izin verilen ama servis yapamayan","hi":"पकाने की अनुमति पर परोसने की नहीं","ar":"مسموحًا له بالطهي دون التقديم"},{"en":"Given gloves and kept on the line","es":"Provisto de guantes y mantenido en la línea","ru":"Обеспечен перчатками и оставлен на линии","tr":"Eldiven verilip hatta tutulan","hi":"दस्ताने देकर लाइन पर रखा","ar":"يُعطى قفازات ويبقى على الخط"},{"en":"Sent to bus tables","es":"Enviado a recoger mesas","ru":"Отправлен убирать столы","tr":"Masa toplamaya gönderilen","hi":"टेबल साफ करने भेजा","ar":"مرسَلًا لتنظيف الطاولات"}],"e":{"en":"Vomiting and diarrhea are exclusion symptoms. The employee cannot work with or around food until symptom-free for at least 24 hours or cleared per the Food Code.","es":"El vómito y la diarrea son síntomas de exclusión. El empleado no puede trabajar con o cerca de alimentos hasta estar sin síntomas por al menos 24 horas o ser autorizado según el Código.","ru":"Рвота и диарея — симптомы отстранения. Работник не может работать с пищей, пока не будет без симптомов минимум 24 часа или не получит допуск по Кодексу.","tr":"Kusma ve ishal, işten uzaklaştırma belirtileridir. Çalışan, en az 24 saat belirtisiz kalana ya da Kanun'a göre onay alana dek gıdayla veya çevresinde çalışamaz.","hi":"उल्टी और दस्त बहिष्करण लक्षण हैं। कर्मचारी कम से कम 24 घंटे लक्षण-मुक्त होने या कोड के अनुसार मंजूरी मिलने तक भोजन के साथ या आसपास काम नहीं कर सकता।","ar":"القيء والإسهال من أعراض الاستبعاد. لا يمكن للموظف العمل بالطعام أو قربه حتى يخلو من الأعراض 24 ساعة على الأقل أو يُصرَّح له وفق القانون."}},{"cat":"illness","a":1,"q":{"en":"Which foodborne pathogen produces a heat-stable toxin, so cooking does not make contaminated food safe?","es":"¿Qué patógeno produce una toxina termoestable, de modo que cocinar no hace segura la comida contaminada?","ru":"Какой пищевой патоген вырабатывает термостойкий токсин, так что готовка не делает загрязнённую пищу безопасной?","tr":"Hangi gıda patojeni ısıya dayanıklı bir toksin üretir; böylece pişirmek kirlenmiş gıdayı güvenli hale getirmez?","hi":"कौन-सा खाद्यजनित रोगाणु ऊष्मा-स्थिर विष बनाता है, जिससे पकाना दूषित भोजन को सुरक्षित नहीं बनाता?","ar":"أي مسبب مرض منقول بالغذاء ينتج سمًا مقاومًا للحرارة، بحيث لا يجعل الطهي الطعام الملوث آمنًا؟"},"o":[{"en":"Salmonella","es":"Salmonella","ru":"Сальмонелла","tr":"Salmonella","hi":"साल्मोनेला","ar":"السالمونيلا"},{"en":"Staphylococcus aureus","es":"Staphylococcus aureus","ru":"Staphylococcus aureus","tr":"Staphylococcus aureus","hi":"स्टैफिलोकोकस ऑरियस","ar":"المكورات العنقودية الذهبية"},{"en":"Shigella","es":"Shigella","ru":"Шигелла","tr":"Shigella","hi":"शिगेला","ar":"الشيغيلا"},{"en":"Hepatitis A","es":"Hepatitis A","ru":"Гепатит A","tr":"Hepatit A","hi":"हेपेटाइटिस A","ar":"التهاب الكبد A"}],"e":{"en":"Staphylococcus aureus, often transferred from hands to food, produces a heat-stable toxin. Once the toxin forms, cooking will not destroy it, so preventing contamination is key.","es":"Staphylococcus aureus, a menudo transferido de las manos a la comida, produce una toxina termoestable. Una vez formada, cocinar no la destruye, por eso prevenir la contaminación es clave.","ru":"Staphylococcus aureus, часто попадающий с рук в пищу, вырабатывает термостойкий токсин. После образования токсина готовка его не разрушает, поэтому важна профилактика загрязнения.","tr":"Genellikle ellerden gıdaya geçen Staphylococcus aureus, ısıya dayanıklı bir toksin üretir. Toksin oluştuğunda pişirmek onu yok etmez; bu yüzden bulaşmayı önlemek esastır.","hi":"स्टैफिलोकोकस ऑरियस, जो अक्सर हाथों से भोजन में जाता है, ऊष्मा-स्थिर विष बनाता है। विष बनने के बाद पकाना इसे नष्ट नहीं करता, इसलिए दूषण रोकना महत्वपूर्ण है।","ar":"المكورات العنقودية الذهبية، التي تنتقل غالبًا من اليدين إلى الطعام، تنتج سمًا مقاومًا للحرارة. بمجرد تكوّن السم لا يدمره الطهي، لذا فمنع التلوث هو الأساس."}},{"cat":"illness","a":2,"q":{"en":"Shiga toxin-producing E. coli (STEC) is most often linked to which food?","es":"La E. coli productora de toxina Shiga (STEC) se vincula más a menudo con qué alimento?","ru":"Энтерогеморрагическая E. coli (STEC) чаще всего связана с каким продуктом?","tr":"Shiga toksini üreten E. coli (STEC) en çok hangi gıdayla ilişkilidir?","hi":"शिगा-टॉक्सिन बनाने वाला E. coli (STEC) सबसे अधिक किस भोजन से जुड़ा है?","ar":"الإشريكية القولونية المنتجة لسم شيغا (STEC) ترتبط غالبًا بأي طعام؟"},"o":[{"en":"Canned fruit","es":"Fruta enlatada","ru":"Консервированные фрукты","tr":"Konserve meyve","hi":"डिब्बाबंद फल","ar":"الفاكهة المعلبة"},{"en":"White bread","es":"Pan blanco","ru":"Белый хлеб","tr":"Beyaz ekmek","hi":"सफेद ब्रेड","ar":"الخبز الأبيض"},{"en":"Undercooked ground beef and contaminated produce","es":"Carne molida poco cocida y verduras contaminadas","ru":"Недоготовленный говяжий фарш и загрязнённые овощи","tr":"Az pişmiş dana kıyma ve kirlenmiş sebze-meyve","hi":"अधपका पिसा बीफ और दूषित उत्पाद","ar":"اللحم المفروم غير المطهو جيدًا والخضار الملوثة"},{"en":"Dry pasta","es":"Pasta seca","ru":"Сухая паста","tr":"Kuru makarna","hi":"सूखा पास्ता","ar":"المعكرونة الجافة"}],"e":{"en":"STEC is strongly associated with undercooked ground beef and with produce contaminated by cattle feces. It can cause severe bloody diarrhea and is a Big 6 pathogen.","es":"La STEC se asocia fuertemente con carne molida poco cocida y con verduras contaminadas por heces de ganado. Puede causar diarrea con sangre grave y es un patógeno de los Big 6.","ru":"STEC тесно связана с недоготовленным говяжьим фаршем и овощами, загрязнёнными фекалиями скота. Может вызвать тяжёлую кровавую диарею; входит в «Большую шестёрку».","tr":"STEC, az pişmiş dana kıyma ve sığır dışkısıyla kirlenmiş sebze-meyveyle güçlü şekilde ilişkilidir. Ağır kanlı ishale yol açabilir ve Büyük 6 patojenidir.","hi":"STEC अधपके पिसे बीफ और मवेशी मल से दूषित उत्पाद से दृढ़ता से जुड़ा है। यह गंभीर खूनी दस्त पैदा कर सकता है और बिग 6 रोगाणु है।","ar":"ترتبط STEC بقوة باللحم المفروم غير المطهو جيدًا وبالخضار الملوثة ببراز الماشية. وقد تسبب إسهالًا دمويًا شديدًا وهي من الستة الكبار."}},{"cat":"illness","a":3,"q":{"en":"When must a food handler diagnosed with a reportable illness inform the person in charge?","es":"¿Cuándo debe un manipulador diagnosticado con una enfermedad de declaración obligatoria informar a la persona a cargo?","ru":"Когда работник с диагностированной подлежащей отчётности болезнью должен сообщить ответственному лицу?","tr":"Bildirimi zorunlu bir hastalık teşhisi konan bir gıda çalışanı sorumlu kişiye ne zaman haber vermeli?","hi":"रिपोर्ट-योग्य बीमारी से निदान किए गए फूड हैंडलर को प्रभारी व्यक्ति को कब सूचित करना चाहिए?","ar":"متى يجب على متداول طعام شُخِّص بمرض واجب الإبلاغ أن يخبر الشخص المسؤول؟"},"o":[{"en":"Only at the next scheduled meeting","es":"Solo en la próxima reunión programada","ru":"Только на следующем плановом собрании","tr":"Yalnızca bir sonraki planlı toplantıda","hi":"केवल अगली निर्धारित बैठक में","ar":"في الاجتماع المجدول القادم فقط"},{"en":"Within one week","es":"Dentro de una semana","ru":"В течение недели","tr":"Bir hafta içinde","hi":"एक सप्ताह के भीतर","ar":"خلال أسبوع"},{"en":"Only if a customer gets sick","es":"Solo si un cliente se enferma","ru":"Только если заболеет клиент","tr":"Yalnızca bir müşteri hastalanırsa","hi":"केवल यदि कोई ग्राहक बीमार हो","ar":"فقط إذا مرض زبون"},{"en":"As soon as possible","es":"Lo antes posible","ru":"Как можно скорее","tr":"En kısa sürede","hi":"जितनी जल्दी संभव हो","ar":"في أقرب وقت ممكن"}],"e":{"en":"Employees must report a diagnosis of a Big 6 illness to the person in charge as soon as possible, so the PIC can restrict or exclude them and notify authorities if required.","es":"Los empleados deben informar un diagnóstico de una enfermedad de los Big 6 a la persona a cargo lo antes posible, para que pueda restringirlos o excluirlos y avisar a las autoridades si corresponde.","ru":"Работники должны сообщать о диагнозе болезни из «Большой шестёрки» ответственному лицу как можно скорее, чтобы оно могло ограничить или отстранить их и при необходимости уведомить органы.","tr":"Çalışanlar Büyük 6 hastalıklarından birinin teşhisini en kısa sürede sorumlu kişiye bildirmelidir; böylece sorumlu kişi onları kısıtlayabilir veya uzaklaştırabilir ve gerekirse yetkilileri bilgilendirebilir.","hi":"कर्मचारियों को बिग 6 बीमारी के निदान की सूचना प्रभारी व्यक्ति को जितनी जल्दी संभव हो देनी चाहिए, ताकि PIC उन्हें प्रतिबंधित या बाहर कर सके और आवश्यक होने पर अधिकारियों को सूचित कर सके।","ar":"يجب على الموظفين إبلاغ الشخص المسؤول بتشخيص أحد أمراض الستة الكبار في أقرب وقت ممكن، ليتمكن من تقييدهم أو استبعادهم وإبلاغ السلطات عند اللزوم."}},{"cat":"illness","a":0,"q":{"en":"What is the difference between restricting and excluding a food employee?","es":"¿Cuál es la diferencia entre restringir y excluir a un empleado de alimentos?","ru":"В чём разница между ограничением и отстранением работника пищевого производства?","tr":"Bir gıda çalışanını kısıtlamak ile işten uzaklaştırmak arasındaki fark nedir?","hi":"एक फूड कर्मचारी को प्रतिबंधित करने और बाहर करने में क्या अंतर है?","ar":"ما الفرق بين تقييد موظف الطعام واستبعاده؟"},"o":[{"en":"Restricting limits their duties; excluding keeps them out of the establishment","es":"Restringir limita sus tareas; excluir lo mantiene fuera del establecimiento","ru":"Ограничение сужает его обязанности; отстранение не пускает его в заведение","tr":"Kısıtlama görevlerini sınırlar; uzaklaştırma ise işletmeden uzak tutar","hi":"प्रतिबंधित करना उसके कर्तव्य सीमित करता है; बाहर करना उसे प्रतिष्ठान से दूर रखता है","ar":"التقييد يحدّ من مهامه؛ والاستبعاد يبقيه خارج المنشأة"},{"en":"They mean exactly the same thing","es":"Significan exactamente lo mismo","ru":"Они означают одно и то же","tr":"İkisi tamamen aynı anlama gelir","hi":"वे बिल्कुल एक ही अर्थ रखते हैं","ar":"لهما المعنى نفسه تمامًا"},{"en":"Excluding is less serious than restricting","es":"Excluir es menos grave que restringir","ru":"Отстранение менее серьёзно, чем ограничение","tr":"Uzaklaştırma, kısıtlamadan daha az ciddidir","hi":"बाहर करना प्रतिबंधित करने से कम गंभीर है","ar":"الاستبعاد أقل خطورة من التقييد"},{"en":"Restricting means firing the employee","es":"Restringir significa despedir al empleado","ru":"Ограничение означает увольнение работника","tr":"Kısıtlama, çalışanı işten çıkarmak demektir","hi":"प्रतिबंधित करना कर्मचारी को नौकरी से निकालना है","ar":"التقييد يعني فصل الموظف"}],"e":{"en":"A restricted employee stays at work but is kept away from exposed food and clean equipment. An excluded employee is not allowed in the establishment at all until cleared.","es":"Un empleado restringido permanece en el trabajo pero se le mantiene lejos de alimentos expuestos y equipo limpio. Un empleado excluido no puede estar en el establecimiento hasta ser autorizado.","ru":"Ограниченный работник остаётся на работе, но держится вдали от открытой пищи и чистого оборудования. Отстранённого работника вообще не пускают в заведение до получения допуска.","tr":"Kısıtlanan çalışan işte kalır ama açıkta gıdadan ve temiz ekipmandan uzak tutulur. Uzaklaştırılan çalışanın ise onay alana dek işletmeye girmesine izin verilmez.","hi":"प्रतिबंधित कर्मचारी काम पर रहता है पर खुले भोजन और साफ उपकरण से दूर रखा जाता है। बाहर किए गए कर्मचारी को मंजूरी मिलने तक प्रतिष्ठान में बिल्कुल अनुमति नहीं होती।","ar":"الموظف المقيَّد يبقى في العمل لكن يُبعَد عن الطعام المكشوف والمعدات النظيفة. أما المستبعَد فلا يُسمح له بدخول المنشأة إطلاقًا حتى يُصرَّح له."}},{"cat":"illness","a":1,"q":{"en":"Which group of symptoms would require RESTRICTING (not excluding) a food handler in a typical restaurant?","es":"¿Qué grupo de síntomas requeriría RESTRINGIR (no excluir) a un manipulador en un restaurante típico?","ru":"Какая группа симптомов требует ОГРАНИЧЕНИЯ (а не отстранения) работника в обычном ресторане?","tr":"Tipik bir restoranda hangi belirti grubu bir gıda çalışanını KISITLAMAYI (uzaklaştırmayı değil) gerektirir?","hi":"एक सामान्य रेस्तरां में कौन-सा लक्षण समूह एक फूड हैंडलर को प्रतिबंधित (बाहर नहीं) करने की आवश्यकता होगी?","ar":"أي مجموعة أعراض تتطلب تقييد (لا استبعاد) متداول طعام في مطعم اعتيادي؟"},"o":[{"en":"Vomiting and diarrhea","es":"Vómitos y diarrea","ru":"Рвота и диарея","tr":"Kusma ve ishal","hi":"उल्टी और दस्त","ar":"القيء والإسهال"},{"en":"A sore throat with fever","es":"Dolor de garganta con fiebre","ru":"Боль в горле с лихорадкой","tr":"Ateşli boğaz ağrısı","hi":"बुखार के साथ गले में खराश","ar":"التهاب حلق مع حمى"},{"en":"Jaundice","es":"Ictericia","ru":"Желтуха","tr":"Sarılık","hi":"पीलिया","ar":"اليرقان"},{"en":"A confirmed Norovirus diagnosis","es":"Un diagnóstico confirmado de Norovirus","ru":"Подтверждённый диагноз норовируса","tr":"Doğrulanmış Norovirüs teşhisi","hi":"पुष्ट नोरोवायरस निदान","ar":"تشخيص مؤكد بنوروفيروس"}],"e":{"en":"In a typical operation, a sore throat with fever leads to restriction, keeping the employee away from exposed food. Vomiting, diarrhea, jaundice, and Big 6 diagnoses require exclusion.","es":"En una operación típica, dolor de garganta con fiebre lleva a restricción, manteniendo al empleado lejos de alimentos expuestos. Vómitos, diarrea, ictericia y diagnósticos de los Big 6 exigen exclusión.","ru":"В обычном заведении боль в горле с лихорадкой ведёт к ограничению, отдаляя работника от открытой пищи. Рвота, диарея, желтуха и диагнозы «Большой шестёрки» требуют отстранения.","tr":"Tipik bir işletmede ateşli boğaz ağrısı kısıtlamaya yol açar ve çalışanı açıktaki gıdadan uzak tutar. Kusma, ishal, sarılık ve Büyük 6 teşhisleri uzaklaştırma gerektirir.","hi":"एक सामान्य प्रतिष्ठान में, बुखार के साथ गले में खराश प्रतिबंध की ओर ले जाती है, कर्मचारी को खुले भोजन से दूर रखते हुए। उल्टी, दस्त, पीलिया और बिग 6 निदान बहिष्करण की मांग करते हैं।","ar":"في منشأة اعتيادية، التهاب الحلق مع الحمى يؤدي إلى التقييد وإبعاد الموظف عن الطعام المكشوف. أما القيء والإسهال واليرقان وتشخيصات الستة الكبار فتتطلب الاستبعاد."}},{"cat":"illness","a":2,"q":{"en":"Hepatitis A is best prevented in a food operation by which practice?","es":"¿Con qué práctica se previene mejor la Hepatitis A en una operación de alimentos?","ru":"Какая практика лучше всего предотвращает гепатит A в пищевом заведении?","tr":"Bir gıda işletmesinde Hepatit A en iyi hangi uygulamayla önlenir?","hi":"किस प्रथा से खाद्य प्रतिष्ठान में हेपेटाइटिस A सबसे अच्छा रोका जाता है?","ar":"بأي ممارسة يُمنع التهاب الكبد A على أفضل وجه في منشأة طعام؟"},"o":[{"en":"Cooking all food to 165°F","es":"Cocinar toda la comida a 165°F","ru":"Готовить всю пищу до 165°F","tr":"Tüm gıdayı 165°F'e pişirmek","hi":"सारे भोजन को 165°F तक पकाना","ar":"طهي كل الطعام إلى 165°F"},{"en":"Storing food below 41°F","es":"Almacenar la comida por debajo de 41°F","ru":"Хранить пищу ниже 41°F","tr":"Gıdayı 41°F altında saklamak","hi":"भोजन को 41°F से नीचे रखना","ar":"تخزين الطعام أقل من 41°F"},{"en":"Proper handwashing and excluding infected employees","es":"Lavado de manos adecuado y exclusión de empleados infectados","ru":"Правильное мытьё рук и отстранение инфицированных работников","tr":"Doğru el yıkama ve enfekte çalışanları uzaklaştırma","hi":"उचित हाथ धोना और संक्रमित कर्मचारियों को बाहर करना","ar":"غسل اليدين السليم واستبعاد الموظفين المصابين"},{"en":"Using more sanitizer on tables","es":"Usar más desinfectante en las mesas","ru":"Использовать больше санитайзера на столах","tr":"Masalarda daha fazla dezenfektan kullanmak","hi":"मेजों पर अधिक सैनिटाइज़र उपयोग करना","ar":"استخدام مزيد من المعقّم على الطاولات"}],"e":{"en":"Hepatitis A spreads by the fecal-oral route, so proper handwashing, no bare-hand contact with ready-to-eat food, and excluding infected or jaundiced employees are the key controls.","es":"La Hepatitis A se propaga por vía fecal-oral, así que el lavado de manos adecuado, evitar el contacto con las manos desnudas con alimentos listos para comer y excluir empleados infectados o con ictericia son los controles clave.","ru":"Гепатит A распространяется фекально-оральным путём, поэтому ключевые меры — правильное мытьё рук, запрет голых рук с готовой пищей и отстранение инфицированных или желтушных работников.","tr":"Hepatit A fekal-oral yolla yayılır; bu yüzden doğru el yıkama, yenmeye hazır gıdaya çıplak elle temas etmemek ve enfekte ya da sarılıklı çalışanları uzaklaştırmak temel kontrollerdir.","hi":"हेपेटाइटिस A मल-मुख मार्ग से फैलता है, इसलिए उचित हाथ धोना, खाने-के-लिए-तैयार भोजन से नंगे हाथ का संपर्क न होना, और संक्रमित या पीलिया वाले कर्मचारियों को बाहर करना मुख्य नियंत्रण हैं।","ar":"ينتشر التهاب الكبد A عبر المسار البرازي-الفموي، لذا فإن غسل اليدين السليم وعدم ملامسة الطعام الجاهز باليد العارية واستبعاد المصابين أو المصفرّين هي الضوابط الأساسية."}},{"cat":"illness","a":3,"q":{"en":"Which practice most directly reduces the spread of Shigella in a food operation?","es":"¿Qué práctica reduce más directamente la propagación de Shigella en una operación de alimentos?","ru":"Какая практика наиболее прямо снижает распространение шигеллы в пищевом заведении?","tr":"Bir gıda işletmesinde Shigella yayılımını en doğrudan hangi uygulama azaltır?","hi":"कौन-सी प्रथा खाद्य प्रतिष्ठान में शिगेला के प्रसार को सबसे प्रत्यक्ष रूप से कम करती है?","ar":"أي ممارسة تقلل بشكل مباشر أكثر انتشار الشيغيلا في منشأة طعام؟"},"o":[{"en":"Freezing food quickly","es":"Congelar la comida rápidamente","ru":"Быстрое замораживание пищи","tr":"Gıdayı hızlı dondurmak","hi":"भोजन को जल्दी जमाना","ar":"تجميد الطعام بسرعة"},{"en":"Cooking vegetables longer","es":"Cocinar las verduras por más tiempo","ru":"Более долгая варка овощей","tr":"Sebzeleri daha uzun pişirmek","hi":"सब्जियों को अधिक देर पकाना","ar":"طهي الخضار مدة أطول"},{"en":"Chilling drinks before service","es":"Enfriar las bebidas antes del servicio","ru":"Охлаждение напитков перед подачей","tr":"İçecekleri servisten önce soğutmak","hi":"सेवा से पहले पेय ठंडा करना","ar":"تبريد المشروبات قبل التقديم"},{"en":"Handwashing and controlling flies","es":"Lavado de manos y control de moscas","ru":"Мытьё рук и борьба с мухами","tr":"El yıkama ve sinek kontrolü","hi":"हाथ धोना और मक्खियों को नियंत्रित करना","ar":"غسل اليدين ومكافحة الذباب"}],"e":{"en":"Shigella spreads through the fecal-oral route and is also carried by flies. Good handwashing, keeping ill workers out, and controlling flies are the most effective defenses.","es":"La Shigella se propaga por vía fecal-oral y también la transportan las moscas. Buen lavado de manos, mantener fuera a los trabajadores enfermos y controlar moscas son las defensas más eficaces.","ru":"Шигелла распространяется фекально-оральным путём и переносится мухами. Хорошее мытьё рук, недопущение больных работников и борьба с мухами — самые эффективные меры.","tr":"Shigella fekal-oral yolla yayılır ve ayrıca sineklerle taşınır. İyi el yıkama, hasta çalışanları uzak tutmak ve sinek kontrolü en etkili savunmalardır.","hi":"शिगेला मल-मुख मार्ग से फैलती है और मक्खियों द्वारा भी ले जाई जाती है। अच्छा हाथ धोना, बीमार कर्मचारियों को दूर रखना और मक्खियों को नियंत्रित करना सबसे प्रभावी बचाव हैं।","ar":"تنتشر الشيغيلا عبر المسار البرازي-الفموي وينقلها الذباب أيضًا. غسل اليدين الجيد وإبعاد العاملين المرضى ومكافحة الذباب هي أكثر الدفاعات فعالية."}},{"cat":"illness","a":0,"q":{"en":"After being excluded for vomiting and diarrhea (no diagnosed illness), when may a food handler usually return to work?","es":"Tras ser excluido por vómitos y diarrea (sin enfermedad diagnosticada), ¿cuándo puede volver a trabajar un manipulador normalmente?","ru":"После отстранения из-за рвоты и диареи (без установленного диагноза) когда обычно работник может вернуться к работе?","tr":"Kusma ve ishal nedeniyle (teşhis konmamış) uzaklaştırıldıktan sonra bir gıda çalışanı genellikle işe ne zaman dönebilir?","hi":"उल्टी और दस्त (कोई निदान बीमारी नहीं) के लिए बाहर किए जाने के बाद, एक फूड हैंडलर आमतौर पर कब काम पर लौट सकता है?","ar":"بعد الاستبعاد بسبب القيء والإسهال (دون مرض مشخّص)، متى يمكن لمتداول الطعام العودة للعمل عادةً؟"},"o":[{"en":"After being symptom-free for at least 24 hours","es":"Tras estar sin síntomas por al menos 24 horas","ru":"После отсутствия симптомов не менее 24 часов","tr":"En az 24 saat belirtisiz kaldıktan sonra","hi":"कम से कम 24 घंटे लक्षण-मुक्त रहने के बाद","ar":"بعد خلوّه من الأعراض 24 ساعة على الأقل"},{"en":"Immediately, once vomiting stops","es":"De inmediato, en cuanto pare el vómito","ru":"Сразу, как только прекратится рвота","tr":"Kusma durur durmaz hemen","hi":"तुरंत, जैसे ही उल्टी रुके","ar":"فورًا، بمجرد توقف القيء"},{"en":"After one hour of rest","es":"Tras una hora de descanso","ru":"После одного часа отдыха","tr":"Bir saat dinlendikten sonra","hi":"एक घंटे के आराम के बाद","ar":"بعد ساعة من الراحة"},{"en":"Only after 30 days","es":"Solo después de 30 días","ru":"Только через 30 дней","tr":"Yalnızca 30 gün sonra","hi":"केवल 30 दिनों के बाद","ar":"بعد 30 يومًا فقط"}],"e":{"en":"For vomiting or diarrhea without a diagnosed illness, an employee may generally return once they have been symptom-free for at least 24 hours.","es":"Para vómitos o diarrea sin enfermedad diagnosticada, un empleado puede volver en general una vez que ha estado sin síntomas por al menos 24 horas.","ru":"При рвоте или диарее без установленного диагноза работник обычно может вернуться, когда не будет симптомов минимум 24 часа.","tr":"Teşhis konmamış kusma veya ishalde çalışan, genellikle en az 24 saat belirtisiz kaldığında işe dönebilir.","hi":"निदान बीमारी के बिना उल्टी या दस्त के लिए, एक कर्मचारी आमतौर पर कम से कम 24 घंटे लक्षण-मुक्त रहने के बाद लौट सकता है।","ar":"في حالة القيء أو الإسهال دون مرض مشخّص، يمكن للموظف العودة عمومًا بعد أن يخلو من الأعراض 24 ساعة على الأقل."}},{"cat":"illness","a":1,"q":{"en":"Nontyphoidal Salmonella is commonly associated with which foods?","es":"La Salmonella no tifoidea se asocia comúnmente con qué alimentos?","ru":"Нетифоидная сальмонелла обычно связана с какими продуктами?","tr":"Tifo dışı Salmonella yaygın olarak hangi gıdalarla ilişkilidir?","hi":"गैर-टाइफाइड साल्मोनेला आमतौर पर किन खाद्य पदार्थों से जुड़ा है?","ar":"ترتبط السالمونيلا غير التيفية عادةً بأي أطعمة؟"},"o":[{"en":"Bread and dry cereal","es":"Pan y cereal seco","ru":"Хлеб и сухие хлопья","tr":"Ekmek ve kuru mısır gevreği","hi":"ब्रेड और सूखा अनाज","ar":"الخبز والحبوب الجافة"},{"en":"Poultry, eggs, and dairy","es":"Aves, huevos y lácteos","ru":"Птица, яйца и молочные продукты","tr":"Kümes hayvanları, yumurta ve süt ürünleri","hi":"पोल्ट्री, अंडे और डेयरी","ar":"الدواجن والبيض ومنتجات الألبان"},{"en":"Cooking oil and vinegar","es":"Aceite de cocina y vinagre","ru":"Растительное масло и уксус","tr":"Sıvı yağ ve sirke","hi":"खाना पकाने का तेल और सिरका","ar":"زيت الطهي والخل"},{"en":"Sugar and salt","es":"Azúcar y sal","ru":"Сахар и соль","tr":"Şeker ve tuz","hi":"चीनी और नमक","ar":"السكر والملح"}],"e":{"en":"Nontyphoidal Salmonella is often linked to poultry, eggs, dairy, and produce. Cooking to required temperatures and avoiding cross-contamination reduce the risk.","es":"La Salmonella no tifoidea suele vincularse con aves, huevos, lácteos y verduras. Cocinar a las temperaturas requeridas y evitar la contaminación cruzada reduce el riesgo.","ru":"Нетифоидная сальмонелла часто связана с птицей, яйцами, молочными продуктами и овощами. Готовка до нужных температур и отсутствие перекрёстного загрязнения снижают риск.","tr":"Tifo dışı Salmonella genellikle kümes hayvanları, yumurta, süt ürünleri ve sebze-meyveyle ilişkilidir. Gereken sıcaklıklara pişirmek ve çapraz bulaşmayı önlemek riski azaltır.","hi":"गैर-टाइफाइड साल्मोनेला अक्सर पोल्ट्री, अंडे, डेयरी और उत्पाद से जुड़ा है। आवश्यक तापमान तक पकाना और क्रॉस-कॉन्टैमिनेशन से बचना जोखिम कम करते हैं।","ar":"ترتبط السالمونيلا غير التيفية غالبًا بالدواجن والبيض ومنتجات الألبان والخضار. الطهي إلى الدرجات المطلوبة وتجنب التلوث المتبادل يقللان الخطر."}},{"cat":"illness","a":2,"q":{"en":"Which of the following is considered a highly susceptible population (HSP)?","es":"¿Cuál de los siguientes se considera una población altamente susceptible (HSP)?","ru":"Что из перечисленного считается высоковосприимчивой группой населения (HSP)?","tr":"Aşağıdakilerden hangisi yüksek riskli nüfus (HSP) sayılır?","hi":"निम्न में से किसे अत्यधिक संवेदनशील आबादी (HSP) माना जाता है?","ar":"أي مما يلي يُعدّ فئة شديدة التأثر (HSP)؟"},"o":[{"en":"Healthy adults dining out","es":"Adultos sanos que salen a comer","ru":"Здоровые взрослые в ресторане","tr":"Dışarıda yemek yiyen sağlıklı yetişkinler","hi":"बाहर भोजन करने वाले स्वस्थ वयस्क","ar":"بالغون أصحّاء يتناولون الطعام بالخارج"},{"en":"Office workers at lunch","es":"Trabajadores de oficina almorzando","ru":"Офисные работники на обеде","tr":"Öğle yemeğindeki ofis çalışanları","hi":"दोपहर के भोजन पर कार्यालय कर्मचारी","ar":"موظفو المكاتب في الغداء"},{"en":"Preschool children and elderly residents of a care home","es":"Niños de preescolar y ancianos residentes de un asilo","ru":"Дети дошкольного возраста и пожилые жители дома престарелых","tr":"Okul öncesi çocuklar ve bakımevi sakini yaşlılar","hi":"पूर्वस्कूली बच्चे और देखभाल गृह के बुजुर्ग निवासी","ar":"أطفال الحضانة والمسنّون المقيمون في دار رعاية"},{"en":"Teenage sports teams","es":"Equipos deportivos de adolescentes","ru":"Подростковые спортивные команды","tr":"Genç spor takımları","hi":"किशोर खेल टीमें","ar":"فرق رياضية للمراهقين"}],"e":{"en":"Highly susceptible populations include young children, older adults, pregnant women, and people with weakened immune systems, often in hospitals, care homes, and daycares.","es":"Las poblaciones altamente susceptibles incluyen niños pequeños, adultos mayores, embarazadas y personas inmunodeprimidas, a menudo en hospitales, asilos y guarderías.","ru":"К высоковосприимчивым группам относятся дети младшего возраста, пожилые, беременные и люди с ослабленным иммунитетом, часто в больницах, домах престарелых и детсадах.","tr":"Yüksek riskli nüfuslar; küçük çocukları, yaşlıları, hamileleri ve bağışıklığı zayıf kişileri kapsar; çoğunlukla hastane, bakımevi ve kreşlerde bulunurlar.","hi":"अत्यधिक संवेदनशील आबादी में छोटे बच्चे, वृद्ध, गर्भवती महिलाएं और कमजोर प्रतिरक्षा वाले लोग शामिल हैं, अक्सर अस्पतालों, देखभाल गृहों और डेकेयर में।","ar":"تشمل الفئات شديدة التأثر الأطفال الصغار وكبار السن والحوامل وضعيفي المناعة، وغالبًا في المستشفيات ودور الرعاية والحضانات."}},{"cat":"illness","a":3,"q":{"en":"Why are the Big 6 pathogens singled out for mandatory reporting?","es":"¿Por qué se destacan los patógenos Big 6 para declaración obligatoria?","ru":"Почему патогены «Большой шестёрки» выделены для обязательной отчётности?","tr":"Büyük 6 patojenleri neden zorunlu bildirim için ayrı tutulur?","hi":"बिग 6 रोगाणुओं को अनिवार्य रिपोर्टिंग के लिए क्यों अलग किया जाता है?","ar":"لماذا تُخصّ مسببات الستة الكبار بالإبلاغ الإلزامي؟"},"o":[{"en":"They only affect equipment, not people","es":"Solo afectan al equipo, no a las personas","ru":"Они влияют только на оборудование, не на людей","tr":"Yalnızca ekipmanı etkiler, insanları değil","hi":"वे केवल उपकरण को प्रभावित करते हैं, लोगों को नहीं","ar":"تؤثر على المعدات فقط، لا على الناس"},{"en":"They are harmless in small amounts","es":"Son inofensivos en pequeñas cantidades","ru":"Они безвредны в малых количествах","tr":"Küçük miktarlarda zararsızdır","hi":"वे कम मात्रा में हानिरहित हैं","ar":"غير ضارة بكميات صغيرة"},{"en":"They cannot be spread by food","es":"No pueden propagarse por alimentos","ru":"Они не могут передаваться через пищу","tr":"Gıdayla yayılamaz","hi":"वे भोजन से नहीं फैल सकते","ar":"لا يمكن أن تنتشر عبر الطعام"},{"en":"They are highly infectious and easily transmitted through food by sick workers","es":"Son muy infecciosos y se transmiten fácilmente por alimentos a través de trabajadores enfermos","ru":"Они очень заразны и легко передаются через пищу больными работниками","tr":"Son derece bulaşıcıdır ve hasta çalışanlar aracılığıyla gıdayla kolayca bulaşır","hi":"वे अत्यधिक संक्रामक हैं और बीमार कर्मचारियों द्वारा भोजन से आसानी से फैलते हैं","ar":"شديدة العدوى وتنتقل بسهولة عبر الطعام من العاملين المرضى"}],"e":{"en":"The Big 6 are singled out because they are highly infectious, need only a small dose to cause illness, and are readily transmitted through food by an infected worker.","es":"Los Big 6 se destacan porque son muy infecciosos, basta una dosis pequeña para enfermar y se transmiten fácilmente por alimentos a través de un trabajador infectado.","ru":"«Большая шестёрка» выделена, потому что эти патогены очень заразны, для болезни достаточно малой дозы, и они легко передаются через пищу от инфицированного работника.","tr":"Büyük 6, son derece bulaşıcı oldukları, hastalık için küçük bir doz yettiği ve enfekte bir çalışan aracılığıyla gıdayla kolayca bulaştıkları için ayrı tutulur.","hi":"बिग 6 को इसलिए अलग किया जाता है क्योंकि वे अत्यधिक संक्रामक हैं, बीमारी के लिए केवल छोटी खुराक चाहिए, और संक्रमित कर्मचारी द्वारा भोजन से आसानी से फैलते हैं।","ar":"تُخصّ الستة الكبار لأنها شديدة العدوى، وتحتاج جرعة صغيرة فقط لإحداث المرض، وتنتقل بسهولة عبر الطعام من عامل مصاب."}},{"cat":"illness","a":0,"q":{"en":"Which is the single most important thing a sick food handler can do to protect customers?","es":"¿Cuál es lo más importante que un manipulador enfermo puede hacer para proteger a los clientes?","ru":"Что самое важное может сделать заболевший работник, чтобы защитить клиентов?","tr":"Hasta bir gıda çalışanının müşterileri korumak için yapabileceği en önemli tek şey nedir?","hi":"बीमार फूड हैंडलर ग्राहकों की रक्षा के लिए सबसे महत्वपूर्ण एक काम क्या कर सकता है?","ar":"ما أهم شيء واحد يمكن لمتداول طعام مريض فعله لحماية الزبائن؟"},"o":[{"en":"Report symptoms to the manager and stay home when required","es":"Reportar los síntomas al gerente y quedarse en casa cuando se requiera","ru":"Сообщить о симптомах менеджеру и оставаться дома при необходимости","tr":"Belirtileri yöneticiye bildirmek ve gerektiğinde evde kalmak","hi":"प्रबंधक को लक्षण बताना और आवश्यक होने पर घर पर रहना","ar":"إبلاغ المدير بالأعراض والبقاء في المنزل عند اللزوم"},{"en":"Take extra breaks","es":"Tomar descansos adicionales","ru":"Делать дополнительные перерывы","tr":"Fazladan mola vermek","hi":"अतिरिक्त ब्रेक लेना","ar":"أخذ استراحات إضافية"},{"en":"Work faster to finish sooner","es":"Trabajar más rápido para terminar antes","ru":"Работать быстрее, чтобы закончить раньше","tr":"Daha erken bitirmek için daha hızlı çalışmak","hi":"जल्दी खत्म करने के लिए तेजी से काम करना","ar":"العمل بسرعة أكبر للانتهاء مبكرًا"},{"en":"Wear two pairs of gloves","es":"Usar dos pares de guantes","ru":"Надеть две пары перчаток","tr":"İki çift eldiven giymek","hi":"दो जोड़ी दस्ताने पहनना","ar":"ارتداء زوجين من القفازات"}],"e":{"en":"The most important action is to report symptoms to the person in charge and stay away from work when excluded, so an illness is not passed to customers through food.","es":"La acción más importante es reportar los síntomas a la persona a cargo y no ir a trabajar cuando se es excluido, para no pasar una enfermedad a los clientes por los alimentos.","ru":"Самое важное — сообщить о симптомах ответственному лицу и не выходить на работу при отстранении, чтобы болезнь не передалась клиентам через пищу.","tr":"En önemli eylem, belirtileri sorumlu kişiye bildirmek ve uzaklaştırıldığında işe gitmemektir; böylece hastalık gıda yoluyla müşterilere geçmez.","hi":"सबसे महत्वपूर्ण कार्रवाई है प्रभारी व्यक्ति को लक्षण बताना और बाहर किए जाने पर काम से दूर रहना, ताकि बीमारी भोजन के माध्यम से ग्राहकों तक न पहुंचे।","ar":"أهم إجراء هو إبلاغ الشخص المسؤول بالأعراض والابتعاد عن العمل عند الاستبعاد، حتى لا ينتقل المرض إلى الزبائن عبر الطعام."}},{"cat":"illness","a":1,"q":{"en":"A norovirus outbreak is linked to a restaurant. What is the most likely cause?","es":"Un brote de norovirus se vincula a un restaurante. ¿Cuál es la causa más probable?","ru":"Вспышка норовируса связана с рестораном. Какова наиболее вероятная причина?","tr":"Bir restoranla bağlantılı bir norovirüs salgını var. En olası neden nedir?","hi":"एक नोरोवायरस प्रकोप एक रेस्तरां से जुड़ा है। सबसे संभावित कारण क्या है?","ar":"ارتبط تفشٍّ لنوروفيروس بمطعم. ما السبب الأرجح؟"},"o":[{"en":"Food stored slightly below 41°F","es":"Comida almacenada apenas por debajo de 41°F","ru":"Пища, хранящаяся чуть ниже 41°F","tr":"41°F'in biraz altında saklanan gıda","hi":"41°F से थोड़ा नीचे संग्रहीत भोजन","ar":"طعام مخزّن أقل بقليل من 41°F"},{"en":"An infected worker handling ready-to-eat food without proper handwashing","es":"Un trabajador infectado manipulando alimentos listos para comer sin lavado de manos adecuado","ru":"Инфицированный работник, трогающий готовую пищу без должного мытья рук","tr":"Enfekte bir çalışanın doğru el yıkama olmadan yenmeye hazır gıdaya dokunması","hi":"एक संक्रमित कर्मचारी बिना उचित हाथ धोए खाने-के-लिए-तैयार भोजन संभालना","ar":"عامل مصاب يتعامل مع طعام جاهز للأكل دون غسل يدين سليم"},{"en":"Cooking chicken to 165°F","es":"Cocinar pollo a 165°F","ru":"Готовка курицы до 165°F","tr":"Tavuğu 165°F'e pişirmek","hi":"चिकन को 165°F तक पकाना","ar":"طهي الدجاج إلى 165°F"},{"en":"Using color-coded cutting boards","es":"Usar tablas de cortar codificadas por color","ru":"Использование досок с цветовой кодировкой","tr":"Renk kodlu kesme tahtaları kullanmak","hi":"रंग-कोडित कटिंग बोर्ड का उपयोग","ar":"استخدام ألواح تقطيع مرمّزة بالألوان"}],"e":{"en":"Norovirus outbreaks are frequently traced to an infected food handler who touched ready-to-eat food after not washing hands properly, especially after using the restroom.","es":"Los brotes de norovirus suelen rastrearse a un manipulador infectado que tocó alimentos listos para comer tras no lavarse bien las manos, sobre todo después del baño.","ru":"Вспышки норовируса часто связывают с инфицированным работником, который тронул готовую пищу, не вымыв как следует руки, особенно после туалета.","tr":"Norovirüs salgınları sıklıkla, özellikle tuvaletten sonra ellerini doğru yıkamayıp yenmeye hazır gıdaya dokunan enfekte bir çalışana dayandırılır.","hi":"नोरोवायरस प्रकोप अक्सर एक संक्रमित हैंडलर से जोड़े जाते हैं जिसने ठीक से हाथ न धोकर, खासकर शौचालय के बाद, खाने-के-लिए-तैयार भोजन छुआ।","ar":"غالبًا ما تُعزى تفشيات نوروفيروس إلى عامل مصاب لمس طعامًا جاهزًا للأكل بعد عدم غسل يديه جيدًا، خصوصًا بعد دورة المياه."}},{"cat":"illness","a":2,"q":{"en":"Which pathogen type does NOT grow in food but can still cause illness if present?","es":"¿Qué tipo de patógeno NO crece en los alimentos pero aún puede causar enfermedad si está presente?","ru":"Какой тип патогена НЕ растёт в пище, но всё же может вызвать болезнь при наличии?","tr":"Hangi patojen türü gıdada ÜREMEZ ama varsa yine de hastalığa yol açabilir?","hi":"कौन-सा रोगाणु प्रकार भोजन में नहीं बढ़ता पर मौजूद होने पर भी बीमारी पैदा कर सकता है?","ar":"أي نوع من مسببات المرض لا ينمو في الطعام لكنه قد يسبب المرض إن وُجد؟"},"o":[{"en":"Bacteria","es":"Bacterias","ru":"Бактерии","tr":"Bakteriler","hi":"बैक्टीरिया","ar":"البكتيريا"},{"en":"Yeast","es":"Levaduras","ru":"Дрожжи","tr":"Mayalar","hi":"यीस्ट","ar":"الخميرة"},{"en":"Viruses","es":"Virus","ru":"Вирусы","tr":"Virüsler","hi":"वायरस","ar":"الفيروسات"},{"en":"Mold","es":"Moho","ru":"Плесень","tr":"Küf","hi":"फफूंद","ar":"العفن"}],"e":{"en":"Viruses such as Norovirus and Hepatitis A do not grow in food, but even a tiny amount transferred by a food handler can make people sick, so handwashing is critical.","es":"Los virus como el Norovirus y la Hepatitis A no crecen en los alimentos, pero incluso una mínima cantidad transferida por un manipulador puede enfermar, por eso el lavado de manos es crítico.","ru":"Вирусы, такие как норовирус и гепатит A, не растут в пище, но даже крошечное количество, перенесённое работником, может вызвать болезнь, поэтому мытьё рук критично.","tr":"Norovirüs ve Hepatit A gibi virüsler gıdada üremez; ancak bir çalışanın taşıdığı çok küçük bir miktar bile insanları hasta edebilir, bu yüzden el yıkama kritiktir.","hi":"नोरोवायरस और हेपेटाइटिस A जैसे वायरस भोजन में नहीं बढ़ते, पर हैंडलर द्वारा स्थानांतरित बहुत छोटी मात्रा भी लोगों को बीमार कर सकती है, इसलिए हाथ धोना महत्वपूर्ण है।","ar":"الفيروسات مثل نوروفيروس والتهاب الكبد A لا تنمو في الطعام، لكن حتى كمية ضئيلة ينقلها عامل قد تُمرض الناس، لذا فغسل اليدين حاسم."}},{"cat":"illness","a":3,"q":{"en":"A cook diagnosed with STEC (E. coli) wants to return to work. When may they return?","es":"Un cocinero diagnosticado con STEC (E. coli) quiere volver al trabajo. ¿Cuándo puede regresar?","ru":"Повар с диагнозом STEC (E. coli) хочет вернуться на работу. Когда он может вернуться?","tr":"STEC (E. coli) teşhisi konan bir aşçı işe dönmek istiyor. Ne zaman dönebilir?","hi":"STEC (E. coli) से निदान किया रसोइया काम पर लौटना चाहता है। वह कब लौट सकता है?","ar":"طاهٍ شُخِّص بـ STEC (E. coli) يريد العودة للعمل. متى يمكنه العودة؟"},"o":[{"en":"As soon as he feels better","es":"En cuanto se sienta mejor","ru":"Как только почувствует себя лучше","tr":"Kendini daha iyi hisseder hissetmez","hi":"जैसे ही वह बेहतर महसूस करे","ar":"بمجرد أن يشعر بتحسّن"},{"en":"After one symptom-free day","es":"Tras un día sin síntomas","ru":"После одного дня без симптомов","tr":"Bir gün belirtisiz kaldıktan sonra","hi":"एक लक्षण-मुक्त दिन के बाद","ar":"بعد يوم واحد خالٍ من الأعراض"},{"en":"Whenever the manager decides","es":"Cuando lo decida el gerente","ru":"Когда решит менеджер","tr":"Yönetici ne zaman karar verirse","hi":"जब भी प्रबंधक तय करे","ar":"متى قرر المدير"},{"en":"Only with approval from the regulatory authority and medical clearance","es":"Solo con aprobación de la autoridad reguladora y alta médica","ru":"Только с одобрения регулирующего органа и медицинского допуска","tr":"Yalnızca düzenleyici otoritenin onayı ve tıbbi izinle","hi":"केवल नियामक प्राधिकरण की मंजूरी और चिकित्सा अनुमति के साथ","ar":"فقط بموافقة الجهة التنظيمية والتصريح الطبي"}],"e":{"en":"For a Big 6 diagnosis like STEC, the excluded employee may return only when approved by the regulatory authority, usually after medical clearance confirming they are no longer infectious.","es":"Para un diagnóstico de los Big 6 como STEC, el empleado excluido puede regresar solo con aprobación de la autoridad reguladora, normalmente tras alta médica que confirme que ya no es infeccioso.","ru":"При диагнозе из «Большой шестёрки», например STEC, отстранённый работник может вернуться только с одобрения регулирующего органа, обычно после медицинского допуска, подтверждающего, что он больше не заразен.","tr":"STEC gibi bir Büyük 6 teşhisinde, uzaklaştırılan çalışan yalnızca düzenleyici otoritenin onayıyla, genellikle artık bulaştırıcı olmadığını doğrulayan tıbbi izinden sonra dönebilir.","hi":"STEC जैसे बिग 6 निदान के लिए, बाहर किया गया कर्मचारी केवल नियामक प्राधिकरण की मंजूरी के साथ लौट सकता है, आमतौर पर चिकित्सा अनुमति के बाद जो पुष्टि करती है कि वह अब संक्रामक नहीं है।","ar":"في تشخيص من الستة الكبار مثل STEC، لا يعود الموظف المستبعَد إلا بموافقة الجهة التنظيمية، وعادةً بعد تصريح طبي يؤكد أنه لم يعد مُعديًا."}},{"cat":"illness","a":0,"q":{"en":"Which describes the fecal-oral route of contamination?","es":"¿Qué describe la ruta de contaminación fecal-oral?","ru":"Что описывает фекально-оральный путь загрязнения?","tr":"Fekal-oral bulaşma yolunu hangisi tanımlar?","hi":"मल-मुख दूषण मार्ग को क्या वर्णित करता है?","ar":"أي مما يلي يصف مسار التلوث البرازي-الفموي؟"},"o":[{"en":"Pathogens from feces reach food and then a person's mouth","es":"Patógenos de las heces llegan a la comida y luego a la boca de una persona","ru":"Патогены из фекалий попадают в пищу, а затем в рот человека","tr":"Dışkıdaki patojenler gıdaya, sonra bir kişinin ağzına ulaşır","hi":"मल से रोगाणु भोजन तक और फिर व्यक्ति के मुंह तक पहुंचते हैं","ar":"مسببات من البراز تصل إلى الطعام ثم إلى فم الشخص"},{"en":"Pathogens spread only through the air","es":"Los patógenos se propagan solo por el aire","ru":"Патогены распространяются только по воздуху","tr":"Patojenler yalnızca havayla yayılır","hi":"रोगाणु केवल हवा से फैलते हैं","ar":"تنتشر المسببات عبر الهواء فقط"},{"en":"Pathogens are created by cooking","es":"Los patógenos se crean al cocinar","ru":"Патогены создаются при готовке","tr":"Patojenler pişirmeyle oluşur","hi":"रोगाणु पकाने से बनते हैं","ar":"تُنتَج المسببات بالطهي"},{"en":"Pathogens only affect frozen food","es":"Los patógenos solo afectan la comida congelada","ru":"Патогены влияют только на замороженную пищу","tr":"Patojenler yalnızca donmuş gıdayı etkiler","hi":"रोगाणु केवल जमे भोजन को प्रभावित करते हैं","ar":"تؤثر المسببات على الطعام المجمد فقط"}],"e":{"en":"In the fecal-oral route, pathogens in feces (via unwashed hands after using the restroom) contaminate food, which is then eaten. Handwashing breaks this route.","es":"En la ruta fecal-oral, los patógenos de las heces (por manos sin lavar tras el baño) contaminan la comida, que luego se ingiere. El lavado de manos rompe esta ruta.","ru":"При фекально-оральном пути патогены из фекалий (через немытые руки после туалета) загрязняют пищу, которую затем едят. Мытьё рук разрывает этот путь.","tr":"Fekal-oral yolda, dışkıdaki patojenler (tuvaletten sonra yıkanmamış eller aracılığıyla) gıdayı kirletir ve gıda sonra yenir. El yıkama bu yolu keser.","hi":"मल-मुख मार्ग में, मल के रोगाणु (शौचालय के बाद बिना धुले हाथों से) भोजन को दूषित करते हैं, जिसे फिर खाया जाता है। हाथ धोना इस मार्ग को तोड़ता है।","ar":"في المسار البرازي-الفموي، تلوّث مسببات البراز (عبر أيدٍ غير مغسولة بعد دورة المياه) الطعام الذي يُؤكل بعدها. غسل اليدين يقطع هذا المسار."}},{"cat":"illness","a":1,"q":{"en":"Which control most directly prevents Clostridium botulinum growth in canned or vacuum-packed foods?","es":"¿Qué control previene más directamente el crecimiento de Clostridium botulinum en alimentos enlatados o envasados al vacío?","ru":"Какой контроль наиболее прямо предотвращает рост Clostridium botulinum в консервах или вакуумной упаковке?","tr":"Konserve veya vakumlu gıdalarda Clostridium botulinum üremesini en doğrudan hangi kontrol önler?","hi":"कौन-सा नियंत्रण डिब्बाबंद या वैक्यूम-पैक भोजन में क्लॉस्ट्रिडियम बॉटुलिनम की वृद्धि को सबसे प्रत्यक्ष रूप से रोकता है?","ar":"أي ضابط يمنع بشكل مباشر أكثر نمو المطثية الوشيقية في الأطعمة المعلبة أو المفرّغة من الهواء؟"},"o":[{"en":"Adding extra salt only","es":"Añadir solo sal adicional","ru":"Добавить только больше соли","tr":"Yalnızca fazladan tuz eklemek","hi":"केवल अतिरिक्त नमक डालना","ar":"إضافة ملح إضافي فقط"},{"en":"Proper temperature control and following approved canning or packaging procedures","es":"Control adecuado de temperatura y seguir procedimientos aprobados de enlatado o envasado","ru":"Правильный контроль температуры и соблюдение одобренных процедур консервирования или упаковки","tr":"Doğru sıcaklık kontrolü ve onaylı konserveleme veya paketleme prosedürlerini uygulamak","hi":"उचित तापमान नियंत्रण और स्वीकृत कैनिंग या पैकेजिंग प्रक्रियाओं का पालन","ar":"ضبط الحرارة السليم واتباع إجراءات التعليب أو التعبئة المعتمدة"},{"en":"Storing in clear containers","es":"Almacenar en recipientes transparentes","ru":"Хранение в прозрачных ёмкостях","tr":"Şeffaf kaplarda saklamak","hi":"पारदर्शी बर्तनों में भंडारण","ar":"التخزين في أوعية شفافة"},{"en":"Serving the food cold","es":"Servir la comida fría","ru":"Подавать пищу холодной","tr":"Gıdayı soğuk servis etmek","hi":"भोजन को ठंडा परोसना","ar":"تقديم الطعام باردًا"}],"e":{"en":"Clostridium botulinum is an anaerobe that grows in oxygen-free environments like cans and vacuum packs. Temperature control and approved canning/packaging procedures prevent its growth and toxin.","es":"Clostridium botulinum es anaerobio y crece en ambientes sin oxígeno, como latas y envases al vacío. El control de temperatura y los procedimientos aprobados evitan su crecimiento y toxina.","ru":"Clostridium botulinum — анаэроб, растущий в бескислородной среде, например в банках и вакуумной упаковке. Контроль температуры и одобренные процедуры предотвращают его рост и токсин.","tr":"Clostridium botulinum, konserve ve vakumlu paket gibi oksijensiz ortamlarda üreyen bir anaeropdur. Sıcaklık kontrolü ve onaylı prosedürler üremesini ve toksinini önler.","hi":"क्लॉस्ट्रिडियम बॉटुलिनम एक अवायवीय है जो डिब्बे और वैक्यूम पैक जैसे ऑक्सीजन-मुक्त वातावरण में बढ़ता है। तापमान नियंत्रण और स्वीकृत प्रक्रियाएं इसकी वृद्धि और विष रोकती हैं।","ar":"المطثية الوشيقية لاهوائية تنمو في بيئات خالية من الأكسجين كالعلب والتعبئة المفرّغة. ضبط الحرارة والإجراءات المعتمدة يمنعان نموها وسمّها."}},{"cat":"illness","a":2,"q":{"en":"What does a food establishment's employee health policy primarily aim to do?","es":"¿Qué busca principalmente la política de salud de empleados de un establecimiento de alimentos?","ru":"Какова главная цель политики здоровья сотрудников пищевого заведения?","tr":"Bir gıda işletmesinin çalışan sağlığı politikası öncelikle neyi amaçlar?","hi":"एक खाद्य प्रतिष्ठान की कर्मचारी स्वास्थ्य नीति मुख्य रूप से क्या करने का लक्ष्य रखती है?","ar":"ما الهدف الأساسي من سياسة صحة الموظفين في منشأة طعام؟"},"o":[{"en":"Track employee vacation days","es":"Registrar los días de vacaciones","ru":"Учитывать отпускные дни сотрудников","tr":"Çalışanların izin günlerini takip etmek","hi":"कर्मचारी छुट्टी के दिन ट्रैक करना","ar":"تتبّع أيام إجازات الموظفين"},{"en":"Set uniform standards","es":"Establecer normas de uniforme","ru":"Устанавливать стандарты формы","tr":"Üniforma standartları belirlemek","hi":"वर्दी मानक तय करना","ar":"وضع معايير الزي"},{"en":"Keep ill employees from contaminating food and spreading illness","es":"Evitar que empleados enfermos contaminen la comida y propaguen enfermedades","ru":"Не дать больным работникам загрязнять пищу и распространять болезни","tr":"Hasta çalışanların gıdayı kirletmesini ve hastalık yaymasını önlemek","hi":"बीमार कर्मचारियों को भोजन दूषित करने और बीमारी फैलाने से रोकना","ar":"منع الموظفين المرضى من تلويث الطعام ونشر المرض"},{"en":"Decide employee pay rates","es":"Decidir las tarifas de pago","ru":"Определять ставки оплаты труда","tr":"Çalışan ücretlerini belirlemek","hi":"कर्मचारी वेतन दरें तय करना","ar":"تحديد أجور الموظفين"}],"e":{"en":"An employee health policy ensures workers report symptoms and diagnoses, and are restricted or excluded as needed, so ill employees do not contaminate food and cause foodborne illness.","es":"Una política de salud de empleados asegura que reporten síntomas y diagnósticos, y sean restringidos o excluidos según sea necesario, para que no contaminen la comida ni causen enfermedades.","ru":"Политика здоровья сотрудников обеспечивает, чтобы работники сообщали о симптомах и диагнозах и были ограничены или отстранены при необходимости, чтобы больные не загрязняли пищу.","tr":"Çalışan sağlığı politikası, çalışanların belirti ve teşhisleri bildirmesini ve gerektiğinde kısıtlanıp uzaklaştırılmasını sağlar; böylece hasta çalışanlar gıdayı kirletmez ve hastalığa yol açmaz.","hi":"कर्मचारी स्वास्थ्य नीति सुनिश्चित करती है कि कर्मचारी लक्षण और निदान बताएं और आवश्यकतानुसार प्रतिबंधित या बाहर किए जाएं, ताकि बीमार कर्मचारी भोजन दूषित न करें और खाद्यजनित बीमारी न फैलाएं।","ar":"سياسة صحة الموظفين تضمن أن يبلّغ العاملون عن الأعراض والتشخيصات ويُقيَّدوا أو يُستبعَدوا عند اللزوم، حتى لا يلوّث المرضى الطعام ويسببوا مرضًا منقولًا بالغذاء."}},{"cat":"illness","a":3,"q":{"en":"Parasites such as Anisakis are a concern in which type of food?","es":"Los parásitos como el Anisakis son una preocupación en qué tipo de alimento?","ru":"Паразиты, такие как анизакиды, вызывают беспокойство в каком типе пищи?","tr":"Anisakis gibi parazitler hangi tür gıdada endişe kaynağıdır?","hi":"एनिसाकिस जैसे परजीवी किस प्रकार के भोजन में चिंता हैं?","ar":"الطفيليات مثل الأنيساكيس مصدر قلق في أي نوع من الطعام؟"},"o":[{"en":"Fresh bread","es":"Pan fresco","ru":"Свежий хлеб","tr":"Taze ekmek","hi":"ताजी ब्रेड","ar":"الخبز الطازج"},{"en":"Boiled potatoes","es":"Papas hervidas","ru":"Варёный картофель","tr":"Haşlanmış patates","hi":"उबले आलू","ar":"البطاطس المسلوقة"},{"en":"Pasteurized milk","es":"Leche pasteurizada","ru":"Пастеризованное молоко","tr":"Pastörize süt","hi":"पाश्चराइज्ड दूध","ar":"الحليب المبستر"},{"en":"Raw or undercooked fish","es":"Pescado crudo o poco cocido","ru":"Сырая или недоготовленная рыба","tr":"Çiğ veya az pişmiş balık","hi":"कच्ची या अधपकी मछली","ar":"السمك النيئ أو غير المطهو جيدًا"}],"e":{"en":"Parasites like Anisakis are associated with raw or undercooked fish. Cooking to required temperatures or freezing fish under approved conditions destroys these parasites.","es":"Los parásitos como el Anisakis se asocian con pescado crudo o poco cocido. Cocinar a las temperaturas requeridas o congelar el pescado bajo condiciones aprobadas destruye estos parásitos.","ru":"Паразиты, как анизакиды, связаны с сырой или недоготовленной рыбой. Готовка до нужных температур или заморозка рыбы по одобренным условиям уничтожает этих паразитов.","tr":"Anisakis gibi parazitler çiğ ya da az pişmiş balıkla ilişkilidir. Gereken sıcaklıklara pişirmek ya da balığı onaylı koşullarda dondurmak bu parazitleri yok eder.","hi":"एनिसाकिस जैसे परजीवी कच्ची या अधपकी मछली से जुड़े हैं। आवश्यक तापमान तक पकाना या स्वीकृत शर्तों के तहत मछली जमाना इन परजीवियों को नष्ट करता है।","ar":"ترتبط طفيليات مثل الأنيساكيس بالسمك النيئ أو غير المطهو جيدًا. الطهي إلى الدرجات المطلوبة أو تجميد السمك وفق شروط معتمدة يقضي على هذه الطفيليات."}},{"cat":"illness","a":0,"q":{"en":"A restaurant serves mainly a general, healthy population. A worker reports a persistent cough only. Is this a reportable illness symptom under the Food Code?","es":"Un restaurante sirve principalmente a población general y sana. Un trabajador reporta solo tos persistente. ¿Es este un síntoma de enfermedad de declaración obligatoria según el Código?","ru":"Ресторан обслуживает в основном здоровое население. Работник сообщает только о стойком кашле. Является ли это симптомом, подлежащим отчётности по Кодексу?","tr":"Bir restoran esas olarak genel, sağlıklı bir nüfusa hizmet veriyor. Bir çalışan yalnızca inatçı bir öksürük bildiriyor. Bu, Gıda Kanunu'na göre bildirimi gereken bir hastalık belirtisi midir?","hi":"एक रेस्तरां मुख्य रूप से सामान्य, स्वस्थ आबादी की सेवा करता है। एक कर्मचारी केवल लगातार खांसी की रिपोर्ट करता है। क्या यह फूड कोड के तहत रिपोर्ट-योग्य बीमारी लक्षण है?","ar":"مطعم يخدم أساسًا فئة عامة سليمة. يبلّغ عامل عن سعال مستمر فقط. هل هذا عرض مرض واجب الإبلاغ وفق قانون الغذاء؟"},"o":[{"en":"No; cough alone is not one of the specific reportable symptoms","es":"No; la tos por sí sola no es uno de los síntomas de declaración específicos","ru":"Нет; один кашель не входит в конкретные симптомы, подлежащие отчётности","tr":"Hayır; tek başına öksürük, belirli bildirilen belirtilerden biri değildir","hi":"नहीं; अकेले खांसी विशिष्ट रिपोर्ट-योग्य लक्षणों में से एक नहीं है","ar":"لا؛ السعال وحده ليس من الأعراض المحددة الواجب الإبلاغ عنها"},{"en":"Yes; all coughs require exclusion","es":"Sí; toda tos exige exclusión","ru":"Да; любой кашель требует отстранения","tr":"Evet; her öksürük uzaklaştırma gerektirir","hi":"हां; सभी खांसी बहिष्करण की आवश्यकता होती है","ar":"نعم؛ كل سعال يتطلب الاستبعاد"},{"en":"Yes; a cough always means Norovirus","es":"Sí; una tos siempre significa Norovirus","ru":"Да; кашель всегда означает норовирус","tr":"Evet; öksürük her zaman Norovirüs demektir","hi":"हां; खांसी का हमेशा अर्थ नोरोवायरस है","ar":"نعم؛ السعال يعني دائمًا نوروفيروس"},{"en":"Yes; a cough requires reporting to the health department","es":"Sí; una tos requiere notificar al departamento de salud","ru":"Да; кашель требует уведомления органов здравоохранения","tr":"Evet; öksürük sağlık müdürlüğüne bildirim gerektirir","hi":"हां; खांसी स्वास्थ्य विभाग को रिपोर्ट करने की आवश्यकता है","ar":"نعم؛ السعال يتطلب إبلاغ إدارة الصحة"}],"e":{"en":"The Food Code's specific reportable symptoms are vomiting, diarrhea, jaundice, sore throat with fever, and infected wounds. A simple cough is not on that list, though good hygiene still applies.","es":"Los síntomas de declaración específicos del Código son vómito, diarrea, ictericia, dolor de garganta con fiebre y heridas infectadas. Una tos simple no está en esa lista, aunque la buena higiene sigue aplicando.","ru":"Конкретные симптомы по Кодексу: рвота, диарея, желтуха, боль в горле с лихорадкой и инфицированные раны. Простой кашель в этот список не входит, хотя гигиена всё равно нужна.","tr":"Gıda Kanunu'nun belirli bildirilecek belirtileri: kusma, ishal, sarılık, ateşli boğaz ağrısı ve enfekte yaralar. Basit bir öksürük bu listede yoktur; yine de iyi hijyen geçerlidir.","hi":"फूड कोड के विशिष्ट रिपोर्ट-योग्य लक्षण हैं उल्टी, दस्त, पीलिया, बुखार के साथ गले में खराश, और संक्रमित घाव। साधारण खांसी उस सूची में नहीं है, हालांकि अच्छी स्वच्छता फिर भी लागू होती है।","ar":"الأعراض المحددة الواجب الإبلاغ عنها في القانون هي القيء والإسهال واليرقان والتهاب الحلق مع الحمى والجروح الملتهبة. السعال البسيط ليس ضمنها، وإن بقيت النظافة الجيدة مطلوبة."}},{"cat":"illness","a":1,"q":{"en":"Which action helps a manager verify an employee is well enough to safely handle food after illness?","es":"¿Qué acción ayuda a un gerente a verificar que un empleado está lo bastante bien para manipular alimentos con seguridad tras una enfermedad?","ru":"Какое действие помогает менеджеру убедиться, что работник достаточно здоров, чтобы безопасно работать с пищей после болезни?","tr":"Bir yöneticinin, hastalıktan sonra bir çalışanın gıdayı güvenle işleyecek kadar iyi olduğunu doğrulamasına hangi eylem yardımcı olur?","hi":"कौन-सी कार्रवाई एक प्रबंधक को यह सत्यापित करने में मदद करती है कि एक कर्मचारी बीमारी के बाद भोजन को सुरक्षित रूप से संभालने के लिए पर्याप्त स्वस्थ है?","ar":"أي إجراء يساعد المدير على التحقق من أن الموظف بصحة كافية للتعامل مع الطعام بأمان بعد المرض؟"},"o":[{"en":"Assuming they are fine if they show up","es":"Suponer que están bien si se presentan","ru":"Предположить, что всё в порядке, раз он пришёл","tr":"Gelirlerse iyi olduklarını varsaymak","hi":"मान लेना कि वे ठीक हैं यदि वे आते हैं","ar":"افتراض أنهم بخير إذا حضروا"},{"en":"Following the employee health policy and required symptom-free or clearance criteria","es":"Seguir la política de salud y los criterios requeridos de estar sin síntomas o de alta","ru":"Следовать политике здоровья и требуемым критериям отсутствия симптомов или допуска","tr":"Çalışan sağlığı politikasını ve gereken belirtisizlik ya da onay ölçütlerini uygulamak","hi":"कर्मचारी स्वास्थ्य नीति और आवश्यक लक्षण-मुक्त या मंजूरी मानदंडों का पालन","ar":"اتباع سياسة صحة الموظفين ومعايير خلوّ الأعراض أو التصريح المطلوبة"},{"en":"Letting coworkers vote","es":"Dejar que los compañeros voten","ru":"Позволить коллегам проголосовать","tr":"İş arkadaşlarının oylamasına bırakmak","hi":"सहकर्मियों को वोट देने देना","ar":"ترك القرار لتصويت الزملاء"},{"en":"Checking their uniform is clean","es":"Verificar que su uniforme esté limpio","ru":"Проверить, чиста ли форма","tr":"Üniformalarının temiz olduğunu kontrol etmek","hi":"जांचना कि उनकी वर्दी साफ है","ar":"التحقق من نظافة زيّهم"}],"e":{"en":"Managers rely on the written employee health policy, which spells out when workers can return, such as being symptom-free for 24 hours or having regulatory clearance for a Big 6 illness.","es":"Los gerentes se apoyan en la política escrita de salud, que indica cuándo pueden volver, como estar 24 horas sin síntomas o tener alta reguladora para una enfermedad de los Big 6.","ru":"Менеджеры опираются на письменную политику здоровья, где указано, когда работник может вернуться: например, 24 часа без симптомов или допуск регулятора при болезни из «Большой шестёрки».","tr":"Yöneticiler, çalışanların ne zaman dönebileceğini belirten yazılı sağlık politikasına dayanır; örneğin 24 saat belirtisizlik ya da Büyük 6 hastalığı için düzenleyici onay.","hi":"प्रबंधक लिखित कर्मचारी स्वास्थ्य नीति पर निर्भर करते हैं, जो बताती है कि कर्मचारी कब लौट सकते हैं, जैसे 24 घंटे लक्षण-मुक्त होना या बिग 6 बीमारी के लिए नियामक मंजूरी होना।","ar":"يعتمد المديرون على سياسة صحة الموظفين المكتوبة التي تحدد متى يعودون، مثل خلوّ الأعراض 24 ساعة أو الحصول على تصريح تنظيمي لمرض من الستة الكبار."}},{"cat":"illness","a":2,"q":{"en":"Why is a very low 'infectious dose' important for pathogens like Shigella and Norovirus?","es":"¿Por qué es importante una 'dosis infecciosa' muy baja para patógenos como Shigella y Norovirus?","ru":"Почему очень низкая «инфицирующая доза» важна для патогенов вроде шигеллы и норовируса?","tr":"Shigella ve Norovirüs gibi patojenler için çok düşük bir 'bulaştırıcı doz' neden önemlidir?","hi":"शिगेला और नोरोवायरस जैसे रोगाणुओं के लिए बहुत कम 'संक्रामक खुराक' क्यों महत्वपूर्ण है?","ar":"لماذا تُعدّ 'الجرعة المُعدية' المنخفضة جدًا مهمة لمسببات مثل الشيغيلا ونوروفيروس؟"},"o":[{"en":"It means the food tastes different","es":"Significa que la comida sabe diferente","ru":"Это значит, что еда на вкус другая","tr":"Gıdanın farklı tat vermesi demektir","hi":"इसका अर्थ है कि भोजन का स्वाद अलग है","ar":"يعني أن طعم الطعام يختلف"},{"en":"It means cooking always destroys them","es":"Significa que cocinar siempre los destruye","ru":"Это значит, что готовка всегда их уничтожает","tr":"Pişirmenin onları her zaman yok ettiği anlamına gelir","hi":"इसका अर्थ है कि पकाना हमेशा उन्हें नष्ट करता है","ar":"يعني أن الطهي يدمرها دائمًا"},{"en":"Just a few organisms can make someone sick, so tiny lapses in hygiene matter","es":"Bastan unos pocos organismos para enfermar, por eso importan los pequeños descuidos de higiene","ru":"Даже несколько микроорганизмов могут вызвать болезнь, поэтому важны малейшие нарушения гигиены","tr":"Birkaç organizma bile hastalık yapabilir; bu yüzden en küçük hijyen ihmalleri önemlidir","hi":"बस कुछ जीव किसी को बीमार कर सकते हैं, इसलिए स्वच्छता में छोटी चूक मायने रखती है","ar":"يكفي عدد قليل من الكائنات لإمراض الشخص، لذا فحتى الهفوات الصغيرة في النظافة مهمة"},{"en":"It means they cannot spread between people","es":"Significa que no pueden propagarse entre personas","ru":"Это значит, что они не передаются между людьми","tr":"İnsanlar arasında yayılamayacakları anlamına gelir","hi":"इसका अर्थ है कि वे लोगों के बीच नहीं फैल सकते","ar":"يعني أنها لا تنتقل بين الناس"}],"e":{"en":"A low infectious dose means only a few pathogen cells or viral particles can cause illness, so even a small hygiene failure, like skipping handwashing, can trigger an outbreak.","es":"Una dosis infecciosa baja significa que bastan pocas células o partículas virales para enfermar, así que hasta un pequeño fallo de higiene, como no lavarse las manos, puede causar un brote.","ru":"Низкая инфицирующая доза означает, что для болезни достаточно немногих клеток или вирусных частиц, поэтому даже малое нарушение гигиены, например пропуск мытья рук, может вызвать вспышку.","tr":"Düşük bulaştırıcı doz, hastalık için yalnızca birkaç patojen hücresi ya da virüs parçacığının yeterli olması demektir; bu yüzden el yıkamayı atlamak gibi küçük bir hijyen hatası bile salgın başlatabilir.","hi":"कम संक्रामक खुराक का अर्थ है कि बीमारी के लिए केवल कुछ रोगाणु कोशिकाएं या वायरल कण पर्याप्त हैं, इसलिए हाथ धोना छोड़ने जैसी छोटी स्वच्छता विफलता भी प्रकोप ट्रिगर कर सकती है।","ar":"الجرعة المُعدية المنخفضة تعني أن عددًا قليلًا من الخلايا أو الجزيئات الفيروسية يكفي للإمراض، لذا حتى هفوة نظافة صغيرة، كإهمال غسل اليدين، قد تُشعل تفشيًا."}},{"cat":"cleaning","a":3,"q":{"en":"What does 'sanitizing' a food-contact surface accomplish?","es":"¿Qué logra 'desinfectar' una superficie de contacto con alimentos?","ru":"Что достигается «санитарной обработкой» поверхности контакта с пищей?","tr":"Bir gıda temas yüzeyini 'dezenfekte etmek' neyi sağlar?","hi":"भोजन-संपर्क सतह को 'सैनिटाइज़' करने से क्या हासिल होता है?","ar":"ماذا يحقق 'تعقيم' سطح ملامسة الطعام؟"},"o":[{"en":"It removes visible food and grease","es":"Elimina comida y grasa visibles","ru":"Удаляет видимую пищу и жир","tr":"Görünen gıda ve yağı giderir","hi":"दृश्य भोजन और चिकनाई हटाता है","ar":"يزيل الطعام والدهون المرئية"},{"en":"It makes the surface shiny","es":"Hace la superficie brillante","ru":"Делает поверхность блестящей","tr":"Yüzeyi parlak yapar","hi":"सतह को चमकदार बनाता है","ar":"يجعل السطح لامعًا"},{"en":"It sharpens knives","es":"Afila los cuchillos","ru":"Затачивает ножи","tr":"Bıçakları biler","hi":"चाकुओं को तेज करता है","ar":"يشحذ السكاكين"},{"en":"It reduces pathogens to safe levels","es":"Reduce los patógenos a niveles seguros","ru":"Снижает количество патогенов до безопасного уровня","tr":"Patojenleri güvenli düzeye indirir","hi":"रोगाणुओं को सुरक्षित स्तर तक कम करता है","ar":"يقلل المسببات إلى مستويات آمنة"}],"e":{"en":"Cleaning removes visible soil; sanitizing then reduces the remaining pathogens on a clean surface to safe levels. Both steps are needed, cleaning first, then sanitizing.","es":"Limpiar elimina la suciedad visible; desinfectar luego reduce los patógenos restantes en una superficie limpia a niveles seguros. Ambos pasos son necesarios: primero limpiar, luego desinfectar.","ru":"Мытьё удаляет видимую грязь; санобработка затем снижает оставшиеся патогены на чистой поверхности до безопасного уровня. Нужны оба этапа: сначала мытьё, затем санобработка.","tr":"Temizlik görünen kiri giderir; dezenfeksiyon ise temiz bir yüzeydeki kalan patojenleri güvenli düzeye indirir. Önce temizlik, sonra dezenfeksiyon; ikisi de gereklidir.","hi":"सफाई दृश्य गंदगी हटाती है; सैनिटाइज़िंग फिर साफ सतह पर बचे रोगाणुओं को सुरक्षित स्तर तक कम करती है। दोनों चरण आवश्यक हैं, पहले सफाई, फिर सैनिटाइज़िंग।","ar":"التنظيف يزيل الأوساخ المرئية؛ ثم التعقيم يقلل المسببات المتبقية على سطح نظيف إلى مستويات آمنة. كلا الخطوتين مطلوبتان، التنظيف أولًا ثم التعقيم."}},{"cat":"cleaning","a":0,"q":{"en":"What is the correct order of sinks in a three-compartment sink setup?","es":"¿Cuál es el orden correcto de los fregaderos en un fregadero de tres compartimentos?","ru":"Каков правильный порядок отсеков в трёхсекционной раковине?","tr":"Üç bölmeli evye düzeninde bölmelerin doğru sırası nedir?","hi":"तीन-कम्पार्टमेंट सिंक व्यवस्था में सिंक का सही क्रम क्या है?","ar":"ما الترتيب الصحيح للأحواض في نظام الحوض ذي الثلاث حجرات؟"},"o":[{"en":"Wash, rinse, sanitize","es":"Lavar, enjuagar, desinfectar","ru":"Мойка, ополаскивание, санобработка","tr":"Yıkama, durulama, dezenfeksiyon","hi":"धोना, कुल्ला, सैनिटाइज़","ar":"غسل، شطف، تعقيم"},{"en":"Rinse, wash, sanitize","es":"Enjuagar, lavar, desinfectar","ru":"Ополаскивание, мойка, санобработка","tr":"Durulama, yıkama, dezenfeksiyon","hi":"कुल्ला, धोना, सैनिटाइज़","ar":"شطف، غسل، تعقيم"},{"en":"Sanitize, wash, rinse","es":"Desinfectar, lavar, enjuagar","ru":"Санобработка, мойка, ополаскивание","tr":"Dezenfeksiyon, yıkama, durulama","hi":"सैनिटाइज़, धोना, कुल्ला","ar":"تعقيم، غسل، شطف"},{"en":"Wash, sanitize, rinse","es":"Lavar, desinfectar, enjuagar","ru":"Мойка, санобработка, ополаскивание","tr":"Yıkama, dezenfeksiyon, durulama","hi":"धोना, सैनिटाइज़, कुल्ला","ar":"غسل، تعقيم، شطف"}],"e":{"en":"The order is wash (hot soapy water), rinse (clean water), then sanitize (sanitizer solution), followed by air drying. Scrape and pre-rinse items before washing.","es":"El orden es lavar (agua caliente con jabón), enjuagar (agua limpia) y desinfectar (solución desinfectante), seguido de secado al aire. Raspe y preenjuague antes de lavar.","ru":"Порядок: мойка (горячая мыльная вода), ополаскивание (чистая вода), затем санобработка (раствор санитайзера), после чего сушка на воздухе. Перед мойкой соскоблить и предварительно ополоснуть.","tr":"Sıra: yıkama (sıcak sabunlu su), durulama (temiz su), sonra dezenfeksiyon (dezenfektan solüsyonu) ve ardından havada kurutma. Yıkamadan önce kazıyıp ön durulama yapın.","hi":"क्रम है धोना (गर्म साबुन का पानी), कुल्ला (साफ पानी), फिर सैनिटाइज़ (सैनिटाइज़र घोल), उसके बाद हवा में सुखाना। धोने से पहले खुरचें और पूर्व-कुल्ला करें।","ar":"الترتيب هو الغسل (ماء ساخن بالصابون)، الشطف (ماء نظيف)، ثم التعقيم (محلول معقّم)، يليه التجفيف بالهواء. اكشط وأجرِ شطفًا أوليًا قبل الغسل."}},{"cat":"cleaning","a":1,"q":{"en":"How should washed and sanitized dishes be dried?","es":"¿Cómo deben secarse los platos lavados y desinfectados?","ru":"Как нужно сушить вымытую и продезинфицированную посуду?","tr":"Yıkanıp dezenfekte edilen bulaşıklar nasıl kurutulmalı?","hi":"धुले और सैनिटाइज़ किए बर्तनों को कैसे सुखाना चाहिए?","ar":"كيف يجب تجفيف الأطباق المغسولة والمعقمة؟"},"o":[{"en":"With a shared kitchen towel","es":"Con una toalla de cocina compartida","ru":"Общим кухонным полотенцем","tr":"Ortak bir mutfak havlusuyla","hi":"साझा रसोई तौलिये से","ar":"بمنشفة مطبخ مشتركة"},{"en":"Air dried completely","es":"Secados al aire por completo","ru":"Полностью на воздухе","tr":"Tamamen havada kurutularak","hi":"पूरी तरह हवा में सुखाकर","ar":"تُجفَّف بالهواء تمامًا"},{"en":"Stacked wet to save time","es":"Apilados mojados para ahorrar tiempo","ru":"Сложены мокрыми, чтобы сэкономить время","tr":"Zaman kazanmak için ıslak istiflenerek","hi":"समय बचाने के लिए गीले ढेर करके","ar":"تُكدَّس مبللة لتوفير الوقت"},{"en":"Wiped with an apron","es":"Secados con un delantal","ru":"Вытерты фартуком","tr":"Bir önlükle silinerek","hi":"एप्रन से पोंछकर","ar":"تُمسح بمريلة"}],"e":{"en":"Dishes must air dry completely. Towel-drying can recontaminate them, and stacking or storing wet items lets bacteria grow in trapped moisture.","es":"Los platos deben secarse al aire por completo. Secar con toalla puede recontaminarlos, y apilar o guardar mojado permite que crezcan bacterias en la humedad atrapada.","ru":"Посуда должна полностью высохнуть на воздухе. Вытирание полотенцем может её заново загрязнить, а хранение мокрой позволяет бактериям расти во влаге.","tr":"Bulaşıklar tamamen havada kurumalıdır. Havluyla kurulamak yeniden kirletebilir; ıslak istiflemek ya da saklamak, hapsolan nemde bakteri üremesine izin verir.","hi":"बर्तनों को पूरी तरह हवा में सुखाना चाहिए। तौलिये से सुखाना उन्हें फिर से दूषित कर सकता है, और गीला ढेर करना या रखना फंसी नमी में बैक्टीरिया को बढ़ने देता है।","ar":"يجب أن تجف الأطباق بالهواء تمامًا. التجفيف بالمنشفة قد يعيد تلويثها، وتكديس أو تخزين الأصناف مبللة يسمح بنمو البكتيريا في الرطوبة المحبوسة."}},{"cat":"cleaning","a":2,"q":{"en":"For a chlorine (bleach) sanitizer solution, which concentration range is commonly used for food-contact surfaces?","es":"Para una solución desinfectante de cloro (lejía), ¿qué rango de concentración se usa comúnmente en superficies de contacto?","ru":"Для хлорного (отбеливающего) санитайзера какой диапазон концентрации обычно используется для поверхностей контакта с пищей?","tr":"Klor (çamaşır suyu) dezenfektan solüsyonu için gıda temas yüzeylerinde yaygın kullanılan konsantrasyon aralığı hangisidir?","hi":"क्लोरीन (ब्लीच) सैनिटाइज़र घोल के लिए, भोजन-संपर्क सतहों पर आमतौर पर कौन-सी सांद्रता सीमा उपयोग होती है?","ar":"لمحلول معقّم بالكلور (المبيّض)، أي نطاق تركيز يُستخدم عادةً لأسطح ملامسة الطعام؟"},"o":[{"en":"5 to 10 ppm","es":"5 a 10 ppm","ru":"5–10 ppm","tr":"5–10 ppm","hi":"5 से 10 ppm","ar":"5 إلى 10 جزء بالمليون"},{"en":"500 to 1000 ppm","es":"500 a 1000 ppm","ru":"500–1000 ppm","tr":"500–1000 ppm","hi":"500 से 1000 ppm","ar":"500 إلى 1000 جزء بالمليون"},{"en":"50 to 100 ppm","es":"50 a 100 ppm","ru":"50–100 ppm","tr":"50–100 ppm","hi":"50 से 100 ppm","ar":"50 إلى 100 جزء بالمليون"},{"en":"2000 to 3000 ppm","es":"2000 a 3000 ppm","ru":"2000–3000 ppm","tr":"2000–3000 ppm","hi":"2000 से 3000 ppm","ar":"2000 إلى 3000 جزء بالمليون"}],"e":{"en":"Chlorine sanitizer is commonly used at about 50 to 100 ppm for food-contact surfaces. Too little is ineffective; too much is unsafe. Always test with a sanitizer test strip.","es":"El desinfectante de cloro se usa comúnmente a unos 50 a 100 ppm en superficies de contacto. Muy poco es ineficaz; demasiado es inseguro. Siempre pruebe con tira de prueba.","ru":"Хлорный санитайзер обычно применяют около 50–100 ppm для поверхностей контакта. Слишком мало — неэффективно; слишком много — небезопасно. Всегда проверяйте тест-полоской.","tr":"Klor dezenfektanı gıda temas yüzeyleri için genellikle yaklaşık 50–100 ppm kullanılır. Az olması etkisiz, fazla olması güvensizdir. Her zaman test şeridiyle ölçün.","hi":"क्लोरीन सैनिटाइज़र आमतौर पर भोजन-संपर्क सतहों के लिए लगभग 50 से 100 ppm पर उपयोग होता है। बहुत कम अप्रभावी है; बहुत अधिक असुरक्षित। हमेशा टेस्ट स्ट्रिप से जांचें।","ar":"يُستخدم معقّم الكلور عادةً بنحو 50 إلى 100 جزء بالمليون لأسطح ملامسة الطعام. القليل جدًا غير فعّال والكثير جدًا غير آمن. اختبر دائمًا بشريط الفحص."}},{"cat":"cleaning","a":3,"q":{"en":"How should the concentration of a sanitizer solution be checked?","es":"¿Cómo debe verificarse la concentración de una solución desinfectante?","ru":"Как нужно проверять концентрацию раствора санитайзера?","tr":"Bir dezenfektan solüsyonunun konsantrasyonu nasıl kontrol edilmeli?","hi":"सैनिटाइज़र घोल की सांद्रता कैसे जांची जानी चाहिए?","ar":"كيف يجب فحص تركيز محلول المعقّم؟"},"o":[{"en":"By its smell","es":"Por su olor","ru":"По запаху","tr":"Kokusuna göre","hi":"इसकी गंध से","ar":"من رائحته"},{"en":"By its color only","es":"Solo por su color","ru":"Только по цвету","tr":"Yalnızca rengine göre","hi":"केवल इसके रंग से","ar":"من لونه فقط"},{"en":"By how bubbly it is","es":"Por cuántas burbujas hace","ru":"По количеству пены","tr":"Ne kadar köpürdüğüne göre","hi":"यह कितना बुलबुलेदार है इससे","ar":"بمقدار رغوته"},{"en":"With a sanitizer test kit or test strips","es":"Con un kit de prueba o tiras reactivas para desinfectante","ru":"С помощью тест-набора или тест-полосок для санитайзера","tr":"Dezenfektan test kiti veya test şeritleriyle","hi":"सैनिटाइज़र टेस्ट किट या टेस्ट स्ट्रिप से","ar":"بعدّة فحص المعقّم أو شرائط الفحص"}],"e":{"en":"Sanitizer concentration is verified with a test kit or test strips designed for that sanitizer, not by smell or appearance, to confirm it is strong enough but not too strong.","es":"La concentración del desinfectante se verifica con un kit o tiras de prueba para ese desinfectante, no por olor o apariencia, para confirmar que es lo bastante fuerte pero no demasiado.","ru":"Концентрацию санитайзера проверяют тест-набором или тест-полосками для этого санитайзера, а не по запаху или виду, чтобы убедиться, что она достаточная, но не чрезмерная.","tr":"Dezenfektan konsantrasyonu, o dezenfektana özel test kiti veya test şeritleriyle doğrulanır; koku ya da görünüşle değil. Böylece yeterince güçlü ama fazla değil olduğu teyit edilir.","hi":"सैनिटाइज़र सांद्रता उस सैनिटाइज़र के लिए बने टेस्ट किट या टेस्ट स्ट्रिप से जांची जाती है, गंध या दिखावट से नहीं, ताकि पुष्टि हो कि यह पर्याप्त मजबूत है पर बहुत अधिक नहीं।","ar":"يُتحقق من تركيز المعقّم بعدّة فحص أو شرائط فحص مخصصة لذلك المعقّم، لا بالرائحة أو المظهر، للتأكد من أنه قوي بما يكفي لكن ليس مفرطًا."}},{"cat":"cleaning","a":0,"q":{"en":"When not in use, wet wiping cloths should be stored:","es":"Cuando no se usan, los paños húmedos de limpieza deben guardarse:","ru":"Когда не используются, влажные протирочные тряпки нужно хранить:","tr":"Kullanılmadığında ıslak silme bezleri nasıl saklanmalı:","hi":"उपयोग में न होने पर, गीले पोंछने वाले कपड़े रखे जाने चाहिए:","ar":"عند عدم الاستخدام، يجب تخزين أقمشة المسح المبللة:"},"o":[{"en":"Submerged in sanitizer solution","es":"Sumergidos en solución desinfectante","ru":"Погружёнными в раствор санитайзера","tr":"Dezenfektan solüsyonuna batırılmış olarak","hi":"सैनिटाइज़र घोल में डुबोकर","ar":"مغمورة في محلول معقّم"},{"en":"Wadded up on the counter","es":"Amontonados en la barra","ru":"Скомканными на столе","tr":"Tezgahta buruşturulmuş olarak","hi":"काउंटर पर मुड़े हुए","ar":"ملفوفة على الطاولة"},{"en":"In an apron pocket","es":"En el bolsillo del delantal","ru":"В кармане фартука","tr":"Önlük cebinde","hi":"एप्रन की जेब में","ar":"في جيب المريلة"},{"en":"Hung over the faucet","es":"Colgados sobre el grifo","ru":"Повешенными на кран","tr":"Muslugun üzerine asılı","hi":"नल के ऊपर लटकाकर","ar":"معلّقة على الصنبور"}],"e":{"en":"Between uses, wet wiping cloths are kept fully submerged in a properly mixed sanitizer solution. Leaving them out lets bacteria multiply and spreads contamination when reused.","es":"Entre usos, los paños húmedos se mantienen totalmente sumergidos en solución desinfectante bien mezclada. Dejarlos fuera permite que las bacterias se multipliquen y esparce contaminación.","ru":"Между использованиями влажные тряпки держат полностью погружёнными в правильно приготовленный раствор санитайзера. Иначе бактерии размножаются и распространяют загрязнение при повторном использовании.","tr":"Kullanımlar arasında ıslak bezler, doğru hazırlanmış dezenfektan solüsyonuna tamamen batırılmış tutulur. Dışarıda bırakmak bakterilerin çoğalmasına ve yeniden kullanımda bulaşmaya yol açar.","hi":"उपयोगों के बीच, गीले पोंछने वाले कपड़े ठीक से मिश्रित सैनिटाइज़र घोल में पूरी तरह डूबे रखे जाते हैं। बाहर छोड़ना बैक्टीरिया को बढ़ने देता है और पुन: उपयोग पर दूषण फैलाता है।","ar":"بين الاستخدامات، تُبقى أقمشة المسح المبللة مغمورة كليًا في محلول معقّم محضّر بشكل صحيح. تركها في الخارج يسمح بتكاثر البكتيريا وينشر التلوث عند إعادة الاستخدام."}},{"cat":"cleaning","a":1,"q":{"en":"In a high-temperature (hot water) dishwasher, the final sanitizing rinse must reach at least:","es":"En un lavavajillas de alta temperatura (agua caliente), el enjuague final de desinfección debe alcanzar al menos:","ru":"В высокотемпературной (горячая вода) посудомоечной машине финальное ополаскивание должно достигать не менее:","tr":"Yüksek sıcaklıklı (sıcak su) bulaşık makinesinde son dezenfeksiyon durulaması en az kaç dereceye ulaşmalı:","hi":"उच्च-तापमान (गर्म पानी) डिशवॉशर में, अंतिम सैनिटाइज़िंग रिन्स कम से कम पहुंचना चाहिए:","ar":"في غسالة أطباق عالية الحرارة (ماء ساخن)، يجب أن تصل شطفة التعقيم النهائية إلى ما لا يقل عن:"},"o":[{"en":"120°F (49°C)","es":"120°F (49°C)","ru":"120°F (49°C)","tr":"120°F (49°C)","hi":"120°F (49°C)","ar":"120°F (49°C)"},{"en":"180°F (82°C) at the manifold","es":"180°F (82°C) en el colector","ru":"180°F (82°C) на коллекторе","tr":"180°F (82°C) manifoldda","hi":"मैनिफोल्ड पर 180°F (82°C)","ar":"180°F (82°C) عند المشعب"},{"en":"100°F (38°C)","es":"100°F (38°C)","ru":"100°F (38°C)","tr":"100°F (38°C)","hi":"100°F (38°C)","ar":"100°F (38°C)"},{"en":"70°F (21°C)","es":"70°F (21°C)","ru":"70°F (21°C)","tr":"70°F (21°C)","hi":"70°F (21°C)","ar":"70°F (21°C)"}],"e":{"en":"In a high-temperature machine, the final rinse is typically about 180°F (82°C) at the manifold so the dish surface reaches at least 160°F (71°C) to sanitize by heat.","es":"En una máquina de alta temperatura, el enjuague final suele ser de unos 180°F (82°C) en el colector, para que la superficie del plato alcance al menos 160°F (71°C) y se desinfecte por calor.","ru":"В высокотемпературной машине финальное ополаскивание обычно около 180°F (82°C) на коллекторе, чтобы поверхность посуды достигла не менее 160°F (71°C) для санобработки теплом.","tr":"Yüksek sıcaklıklı makinede son durulama genellikle manifoldda yaklaşık 180°F'tir (82°C); böylece tabak yüzeyi ısıyla dezenfekte olmak için en az 160°F'e (71°C) ulaşır.","hi":"उच्च-तापमान मशीन में, अंतिम रिन्स आमतौर पर मैनिफोल्ड पर लगभग 180°F (82°C) होता है ताकि बर्तन की सतह ऊष्मा से सैनिटाइज़ होने के लिए कम से कम 160°F (71°C) तक पहुंचे।","ar":"في الآلة عالية الحرارة، تكون شطفة النهاية عادةً نحو 180°F (82°C) عند المشعب حتى يصل سطح الطبق إلى 160°F (71°C) على الأقل للتعقيم بالحرارة."}},{"cat":"cleaning","a":2,"q":{"en":"How should cleaning chemicals be stored in a food establishment?","es":"¿Cómo deben almacenarse los químicos de limpieza en un establecimiento de alimentos?","ru":"Как нужно хранить чистящие средства в пищевом заведении?","tr":"Bir gıda işletmesinde temizlik kimyasalları nasıl saklanmalı?","hi":"एक खाद्य प्रतिष्ठान में सफाई रसायन कैसे संग्रहीत किए जाने चाहिए?","ar":"كيف يجب تخزين مواد التنظيف في منشأة طعام؟"},"o":[{"en":"On a shelf above the prep table","es":"En un estante sobre la mesa de preparación","ru":"На полке над разделочным столом","tr":"Hazırlık masasının üstündeki rafta","hi":"प्रेप टेबल के ऊपर शेल्फ पर","ar":"على رف فوق طاولة التحضير"},{"en":"Next to the food in the cooler","es":"Junto a la comida en el refrigerador","ru":"Рядом с пищей в холодильнике","tr":"Soğutucuda gıdanın yanında","hi":"कूलर में भोजन के बगल में","ar":"بجانب الطعام في المبرّد"},{"en":"In a designated area away from and below food and food equipment","es":"En un área designada, lejos y debajo de alimentos y equipo","ru":"В отведённом месте, вдали и ниже пищи и оборудования","tr":"Gıda ve ekipmandan uzak ve altında, ayrılmış bir alanda","hi":"भोजन और उपकरण से दूर और नीचे एक निर्दिष्ट क्षेत्र में","ar":"في منطقة مخصصة بعيدًا وأسفل الطعام ومعدات الطعام"},{"en":"Inside empty food containers","es":"Dentro de recipientes de alimentos vacíos","ru":"Внутри пустых пищевых ёмкостей","tr":"Boş gıda kaplarının içinde","hi":"खाली भोजन बर्तनों के अंदर","ar":"داخل أوعية طعام فارغة"}],"e":{"en":"Chemicals are stored in a designated area, separate from and below food, utensils, and equipment, so they cannot spill or drip onto food and cause chemical contamination.","es":"Los químicos se guardan en un área designada, separada y debajo de alimentos, utensilios y equipo, para que no goteen ni derramen sobre la comida y causen contaminación química.","ru":"Химикаты хранят в отведённом месте, отдельно и ниже пищи, инвентаря и оборудования, чтобы они не пролились и не капнули на пищу, вызвав химическое загрязнение.","tr":"Kimyasallar; gıda, alet ve ekipmandan ayrı ve altında, ayrılmış bir alanda saklanır; böylece gıdaya dökülüp damlayarak kimyasal bulaşma yapamaz.","hi":"रसायन एक निर्दिष्ट क्षेत्र में, भोजन, बर्तनों और उपकरण से अलग और नीचे रखे जाते हैं, ताकि वे भोजन पर गिर या टपक न सकें और रासायनिक दूषण न करें।","ar":"تُخزَّن المواد الكيميائية في منطقة مخصصة، منفصلة وأسفل الطعام والأدوات والمعدات، حتى لا تنسكب أو تتنقط على الطعام فتسبب تلوثًا كيميائيًا."}},{"cat":"cleaning","a":3,"q":{"en":"Before a food-contact surface can be sanitized effectively, what must be done first?","es":"Antes de poder desinfectar eficazmente una superficie de contacto, ¿qué debe hacerse primero?","ru":"Прежде чем поверхность контакта можно эффективно продезинфицировать, что нужно сделать сначала?","tr":"Bir gıda temas yüzeyi etkili şekilde dezenfekte edilmeden önce ilk olarak ne yapılmalı?","hi":"एक भोजन-संपर्क सतह को प्रभावी ढंग से सैनिटाइज़ करने से पहले, पहले क्या किया जाना चाहिए?","ar":"قبل أن يُعقَّم سطح ملامسة الطعام بفعالية، ماذا يجب فعله أولًا؟"},"o":[{"en":"Warm it up","es":"Calentarla","ru":"Нагреть её","tr":"Onu ısıtmak","hi":"इसे गर्म करना","ar":"تسخينه"},{"en":"Rinse it with sanitizer","es":"Enjuagarla con desinfectante","ru":"Ополоснуть её санитайзером","tr":"Dezenfektanla durulamak","hi":"इसे सैनिटाइज़र से धोना","ar":"شطفه بالمعقّم"},{"en":"Wax it","es":"Encerarla","ru":"Натереть воском","tr":"Cilalamak","hi":"इस पर मोम लगाना","ar":"تلميعه بالشمع"},{"en":"Clean it to remove food and grease","es":"Limpiarla para eliminar comida y grasa","ru":"Вымыть её, чтобы удалить пищу и жир","tr":"Gıda ve yağı gidermek için temizlemek","hi":"भोजन और चिकनाई हटाने के लिए इसे साफ करना","ar":"تنظيفه لإزالة الطعام والدهون"}],"e":{"en":"A surface must be cleaned first, because leftover food and grease shield pathogens and neutralize sanitizer. Only a clean surface can be effectively sanitized.","es":"Una superficie debe limpiarse primero, porque los restos de comida y grasa protegen a los patógenos y neutralizan el desinfectante. Solo una superficie limpia puede desinfectarse eficazmente.","ru":"Поверхность сначала нужно вымыть, так как остатки пищи и жира защищают патогены и нейтрализуют санитайзер. Эффективно дезинфицировать можно только чистую поверхность.","tr":"Yüzey önce temizlenmelidir; çünkü artık gıda ve yağ patojenleri korur ve dezenfektanı etkisizleştirir. Yalnızca temiz bir yüzey etkili dezenfekte edilebilir.","hi":"सतह को पहले साफ करना चाहिए, क्योंकि बचा भोजन और चिकनाई रोगाणुओं को ढालते हैं और सैनिटाइज़र को निष्क्रिय करते हैं। केवल साफ सतह प्रभावी रूप से सैनिटाइज़ की जा सकती है।","ar":"يجب تنظيف السطح أولًا، لأن بقايا الطعام والدهون تحمي المسببات وتُبطل مفعول المعقّم. السطح النظيف فقط يمكن تعقيمه بفعالية."}},{"cat":"cleaning","a":0,"q":{"en":"Which factor does NOT affect how well a chemical sanitizer works?","es":"¿Qué factor NO afecta qué tan bien funciona un desinfectante químico?","ru":"Какой фактор НЕ влияет на эффективность химического санитайзера?","tr":"Hangi faktör kimyasal dezenfektanın ne kadar iyi çalıştığını ETKİLEMEZ?","hi":"कौन-सा कारक इस पर प्रभाव नहीं डालता कि रासायनिक सैनिटाइज़र कितनी अच्छी तरह काम करता है?","ar":"أي عامل لا يؤثر على مدى فعالية المعقّم الكيميائي؟"},"o":[{"en":"The color of the bucket","es":"El color del balde","ru":"Цвет ведра","tr":"Kovanın rengi","hi":"बाल्टी का रंग","ar":"لون الدلو"},{"en":"Concentration","es":"La concentración","ru":"Концентрация","tr":"Konsantrasyon","hi":"सांद्रता","ar":"التركيز"},{"en":"Contact time","es":"El tiempo de contacto","ru":"Время контакта","tr":"Temas süresi","hi":"संपर्क समय","ar":"زمن الملامسة"},{"en":"Water temperature","es":"La temperatura del agua","ru":"Температура воды","tr":"Su sıcaklığı","hi":"पानी का तापमान","ar":"درجة حرارة الماء"}],"e":{"en":"Sanitizer effectiveness depends on concentration, contact time, water temperature, water hardness, and pH. The bucket's color has no effect on how the chemical performs.","es":"La eficacia del desinfectante depende de concentración, tiempo de contacto, temperatura y dureza del agua, y pH. El color del balde no afecta el desempeño del químico.","ru":"Эффективность санитайзера зависит от концентрации, времени контакта, температуры и жёсткости воды и pH. Цвет ведра не влияет на работу химиката.","tr":"Dezenfektan etkinliği; konsantrasyon, temas süresi, su sıcaklığı, su sertliği ve pH'a bağlıdır. Kovanın rengi kimyasalın performansını etkilemez.","hi":"सैनिटाइज़र प्रभावशीलता सांद्रता, संपर्क समय, पानी का तापमान, पानी की कठोरता और pH पर निर्भर करती है। बाल्टी का रंग रसायन के प्रदर्शन को प्रभावित नहीं करता।","ar":"تعتمد فعالية المعقّم على التركيز وزمن الملامسة ودرجة حرارة الماء وعسر الماء ودرجة الحموضة. لون الدلو لا يؤثر على أداء المادة."}},{"cat":"cleaning","a":1,"q":{"en":"For a quaternary ammonium (quat) sanitizer, how do you know the correct concentration and contact time?","es":"Para un desinfectante de amonio cuaternario (quat), ¿cómo sabe la concentración y el tiempo de contacto correctos?","ru":"Для санитайзера на основе четвертичного аммония (quat) как узнать правильную концентрацию и время контакта?","tr":"Kuaterner amonyum (quat) dezenfektanı için doğru konsantrasyon ve temas süresini nasıl bilirsiniz?","hi":"क्वाटरनरी अमोनियम (क्वाट) सैनिटाइज़र के लिए, आप सही सांद्रता और संपर्क समय कैसे जानते हैं?","ar":"لمعقّم الأمونيوم الرباعي (كوات)، كيف تعرف التركيز الصحيح وزمن الملامسة؟"},"o":[{"en":"Guess based on the smell","es":"Adivinar por el olor","ru":"Угадать по запаху","tr":"Kokusuna göre tahmin etmek","hi":"गंध के आधार पर अनुमान लगाएं","ar":"التخمين حسب الرائحة"},{"en":"Follow the manufacturer's label directions","es":"Seguir las instrucciones de la etiqueta del fabricante","ru":"Следовать инструкциям на этикетке производителя","tr":"Üreticinin etiket talimatlarını izlemek","hi":"निर्माता के लेबल निर्देशों का पालन करें","ar":"اتباع تعليمات ملصق الشركة المصنّعة"},{"en":"Always use the same as chlorine","es":"Usar siempre lo mismo que el cloro","ru":"Всегда использовать как для хлора","tr":"Her zaman klorla aynısını kullanmak","hi":"हमेशा क्लोरीन के समान उपयोग करें","ar":"استخدام نفس الكلور دائمًا"},{"en":"Use as much as possible","es":"Usar tanto como sea posible","ru":"Использовать как можно больше","tr":"Mümkün olduğunca çok kullanmak","hi":"जितना संभव हो उतना उपयोग करें","ar":"استخدام أكبر قدر ممكن"}],"e":{"en":"Quat sanitizer concentration and contact time vary by product, so always follow the manufacturer's label directions and verify with the matching test strips.","es":"La concentración y el tiempo de contacto del quat varían según el producto, así que siga siempre la etiqueta del fabricante y verifique con las tiras de prueba correspondientes.","ru":"Концентрация и время контакта quat зависят от продукта, поэтому всегда следуйте инструкциям на этикетке и проверяйте соответствующими тест-полосками.","tr":"Quat konsantrasyonu ve temas süresi ürüne göre değişir; bu yüzden her zaman üretici etiketini izleyin ve uygun test şeritleriyle doğrulayın.","hi":"क्वाट सांद्रता और संपर्क समय उत्पाद के अनुसार भिन्न होते हैं, इसलिए हमेशा निर्माता के लेबल निर्देशों का पालन करें और मेल खाती टेस्ट स्ट्रिप से जांचें।","ar":"يختلف تركيز الكوات وزمن الملامسة حسب المنتج، لذا اتبع دائمًا تعليمات ملصق الشركة وتحقق بشرائط الفحص المطابقة."}},{"cat":"cleaning","a":2,"q":{"en":"How often must a food-contact surface be cleaned and sanitized if it is used continuously with the same food for a long shift?","es":"¿Con qué frecuencia debe limpiarse y desinfectarse una superficie de contacto si se usa continuamente con el mismo alimento durante un turno largo?","ru":"Как часто нужно мыть и дезинфицировать поверхность контакта, если она непрерывно используется с одним продуктом в течение долгой смены?","tr":"Uzun bir vardiyada aynı gıdayla sürekli kullanılırsa gıda temas yüzeyi ne sıklıkta temizlenip dezenfekte edilmeli?","hi":"यदि एक भोजन-संपर्क सतह लंबी शिफ्ट में एक ही भोजन के साथ लगातार उपयोग होती है तो इसे कितनी बार साफ और सैनिटाइज़ किया जाना चाहिए?","ar":"كم مرة يجب تنظيف وتعقيم سطح ملامسة الطعام إذا استُخدم باستمرار مع الطعام نفسه خلال نوبة طويلة؟"},"o":[{"en":"Once at the end of the shift","es":"Una vez al final del turno","ru":"Один раз в конце смены","tr":"Vardiya sonunda bir kez","hi":"शिफ्ट के अंत में एक बार","ar":"مرة واحدة في نهاية النوبة"},{"en":"Every 30 minutes","es":"Cada 30 minutos","ru":"Каждые 30 минут","tr":"Her 30 dakikada bir","hi":"हर 30 मिनट में","ar":"كل 30 دقيقة"},{"en":"At least every 4 hours","es":"Al menos cada 4 horas","ru":"Не реже чем каждые 4 часа","tr":"En az her 4 saatte bir","hi":"कम से कम हर 4 घंटे में","ar":"كل 4 ساعات على الأقل"},{"en":"Only when it looks dirty","es":"Solo cuando se vea sucia","ru":"Только когда выглядит грязной","tr":"Yalnızca kirli göründüğünde","hi":"केवल जब यह गंदा दिखे","ar":"فقط عندما يبدو متسخًا"}],"e":{"en":"During continuous use with the same TCS food, food-contact surfaces must be cleaned and sanitized at least every 4 hours to stop bacteria from building up.","es":"Durante el uso continuo con el mismo alimento TCS, las superficies de contacto deben limpiarse y desinfectarse al menos cada 4 horas para evitar la acumulación de bacterias.","ru":"При непрерывном использовании с одним TCS-продуктом поверхности контакта нужно мыть и дезинфицировать не реже чем каждые 4 часа, чтобы бактерии не накапливались.","tr":"Aynı TCS gıdayla sürekli kullanımda, gıda temas yüzeyleri bakteri birikimini durdurmak için en az her 4 saatte bir temizlenip dezenfekte edilmelidir.","hi":"एक ही TCS भोजन के साथ निरंतर उपयोग के दौरान, भोजन-संपर्क सतहों को बैक्टीरिया जमा होने से रोकने के लिए कम से कम हर 4 घंटे में साफ और सैनिटाइज़ किया जाना चाहिए।","ar":"أثناء الاستخدام المستمر مع طعام TCS نفسه، يجب تنظيف وتعقيم أسطح ملامسة الطعام كل 4 ساعات على الأقل لمنع تراكم البكتيريا."}},{"cat":"cleaning","a":3,"q":{"en":"A cleaning chemical is moved from its original container into a spray bottle. What must be done?","es":"Un químico de limpieza se pasa de su recipiente original a una botella rociadora. ¿Qué debe hacerse?","ru":"Чистящее средство перелито из оригинальной ёмкости в распылитель. Что нужно сделать?","tr":"Bir temizlik kimyasalı orijinal kabından bir sprey şişesine aktarılıyor. Ne yapılmalı?","hi":"एक सफाई रसायन को उसके मूल बर्तन से स्प्रे बोतल में स्थानांतरित किया जाता है। क्या किया जाना चाहिए?","ar":"تُنقل مادة تنظيف من عبوتها الأصلية إلى زجاجة رذاذ. ماذا يجب أن يُفعل؟"},"o":[{"en":"Nothing, everyone knows what it is","es":"Nada, todos saben qué es","ru":"Ничего, все знают, что это","tr":"Hiçbir şey, herkes ne olduğunu bilir","hi":"कुछ नहीं, सभी जानते हैं यह क्या है","ar":"لا شيء، الجميع يعرف ما هي"},{"en":"Add a splash of water","es":"Añadir un poco de agua","ru":"Добавить немного воды","tr":"Biraz su eklemek","hi":"थोड़ा पानी डालें","ar":"إضافة رشة ماء"},{"en":"Store it in the walk-in cooler","es":"Guardarla en el refrigerador de acceso","ru":"Хранить в холодильной камере","tr":"Soğuk odada saklamak","hi":"इसे वॉक-इन कूलर में रखें","ar":"تخزينها في الغرفة المبرّدة"},{"en":"Label the spray bottle with the chemical's name","es":"Etiquetar la botella con el nombre del químico","ru":"Промаркировать распылитель названием химиката","tr":"Sprey şişesini kimyasalın adıyla etiketlemek","hi":"स्प्रे बोतल पर रसायन का नाम लेबल करें","ar":"وسم زجاجة الرذاذ باسم المادة الكيميائية"}],"e":{"en":"Any working container that a chemical is transferred into must be clearly labeled with the common name of the chemical, so no one mistakes it for food, water, or another product.","es":"Todo recipiente de trabajo al que se transfiera un químico debe etiquetarse claramente con el nombre común del químico, para que nadie lo confunda con comida, agua u otro producto.","ru":"Любая рабочая ёмкость, в которую перелит химикат, должна быть чётко промаркирована общим названием химиката, чтобы её не спутали с едой, водой или другим средством.","tr":"Bir kimyasalın aktarıldığı her çalışma kabı, kimsenin onu gıda, su ya da başka ürünle karıştırmaması için kimyasalın yaygın adıyla açıkça etiketlenmelidir.","hi":"किसी भी कार्यशील बर्तन में जिसमें रसायन स्थानांतरित किया जाता है, रसायन के सामान्य नाम के साथ स्पष्ट रूप से लेबल किया जाना चाहिए, ताकि कोई इसे भोजन, पानी या अन्य उत्पाद न समझे।","ar":"أي وعاء عمل تُنقل إليه مادة كيميائية يجب وسمه بوضوح بالاسم الشائع للمادة، حتى لا يخلط أحد بينه وبين الطعام أو الماء أو منتج آخر."}},{"cat":"cleaning","a":0,"q":{"en":"When should the sanitizer in a three-compartment sink be changed?","es":"¿Cuándo debe cambiarse el desinfectante en un fregadero de tres compartimentos?","ru":"Когда нужно менять санитайзер в трёхсекционной раковине?","tr":"Üç bölmeli evyedeki dezenfektan ne zaman değiştirilmeli?","hi":"तीन-कम्पार्टमेंट सिंक में सैनिटाइज़र कब बदला जाना चाहिए?","ar":"متى يجب تغيير المعقّم في الحوض ذي الثلاث حجرات؟"},"o":[{"en":"When it is dirty, cloudy, or below the required concentration","es":"Cuando esté sucio, turbio o por debajo de la concentración requerida","ru":"Когда он грязный, мутный или ниже нужной концентрации","tr":"Kirlendiğinde, bulanıklaştığında ya da gereken konsantrasyonun altına düştüğünde","hi":"जब यह गंदा, धुंधला या आवश्यक सांद्रता से नीचे हो","ar":"عندما يصبح متسخًا أو عكرًا أو أقل من التركيز المطلوب"},{"en":"Only once a week","es":"Solo una vez a la semana","ru":"Только раз в неделю","tr":"Yalnızca haftada bir","hi":"केवल सप्ताह में एक बार","ar":"مرة واحدة أسبوعيًا فقط"},{"en":"Never, if it still looks wet","es":"Nunca, si todavía se ve mojado","ru":"Никогда, если он ещё влажный на вид","tr":"Hâlâ ıslak görünüyorsa asla","hi":"कभी नहीं, यदि यह अभी भी गीला दिखे","ar":"أبدًا، إن بدا لا يزال مبللًا"},{"en":"Only at closing","es":"Solo al cerrar","ru":"Только при закрытии","tr":"Yalnızca kapanışta","hi":"केवल बंद करते समय","ar":"فقط عند الإغلاق"}],"e":{"en":"Sanitizer solution must be changed whenever it becomes visibly dirty or cloudy or drops below the required concentration, verified with test strips, to stay effective.","es":"La solución desinfectante debe cambiarse cuando se ensucie o enturbie a la vista o baje de la concentración requerida, verificada con tiras de prueba, para seguir siendo eficaz.","ru":"Раствор санитайзера нужно менять, когда он заметно загрязнился, помутнел или опустился ниже нужной концентрации (проверяют тест-полоской), чтобы оставаться эффективным.","tr":"Dezenfektan solüsyonu; gözle görülür kirlendiğinde, bulanıklaştığında ya da test şeritleriyle doğrulanan gereken konsantrasyonun altına düştüğünde etkinliğini koruması için değiştirilmelidir.","hi":"सैनिटाइज़र घोल को तब बदला जाना चाहिए जब यह दृश्य रूप से गंदा या धुंधला हो जाए या आवश्यक सांद्रता से नीचे गिर जाए (टेस्ट स्ट्रिप से सत्यापित), ताकि प्रभावी बना रहे।","ar":"يجب تغيير محلول المعقّم كلما أصبح متسخًا أو عكرًا بوضوح أو انخفض دون التركيز المطلوب، المتحقَّق منه بشرائط الفحص، للحفاظ على فعاليته."}},{"cat":"cleaning","a":1,"q":{"en":"What is the difference between in-use equipment that is cleaned 'as needed' versus food-contact surfaces on a fixed schedule?","es":"¿Cuál es la diferencia entre equipo en uso limpiado 'según se necesite' y superficies de contacto con un horario fijo?","ru":"В чём разница между используемым оборудованием, которое чистят «по мере необходимости», и поверхностями контакта по фиксированному графику?","tr":"'Gerektikçe' temizlenen kullanımdaki ekipman ile sabit programa göre temizlenen gıda temas yüzeyleri arasındaki fark nedir?","hi":"'आवश्यकतानुसार' साफ किए जाने वाले उपयोग-में उपकरण और निश्चित समय-सारणी पर भोजन-संपर्क सतहों के बीच क्या अंतर है?","ar":"ما الفرق بين المعدات قيد الاستخدام التي تُنظَّف 'عند الحاجة' وأسطح ملامسة الطعام وفق جدول ثابت؟"},"o":[{"en":"Non-food-contact surfaces never need cleaning","es":"Las superficies sin contacto con alimentos nunca necesitan limpieza","ru":"Поверхности без контакта с пищей никогда не нуждаются в чистке","tr":"Gıdayla temas etmeyen yüzeyler asla temizlenmez","hi":"गैर-भोजन-संपर्क सतहों को कभी सफाई की जरूरत नहीं","ar":"الأسطح غير الملامسة للطعام لا تحتاج تنظيفًا أبدًا"},{"en":"Food-contact surfaces follow strict timing rules; non-food-contact surfaces are cleaned on a regular routine but less critically","es":"Las superficies de contacto siguen reglas de tiempo estrictas; las que no tocan alimentos se limpian de forma rutinaria pero menos crítica","ru":"Поверхности контакта следуют строгим правилам по времени; поверхности без контакта чистят регулярно, но менее критично","tr":"Gıda temas yüzeyleri katı zaman kurallarına uyar; gıdayla temas etmeyenler düzenli ama daha az kritik biçimde temizlenir","hi":"भोजन-संपर्क सतहें सख्त समय नियमों का पालन करती हैं; गैर-भोजन-संपर्क सतहें नियमित पर कम गंभीर रूप से साफ होती हैं","ar":"أسطح ملامسة الطعام تتبع قواعد توقيت صارمة؛ أما غير الملامسة فتُنظَّف بروتين منتظم لكن بأهمية أقل"},{"en":"Both must be sanitized every 15 minutes","es":"Ambas deben desinfectarse cada 15 minutos","ru":"Обе нужно дезинфицировать каждые 15 минут","tr":"İkisi de her 15 dakikada dezenfekte edilmeli","hi":"दोनों को हर 15 मिनट में सैनिटाइज़ किया जाना चाहिए","ar":"يجب تعقيم كليهما كل 15 دقيقة"},{"en":"There is no difference at all","es":"No hay diferencia alguna","ru":"Разницы вообще нет","tr":"Hiçbir fark yoktur","hi":"कोई अंतर बिल्कुल नहीं","ar":"لا يوجد فرق على الإطلاق"}],"e":{"en":"Food-contact surfaces must be cleaned and sanitized on strict schedules (such as every 4 hours or between tasks). Non-food-contact surfaces, like floors and walls, are cleaned regularly but on a routine basis.","es":"Las superficies de contacto se limpian y desinfectan con horarios estrictos (como cada 4 horas o entre tareas). Las que no tocan alimentos, como pisos y paredes, se limpian de forma rutinaria.","ru":"Поверхности контакта моют и дезинфицируют по строгому графику (например, каждые 4 часа или между задачами). Поверхности без контакта, как полы и стены, чистят регулярно, но по расписанию.","tr":"Gıda temas yüzeyleri katı programlarla (her 4 saatte bir ya da işler arası) temizlenip dezenfekte edilir. Zemin ve duvar gibi temas etmeyen yüzeyler düzenli rutinle temizlenir.","hi":"भोजन-संपर्क सतहें सख्त समय-सारणी पर (जैसे हर 4 घंटे या कार्यों के बीच) साफ और सैनिटाइज़ की जाती हैं। फर्श और दीवारों जैसी गैर-संपर्क सतहें नियमित रूप से साफ होती हैं।","ar":"تُنظَّف وتُعقَّم أسطح ملامسة الطعام وفق جداول صارمة (كل 4 ساعات أو بين المهام). أما غير الملامسة كالأرضيات والجدران فتُنظَّف بروتين منتظم."}},{"cat":"cleaning","a":2,"q":{"en":"Which is the best way to clean up after a customer vomits in the dining area?","es":"¿Cuál es la mejor forma de limpiar después de que un cliente vomita en el comedor?","ru":"Как лучше всего убрать после того, как клиента вырвало в обеденной зоне?","tr":"Bir müşteri yemek alanında kustuktan sonra temizlemenin en iyi yolu nedir?","hi":"भोजन क्षेत्र में एक ग्राहक के उल्टी करने के बाद सफाई का सबसे अच्छा तरीका क्या है?","ar":"ما أفضل طريقة للتنظيف بعد تقيؤ زبون في منطقة تناول الطعام؟"},"o":[{"en":"Wipe it with a dry towel and continue service","es":"Limpiarlo con una toalla seca y seguir el servicio","ru":"Вытереть сухим полотенцем и продолжить обслуживание","tr":"Kuru bir havluyla silip servise devam etmek","hi":"सूखे तौलिये से पोंछें और सेवा जारी रखें","ar":"مسحه بمنشفة جافة ومواصلة الخدمة"},{"en":"Cover it and leave it until closing","es":"Cubrirlo y dejarlo hasta el cierre","ru":"Накрыть и оставить до закрытия","tr":"Üzerini örtüp kapanışa kadar bırakmak","hi":"इसे ढकें और बंद होने तक छोड़ दें","ar":"تغطيته وتركه حتى الإغلاق"},{"en":"Follow the written clean-up procedure using proper PPE and a strong sanitizer","es":"Seguir el procedimiento escrito de limpieza usando EPP adecuado y un desinfectante fuerte","ru":"Следовать письменной процедуре уборки с использованием СИЗ и сильного санитайзера","tr":"Uygun KKD ve güçlü bir dezenfektanla yazılı temizlik prosedürünü uygulamak","hi":"उचित PPE और मजबूत सैनिटाइज़र का उपयोग करते हुए लिखित सफाई प्रक्रिया का पालन करें","ar":"اتباع إجراء التنظيف المكتوب باستخدام معدات وقاية مناسبة ومعقّم قوي"},{"en":"Spray air freshener over the area","es":"Rociar ambientador sobre el área","ru":"Распылить освежитель воздуха над зоной","tr":"Alana oda spreyi sıkmak","hi":"क्षेत्र पर एयर फ्रेशनर छिड़कें","ar":"رشّ معطر جو على المنطقة"}],"e":{"en":"Vomit and diarrhea can carry Norovirus, so operations must have a written clean-up plan: isolate the area, use gloves and protective equipment, clean, and sanitize with a product effective against Norovirus.","es":"El vómito y la diarrea pueden portar Norovirus, así que debe existir un plan escrito: aislar el área, usar guantes y equipo de protección, limpiar y desinfectar con un producto eficaz contra el Norovirus.","ru":"Рвота и диарея могут нести норовирус, поэтому нужен письменный план: изолировать зону, надеть перчатки и защиту, вымыть и продезинфицировать средством, эффективным против норовируса.","tr":"Kusma ve ishal Norovirüs taşıyabilir; bu yüzden yazılı bir temizlik planı gerekir: alanı izole edin, eldiven ve koruyucu ekipman kullanın, temizleyin ve Norovirüse etkili bir ürünle dezenfekte edin.","hi":"उल्टी और दस्त नोरोवायरस ले सकते हैं, इसलिए लिखित सफाई योजना होनी चाहिए: क्षेत्र को अलग करें, दस्ताने और सुरक्षात्मक उपकरण उपयोग करें, साफ करें और नोरोवायरस के खिलाफ प्रभावी उत्पाद से सैनिटाइज़ करें।","ar":"القيء والإسهال قد يحملان نوروفيروس، لذا يجب وجود خطة تنظيف مكتوبة: عزل المنطقة، واستخدام قفازات ومعدات وقاية، والتنظيف والتعقيم بمنتج فعّال ضد نوروفيروس."}},{"cat":"cleaning","a":3,"q":{"en":"Why should a food-contact surface be allowed enough sanitizer contact time?","es":"¿Por qué debe dejarse suficiente tiempo de contacto con el desinfectante en una superficie de contacto?","ru":"Почему поверхности контакта нужно давать достаточно времени контакта с санитайзером?","tr":"Bir gıda temas yüzeyine neden yeterli dezenfektan temas süresi tanınmalı?","hi":"भोजन-संपर्क सतह को पर्याप्त सैनिटाइज़र संपर्क समय क्यों दिया जाना चाहिए?","ar":"لماذا يجب منح سطح ملامسة الطعام زمن ملامسة كافيًا للمعقّم؟"},"o":[{"en":"So the surface looks wet longer","es":"Para que la superficie se vea mojada más tiempo","ru":"Чтобы поверхность дольше выглядела мокрой","tr":"Yüzey daha uzun ıslak görünsün diye","hi":"ताकि सतह अधिक देर गीली दिखे","ar":"لكي يبدو السطح مبللًا مدة أطول"},{"en":"So it uses more chemical","es":"Para que use más químico","ru":"Чтобы использовать больше химиката","tr":"Daha fazla kimyasal kullansın diye","hi":"ताकि यह अधिक रसायन उपयोग करे","ar":"لكي يستخدم مزيدًا من المادة الكيميائية"},{"en":"To cool the surface","es":"Para enfriar la superficie","ru":"Чтобы охладить поверхность","tr":"Yüzeyi soğutmak için","hi":"सतह को ठंडा करने के लिए","ar":"لتبريد السطح"},{"en":"The sanitizer needs time to kill pathogens effectively","es":"El desinfectante necesita tiempo para eliminar patógenos con eficacia","ru":"Санитайзеру нужно время, чтобы эффективно уничтожить патогены","tr":"Dezenfektanın patojenleri etkili öldürmek için zamana ihtiyacı vardır","hi":"सैनिटाइज़र को रोगाणुओं को प्रभावी ढंग से मारने के लिए समय चाहिए","ar":"يحتاج المعقّم وقتًا ليقتل المسببات بفعالية"}],"e":{"en":"Sanitizers need a minimum contact time to kill pathogens. Wiping it off too soon leaves live pathogens behind, so the surface must stay wet with sanitizer for the time on the label.","es":"Los desinfectantes necesitan un tiempo mínimo de contacto para eliminar patógenos. Secar demasiado pronto deja patógenos vivos, así que la superficie debe permanecer húmeda el tiempo indicado.","ru":"Санитайзерам нужно минимальное время контакта для уничтожения патогенов. Слишком раннее вытирание оставляет живые патогены, поэтому поверхность должна оставаться влажной указанное на этикетке время.","tr":"Dezenfektanlar patojenleri öldürmek için asgari bir temas süresine ihtiyaç duyar. Erken silmek canlı patojen bırakır; bu yüzden yüzey, etikette belirtilen süre boyunca dezenfektanla ıslak kalmalıdır.","hi":"सैनिटाइज़र को रोगाणुओं को मारने के लिए न्यूनतम संपर्क समय चाहिए। बहुत जल्दी पोंछना जीवित रोगाणु छोड़ देता है, इसलिए सतह को लेबल पर दिए समय तक सैनिटाइज़र से गीली रहनी चाहिए।","ar":"تحتاج المعقّمات زمن ملامسة أدنى لقتل المسببات. مسحه مبكرًا يترك مسببات حية، لذا يجب أن يبقى السطح مبللًا بالمعقّم للمدة المذكورة على الملصق."}},{"cat":"cleaning","a":0,"q":{"en":"In a low-temperature (chemical) dishwasher, sanitizing is achieved by:","es":"En un lavavajillas de baja temperatura (químico), la desinfección se logra mediante:","ru":"В низкотемпературной (химической) посудомоечной машине санобработка достигается за счёт:","tr":"Düşük sıcaklıklı (kimyasal) bulaşık makinesinde dezenfeksiyon şununla sağlanır:","hi":"निम्न-तापमान (रासायनिक) डिशवॉशर में, सैनिटाइज़िंग किससे प्राप्त होती है:","ar":"في غسالة أطباق منخفضة الحرارة (كيميائية)، يتحقق التعقيم عن طريق:"},"o":[{"en":"A chemical sanitizer in the rinse","es":"Un desinfectante químico en el enjuague","ru":"Химического санитайзера в ополаскивании","tr":"Durulamadaki kimyasal dezenfektan","hi":"रिन्स में एक रासायनिक सैनिटाइज़र","ar":"معقّم كيميائي في الشطف"},{"en":"Very hot water at 180°F","es":"Agua muy caliente a 180°F","ru":"Очень горячей воды 180°F","tr":"180°F'te çok sıcak su","hi":"180°F पर बहुत गर्म पानी","ar":"ماء ساخن جدًا عند 180°F"},{"en":"Ultraviolet light","es":"Luz ultravioleta","ru":"Ультрафиолета","tr":"Ultraviyole ışık","hi":"पराबैंगनी प्रकाश","ar":"الأشعة فوق البنفسجية"},{"en":"High-pressure steam only","es":"Solo vapor a alta presión","ru":"Только пара высокого давления","tr":"Yalnızca yüksek basınçlı buhar","hi":"केवल उच्च दबाव भाप","ar":"البخار عالي الضغط فقط"}],"e":{"en":"Low-temperature machines sanitize using a chemical sanitizer (often chlorine) injected into the final rinse, since their water is not hot enough to sanitize by heat alone.","es":"Las máquinas de baja temperatura desinfectan con un desinfectante químico (a menudo cloro) inyectado en el enjuague final, ya que su agua no es lo bastante caliente para desinfectar solo por calor.","ru":"Низкотемпературные машины санируют химическим санитайзером (часто хлором), впрыскиваемым в финальное ополаскивание, так как их вода недостаточно горяча для санобработки теплом.","tr":"Düşük sıcaklıklı makineler, suları yalnızca ısıyla dezenfekte edecek kadar sıcak olmadığından, son durulamaya enjekte edilen kimyasal dezenfektanla (genellikle klor) dezenfekte eder.","hi":"निम्न-तापमान मशीनें अंतिम रिन्स में इंजेक्ट किए रासायनिक सैनिटाइज़र (अक्सर क्लोरीन) से सैनिटाइज़ करती हैं, क्योंकि उनका पानी अकेले ऊष्मा से सैनिटाइज़ करने के लिए पर्याप्त गर्म नहीं होता।","ar":"الآلات منخفضة الحرارة تعقّم بمعقّم كيميائي (غالبًا الكلور) يُحقن في الشطفة النهائية، لأن ماءها ليس ساخنًا بما يكفي للتعقيم بالحرارة وحدها."}},{"cat":"cleaning","a":1,"q":{"en":"How should a food establishment store clean, sanitized utensils?","es":"¿Cómo debe almacenar un establecimiento los utensilios limpios y desinfectados?","ru":"Как заведение должно хранить чистый, продезинфицированный инвентарь?","tr":"Bir gıda işletmesi temiz, dezenfekte edilmiş aletleri nasıl saklamalı?","hi":"एक खाद्य प्रतिष्ठान को साफ, सैनिटाइज़ किए बर्तन कैसे संग्रहीत करने चाहिए?","ar":"كيف يجب أن تخزّن المنشأة الأدوات النظيفة المعقمة؟"},"o":[{"en":"Piled loosely in an open bin on the floor","es":"Amontonados sueltos en un cesto abierto en el piso","ru":"Свалены в открытый контейнер на полу","tr":"Zemindeki açık bir kutuda gevşekçe yığılı","hi":"फर्श पर एक खुले डिब्बे में ढीले ढेर","ar":"مكوّمة بلا ترتيب في صندوق مفتوح على الأرض"},{"en":"Covered or inverted, off the floor, and protected from contamination","es":"Cubiertos o invertidos, sobre el piso y protegidos de contaminación","ru":"Накрытыми или перевёрнутыми, над полом и защищёнными от загрязнения","tr":"Örtülü ya da ters çevrilmiş, zeminden yüksekte ve bulaşmadan korunmuş","hi":"ढके या उल्टे, फर्श से ऊपर, और दूषण से सुरक्षित","ar":"مغطاة أو مقلوبة، مرفوعة عن الأرض، ومحمية من التلوث"},{"en":"Next to the trash can","es":"Junto al bote de basura","ru":"Рядом с мусорным ведром","tr":"Çöp kovasının yanında","hi":"कचरे के डिब्बे के बगल में","ar":"بجانب سلة القمامة"},{"en":"Wet in a sealed bag","es":"Mojados en una bolsa sellada","ru":"Мокрыми в закрытом пакете","tr":"Kapalı bir torbada ıslak halde","hi":"सीलबंद बैग में गीले","ar":"مبللة في كيس محكم الغلق"}],"e":{"en":"Clean utensils are stored at least six inches off the floor, covered or inverted, in a clean dry location, with handles up, to protect them from splash, dust, and other contamination.","es":"Los utensilios limpios se guardan al menos a quince centímetros del piso, cubiertos o invertidos, en un lugar limpio y seco, con los mangos hacia arriba, para protegerlos de salpicaduras, polvo y otras contaminaciones.","ru":"Чистый инвентарь хранят не менее чем в 15 см от пола, накрытым или перевёрнутым, в чистом сухом месте, ручками вверх, чтобы защитить от брызг, пыли и загрязнений.","tr":"Temiz aletler; sıçrama, toz ve diğer kirlenmelerden korumak için zeminden en az 15 cm yüksekte, örtülü ya da ters, temiz ve kuru bir yerde, sapları yukarı gelecek şekilde saklanır.","hi":"साफ बर्तन फर्श से कम से कम छह इंच ऊपर, ढके या उल्टे, साफ सूखे स्थान पर, हैंडल ऊपर करके रखे जाते हैं, ताकि छींटे, धूल और अन्य दूषण से सुरक्षित रहें।","ar":"تُخزَّن الأدوات النظيفة على ارتفاع لا يقل عن 15 سم عن الأرض، مغطاة أو مقلوبة، في مكان نظيف جاف، ومقابضها لأعلى، لحمايتها من الرذاذ والغبار والتلوث."}},{"cat":"cleaning","a":2,"q":{"en":"After cleaning and sanitizing, when does a sanitizer bucket for wiping cloths typically need remaking?","es":"Tras limpiar y desinfectar, ¿cuándo suele necesitar rehacerse un balde de desinfectante para paños?","ru":"После мытья и санобработки когда обычно нужно заново готовить ведро санитайзера для тряпок?","tr":"Temizlik ve dezenfeksiyondan sonra, silme bezleri için dezenfektan kovası genellikle ne zaman yeniden hazırlanmalı?","hi":"सफाई और सैनिटाइज़िंग के बाद, पोंछने वाले कपड़ों के लिए सैनिटाइज़र बाल्टी को आमतौर पर कब फिर से बनाने की जरूरत होती है?","ar":"بعد التنظيف والتعقيم، متى تحتاج دلو المعقّم لأقمشة المسح عادةً إلى إعادة تحضير؟"},"o":[{"en":"Once a month","es":"Una vez al mes","ru":"Раз в месяц","tr":"Ayda bir kez","hi":"महीने में एक बार","ar":"مرة في الشهر"},{"en":"Never during the day","es":"Nunca durante el día","ru":"Никогда в течение дня","tr":"Gün içinde asla","hi":"दिन में कभी नहीं","ar":"أبدًا خلال اليوم"},{"en":"When the concentration drops or the solution gets dirty","es":"Cuando baja la concentración o la solución se ensucia","ru":"Когда падает концентрация или раствор загрязняется","tr":"Konsantrasyon düştüğünde ya da solüsyon kirlendiğinde","hi":"जब सांद्रता गिरे या घोल गंदा हो जाए","ar":"عندما ينخفض التركيز أو يتسخ المحلول"},{"en":"Only after service ends","es":"Solo después de terminar el servicio","ru":"Только после окончания обслуживания","tr":"Yalnızca servis bittikten sonra","hi":"केवल सेवा समाप्त होने के बाद","ar":"فقط بعد انتهاء الخدمة"}],"e":{"en":"A wiping-cloth sanitizer bucket is remade whenever the solution becomes visibly dirty or tests below the required concentration, which can happen several times a shift.","es":"El balde de desinfectante para paños se rehace cuando la solución se ensucia a la vista o da por debajo de la concentración requerida, lo que puede ocurrir varias veces por turno.","ru":"Ведро санитайзера для тряпок готовят заново, когда раствор заметно загрязнился или тест показывает ниже нужной концентрации, что может случаться несколько раз за смену.","tr":"Silme bezi dezenfektan kovası; solüsyon gözle görülür kirlendiğinde ya da gereken konsantrasyonun altına düştüğünde yenilenir; bu bir vardiyada birkaç kez olabilir.","hi":"पोंछने-कपड़े सैनिटाइज़र बाल्टी तब फिर से बनाई जाती है जब घोल दृश्य रूप से गंदा हो जाए या आवश्यक सांद्रता से नीचे परीक्षण करे, जो एक शिफ्ट में कई बार हो सकता है।","ar":"يُعاد تحضير دلو معقّم أقمشة المسح كلما أصبح المحلول متسخًا بوضوح أو انخفض تحت التركيز المطلوب، وقد يحدث ذلك عدة مرات في النوبة."}},{"cat":"cleaning","a":3,"q":{"en":"Which sink or area is the correct place to dump a mop bucket of dirty water?","es":"¿Cuál es el lugar correcto para vaciar un balde de trapeador con agua sucia?","ru":"Куда правильно выливать ведро с грязной водой после мытья пола?","tr":"Kirli su dolu bir paspas kovası nereye boşaltılmalı?","hi":"गंदे पानी की मॉप बाल्टी को खाली करने के लिए सही जगह कौन-सा सिंक या क्षेत्र है?","ar":"ما الحوض أو المكان الصحيح لتفريغ دلو المسّاحة المليء بالماء المتسخ؟"},"o":[{"en":"The food-prep sink","es":"El fregadero de preparación de alimentos","ru":"Раковина для приготовления пищи","tr":"Gıda hazırlama evyesi","hi":"फूड-प्रेप सिंक","ar":"حوض تحضير الطعام"},{"en":"The handwashing sink","es":"El lavamanos","ru":"Раковина для мытья рук","tr":"El yıkama lavabosu","hi":"हाथ धोने वाला सिंक","ar":"حوض غسل اليدين"},{"en":"The three-compartment sink","es":"El fregadero de tres compartimentos","ru":"Трёхсекционная раковина","tr":"Üç bölmeli evye","hi":"तीन-कम्पार्टमेंट सिंक","ar":"الحوض ذو الثلاث حجرات"},{"en":"A designated mop sink or service sink","es":"Un fregadero de trapeador o de servicio designado","ru":"Специальная раковина для швабры или хозяйственная раковина","tr":"Ayrılmış bir paspas evyesi ya da servis evyesi","hi":"एक निर्दिष्ट मॉप सिंक या सर्विस सिंक","ar":"حوض مسّاحة مخصص أو حوض خدمة"}],"e":{"en":"Dirty mop water is emptied into a designated mop or service sink (utility sink), never into sinks used for food, handwashing, or dishes, to avoid contaminating them.","es":"El agua sucia del trapeador se vacía en un fregadero de trapeador o de servicio designado, nunca en fregaderos de alimentos, de manos o de platos, para no contaminarlos.","ru":"Грязную воду выливают в специальную раковину для швабры или хозяйственную, но не в раковины для еды, рук или посуды, чтобы не загрязнять их.","tr":"Kirli paspas suyu, gıda, el yıkama ya da bulaşık evyelerine değil, ayrılmış bir paspas ya da servis evyesine (fayans evye) boşaltılır; böylece kirlenmeleri önlenir.","hi":"गंदा मॉप पानी एक निर्दिष्ट मॉप या सर्विस सिंक में खाली किया जाता है, कभी भोजन, हाथ धोने या बर्तन के सिंक में नहीं, ताकि उन्हें दूषित न किया जाए।","ar":"يُفرَّغ ماء المسّاحة المتسخ في حوض مسّاحة أو خدمة مخصص، وليس في أحواض الطعام أو غسل اليدين أو الأطباق، لتجنب تلويثها."}},{"cat":"cleaning","a":0,"q":{"en":"What is a master cleaning schedule used for in a food operation?","es":"¿Para qué sirve un programa maestro de limpieza en una operación de alimentos?","ru":"Для чего в пищевом заведении используется общий график уборки?","tr":"Bir gıda işletmesinde ana temizlik programı ne işe yarar?","hi":"एक खाद्य प्रतिष्ठान में मास्टर सफाई अनुसूची किसके लिए उपयोग होती है?","ar":"لماذا يُستخدم جدول التنظيف الرئيسي في منشأة طعام؟"},"o":[{"en":"To document what must be cleaned, how, when, and by whom","es":"Para documentar qué debe limpiarse, cómo, cuándo y por quién","ru":"Чтобы зафиксировать, что, как, когда и кем должно быть очищено","tr":"Neyin, nasıl, ne zaman ve kim tarafından temizleneceğini belgelemek için","hi":"यह दस्तावेज करने के लिए कि क्या, कैसे, कब और किसके द्वारा साफ किया जाना चाहिए","ar":"لتوثيق ما يجب تنظيفه وكيف ومتى ومن قبل من"},{"en":"To schedule employee breaks","es":"Para programar los descansos de los empleados","ru":"Чтобы планировать перерывы сотрудников","tr":"Çalışan molalarını planlamak için","hi":"कर्मचारी ब्रेक शेड्यूल करने के लिए","ar":"لجدولة استراحات الموظفين"},{"en":"To set menu prices","es":"Para fijar los precios del menú","ru":"Чтобы устанавливать цены меню","tr":"Menü fiyatlarını belirlemek için","hi":"मेनू कीमतें तय करने के लिए","ar":"لتحديد أسعار القائمة"},{"en":"To record delivery temperatures","es":"Para registrar temperaturas de entrega","ru":"Чтобы записывать температуры доставки","tr":"Teslimat sıcaklıklarını kaydetmek için","hi":"डिलीवरी तापमान रिकॉर्ड करने के लिए","ar":"لتسجيل درجات حرارة التسليم"}],"e":{"en":"A master cleaning schedule lists what needs cleaning, the method and chemicals to use, how often, and who is responsible, so nothing is missed and cleaning stays consistent.","es":"Un programa maestro de limpieza indica qué debe limpiarse, el método y los químicos, con qué frecuencia y quién es responsable, para que no se olvide nada y la limpieza sea consistente.","ru":"Общий график уборки перечисляет, что нужно чистить, каким методом и средствами, как часто и кто отвечает, чтобы ничего не упустить и обеспечить постоянство.","tr":"Ana temizlik programı; neyin temizleneceğini, yöntem ve kimyasalları, ne sıklıkta ve kimin sorumlu olduğunu listeler; böylece hiçbir şey atlanmaz ve temizlik tutarlı kalır.","hi":"मास्टर सफाई अनुसूची सूचीबद्ध करती है कि क्या साफ करना है, कौन-सी विधि और रसायन, कितनी बार, और कौन जिम्मेदार है, ताकि कुछ छूटे नहीं और सफाई सुसंगत रहे।","ar":"يسرد جدول التنظيف الرئيسي ما يحتاج تنظيفًا وطريقته والمواد المستخدمة وتكراره ومن المسؤول، حتى لا يُغفل شيء وتبقى النظافة متسقة."}},{"cat":"cleaning","a":1,"q":{"en":"Why should equipment be unplugged or turned off before it is cleaned?","es":"¿Por qué debe desconectarse o apagarse el equipo antes de limpiarlo?","ru":"Почему оборудование нужно отключить или выключить перед чисткой?","tr":"Ekipman temizlenmeden önce neden fişten çekilmeli ya da kapatılmalı?","hi":"उपकरण को साफ करने से पहले इसे अनप्लग या बंद क्यों किया जाना चाहिए?","ar":"لماذا يجب فصل المعدات أو إطفاؤها قبل تنظيفها؟"},"o":[{"en":"To save electricity","es":"Para ahorrar electricidad","ru":"Чтобы экономить электричество","tr":"Elektrik tasarrufu için","hi":"बिजली बचाने के लिए","ar":"لتوفير الكهرباء"},{"en":"For worker safety and to clean it properly","es":"Por seguridad del trabajador y para limpiarlo correctamente","ru":"Ради безопасности работника и правильной чистки","tr":"Çalışan güvenliği ve düzgün temizlik için","hi":"कर्मचारी सुरक्षा के लिए और इसे ठीक से साफ करने के लिए","ar":"لسلامة العامل ولتنظيفها بشكل سليم"},{"en":"To make it cool faster","es":"Para que se enfríe más rápido","ru":"Чтобы оно быстрее остыло","tr":"Daha hızlı soğuması için","hi":"इसे तेजी से ठंडा करने के लिए","ar":"لتبرد أسرع"},{"en":"It is not necessary","es":"No es necesario","ru":"Это не обязательно","tr":"Gerekli değildir","hi":"यह आवश्यक नहीं है","ar":"ليس ضروريًا"}],"e":{"en":"Equipment such as slicers and mixers should be turned off and unplugged before cleaning to protect the worker from injury and to allow safe, thorough disassembly and cleaning.","es":"Equipos como rebanadoras y batidoras deben apagarse y desconectarse antes de limpiarse, para proteger al trabajador de lesiones y permitir un desmontaje y limpieza seguros y minuciosos.","ru":"Оборудование, например слайсеры и миксеры, нужно выключать и отключать перед чисткой, чтобы защитить работника от травм и обеспечить безопасную полную разборку и мойку.","tr":"Dilimleyici ve mikser gibi ekipmanlar, çalışanı yaralanmadan korumak ve güvenli, eksiksiz sökme ve temizliğe olanak vermek için temizlikten önce kapatılıp fişten çekilmelidir.","hi":"स्लाइसर और मिक्सर जैसे उपकरण सफाई से पहले बंद और अनप्लग किए जाने चाहिए, ताकि कर्मचारी को चोट से बचाया जा सके और सुरक्षित, पूर्ण डिससेंबली और सफाई हो सके।","ar":"يجب إطفاء وفصل المعدات مثل الشرائح والخلاطات قبل التنظيف لحماية العامل من الإصابة والسماح بالفك والتنظيف الآمن والكامل."}},{"cat":"cleaning","a":2,"q":{"en":"If a chlorine sanitizer solution tests at 200 ppm (too strong), what should be done?","es":"Si una solución de cloro da 200 ppm (demasiado fuerte), ¿qué debe hacerse?","ru":"Если хлорный санитайзер показывает 200 ppm (слишком сильный), что делать?","tr":"Bir klor dezenfektan solüsyonu 200 ppm (çok güçlü) ölçüyorsa ne yapılmalı?","hi":"यदि क्लोरीन सैनिटाइज़र घोल 200 ppm (बहुत मजबूत) परीक्षण करता है, तो क्या किया जाना चाहिए?","ar":"إذا أظهر محلول معقّم الكلور 200 جزء بالمليون (قوي جدًا)، فماذا يجب فعله؟"},"o":[{"en":"Use it anyway; stronger is better","es":"Usarla igual; más fuerte es mejor","ru":"Использовать всё равно; крепче — лучше","tr":"Yine de kullanmak; daha güçlü daha iyidir","hi":"फिर भी इसका उपयोग करें; मजबूत बेहतर है","ar":"استخدامه على أي حال؛ الأقوى أفضل"},{"en":"Add more bleach","es":"Añadir más lejía","ru":"Добавить ещё отбеливателя","tr":"Daha fazla çamaşır suyu eklemek","hi":"और ब्लीच डालें","ar":"إضافة مزيد من المبيّض"},{"en":"Dilute it with water and retest until it is in range","es":"Diluirla con agua y volver a probar hasta que esté en rango","ru":"Разбавить водой и повторно проверить, пока не будет в норме","tr":"Suyla seyreltip aralığa girene dek yeniden test etmek","hi":"इसे पानी से पतला करें और सीमा में आने तक फिर से परीक्षण करें","ar":"تخفيفه بالماء وإعادة الفحص حتى يصبح ضمن النطاق"},{"en":"Throw out all the dishes","es":"Desechar todos los platos","ru":"Выбросить всю посуду","tr":"Tüm bulaşıkları atmak","hi":"सभी बर्तन फेंक दें","ar":"التخلص من كل الأطباق"}],"e":{"en":"An over-concentrated sanitizer can leave unsafe residue and is corrosive, so it should be diluted with water and retested with a test strip until it falls within the 50 to 100 ppm range.","es":"Un desinfectante demasiado concentrado puede dejar residuo inseguro y es corrosivo, así que debe diluirse con agua y volver a probar con tira hasta caer en el rango de 50 a 100 ppm.","ru":"Слишком концентрированный санитайзер может оставить опасный остаток и вызывает коррозию, поэтому его разбавляют водой и перепроверяют тест-полоской, пока он не будет в диапазоне 50–100 ppm.","tr":"Aşırı konsantre dezenfektan güvensiz kalıntı bırakabilir ve aşındırıcıdır; bu yüzden suyla seyreltilip test şeridiyle 50–100 ppm aralığına girene dek yeniden ölçülmelidir.","hi":"अत्यधिक सांद्र सैनिटाइज़र असुरक्षित अवशेष छोड़ सकता है और संक्षारक है, इसलिए इसे पानी से पतला कर टेस्ट स्ट्रिप से 50 से 100 ppm सीमा में आने तक फिर से जांचना चाहिए।","ar":"المعقّم المفرط التركيز قد يترك بقايا غير آمنة وهو أكّال، لذا يجب تخفيفه بالماء وإعادة فحصه بشريط حتى يصبح ضمن نطاق 50 إلى 100 جزء بالمليون."}},{"cat":"cleaning","a":3,"q":{"en":"Which is the correct first step when manually washing dishes in a three-compartment sink?","es":"¿Cuál es el primer paso correcto al lavar platos a mano en un fregadero de tres compartimentos?","ru":"Каков правильный первый шаг при ручной мойке посуды в трёхсекционной раковине?","tr":"Üç bölmeli evyede bulaşıkları elde yıkarken doğru ilk adım nedir?","hi":"तीन-कम्पार्टमेंट सिंक में हाथ से बर्तन धोते समय सही पहला कदम कौन-सा है?","ar":"ما الخطوة الأولى الصحيحة عند غسل الأطباق يدويًا في الحوض ذي الثلاث حجرات؟"},"o":[{"en":"Sanitize the dishes first","es":"Desinfectar los platos primero","ru":"Сначала продезинфицировать посуду","tr":"Önce bulaşıkları dezenfekte etmek","hi":"पहले बर्तनों को सैनिटाइज़ करें","ar":"تعقيم الأطباق أولًا"},{"en":"Air dry the dishes","es":"Secar los platos al aire","ru":"Высушить посуду на воздухе","tr":"Bulaşıkları havada kurutmak","hi":"बर्तनों को हवा में सुखाएं","ar":"تجفيف الأطباق بالهواء"},{"en":"Rinse in the sanitizer compartment","es":"Enjuagar en el compartimento del desinfectante","ru":"Ополоснуть в отсеке с санитайзером","tr":"Dezenfektan bölmesinde durulamak","hi":"सैनिटाइज़र कम्पार्टमेंट में धोएं","ar":"الشطف في حجرة المعقّم"},{"en":"Scrape off food and pre-rinse the items","es":"Raspar los restos de comida y preenjuagar","ru":"Соскоблить пищу и предварительно ополоснуть предметы","tr":"Gıda artıklarını kazıyıp ön durulama yapmak","hi":"भोजन खुरचें और वस्तुओं को पूर्व-कुल्ला करें","ar":"كشط بقايا الطعام وإجراء شطف أولي للأصناف"}],"e":{"en":"Before washing, scrape and pre-rinse to remove leftover food. Then proceed through wash, rinse, and sanitize, and finally air dry. Skipping the scrape step dirties the wash water quickly.","es":"Antes de lavar, raspe y preenjuague para quitar restos de comida. Luego siga con lavar, enjuagar y desinfectar, y finalmente seque al aire. Saltarse el raspado ensucia rápido el agua de lavado.","ru":"Перед мойкой соскоблите и предварительно ополосните, чтобы удалить остатки пищи. Затем — мойка, ополаскивание, санобработка и сушка на воздухе. Пропуск соскабливания быстро загрязняет воду.","tr":"Yıkamadan önce artık gıdayı gidermek için kazıyıp ön durulama yapın. Sonra yıkama, durulama ve dezenfeksiyonla devam edip en son havada kurutun. Kazıma adımını atlamak yıkama suyunu hızla kirletir.","hi":"धोने से पहले, बचा भोजन हटाने के लिए खुरचें और पूर्व-कुल्ला करें। फिर धोना, कुल्ला और सैनिटाइज़ के माध्यम से आगे बढ़ें, और अंत में हवा में सुखाएं। खुरचना छोड़ना धोने का पानी जल्दी गंदा करता है।","ar":"قبل الغسل، اكشط وأجرِ شطفًا أوليًا لإزالة بقايا الطعام. ثم تابع الغسل والشطف والتعقيم، وأخيرًا التجفيف بالهواء. تخطي الكشط يوسّخ ماء الغسل بسرعة."}},{"cat":"cleaning","a":0,"q":{"en":"Why must the wash water in a three-compartment sink be kept hot and changed when needed?","es":"¿Por qué debe mantenerse caliente y cambiarse cuando sea necesario el agua de lavado en un fregadero de tres compartimentos?","ru":"Почему воду для мойки в трёхсекционной раковине нужно держать горячей и менять при необходимости?","tr":"Üç bölmeli evyedeki yıkama suyu neden sıcak tutulmalı ve gerektiğinde değiştirilmeli?","hi":"तीन-कम्पार्टमेंट सिंक में धोने के पानी को गर्म रखना और आवश्यकता पर बदलना क्यों जरूरी है?","ar":"لماذا يجب إبقاء ماء الغسل في الحوض ذي الثلاث حجرات ساخنًا وتغييره عند الحاجة؟"},"o":[{"en":"Hot, clean detergent water removes grease and soil effectively","es":"El agua caliente y limpia con detergente elimina grasa y suciedad eficazmente","ru":"Горячая чистая вода с моющим средством эффективно удаляет жир и грязь","tr":"Sıcak, temiz deterjanlı su yağı ve kiri etkili giderir","hi":"गर्म, साफ डिटर्जेंट पानी चिकनाई और गंदगी को प्रभावी ढंग से हटाता है","ar":"الماء الساخن النظيف بالمنظف يزيل الدهون والأوساخ بفعالية"},{"en":"It makes the dishes smell nice","es":"Hace que los platos huelan bien","ru":"Это придаёт посуде приятный запах","tr":"Bulaşıkları güzel kokutur","hi":"यह बर्तनों को अच्छी गंध देता है","ar":"يجعل الأطباق ذات رائحة طيبة"},{"en":"Cold water sanitizes better","es":"El agua fría desinfecta mejor","ru":"Холодная вода лучше дезинфицирует","tr":"Soğuk su daha iyi dezenfekte eder","hi":"ठंडा पानी बेहतर सैनिटाइज़ करता है","ar":"الماء البارد يعقّم أفضل"},{"en":"It saves detergent","es":"Ahorra detergente","ru":"Это экономит моющее средство","tr":"Deterjan tasarrufu sağlar","hi":"यह डिटर्जेंट बचाता है","ar":"يوفر المنظف"}],"e":{"en":"The wash compartment needs hot water (usually at least 110°F/43°C) with detergent to dissolve grease and lift soil. When it cools, gets greasy, or turns dirty, it must be replaced.","es":"El compartimento de lavado necesita agua caliente (normalmente al menos 110°F/43°C) con detergente para disolver grasa y quitar suciedad. Cuando se enfría, engrasa o ensucia, debe cambiarse.","ru":"Отсек мойки требует горячей воды (обычно не менее 110°F/43°C) с моющим средством для растворения жира и удаления грязи. Когда вода остывает, жирнеет или загрязняется, её меняют.","tr":"Yıkama bölmesi; yağı çözmek ve kiri kaldırmak için deterjanlı sıcak su (genellikle en az 110°F/43°C) gerektirir. Su soğuyunca, yağlanınca ya da kirlenince değiştirilmelidir.","hi":"धोने के कम्पार्टमेंट को चिकनाई घोलने और गंदगी हटाने के लिए डिटर्जेंट के साथ गर्म पानी (आमतौर पर कम से कम 110°F/43°C) चाहिए। जब यह ठंडा, चिकना या गंदा हो जाए, तो इसे बदला जाना चाहिए।","ar":"تحتاج حجرة الغسل ماءً ساخنًا (عادةً 110°F/43°C على الأقل) بالمنظف لإذابة الدهون ورفع الأوساخ. وعندما يبرد أو يصبح دهنيًا أو متسخًا يجب استبداله."}},{"cat":"cleaning","a":1,"q":{"en":"Which is a non-food-contact surface that still needs regular cleaning?","es":"¿Cuál es una superficie sin contacto con alimentos que aún necesita limpieza regular?","ru":"Что является поверхностью без контакта с пищей, которая всё же нуждается в регулярной чистке?","tr":"Yine de düzenli temizlik gerektiren, gıdayla temas etmeyen bir yüzey hangisidir?","hi":"कौन-सी गैर-भोजन-संपर्क सतह है जिसे फिर भी नियमित सफाई की जरूरत है?","ar":"أي سطح غير ملامس للطعام لا يزال يحتاج تنظيفًا منتظمًا؟"},"o":[{"en":"The inside of a mixing bowl","es":"El interior de un tazón de mezclar","ru":"Внутренняя часть миски для смешивания","tr":"Bir karıştırma kabının içi","hi":"मिक्सिंग बाउल का अंदरूनी हिस्सा","ar":"داخل وعاء الخلط"},{"en":"Floors, walls, and the outsides of equipment","es":"Pisos, paredes y el exterior del equipo","ru":"Полы, стены и внешние поверхности оборудования","tr":"Zeminler, duvarlar ve ekipmanın dış yüzeyleri","hi":"फर्श, दीवारें और उपकरण के बाहरी हिस्से","ar":"الأرضيات والجدران والأسطح الخارجية للمعدات"},{"en":"A cutting board surface","es":"La superficie de una tabla de cortar","ru":"Поверхность разделочной доски","tr":"Bir kesme tahtasının yüzeyi","hi":"कटिंग बोर्ड की सतह","ar":"سطح لوح التقطيع"},{"en":"The tines of a serving fork","es":"Las púas de un tenedor de servir","ru":"Зубцы сервировочной вилки","tr":"Servis çatalının dişleri","hi":"सर्विंग फोर्क के दांते","ar":"أسنان شوكة التقديم"}],"e":{"en":"Non-food-contact surfaces, like floors, walls, and equipment exteriors, do not touch food but must be cleaned on a routine schedule to control dust, grease, and pests.","es":"Las superficies sin contacto con alimentos, como pisos, paredes y exteriores del equipo, no tocan la comida pero deben limpiarse de forma rutinaria para controlar polvo, grasa y plagas.","ru":"Поверхности без контакта с пищей — полы, стены, внешние части оборудования — не касаются пищи, но их нужно регулярно чистить для контроля пыли, жира и вредителей.","tr":"Zemin, duvar ve ekipman dışı gibi gıdayla temas etmeyen yüzeyler gıdaya değmez ama toz, yağ ve haşereyi kontrol için düzenli programda temizlenmelidir.","hi":"गैर-भोजन-संपर्क सतहें, जैसे फर्श, दीवारें और उपकरण के बाहरी हिस्से, भोजन को नहीं छूतीं पर धूल, चिकनाई और कीटों को नियंत्रित करने के लिए नियमित समय-सारणी पर साफ की जानी चाहिए।","ar":"الأسطح غير الملامسة للطعام، كالأرضيات والجدران وأسطح المعدات الخارجية، لا تلمس الطعام لكن يجب تنظيفها بروتين منتظم للسيطرة على الغبار والدهون والآفات."}},{"cat":"cleaning","a":2,"q":{"en":"After the correct wash-rinse-sanitize steps, dishes are stacked while still damp. What is the problem?","es":"Tras los pasos correctos de lavar-enjuagar-desinfectar, los platos se apilan aún húmedos. ¿Cuál es el problema?","ru":"После правильных этапов мойка-ополаскивание-санобработка посуду складывают ещё влажной. В чём проблема?","tr":"Doğru yıkama-durulama-dezenfeksiyon adımlarından sonra bulaşıklar hâlâ nemliyken istifleniyor. Sorun nedir?","hi":"सही धोना-कुल्ला-सैनिटाइज़ चरणों के बाद, बर्तन अभी भी नम रहते हुए ढेर किए जाते हैं। समस्या क्या है?","ar":"بعد خطوات الغسل-الشطف-التعقيم الصحيحة، تُكدَّس الأطباق وهي لا تزال رطبة. ما المشكلة؟"},"o":[{"en":"They will look cleaner","es":"Se verán más limpios","ru":"Они будут выглядеть чище","tr":"Daha temiz görünecekler","hi":"वे साफ दिखेंगे","ar":"ستبدو أنظف"},{"en":"Nothing; damp stacking is fine","es":"Nada; apilar húmedo está bien","ru":"Ничего; складывать влажными нормально","tr":"Hiçbir şey; nemli istifleme uygundur","hi":"कुछ नहीं; नम ढेर करना ठीक है","ar":"لا شيء؛ التكديس رطبًا مقبول"},{"en":"Trapped moisture lets bacteria grow, undoing the sanitizing","es":"La humedad atrapada permite que crezcan bacterias, anulando la desinfección","ru":"Задержанная влага позволяет бактериям расти, сводя на нет санобработку","tr":"Hapsolan nem bakteri üremesine izin verir ve dezenfeksiyonu boşa çıkarır","hi":"फंसी नमी बैक्टीरिया को बढ़ने देती है, सैनिटाइज़िंग को व्यर्थ करते हुए","ar":"الرطوبة المحبوسة تسمح بنمو البكتيريا، مبطلة أثر التعقيم"},{"en":"They will dry too fast","es":"Se secarán demasiado rápido","ru":"Они высохнут слишком быстро","tr":"Çok hızlı kuruyacaklar","hi":"वे बहुत तेजी से सूखेंगे","ar":"ستجف بسرعة كبيرة"}],"e":{"en":"Stacking damp dishes traps moisture, which encourages bacteria to grow again on the just-sanitized surfaces. Dishes must be fully air dried before stacking or storage.","es":"Apilar platos húmedos atrapa humedad, lo que favorece que las bacterias vuelvan a crecer en las superficies recién desinfectadas. Deben secarse al aire por completo antes de apilar o guardar.","ru":"Складывание влажной посуды задерживает влагу, что снова способствует росту бактерий на только что обработанных поверхностях. Посуду нужно полностью высушить на воздухе перед хранением.","tr":"Nemli bulaşıkları istiflemek nemi hapseder; bu da yeni dezenfekte edilmiş yüzeylerde bakterinin yeniden üremesini teşvik eder. Bulaşıklar istiflemeden veya saklamadan önce tamamen havada kurumalıdır.","hi":"नम बर्तन ढेर करना नमी फंसाता है, जो अभी-सैनिटाइज़ सतहों पर बैक्टीरिया को फिर से बढ़ने के लिए प्रोत्साहित करता है। बर्तनों को ढेर या भंडारण से पहले पूरी तरह हवा में सुखाना चाहिए।","ar":"تكديس الأطباق الرطبة يحبس الرطوبة، مما يشجع نمو البكتيريا مجددًا على الأسطح المعقمة للتو. يجب تجفيف الأطباق بالهواء تمامًا قبل التكديس أو التخزين."}},{"cat":"cleaning","a":3,"q":{"en":"A food-contact surface used with raw chicken must be cleaned and sanitized:","es":"Una superficie de contacto usada con pollo crudo debe limpiarse y desinfectarse:","ru":"Поверхность контакта, использованную с сырой курицей, нужно мыть и дезинфицировать:","tr":"Çiğ tavukla kullanılan bir gıda temas yüzeyi ne zaman temizlenip dezenfekte edilmeli:","hi":"कच्चे चिकन के साथ उपयोग की गई भोजन-संपर्क सतह को साफ और सैनिटाइज़ किया जाना चाहिए:","ar":"سطح ملامسة الطعام المستخدم مع الدجاج النيئ يجب تنظيفه وتعقيمه:"},"o":[{"en":"Only at the end of the day","es":"Solo al final del día","ru":"Только в конце дня","tr":"Yalnızca gün sonunda","hi":"केवल दिन के अंत में","ar":"في نهاية اليوم فقط"},{"en":"Once a week","es":"Una vez a la semana","ru":"Раз в неделю","tr":"Haftada bir kez","hi":"सप्ताह में एक बार","ar":"مرة في الأسبوع"},{"en":"Never, if chicken is always used there","es":"Nunca, si siempre se usa pollo ahí","ru":"Никогда, если там всегда используют курицу","tr":"Orada hep tavuk kullanılıyorsa asla","hi":"कभी नहीं, यदि वहां हमेशा चिकन उपयोग होता है","ar":"أبدًا، إن كان الدجاج يُستخدم هناك دائمًا"},{"en":"Before switching to another food and at least every 4 hours","es":"Antes de cambiar a otro alimento y al menos cada 4 horas","ru":"Перед переходом на другой продукт и не реже чем каждые 4 часа","tr":"Başka bir gıdaya geçmeden önce ve en az her 4 saatte bir","hi":"दूसरे भोजन पर जाने से पहले और कम से कम हर 4 घंटे में","ar":"قبل الانتقال إلى طعام آخر وكل 4 ساعات على الأقل"}],"e":{"en":"A surface used with raw chicken must be cleaned and sanitized before it is used for any other food, and at least every 4 hours during continuous use, to prevent cross-contamination.","es":"Una superficie usada con pollo crudo debe limpiarse y desinfectarse antes de usarse para otro alimento, y al menos cada 4 horas durante el uso continuo, para evitar la contaminación cruzada.","ru":"Поверхность, использованную с сырой курицей, нужно вымыть и продезинфицировать перед использованием для другого продукта и не реже чем каждые 4 часа при непрерывном использовании, чтобы избежать перекрёстного загрязнения.","tr":"Çiğ tavukla kullanılan bir yüzey, başka gıdaya geçmeden önce ve sürekli kullanımda en az her 4 saatte bir, çapraz bulaşmayı önlemek için temizlenip dezenfekte edilmelidir.","hi":"कच्चे चिकन के साथ उपयोग की गई सतह को किसी अन्य भोजन के लिए उपयोग से पहले और निरंतर उपयोग के दौरान कम से कम हर 4 घंटे में साफ और सैनिटाइज़ किया जाना चाहिए, ताकि क्रॉस-कॉन्टैमिनेशन रुके।","ar":"السطح المستخدم مع الدجاج النيئ يجب تنظيفه وتعقيمه قبل استخدامه لأي طعام آخر، وكل 4 ساعات على الأقل أثناء الاستخدام المستمر، لمنع التلوث المتبادل."}},{"cat":"cleaning","a":0,"q":{"en":"Which statement about hot-water and chemical sanitizing methods is correct?","es":"¿Qué afirmación sobre los métodos de desinfección con agua caliente y con químicos es correcta?","ru":"Какое утверждение о методах санобработки горячей водой и химикатами верно?","tr":"Sıcak su ve kimyasal dezenfeksiyon yöntemleri hakkında hangi ifade doğrudur?","hi":"गर्म पानी और रासायनिक सैनिटाइज़िंग विधियों के बारे में कौन-सा कथन सही है?","ar":"أي عبارة صحيحة عن طرق التعقيم بالماء الساخن والكيميائي؟"},"o":[{"en":"Both are acceptable; heat sanitizes with high temperature, chemicals with the right concentration and contact time","es":"Ambos son aceptables; el calor desinfecta con alta temperatura, los químicos con la concentración y tiempo correctos","ru":"Оба приемлемы; тепло санирует высокой температурой, химикаты — нужной концентрацией и временем контакта","tr":"İkisi de kabul edilir; ısı yüksek sıcaklıkla, kimyasallar doğru konsantrasyon ve temas süresiyle dezenfekte eder","hi":"दोनों स्वीकार्य हैं; ऊष्मा उच्च तापमान से सैनिटाइज़ करती है, रसायन सही सांद्रता और संपर्क समय से","ar":"كلاهما مقبول؛ الحرارة تعقّم بدرجة عالية، والكيميائيات بالتركيز الصحيح وزمن الملامسة"},{"en":"Only hot water can sanitize","es":"Solo el agua caliente puede desinfectar","ru":"Санировать может только горячая вода","tr":"Yalnızca sıcak su dezenfekte edebilir","hi":"केवल गर्म पानी सैनिटाइज़ कर सकता है","ar":"الماء الساخن وحده يمكنه التعقيم"},{"en":"Chemical sanitizers do not need testing","es":"Los desinfectantes químicos no necesitan prueba","ru":"Химические санитайзеры не нуждаются в проверке","tr":"Kimyasal dezenfektanlar test gerektirmez","hi":"रासायनिक सैनिटाइज़र को परीक्षण की जरूरत नहीं","ar":"المعقّمات الكيميائية لا تحتاج فحصًا"},{"en":"Heat sanitizing works at any temperature","es":"La desinfección por calor funciona a cualquier temperatura","ru":"Тепловая санобработка работает при любой температуре","tr":"Isıyla dezenfeksiyon her sıcaklıkta işe yarar","hi":"ऊष्मा सैनिटाइज़िंग किसी भी तापमान पर काम करती है","ar":"التعقيم بالحرارة يعمل عند أي درجة"}],"e":{"en":"Both heat and chemical sanitizing are approved. Heat requires reaching a high enough temperature, while chemical sanitizing depends on correct concentration, water conditions, and contact time.","es":"Tanto la desinfección por calor como la química están aprobadas. El calor requiere alcanzar una temperatura suficientemente alta, mientras que la química depende de concentración, condiciones del agua y tiempo de contacto correctos.","ru":"Одобрены и тепловой, и химический методы. Тепло требует достаточно высокой температуры, а химическая санобработка зависит от правильной концентрации, свойств воды и времени контакта.","tr":"Hem ısı hem kimyasal dezenfeksiyon onaylıdır. Isı yeterince yüksek sıcaklığa ulaşmayı gerektirir; kimyasal dezenfeksiyon ise doğru konsantrasyon, su koşulları ve temas süresine bağlıdır.","hi":"ऊष्मा और रासायनिक दोनों सैनिटाइज़िंग स्वीकृत हैं। ऊष्मा को पर्याप्त उच्च तापमान तक पहुंचना चाहिए, जबकि रासायनिक सैनिटाइज़िंग सही सांद्रता, पानी की स्थिति और संपर्क समय पर निर्भर करती है।","ar":"كلا التعقيمين بالحرارة والكيميائي معتمدان. الحرارة تتطلب بلوغ درجة عالية كافية، بينما يعتمد التعقيم الكيميائي على التركيز الصحيح وظروف الماء وزمن الملامسة."}},{"cat":"illness","a":3,"q":{"en":"A food employee has an infected, uncovered boil on their hand. Under the Food Code, what should the person in charge do?","es":"Un empleado tiene un forúnculo infectado y descubierto en la mano. Según el Código de Alimentos, ¿qué debe hacer la persona a cargo?","ru":"У работника инфицированный открытый фурункул на руке. Согласно Пищевому кодексу, что должно сделать ответственное лицо?","tr":"Bir gıda çalışanının elinde iltihaplı, üzeri açık bir çıban var. Gıda Kanunu'na göre sorumlu kişi ne yapmalı?","hi":"एक फूड कर्मचारी के हाथ पर संक्रमित, खुला फोड़ा है। फूड कोड के अनुसार, प्रभारी व्यक्ति को क्या करना चाहिए?","ar":"لدى موظف طعام دُمّل ملتهب مكشوف في يده. وفق قانون الغذاء، ماذا يجب أن يفعل الشخص المسؤول؟"},"o":[{"en":"Let them keep working as normal","es":"Dejarlo seguir trabajando normalmente","ru":"Позволить работать как обычно","tr":"Normal şekilde çalışmaya devam ettirmek","hi":"उसे सामान्य रूप से काम करने दें","ar":"تركه يعمل كالمعتاد"},{"en":"Ignore it because boils are common","es":"Ignorarlo porque los forúnculos son comunes","ru":"Игнорировать, потому что фурункулы обычны","tr":"Çıbanlar yaygın olduğu için görmezden gelmek","hi":"इसे अनदेखा करें क्योंकि फोड़े आम हैं","ar":"تجاهله لأن الدمامل شائعة"},{"en":"Send them straight home permanently","es":"Enviarlo a casa de forma permanente","ru":"Отправить его домой навсегда","tr":"Onu kalıcı olarak eve göndermek","hi":"उसे स्थायी रूप से घर भेजें","ar":"إرساله إلى المنزل نهائيًا"},{"en":"Restrict or exclude them until the wound is properly covered or healed","es":"Restringirlo o excluirlo hasta que la herida esté bien cubierta o sanada","ru":"Ограничить или отстранить его, пока рана не будет закрыта или заживёт","tr":"Yara düzgün kapatılana ya da iyileşene kadar onu kısıtlamak veya uzaklaştırmak","hi":"जब तक घाव ठीक से ढका या भर न जाए, उसे प्रतिबंधित या बाहर करें","ar":"تقييده أو استبعاده حتى تُغطّى الجرح بشكل سليم أو تُشفى"}],"e":{"en":"An infected wound with pus, like a boil, is a source of Staphylococcus. The employee must be restricted or excluded until the wound is covered with an impermeable bandage and cover, or has healed.","es":"Una herida infectada con pus, como un forúnculo, es fuente de Staphylococcus. El empleado debe ser restringido o excluido hasta que la herida se cubra con una venda impermeable y protección, o sane.","ru":"Инфицированная рана с гноем, как фурункул, — источник стафилококка. Работника нужно ограничить или отстранить, пока рана не будет закрыта непроницаемой повязкой или не заживёт.","tr":"İltihaplı, cerahatli bir yara (çıban gibi) Staphylococcus kaynağıdır. Çalışan, yara geçirimsiz bir bandaj ve örtüyle kapatılana ya da iyileşene kadar kısıtlanmalı veya uzaklaştırılmalıdır.","hi":"मवाद वाला संक्रमित घाव, जैसे फोड़ा, स्टैफिलोकोकस का स्रोत है। कर्मचारी को तब तक प्रतिबंधित या बाहर किया जाना चाहिए जब तक घाव अभेद्य पट्टी और आवरण से ढका या भर न जाए।","ar":"الجرح الملتهب بالقيح، كالدُّمّل، مصدر للمكورات العنقودية. يجب تقييد الموظف أو استبعاده حتى يُغطّى الجرح بضمادة وغطاء غير منفذين، أو يُشفى."}}]};
